// Sağlık kontrolü - auth gerektirmez, 500 teşhisi için
app.get('/api/health', async (req, res) => {
    try {
        const tables = ['tenants_kullanicilar', 'tenants', 'musteriler', 'kampanyalar'];
        const status = {};
        for (const t of tables) {
            try {
                const r = await query("SELECT name FROM sqlite_master WHERE type='table' AND name=?", [t]);
                status[t] = r && r.length > 0 ? 'ok' : 'missing';
            } catch (e) {
                status[t] = 'error: ' + (e?.message || e);
            }
        }
        res.json({ success: true, db: status });
    } catch (error) {
        res.status(500).json({ success: false, error: error?.message || String(error) });
    }
});

