// Request'ten base URL'i al (localhost veya production)
function getBaseUrlFromRequest(req) {
    // Localhost kontrolü - eğer request localhost'tan geliyorsa localhost kullan
    const host = req.get('host') || req.headers.host || 'localhost:3001';
    const isLocalhost = host.includes('localhost') || 
                       host.includes('127.0.0.1') || 
                       host.includes(':3001') || 
                       host.includes(':5501') ||
                       host.includes(':5500');
    
    if (isLocalhost) {
        // Localhost'ta çalışıyorsak MUTLAKA localhost kullan
        const protocol = 'http'; // Localhost'ta her zaman HTTP
        return `${protocol}://${host}`;
    }
    
    // Production'da: Eğer environment variable set edilmişse ve localhost içermiyorsa onu kullan
    if (process.env.SERVER_PUBLIC_URL && !process.env.SERVER_PUBLIC_URL.includes('localhost') && !process.env.SERVER_PUBLIC_URL.includes('127.0.0.1')) {
        return process.env.SERVER_PUBLIC_URL;
    }
    
    // Request'ten protocol ve host bilgisini al
    // req.protocol Express'te otomatik olarak 'https' veya 'http' olur
    // Ama reverse proxy arkasındaysa req.headers['x-forwarded-proto'] kontrol et
    let protocol = req.protocol || 'http';
    if (req.headers['x-forwarded-proto']) {
        protocol = req.headers['x-forwarded-proto'].split(',')[0].trim();
    } else if (req.secure) {
        protocol = 'https';
    }
    
    const baseUrl = `${protocol}://${host}`;
    if (isDevelopment) {
        console.log('🌐 Base URL oluşturuldu:', baseUrl);
    }
    return baseUrl;
}

