/** Şifre sıfırlama mailindeki linkin base URL'i: FRONTEND_URL > isteğin Origin'i (izinliyse) > getBaseUrlFromRequest */
function getFrontendBaseForResetLink(req) {
    if (process.env.FRONTEND_URL && String(process.env.FRONTEND_URL).trim()) {
        return String(process.env.FRONTEND_URL).replace(/\/$/, '');
    }
    const origin = (req.get('X-Frontend-Origin') || req.get('Origin') || '').trim();
    if (origin && ALLOWED_ORIGINS.includes(origin)) {
        return origin.replace(/\/$/, '');
    }
    return getBaseUrlFromRequest(req);
}

/**
 * Plan işlemleri sonrası abonelik maili gönderir (yeni abonelik, plan değişikliği veya iptal).
 * @param {'yeni'|'plan_degisikligi'|'iptal'} type
 * @param {Object} opts - tenantId, tenantCode (veya tenants_no), tenant row (email, name, firma_adi), planAdi, faturaDongusu, aylikUcretKurus, faturaNo, donemBitis (iptal için), cancel_reason (iptal için)
 */
async function sendAbonelikMail(type, opts) {
    const { tenantId, tenantCode, tenant, planAdi, faturaDongusu, aylikUcretKurus, faturaNo, donemBitis, cancel_reason, baseUrl: optsBaseUrl } = opts;
    const to = tenant && (tenant.email || tenant.e_posta);
    if (!to || !String(to).trim()) return;
    const mailService = getMailService();
    if (!mailService || (!mailService.noreplyInitialized && !mailService.initialized)) return;
    const baseUrl = optsBaseUrl && String(optsBaseUrl).trim() ? String(optsBaseUrl).trim().replace(/\/$/, '') : (process.env.SERVER_PUBLIC_URL || process.env.FRONTEND_URL || '').trim().replace(/\/$/, '') || (process.env.API_BASE_URL || '').trim().replace(/\/api.*$/, '') || 'http://localhost:3001';
    const code = tenantCode || (tenant && tenant.tenants_no) || '';
    const dashboardUrl = code ? `${baseUrl}/landing/dashboard.html?tenant=${encodeURIComponent(code)}` : baseUrl;
    const tenantInfo = [{ firma_adi: (tenant && (tenant.firma_adi || tenant.name)) || '', yetkili_kisi: (tenant && tenant.name) || '' }];
    const planAdiFormatli = planAdi || 'Abonelik Planı';
    try {
        if (type === 'yeni') {
            const ucretMetni = faturaDongusu === 'yillik' ? 'Yıllık Ücret (Aylık Eşdeğer)' : 'Aylık Ücret';
            const gosterilecekFiyat = Math.round(Number(aylikUcretKurus) || 0);
            const toplamTutar = Math.round(gosterilecekFiyat * 1.2);
            const todayStr = new Date().toISOString().split('T')[0];
            const nextStr = donemBitis || todayStr;
            const html = abonelikMailTemplates.generateYeniAbonelikMail({
                tenantInfo,
                planAdiFormatli,
                ucretMetni,
                gosterilecekFiyat,
                faturaDongusu: faturaDongusu || 'aylik',
                faturaNo: faturaNo || '',
                toplamTutar,
                todayStrFormatted: abonelikMailTemplates.formatDateTR(todayStr),
                nextPaymentFormatted: abonelikMailTemplates.formatDateTR(nextStr),
                dashboardUrl
            });
            const attachments = mailService.getLogoAttachment ? mailService.getLogoAttachment() : [];
            await mailService.sendMail({ to, subject: 'Yeni Abonelik Başlatıldı', html, from: 'noreply@floovon.com', attachments, noTenantInSubject: true });
        } else if (type === 'plan_degisikligi') {
            const ucretMetni = faturaDongusu === 'yillik' ? 'Yıllık Ücret (Aylık Eşdeğer)' : 'Aylık Ücret';
            const gosterilecekFiyat = Math.round(Number(aylikUcretKurus) || 0);
            const toplamTutar = Math.round(gosterilecekFiyat * 1.2);
            const faturaTarihiFormatted = abonelikMailTemplates.formatDateTR(new Date().toISOString().split('T')[0]);
            const html = abonelikMailTemplates.generatePlanDegisikligiMail({
                tenantInfo,
                planAdiFormatli,
                ucretMetni,
                gosterilecekFiyat,
                faturaDongusu: faturaDongusu || 'aylik',
                faturaNo: faturaNo || '',
                faturaTarihiFormatted,
                toplamTutar,
                dashboardUrl
            });
            const attachments = mailService.getLogoAttachment ? mailService.getLogoAttachment() : [];
            await mailService.sendMail({ to, subject: 'Abonelik Planı Güncellemesi', html, from: 'noreply@floovon.com', attachments, noTenantInSubject: true });
        } else if (type === 'iptal') {
            const donemBitisTarihi = abonelikMailTemplates.formatDateTR(donemBitis || '');
            const html = abonelikMailTemplates.generateAbonelikIptaliMail({
                tenantInfo,
                planAdiFormatli,
                donemBitisTarihi,
                cancel_reason: (cancel_reason && String(cancel_reason).trim()) ? String(cancel_reason).trim() : 'Belirtilmedi',
                dashboardUrl
            });
            const attachments = mailService.getLogoAttachment ? mailService.getLogoAttachment() : [];
            await mailService.sendMail({ to, subject: 'Abonelik Plan İptali', html, from: 'noreply@floovon.com', attachments, noTenantInSubject: true });
        }
    } catch (e) {
        console.warn('⚠️ Abonelik maili gönderilemedi:', e?.message || e);
    }
}

// Fatura durumları için izin verilen değerler
const ALLOWED_FATURA_DURUMLARI = new Set(['kesildi', 'gonderildi', 'odendi', 'beklemede', 'taslak', 'iptal']);

function normalizeFaturaDurumu(durum) {
    if (durum === undefined || durum === null) {
        return null;
    }

    const raw = String(durum).trim().toLowerCase();
    if (!raw) {
        return null;
    }

    const aliasMap = {
        'tahsil edildi': 'odendi',
        'tahsil-edildi': 'odendi',
        'tahsil_edildi': 'odendi',
        'ödendi': 'odendi',
        'ödenecek': 'beklemede',
        'kesilmedi': 'beklemede'
    };

    if (aliasMap[raw]) {
        return aliasMap[raw];
    }

    const normalized = raw.replace(/\s+/g, '-');
    return normalized.length > 0 ? normalized : null;
}

async function updateMusteriFaturaDurumu(musteriId, faturaId, yeniDurumRaw, req = null) {
    const normalizedDurum = normalizeFaturaDurumu(yeniDurumRaw);

    if (!normalizedDurum || !ALLOWED_FATURA_DURUMLARI.has(normalizedDurum)) {
        return {
            ok: false,
            status: 400,
            body: {
                success: false,
                error: 'Geçersiz fatura durumu'
            }
        };
    }

    const numericFaturaId = Number(faturaId);
    if (!Number.isInteger(numericFaturaId) || numericFaturaId <= 0) {
        return {
            ok: false,
            status: 400,
            body: {
                success: false,
                error: 'Geçersiz fatura ID'
            }
        };
    }

    // Tenant kontrolü ekle
    const tenantId = req ? (req.tenantId || await getTenantId(req)) : null;
    let result;

    // İptal = fatura kaydını sil (eskiden olduğu gibi listeden çıksın)
    if (normalizedDurum === 'iptal') {
        if (tenantId) {
            result = await execute(`
                DELETE FROM musteri_faturalar
                WHERE id = ? AND musteri_id = ? AND tenant_id = ?
            `, [numericFaturaId, musteriId, tenantId]);
        } else {
            result = await execute(`
                DELETE FROM musteri_faturalar
                WHERE id = ? AND musteri_id = ?
            `, [numericFaturaId, musteriId]);
        }
        if (result.changes === 0) {
            return {
                ok: false,
                status: 404,
                body: { success: false, error: 'Fatura bulunamadı' }
            };
        }
        return {
            ok: true,
            status: 200,
            body: {
                success: true,
                message: 'Fatura iptal edildi.',
                data: { durum: 'iptal', deleted: true }
            }
        };
    }

    const kullaniciAdi = req ? await getCurrentUsername(req).catch(() => null) : null;
    if (tenantId) {
        result = await execute(`
            UPDATE musteri_faturalar
            SET durum = ?, updated_at = CURRENT_TIMESTAMP, updated_by = ?
            WHERE id = ? AND musteri_id = ? AND tenant_id = ?
        `, [normalizedDurum, kullaniciAdi, numericFaturaId, musteriId, tenantId]);
    } else {
        result = await execute(`
            UPDATE musteri_faturalar
            SET durum = ?, updated_at = CURRENT_TIMESTAMP, updated_by = ?
            WHERE id = ? AND musteri_id = ?
        `, [normalizedDurum, kullaniciAdi, numericFaturaId, musteriId]);
    }

    if (result.changes === 0) {
        return {
            ok: false,
            status: 404,
            body: {
                success: false,
                error: 'Fatura bulunamadı'
            }
        };
    }

    return {
        ok: true,
        status: 200,
        body: {
            success: true,
            message: 'Fatura durumu güncellendi',
            data: { durum: normalizedDurum }
        }
    };
}

// Middleware
// CORS Configuration - Localhost ve production için
const corsOptions = {
    origin: function (origin, callback) {
        // Origin yoksa (Postman, curl, file:// protokolü gibi) izin ver
        if (!origin || origin === 'null') {
            return callback(null, true);
        }
        
        // Localhost veya 127.0.0.1 ise her zaman izin ver (geliştirme için)
        if (origin.includes('localhost') || origin.includes('127.0.0.1')) {
            return callback(null, true);
        }
        
        // İzin verilen origin'ler listesinde var mı kontrol et
        if (ALLOWED_ORIGINS.indexOf(origin) !== -1) {
            callback(null, true);
        } else {
            console.warn(`⚠️ CORS: İzin verilmeyen origin: ${origin}`);
            callback(new Error('CORS policy tarafından izin verilmedi'));
        }
    },
    credentials: true,
    optionsSuccessStatus: 200,
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS', 'PATCH'],
    allowedHeaders: ['Content-Type', 'Authorization', 'X-User-ID', 'X-Tenant-ID', 'X-Requested-With', 'X-Frontend-Origin', 'Cache-Control', 'Pragma', 'Expires']
};

app.use(cors(corsOptions));
app.use(cookieParser()); // Cookie parser middleware

// SSE: Aynı tenant'taki tüm açık oturumlara anında invalidate yayını (tenantId -> Set<res>)
const sseTenantClients = new Map();
function broadcastSseToTenant(tenantId, eventData) {
    if (!tenantId) return;
    const set = sseTenantClients.get(tenantId);
    if (!set || set.size === 0) return;
    const data = typeof eventData === 'string' ? eventData : JSON.stringify(eventData || { type: 'invalidate' });
    set.forEach((res) => {
        try {
            res.write(`data: ${data}\n\n`);
        } catch (e) {
            // bağlantı kapalı
        }
    });
}

// API için global hata yakalayıcı (4 argüman = Express error handler)
app.use((err, req, res, next) => {
    if (res.headersSent) return next(err);
    const isApi = req.path?.startsWith('/api') || req.path?.startsWith('/uploads');
    if (isApi) {
        console.error('❌ [Express error handler]', err?.message || err);
        if (err?.stack) console.error(err.stack);
        return res.status(500).json({
            success: false,
            error: 'Sunucu hatası',
            message: err?.message || String(err)
        });
    }
    next(err);
});

