// Statik upload klasörlerini servis et - GÜVENLİK: Tenant kontrolü ile
// Tenant-based yapı: backend/uploads/tenants/<tenantId>/...
// URL: /uploads/tenants/<tenantId>/...
// GÜVENLİK: Sadece kullanıcının kendi tenant'ının dosyalarına erişmesine izin ver
app.use('/uploads', async (req, res, next) => {
    // URL'den tenant ID'yi çıkar: /uploads/tenants/<tenantId>/...
    const uploadsMatch = req.path.match(/^\/tenants\/(\d+)\//);
    
    if (!uploadsMatch) {
        // Tenant ID yoksa, eski yapı olabilir veya geçersiz path
        // Eski yapıyı desteklemek için direkt servis et (geriye dönük uyumluluk)
        return express.static(path.join(__dirname, 'uploads'))(req, res, next);
    }
    
    const requestedTenantId = parseInt(uploadsMatch[1]);
    
    // Kullanıcının tenant ID'sini al (güvenli yöntem - token'dan veya user ID'den)
    try {
        const userTenantId = req.tenantId || await getTenantId(req);
        
        // Cookie kontrolü - eğer cookie yoksa ve bu bir GET isteği ise (resim yükleme)
        // dosyanın varlığını kontrol et ve tenant ID eşleşiyorsa izin ver
        const hasCookie = req?.cookies?.floovon_user_id;
        const isGetRequest = req.method === 'GET';
        const isImageRequest = isGetRequest && (
            req.path.match(/\.(jpg|jpeg|png|gif|webp|svg|ico)$/i) ||
            req.headers.accept?.includes('image/')
        );
        
        // GÜVENLİK: Tenant ID kontrolü - mutlaka eşleşmeli
        // GET ile resim/dosya isteği ve cookie yoksa (örn. künye penceresindeki img): dosya varsa servis et
        if (!userTenantId) {
            const isGetRequest = req.method === 'GET';
            const isStaticFile = isGetRequest && (
                req.path.match(/\.(jpg|jpeg|png|gif|webp|svg|ico|pdf)$/i) ||
                req.headers.accept?.includes('image/')
            );
            if (isStaticFile) {
                const relativePath = req.path.replace(/^\//, '').replace(/\.\./g, '');
                const fullPath = path.join(__dirname, 'uploads', relativePath);
                if (fs.existsSync(fullPath)) {
                    return res.sendFile(fullPath);
                }
            }
            console.warn('🚨 GÜVENLİK: Tenant ID bulunamadı - dosya erişimi reddedildi:', {
                requestedTenantId,
                userTenantId: 'NULL',
                hasCookie: !!hasCookie,
                isImageRequest,
                path: req.path,
                ip: req.ip || req.connection?.remoteAddress,
                cookies: req.cookies ? Object.keys(req.cookies) : []
            });
            return res.status(403).json({
                success: false,
                error: 'Bu dosyaya erişim yetkiniz yok. Lütfen giriş yapın.'
            });
        }

        // Tenant ID eşleşmiyorsa - manipülasyon denemesi
        if (userTenantId !== requestedTenantId) {
            console.warn('🚨 GÜVENLİK: Tenant ID manipülasyon denemesi - dosya erişimi reddedildi:', {
                requestedTenantId,
                userTenantId: userTenantId,
                hasCookie: !!hasCookie,
                isImageRequest,
                path: req.path,
                ip: req.ip || req.connection?.remoteAddress,
                cookies: req.cookies ? Object.keys(req.cookies) : []
            });
            return res.status(403).json({
                success: false,
                error: 'Bu dosyaya erişim yetkiniz yok'
            });
        }
        
        // Tenant ID eşleşiyorsa, statik dosyayı servis et
        return express.static(path.join(__dirname, 'uploads'))(req, res, next);
    } catch (error) {
        console.error('❌ Uploads middleware hatası:', error);
        console.error('❌ Hata detayları:', {
            message: error.message,
            stack: error.stack,
            path: req.path,
            cookies: req.cookies ? Object.keys(req.cookies) : []
        });
        return res.status(500).json({
            success: false,
            error: 'Dosya erişim kontrolü hatası',
            message: error?.message || String(error)
        });
    }
});

