// Helper function: HTML dosyası var mı kontrol et ve gönder
function sendHtmlFile(req, res, filePath) {
    const fullPath = path.join(staticFilesPath, filePath);
    if (fs.existsSync(fullPath)) {
        res.sendFile(fullPath);
    } else if (hasTenantAppDist) {
        res.sendFile(path.join(tenantAppDistPath, 'index.html'));
    } else {
        res.status(404).sendFile(path.join(staticFilesPath, 'index.html'));
    }
}

// Helper function: HEAD ve GET request'leri handle et
function handleHtmlRoute(routePath, htmlFile) {
    // GET request'leri için
    app.get(routePath, (req, res) => {
        sendHtmlFile(req, res, htmlFile);
    });
    // HEAD request'leri için (preloader için)
    app.head(routePath, (req, res) => {
        const fullPath = path.join(staticFilesPath, htmlFile);
        if (fs.existsSync(fullPath)) {
            res.status(200).end();
        } else {
            res.status(404).end();
        }
    });
}

// 1. .html uzantılı URL'leri uzantısız versiyona yönlendir (301 redirect - SEO için)
// API ve uploads route'larını hariç tut
app.get(/^(.+)\.html$/, (req, res, next) => {
    // API ve uploads route'larını atla
    if (req.path.startsWith('/api/') || req.path.startsWith('/uploads/')) {
        return next();
    }
    const urlWithoutHtml = req.path.replace(/\.html$/, '');
    const queryString = req.url.includes('?') ? req.url.substring(req.url.indexOf('?')) : '';
    res.redirect(301, urlWithoutHtml + queryString);
});

// HEAD request'leri için de aynı redirect
app.head(/^(.+)\.html$/, (req, res, next) => {
    if (req.path.startsWith('/api/') || req.path.startsWith('/uploads/')) {
        return next();
    }
    const urlWithoutHtml = req.path.replace(/\.html$/, '');
    res.redirect(301, urlWithoutHtml);
});

