// ============================================================================
// TENANT-BASED UPLOAD SYSTEM - Security & Helper Functions
// ============================================================================

/**
 * Güvenlik: tenantId ve bucket adlarını sanitize et
 * Sadece [a-zA-Z0-9_-] karakterlerine izin ver, path traversal engelle
 */
function sanitizeTenantId(tenantId) {
    if (!tenantId || typeof tenantId !== 'string' && typeof tenantId !== 'number') {
        throw new Error('Tenant ID gerekli ve geçerli olmalıdır');
    }
    const sanitized = String(tenantId).replace(/[^a-zA-Z0-9_-]/g, '');
    if (!sanitized || sanitized.length === 0) {
        throw new Error('Geçersiz tenant ID formatı');
    }
    // Path traversal kontrolü
    if (sanitized.includes('..') || sanitized.includes('/') || sanitized.includes('\\')) {
        throw new Error('Güvenlik: Path traversal tespit edildi');
    }
    return sanitized;
}

/**
 * Güvenlik: bucket adını sanitize et
 * Sadece [a-zA-Z0-9_-] karakterlerine izin ver
 */
function sanitizeBucket(bucket) {
    if (!bucket || typeof bucket !== 'string') {
        throw new Error('Bucket adı gerekli ve string olmalıdır');
    }
    const sanitized = bucket.replace(/[^a-zA-Z0-9_-]/g, '');
    if (!sanitized || sanitized.length === 0) {
        throw new Error('Geçersiz bucket formatı');
    }
    // Path traversal kontrolü
    if (sanitized.includes('..') || sanitized.includes('/') || sanitized.includes('\\')) {
        throw new Error('Güvenlik: Path traversal tespit edildi');
    }
    return sanitized;
}

/**
 * Güvenlik: dosya adını sanitize et (path traversal engelle)
 */
function sanitizeFilename(filename) {
    if (!filename || typeof filename !== 'string') {
        return 'file';
    }
    // Path traversal karakterlerini temizle
    let sanitized = filename.replace(/\.\./g, '').replace(/[\/\\]/g, '_');
    // Zararlı karakterleri temizle ama Türkçe karakterleri koru
    sanitized = sanitized.replace(/[<>:"|?*]/g, '_');
    return sanitized || 'file';
}

/**
 * Tenant-based upload path oluştur
 * Format: uploads/tenants/<tenantId>/<bucket>/...
 * 
 * @param {number|string} tenantId - Tenant ID (req.tenantId veya getTenantId'den)
 * @param {string} bucket - Bucket adı (customers, organizations, campaigns, profiles, etc.)
 * @param {...string} subPaths - Ek alt klasörler (opsiyonel)
 * @returns {string} Absolute path
 */
function getTenantUploadPath(tenantId, bucket, ...subPaths) {
    try {
        const safeTenantId = sanitizeTenantId(tenantId);
        const safeBucket = sanitizeBucket(bucket);
        
        // Base path: uploads/tenants/<tenantId>/<bucket>
        let targetPath = path.join(uploadRoot, 'tenants', safeTenantId, safeBucket);
        
        // Alt klasörler varsa ekle
        if (subPaths && subPaths.length > 0) {
            const safeSubPaths = subPaths
                .filter(p => p && typeof p === 'string')
                .map(p => sanitizeFilename(p));
            if (safeSubPaths.length > 0) {
                targetPath = path.join(targetPath, ...safeSubPaths);
            }
        }
        
        // Klasörü oluştur
        fs.mkdirSync(targetPath, { recursive: true });
        
        return targetPath;
    } catch (error) {
        console.error('❌ Tenant upload path oluşturma hatası:', error);
        throw error;
    }
}

/**
 * Tenant-based relative path oluştur (API response için)
 * Format: uploads/tenants/<tenantId>/<bucket>/...
 * 
 * @param {number|string} tenantId - Tenant ID
 * @param {string} bucket - Bucket adı
 * @param {...string} subPaths - Ek alt klasörler ve dosya adı
 * @returns {string} Relative path (uploads/tenants/...)
 */
function getTenantRelativePath(tenantId, bucket, ...subPaths) {
    try {
        const safeTenantId = sanitizeTenantId(tenantId);
        const safeBucket = sanitizeBucket(bucket);
        
        // Base path: uploads/tenants/<tenantId>/<bucket>
        let parts = ['uploads', 'tenants', safeTenantId, safeBucket];
        
        // Alt klasörler ve dosya adı varsa ekle
        if (subPaths && subPaths.length > 0) {
            const safeSubPaths = subPaths
                .filter(p => p && typeof p === 'string')
                .map(p => sanitizeFilename(p));
            parts = parts.concat(safeSubPaths);
        }
        
        return parts.join('/');
    } catch (error) {
        console.error('❌ Tenant relative path oluşturma hatası:', error);
        throw error;
    }
}

