// Teslim foto storage - Tenant-based
const storage = multer.diskStorage({
    destination: async function (req, file, cb) {
        try {
            // Tenant ID'yi güvenli şekilde al (client'tan DEĞİL, backend'den)
            const tenantId = req.tenantId || await getTenantId(req);
            if (!tenantId) {
                return cb(new Error('Tenant ID bulunamadı. Lütfen giriş yapın.'));
            }
            
            const { organizasyonId } = req.params;
            const safeId = String(organizasyonId || 'unknown').replace(/[^a-zA-Z0-9_-]/g, '');
            
            // Tenant-based path: uploads/tenants/<tenantId>/organizations/<organizasyonId>/teslim-fotolar
            const targetDir = getTenantUploadPath(tenantId, 'organizations', safeId, 'teslim-fotolar');
            cb(null, targetDir);
        } catch (error) {
            console.error('❌ Teslim foto storage destination hatası:', error);
            cb(error);
        }
    },
    filename: function (req, file, cb) {
        // Multer'da geçici bir isim kullan - endpoint'te yeniden adlandırılacak
        // Böylece dosya adı formatını endpoint'te tam kontrol edebiliriz
        const ext = path.extname(file.originalname) || '.png';
        const timestamp = Date.now();
        const random = Math.random().toString(36).substring(2, 9);
        const tempFilename = `temp_${timestamp}_${random}${ext}`;
        cb(null, tempFilename);
    }
});

// Müşteri dosya storage - GEÇİCİ bir klasöre kaydet, sonra taşıyacağız
const tempStorage = multer.diskStorage({
    destination: function (req, file, cb) {
        // Geçici klasör
        const tempDir = path.join(uploadRoot, 'temp');
        fs.mkdirSync(tempDir, { recursive: true });
        cb(null, tempDir);
    },
    filename: function (req, file, cb) {
        // Orijinal dosya adını koru
        cb(null, file.originalname);
    }
});

// Müşteri dosya storage - Tenant-based
const customerStorage = multer.diskStorage({
    destination: async function (req, file, cb) {
        try {
            // Tenant ID'yi güvenli şekilde al (client'tan DEĞİL, backend'den)
            const tenantId = req.tenantId || await getTenantId(req);
            if (!tenantId) {
                return cb(new Error('Tenant ID bulunamadı. Lütfen giriş yapın.'));
            }
            
            // Query string'den müşteri bilgilerini al
            const customerId = req.query?.customerId || req.body?.customerId;
            const customerUnvan = req.query?.customerUnvan || req.body?.customerUnvan;
            
            // Güvenli değer kontrolü
            const safeCustomerId = String(customerId || 'unknown').replace(/[^a-zA-Z0-9_-]/g, '');
            const safeCustomerUnvan = customerUnvan || 'musteri';
            
            // Türkçe karakterleri temizle ve müşteri adını düzenle
            const cleanUnvan = safeCustomerUnvan
                .replace(/ç/g, 'c').replace(/ğ/g, 'g').replace(/ı/g, 'i')
                .replace(/ö/g, 'o').replace(/ş/g, 's').replace(/ü/g, 'u')
                .replace(/Ç/g, 'C').replace(/Ğ/g, 'G').replace(/İ/g, 'I')
                .replace(/Ö/g, 'O').replace(/Ş/g, 'S').replace(/Ü/g, 'U')
                .replace(/[^a-zA-Z0-9_-]/g, '-')
                .toLowerCase();
            
            // Müşteri klasörü oluştur: {customerId}-{temiz-unvan}
            const customerFolder = `${safeCustomerId}-${cleanUnvan}`;
            
            // Tenant-based path: uploads/tenants/<tenantId>/customers/<customerFolder>/urun_yazi_dosyalari
            const urunYaziDir = getTenantUploadPath(tenantId, 'customers', customerFolder, 'urun_yazi_dosyalari');
            
            cb(null, urunYaziDir);
        } catch (err) {
            console.error('❌ Upload klasör oluşturma hatası:', err);
            cb(err);
        }
    },
    filename: function (req, file, cb) {
        try {
            let originalName = 'dosya';
            
            // ÖNCE: Query string'den dosya adını al (öncelikli - zaten UTF-8 encode edilmiş)
            if (req.query?.fileName) {
                try {
                    originalName = decodeURIComponent(req.query.fileName);
                } catch (e) {
                    console.warn('⚠️ Query string decode hatası:', e);
                    // Fallback: Multer'dan geleni Latin1→UTF-8 dönüştür
                    originalName = Buffer.from(file.originalname || 'dosya', 'latin1').toString('utf8');
                }
            } else {
                // Query string yoksa Multer'dan geleni Latin1→UTF-8 dönüştür
                originalName = Buffer.from(file.originalname || 'dosya', 'latin1').toString('utf8');
            }
            
            const ext = path.extname(originalName) || '.png';
            
            // Dosya adını path.basename kullanmadan al (Türkçe karakterleri korumak için)
            let nameWithoutExt = originalName;
            if (originalName.includes('.')) {
                nameWithoutExt = originalName.substring(0, originalName.lastIndexOf('.'));
            }
            
            // Sadece güvenlik için zararlı karakterleri temizle, Türkçe karakterleri koru
            const safeName = nameWithoutExt
                .replace(/[<>:"/\\|?*]/g, '_') // Sadece dosya sistemi için zararlı karakterleri temizle
                .replace(/\s+/g, '_'); // Boşlukları alt çizgi ile değiştir
            
            // Türkçe karakterleri koruyarak safe name oluştur
            const filename = `${safeName}${ext}`;
            cb(null, filename);
        } catch (error) {
            console.error('❌ Dosya adı işleme hatası:', error);
            const fallbackName = `dosya_${Date.now()}${path.extname(file.originalname) || '.png'}`;
            cb(null, fallbackName);
        }
    }
});

