// Profil resmi storage - Tenant-based
const profileStorage = multer.diskStorage({
    destination: async function (req, file, cb) {
        try {
            // Tenant ID'yi güvenli şekilde al (client'tan DEĞİL, backend'den)
            let tenantId;
            try {
                tenantId = req.tenantId || await getTenantId(req);
            } catch (tenantError) {
                console.error('❌ Tenant ID alınamadı:', tenantError);
                return cb(new Error('Tenant ID bulunamadı. Lütfen giriş yapın.'));
            }
            
            if (!tenantId) {
                return cb(new Error('Tenant ID bulunamadı. Lütfen giriş yapın.'));
            }
            
            // userId'yi query string veya body'den al
            const userId = req.query.userId || req.body.userId;
            if (!userId) {
                return cb(new Error('Kullanıcı ID/adı gerekli'));
            }
            
            // userId sayısal ise (ID), veritabanından kullanıcı adı kolonunu al (username veya kullaniciadi)
            let userSlug;
            if (/^\d+$/.test(String(userId))) {
                try {
                    const columns = await query('PRAGMA table_info(tenants_kullanicilar)');
                    const colNames = (columns || []).map(c => c.name);
                    const hasTenantId = colNames.includes('tenant_id');
                    const usernameCol = colNames.includes('username') ? 'username' : (colNames.includes('kullaniciadi') ? 'kullaniciadi' : 'username');
                    const user = hasTenantId
                        ? await query(`SELECT ${usernameCol} FROM tenants_kullanicilar WHERE id = ? AND tenant_id = ? AND is_active = 1`, [parseInt(userId, 10), tenantId])
                        : await query(`SELECT ${usernameCol} FROM tenants_kullanicilar WHERE id = ? AND is_active = 1`, [parseInt(userId, 10)]);
                    if (!user || user.length === 0 || !user[0]) {
                        console.error('❌ Kullanıcı bulunamadı (storage):', { userId, tenantId, user });
                        return cb(new Error('Kullanıcı bulunamadı'));
                    }
                    
                    const username = user[0][usernameCol];
                    if (!username || typeof username !== 'string' || String(username).trim() === '') {
                        console.error('❌ Kullanıcı adı boş veya geçersiz (storage):', { userId, tenantId, user: user[0] });
                        return cb(new Error('Kullanıcı adı bulunamadı. Lütfen kullanıcı adını güncelleyin.'));
                    }
                    
                    userSlug = String(username).replace(/[^a-zA-Z0-9_-]/g, '');
                } catch (queryError) {
                    console.error('❌ Kullanıcı sorgusu hatası:', queryError);
                    return cb(new Error('Kullanıcı bilgileri alınamadı'));
                }
            } else {
                // Zaten kullanıcı adı (username) olarak gönderilmiş
                userSlug = userId.replace(/[^a-zA-Z0-9_-]/g, '');
            }
            
            if (!userSlug || userSlug.trim() === '') {
                return cb(new Error('Geçersiz kullanıcı adı'));
            }
            
            // Tenant-based path: uploads/tenants/<tenantId>/profiles/<userSlug>
            let targetDir;
            try {
                targetDir = getTenantUploadPath(tenantId, 'profiles', userSlug);
                fs.mkdirSync(targetDir, { recursive: true });
            } catch (pathError) {
                console.error('❌ Klasör oluşturma hatası:', pathError);
                return cb(new Error('Profil resmi klasörü oluşturulamadı'));
            }
            
            cb(null, targetDir);
        } catch (error) {
            console.error('❌ Profil resmi storage destination hatası:', error);
            console.error('❌ Hata detayları:', error.message, error.stack);
            cb(error);
        }
    },
    filename: function (req, file, cb) {
        const ext = path.extname(file.originalname) || '.jpg';
        const timestamp = Date.now();
        const filename = `profile_${timestamp}${ext}`;
        cb(null, filename);
    }
});

