// Upload teslim foto
app.post('/api/organizasyon-kartlar/:organizasyonId/teslim-fotolar', upload.array('files', 20), async (req, res) => {
    try {
        const { organizasyonId } = req.params;
        const uploadedFiles = req.files || [];
        const count = uploadedFiles.length;
        if (!count) return res.json({ success: true, updated: 0, files: [] });

        // filenamePrefix'i al (query veya body'den)
        let prefixRaw = (req.query?.filenamePrefix || req.body?.filenamePrefix || '').toString().trim();
        
        // Prefix yoksa (galeriye eklenen fotoğraflar için), varsayılan prefix kullan
        if (!prefixRaw) {
            prefixRaw = 'galeriye_eklenen_siparis_teslim_foto';
        }
        
        // Tenant kontrolü (önce tenant ID'yi al)
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // Tenant-based path kullan (storage zaten tenant-based klasöre kaydetti)
        const safeId = String(organizasyonId).replace(/[^a-zA-Z0-9_-]/g, '');
        const teslimFotolarDir = uploadedFiles.length > 0 ? path.dirname(uploadedFiles[0].path) : getTenantUploadPath(tenantId, 'organizations', safeId, 'teslim-fotolar');
        
        // Mevcut dosyaları oku (varsa)
        let existingFiles = [];
        if (fs.existsSync(teslimFotolarDir)) {
            existingFiles = fs.readdirSync(teslimFotolarDir);
        }
        
        // Aynı prefix ile başlayan dosyaları filtrele ve sayıları bul
        const prefixFiles = existingFiles.filter(f => f.startsWith(prefixRaw + '_'));
        const numbers = prefixFiles.map(f => {
            // Format: {prefix}_{sayi}_{timestamp}.ext
            const match = f.match(new RegExp(`^${prefixRaw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}_(\\d+)_\\d+\\.`));
            return match ? parseInt(match[1], 10) : 0;
        });
        
        // Başlangıç sayacını belirle
        let fileCounter = numbers.length > 0 ? Math.max(...numbers) + 1 : 1;
        
        // Depolama limiti kontrolü - dosya yüklenmeden ÖNCE kontrol et
        const totalFileSize = uploadedFiles.reduce((sum, file) => sum + (file.size || 0), 0);
        if (totalFileSize > 0) {
            const limitCheck = await checkTenantStorageLimit(tenantId, totalFileSize);
            if (!limitCheck.allowed) {
                // Yüklenen dosyaları temizle
                for (const file of uploadedFiles) {
                    try {
                        if (fs.existsSync(file.path)) {
                            fs.unlinkSync(file.path);
                        }
                    } catch (cleanupError) {
                        console.error('❌ Dosya temizlenirken hata:', cleanupError);
                    }
                }
                return res.status(403).json({
                    success: false,
                    error: 'Depolama limiti aşıldı',
                    message: limitCheck.message
                });
            }
        }
        
        // Dosyaları yeni formata göre yeniden adlandır
        const renamedFiles = [];
        
        for (const uploadedFile of uploadedFiles) {
            const ext = path.extname(uploadedFile.originalname) || '.png';
            const timestamp = Date.now();
            
            // Yeni format: {prefix}_{sayi}_{timestamp}.ext
            const newFilename = `${prefixRaw}_${fileCounter}_${timestamp}${ext}`;
            const newPath = path.join(teslimFotolarDir, newFilename);
            
            // Dosyayı yeniden adlandır
            fs.renameSync(uploadedFile.path, newPath);
            
            // Tenant-based relative path oluştur
            const relativePath = getTenantRelativePath(tenantId, 'organizations', safeId, 'teslim-fotolar', newFilename);
            
            renamedFiles.push({
                path: relativePath,
                filename: newFilename,
                originalPath: uploadedFile.path
            });
            
            fileCounter++;
        }
        
        // Organizasyon kartının bu tenant'a ait olduğunu kontrol et
        const orgCheck = await query('SELECT id FROM organizasyon_kartlar WHERE id = ? AND tenant_id = ?', [organizasyonId, tenantId]);
        if (orgCheck.length === 0) {
            return res.status(403).json({ success: false, error: 'Bu organizasyon kartına erişim yetkiniz yok' });
        }
        
        // Mevcut değerleri çek
        const existing = await query('SELECT organizasyon_teslim_foto_sayisi, organizasyon_teslim_fotolar FROM organizasyon_kartlar WHERE id = ? AND tenant_id = ?', [organizasyonId, tenantId]);
        const prevCount = existing[0]?.organizasyon_teslim_foto_sayisi || 0;
        const prevList = existing[0]?.organizasyon_teslim_fotolar ? JSON.parse(existing[0].organizasyon_teslim_fotolar) : [];
        // Yeni fotoğraflar her zaman en başa eklenir
        const newList = renamedFiles.map(f => f.path).concat(prevList);

        const kullaniciAdi = await getCurrentUsername(req);
        await new Promise((resolve, reject) => db.run(
            `UPDATE organizasyon_kartlar SET organizasyon_teslim_foto_sayisi = ?, organizasyon_teslim_fotolar = ? , updated_at = ${getTurkeyTimeSQL()}, updated_by = ? WHERE id = ? AND tenant_id = ?`,
            [prevCount + count, JSON.stringify(newList), kullaniciAdi, organizasyonId, tenantId], (err) => err ? reject(err) : resolve()
        ));

        // Depolama kullanımını güncelle (limit kontrolü yukarıda yapıldı)
        for (const uploadedFile of uploadedFiles) {
            if (uploadedFile.size) {
                await updateTenantStorageUsage(tenantId, uploadedFile.size, req);
            }
        }

        res.json({ success: true, updated: count, files: renamedFiles.map(f => ({ path: f.path, filename: f.filename })) });
    } catch (e) {
        console.error('Upload hata:', e);
        res.status(500).json({ success: false, message: 'Upload başarısız', error: e.message });
    }
});

