    // admin_bildirimler tablosu (eski ad: admin_notifications) - created_by → created_by_user migration
    async function initializeAdminNotificationsColumn() {
        try {
            let tableName = 'admin_bildirimler';
            const oldExists = await query("SELECT name FROM sqlite_master WHERE type='table' AND name='admin_notifications'", [], null);
            if (oldExists && oldExists.length > 0) {
                await run('ALTER TABLE admin_notifications RENAME TO admin_bildirimler');
                if (isDevelopment) console.log('✅ admin_notifications → admin_bildirimler');
            }
            const tableExists = await query("SELECT name FROM sqlite_master WHERE type='table' AND name='admin_bildirimler'", [], null);
            if (tableExists && tableExists.length > 0) {
                const columns = await query("PRAGMA table_info(admin_bildirimler)", [], null);
                const columnNames = columns.map(col => col.name);
                const hasCreatedBy = columnNames.includes('created_by');
                const hasCreatedByUser = columnNames.includes('created_by_user');
                if (hasCreatedBy && !hasCreatedByUser) {
                    try {
                        await run('ALTER TABLE admin_bildirimler RENAME COLUMN created_by TO created_by_user');
                    } catch (renameError) {
                        await run('ALTER TABLE admin_bildirimler ADD COLUMN created_by_user INTEGER');
                        await run('UPDATE admin_bildirimler SET created_by_user = created_by WHERE created_by IS NOT NULL');
                        await run('CREATE TABLE admin_bildirimler_new AS SELECT id, type, category, title, message, tenant_id, created_by_user, is_read, created_at, read_at FROM admin_bildirimler');
                        await run('DROP TABLE admin_bildirimler');
                        await run('ALTER TABLE admin_bildirimler_new RENAME TO admin_bildirimler');
                    }
                } else if (!hasCreatedBy && !hasCreatedByUser && columnNames.length > 0) {
                    await run('ALTER TABLE admin_bildirimler ADD COLUMN created_by_user INTEGER');
                }
            }
        } catch (error) {
            console.error('❌ admin_bildirimler kolonu değiştirilirken hata:', error);
        }
    }
    
