// Musteriler tablosu: eski kolon isimlerini yeni (Türkçe/spesifik) isimlere taşı, eksik kolonları ekle
async function initializeCustomerColumns() {
    try {
        const columns = await new Promise((resolve, reject) => {
            db.all("PRAGMA table_info(musteriler)", [], (err, rows) => {
                if (err) reject(err);
                else resolve(rows);
            });
        });
        
        let existingColumns = columns.map(c => c.name);
        
        const renames = [
            ['musteri_no', 'musteri_kodu'],
            ['musteri_unvan', 'musteri_unvani'],
            ['musteri_isim_soyisim', 'musteri_ad_soyad'],
            ['phone', 'musteri_telefon'],
            ['email', 'musteri_eposta'],
            ['address', 'musteri_acik_adres'],
            ['neighborhood', 'musteri_mahalle'],
            ['district', 'musteri_ilce'],
            ['city', 'musteri_il'],
            ['customer_type', 'musteri_tipi'],
            ['vergi_kimlik_no', 'musteri_vergi_kimlik_numarasi'],
            ['vergi_dairesi', 'musteri_vergi_dairesi']
        ];
        for (const [oldName, newName] of renames) {
            if (existingColumns.includes(oldName) && !existingColumns.includes(newName)) {
                try {
                    await new Promise((resolve, reject) => {
                        db.run(`ALTER TABLE musteriler RENAME COLUMN ${oldName} TO ${newName}`, (err) => {
                            if (err) reject(err);
                            else resolve();
                        });
                    });
                    existingColumns = existingColumns.filter(n => n !== oldName).concat(newName);
                    if (isDevelopment) console.log(`✅ musteriler: ${oldName} → ${newName}`);
                } catch (e) {
                    if (isDevelopment) console.warn(`⚠️ musteriler rename ${oldName}:`, e.message);
                }
            }
        }
        if (existingColumns.includes('logo_url')) {
            try {
                await new Promise((resolve, reject) => {
                    db.run('ALTER TABLE musteriler DROP COLUMN logo_url', (err) => { if (err) reject(err); else resolve(); });
                });
            } catch (e) {
                if (isDevelopment) console.warn('⚠️ musteriler DROP logo_url:', e.message);
            }
        }
        
        if (isDevelopment) {
            console.log('📋 Mevcut musteriler kolonları:', existingColumns);
        }
        
        const requiredColumns = {
            'musteri_unvani': 'TEXT',
            'musteri_ad_soyad': 'TEXT',
            'kaydi_duzenleyen': 'TEXT',
            'musteri_urun_yazi_dosyalar': 'TEXT',
            'musteri_urun_yazisi': 'TEXT',
            'musteri_acik_adres': 'TEXT',
            'musteri_il': 'VARCHAR(100)',
            'musteri_ilce': 'VARCHAR(100)',
            'musteri_mahalle': 'VARCHAR(100)',
            'musteri_kodu': 'VARCHAR(50)',
            'musteri_grubu': 'VARCHAR(100)',
            'musteri_vergi_kimlik_numarasi': 'VARCHAR(20)',
            'musteri_vergi_dairesi': 'VARCHAR(100)',
            'musteri_tipi': 'VARCHAR(20)',
            'musteri_telefon': 'TEXT',
            'musteri_eposta': 'TEXT',
            'is_active': 'INTEGER'
        };
        
        for (const [colName, colType] of Object.entries(requiredColumns)) {
            if (!existingColumns.includes(colName)) {
                console.log(`➕ Kolon ekleniyor: ${colName}`);
                await new Promise((resolve, reject) => {
                    db.run(`ALTER TABLE musteriler ADD COLUMN ${colName} ${colType}`, (err) => {
                        if (err) reject(err);
                        else resolve();
                    });
                });
            }
        }
        
        console.log('✅ Musteriler tablosu kontrol edildi');
    } catch (error) {
        console.error('❌ Musteriler kolonları kontrol hatası:', error);
    }
}

