async function initializePasswordResetTokens() {
    const TABLE = 'sifre_sifirlama_tokenlari';
    try {
        const tableExists = await new Promise((resolve, reject) => {
            db.all(`SELECT name FROM sqlite_master WHERE type='table' AND name='${TABLE}'`, [], (err, rows) => {
                if (err) reject(err);
                else resolve(rows && rows.length > 0);
            });
        });

        if (!tableExists) {
            await new Promise((resolve, reject) => {
                db.run(`
                    CREATE TABLE IF NOT EXISTS ${TABLE} (
                        id INTEGER PRIMARY KEY AUTOINCREMENT,
                        user_id INTEGER NOT NULL,
                        tenant_id INTEGER,
                        token_hash TEXT NOT NULL UNIQUE,
                        expires_at DATETIME NOT NULL,
                        used INTEGER DEFAULT 0,
                        created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                        FOREIGN KEY (user_id) REFERENCES tenants_kullanicilar(id),
                        FOREIGN KEY (tenant_id) REFERENCES tenants(id)
                    )
                `, (err) => { if (err) reject(err); else resolve(); });
            });
        } else {
            const columns = await new Promise((resolve, reject) => {
                db.all(`PRAGMA table_info(${TABLE})`, [], (err, rows) => {
                    if (err) reject(err);
                    else resolve(rows.map(r => r.name));
                });
            });
            if (!columns.includes('token_hash')) {
                await new Promise((resolve, reject) => {
                    db.run(`ALTER TABLE ${TABLE} ADD COLUMN token_hash TEXT`, (err) => {
                        if (err) reject(err);
                        else {
                            db.run(`CREATE UNIQUE INDEX IF NOT EXISTS idx_${TABLE}_token_hash ON ${TABLE}(token_hash)`, () => resolve());
                        }
                    });
                });
            }
            if (!columns.includes('tenant_id')) {
                await new Promise((resolve, reject) => {
                    db.run(`ALTER TABLE ${TABLE} ADD COLUMN tenant_id INTEGER`, (err) => { if (err) reject(err); else resolve(); });
                });
            }
            if (!columns.includes('expires_at')) {
                await new Promise((resolve, reject) => {
                    db.run(`ALTER TABLE ${TABLE} ADD COLUMN expires_at DATETIME`, (err) => { if (err) reject(err); else resolve(); });
                });
            }
            if (!columns.includes('used')) {
                await new Promise((resolve, reject) => {
                    db.run(`ALTER TABLE ${TABLE} ADD COLUMN used INTEGER DEFAULT 0`, (err) => { if (err) reject(err); else resolve(); });
                });
            }
        }
    } catch (error) {
        console.error('❌ sifre_sifirlama_tokenlari tablosu kontrol hatası:', error);
    }
}

