// Promise wrapper for database queries
// Tenant ID'yi request'ten al
async function getTenantId(req) {
    try {
        return await getTenantIdInternal(req);
    } catch (error) {
        console.error('❌ getTenantId: Beklenmeyen hata (null döndürülüyor):', error?.message || error);
        return null;
    }
}

async function getTenantIdInternal(req) {
    // GÜVENLİK: X-Tenant-ID header'ına ASLA güvenme - client manipüle edebilir!
    // Tenant ID sadece token'dan veya user ID'den veritabanından alınmalı
    
    // 1. req.tenantId'den al (authenticateToken middleware'i tarafından set edilir)
    if (req && req.tenantId) {
        return req.tenantId;
    }
    
    // 2. JWT token'dan al (eğer token decode edilmişse)
    if (req && req.user && req.user.tenantId) {
        return req.user.tenantId;
    }
    
    // 3. Authorization header'dan token decode et (JWT token varsa)
    if (req && req.headers && req.headers.authorization) {
        try {
            const authHeader = req.headers.authorization;
            if (authHeader.startsWith('Bearer ')) {
                const token = authHeader.substring(7);
                // JWT token decode et (base64 encoded payload)
                try {
                    const parts = token.split('.');
                    if (parts.length === 3) {
                        // JWT formatı: header.payload.signature
                        const payload = JSON.parse(Buffer.from(parts[1], 'base64').toString());
                        if (payload.tenant_id) {
                            return payload.tenant_id;
                        }
                        if (payload.tenantId) {
                            return payload.tenantId;
                        }
                    }
                } catch (decodeError) {
                    // JWT decode hatası - devam et (belki basit token formatı)
                }
            }
        } catch (error) {
            // Token decode hatası - devam et
        }
    }
    
    // 4. X-Tenant-ID header'ını IGNORE ET (güvenlik - client manipüle edebilir)
    // ✅ GÜVENLİ YÖNTEM: Tenant ID cookie'den user ID alınıp veritabanından çekiliyor
    if (req && req.headers) {
        const tenantHeader = req.headers['x-tenant-id'] || 
                            req.headers['X-Tenant-ID'] || 
                            req.headers['X-TENANT-ID'];
        if (tenantHeader && !req._tenantHeaderIgnored) {
            // Bu sadece bilgilendirme amaçlı - header gönderilmiş ama backend cookie kullanıyor (güvenli)
            console.log('ℹ️ GÜVENLİK: X-Tenant-ID header gönderilmiş ama ignore edildi (cookie sistemi kullanılıyor):', tenantHeader);
            req._tenantHeaderIgnored = true;
        }
    }
    
    // 5. Token'dan user ID al (GÜVENLİ YÖNTEM - X-User-ID header'ına güvenme!)
    let userId = null;
    
    // Önce token'dan user ID çıkarmaya çalış
    if (req && req.headers && req.headers.authorization) {
        try {
            const authHeader = req.headers.authorization;
            if (authHeader.startsWith('Bearer ')) {
                const token = authHeader.substring(7);
                
                // Token formatı: "dummy-token-<timestamp>" veya JWT
                // Şimdilik basit token kontrolü (ileride JWT'ye geçilebilir)
                // Token'dan user ID çıkaramıyorsak, token'ı veritabanında kontrol et
                // NOT: Şu anki token sistemi basit, ileride JWT'ye geçilmeli
                
                // Token'ı veritabanında kontrol et (eğer token tablosu varsa)
                // Şimdilik token'dan direkt user ID çıkaramıyoruz, cookie'den al
            }
        } catch (error) {
            // Token parse hatası - devam et
        }
    }
    
    // Cookie'den user ID al (güvenli - HttpOnly cookie manipüle edilemez)
    if (req && req.cookies && req.cookies.floovon_user_id) {
        userId = parseInt(req.cookies.floovon_user_id);
        if (isNaN(userId) || userId <= 0) {
            userId = null;
        }
    }
    
    // X-User-ID header'ını IGNORE ET (güvenlik - client manipüle edebilir)
    // NOT: X-User-ID header'ı client manipüle edebilir, ASLA güvenme!
    // ✅ GÜVENLİ YÖNTEM: Backend HttpOnly cookie'den (floovon_user_id) user ID'yi alıyor
    // Cookie sistemi kullanılıyor: cookie'den user ID alınıyor -> veritabanından tenant_id çekiliyor
    if (req && req.headers) {
        const userHeader = req.headers['x-user-id'] || req.headers['X-User-ID'];
        if (userHeader && !req._userHeaderIgnored) {
            // Bu sadece bilgilendirme amaçlı - header gönderilmiş ama backend cookie kullanıyor (güvenli)
            console.log('ℹ️ GÜVENLİK: X-User-ID header gönderilmiş ama ignore edildi (cookie sistemi kullanılıyor):', userHeader);
            req._userHeaderIgnored = true;
        }
    }
    
    // 6. User ID varsa (cookie'den), veritabanından tenant_id'sini çek (EN GÜVENLİ YÖNTEM)
    if (userId) {
        try {
            const user = await new Promise((resolve, reject) => {
                db.get('SELECT tenant_id FROM tenants_kullanicilar WHERE id = ? AND is_active = 1', [userId], (err, row) => {
                    if (err) reject(err);
                    else resolve(row);
                });
            });
            
            if (user && user.tenant_id) {
                if (!req._tenantIdDebugLogged) {
                    if (isDevelopment) {
                        console.log('✅ getTenantId: Veritabanından tenant_id =', user.tenant_id, '(user_id:', userId, 'cookie\'den)');
                    }
                    req._tenantIdDebugLogged = true;
                }
                // req.tenantId'yi set et (sonraki çağrılar için cache)
                req.tenantId = user.tenant_id;
                return user.tenant_id;
            }
        } catch (error) {
            console.error('❌ getTenantId: Veritabanı hatası:', error);
        }
    }
    
    // 7. Tenant ID bulunamazsa fallback: userId'den tenant_id'yi çek (eğer userId varsa)
    if (userId && !req._tenantIdFallbackTried) {
        try {
            // Direkt userId'den tenant_id çek (tenant_id NULL olabilir)
            const userFallback = await new Promise((resolve, reject) => {
                db.get('SELECT tenant_id FROM tenants_kullanicilar WHERE id = ?', [userId], (err, row) => {
                    if (err) reject(err);
                    else resolve(row);
                });
            });
            
            if (userFallback && userFallback.tenant_id) {
                // tenant_id varsa kullan, yoksa null döndür (GÜVENLİK)
                const fallbackTenantId = userFallback.tenant_id;
                if (!req._tenantIdDebugLogged) {
                    if (isDevelopment) {
                        console.log('✅ getTenantId: Fallback tenant_id =', fallbackTenantId, '(user_id:', userId, ')');
                    }
                    req._tenantIdDebugLogged = true;
                }
                req.tenantId = fallbackTenantId;
                return fallbackTenantId;
            }
        } catch (error) {
            console.error('❌ getTenantId: Fallback veritabanı hatası:', error);
        }
        req._tenantIdFallbackTried = true;
    }
    
    // 8. Tenant ID bulunamazsa - GÜVENLİK: Cookie yoksa null döndür (sadece global servisler için fallback)
    const isWhatsAppEndpoint = req.path && req.path.includes('/whatsapp/');
    const isPublicEndpoint = req.path && (
        req.path.includes('/whatsapp/') ||
        req.path.includes('/api/auth/login') ||
        req.path.includes('/api/auth/logout') ||
        req.path.includes('/api/auth/register') ||
        req.path.includes('/api/auth/forgot-password') ||
        req.path.includes('/api/auth/reset-password') ||
        req.path.startsWith('/api/public/')
    );
    
    // Cookie yoksa ve endpoint public değilse, null döndür (GÜVENLİK)
    const hasCookie = req?.cookies?.floovon_user_id;
    if (!hasCookie && !isPublicEndpoint) {
        if (!req._tenantIdErrorLogged) {
            console.error('🚨 GÜVENLİK: Tenant ID bulunamadı - Cookie yok ve endpoint public değil!', {
                path: req.path,
                hasTenantId: !!req?.tenantId,
                hasUser: !!req?.user,
                userId: userId,
                cookie: 'YOK',
                ip: req.ip || req.connection?.remoteAddress,
                note: 'Erişim reddedildi - Authentication gerekli'
            });
            req._tenantIdErrorLogged = true;
        }
        // GÜVENLİK: Cookie yoksa null döndür (endpoint'ler erişimi reddedecek)
        return null;
    }
    
    // Tenant ID bulunamadı - GÜVENLİK: Fallback tenant ID kullanma, null döndür
    if (!req._tenantIdErrorLogged) {
        const hasCookie = req?.cookies?.floovon_user_id ? 'VAR' : 'YOK';
        if (isWhatsAppEndpoint || isPublicEndpoint) {
            console.warn('⚠️ getTenantId: Tenant ID bulunamadı - Public endpoint ama tenant ID yok!', {
                path: req.path,
                hasTenantId: !!req?.tenantId,
                hasUser: !!req?.user,
                userId: userId,
                cookie: hasCookie,
                note: 'Public endpoint - tenant ID bulunamadı, null döndürülüyor (GÜVENLİK)'
            });
        } else {
            // Bu duruma gelmemeli (yukarıdaki null kontrolü yakalamalı)
            console.error('🚨 GÜVENLİK: Beklenmeyen durum - Cookie yok ama public endpoint değil!', {
                path: req.path,
                hasTenantId: !!req?.tenantId,
                hasUser: !!req?.user,
                userId: userId,
                cookie: 'YOK',
                ip: req.ip || req.connection?.remoteAddress
            });
        }
        req._tenantIdErrorLogged = true;
    }
    
    // GÜVENLİK: Fallback tenant ID kullanma - kullanıcı bilgileri yoksa null döndür
    return null;
}

// Oturum sahibi kullanıcı adı (WhatsApp log: session_owner_user – kimin oturumunda bağlantı yapıldı)
async function getSessionUsername(req) {
    if (!req || !req.cookies || !req.cookies.floovon_user_id) return null;
    const userId = parseInt(req.cookies.floovon_user_id);
    if (isNaN(userId) || userId <= 0) return null;
    try {
        const cols = await new Promise((resolve, reject) => {
            db.all('PRAGMA table_info(tenants_kullanicilar)', [], (err, r) => { if (err) reject(err); else resolve((r || []).map(c => c.name)); });
        });
        const usernameCol = (cols && cols.includes('kullaniciadi')) ? 'kullaniciadi' : ((cols && cols.includes('username')) ? 'username' : null);
        if (!usernameCol) return null;
        const row = await new Promise((resolve, reject) => {
            db.get(`SELECT ${usernameCol} FROM tenants_kullanicilar WHERE id = ? AND is_active = 1`, [userId], (err, r) => { if (err) reject(err); else resolve(r); });
        });
        const val = row && row[usernameCol];
        return (val != null && String(val).trim() !== '') ? String(val).trim() : null;
    } catch (e) {
        return null;
    }
}

// SSE: Aynı tenant’taki tüm açık oturumlara anında invalidate mesajı gönder
const sseClientsByTenant = new Map(); // tenantId -> Set<res>
function broadcastInvalidateToTenant(tenantId) {
    if (!tenantId) return;
    const clients = sseClientsByTenant.get(tenantId);
    if (!clients || clients.size === 0) return;
    const payload = 'data: invalidate\n\n';
    clients.forEach((res) => {
        try {
            res.write(payload);
        } catch (e) {
            clients.delete(res);
        }
    });
}

// ✅ PLAN KONTROL: Tenant'ın plan_id'sini al
// Genel plan bilgisi için kullanılır
async function getTenantPlanId(tenantId) {
    if (!tenantId) {
        return null;
    }
    
    try {
        const subscription = await new Promise((resolve, reject) => {
            db.get(`
                SELECT a.plan_id, a.durum, p.plan_adi
                FROM tenants_abonelikler a
                LEFT JOIN tenants_abonelik_planlari p ON a.plan_id = p.id
                WHERE a.tenant_id = ?
                ORDER BY a.olusturma_tarihi DESC, a.id DESC
                LIMIT 1
            `, [tenantId], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });
        
        if (!subscription) {
            return null;
        }
        
        return parseInt(subscription.plan_id);
    } catch (error) {
        console.error('❌ getTenantPlanId hatası:', error);
        return null;
    }
}

// ✅ PLAN KONTROL: Belirli bir özellik için plan kontrolü yap
// feature: 'whatsapp', 'arac-takip', 'kampanya'
async function checkPlanFeature(tenantId, feature) {
    if (!tenantId) {
        return { allowed: false, error: 'Tenant ID bulunamadı', planId: null };
    }
    
    try {
        const planId = await getTenantPlanId(tenantId);
        
        if (planId === null) {
            return { allowed: false, error: 'Abonelik bulunamadı', planId: null };
        }
        
        // Plan 1 (Başlangıç) ise hiçbir özellik kullanılamaz
        if (planId === 1) {
            const featureNames = {
                'whatsapp': 'WhatsApp',
                'arac-takip': 'Araç Takip',
                'kampanya': 'Kampanya Yönetimi'
            };
            
            return { 
                allowed: false, 
                error: `${featureNames[feature] || 'Bu özellik'} Başlangıç paketinde kullanılamaz. Planınızı yükseltin.`,
                planId: planId
            };
        }
        
        // Plan 2+ için tüm özellikler açık
        return { allowed: true, planId: planId };
        
    } catch (error) {
        console.error('❌ checkPlanFeature hatası:', error);
        return { allowed: false, error: 'Plan kontrolü yapılamadı', planId: null };
    }
}

// ✅ PLAN KONTROL: Tenant'ın plan_id'sini kontrol et
// Plan 1 (Başlangıç paketi) için WhatsApp hizmetlerini engelle
// @deprecated checkPlanFeature kullanılmalı
async function checkWhatsAppPlanAccess(tenantId) {
    return await checkPlanFeature(tenantId, 'whatsapp');
}

// Role guard middleware - Belirli roller için erişim kontrolü
async function requireRole(allowedRoles) {
    // allowedRoles string veya array olabilir
    const roles = Array.isArray(allowedRoles) ? allowedRoles : [allowedRoles];
    
    return async (req, res, next) => {
        try {
            // Önce tenant ID'yi al
            const tenantId = req.tenantId || await getTenantId(req);
            if (!tenantId) {
                return res.status(401).json({
                    success: false,
                    error: 'Kimlik doğrulama gerekli. Lütfen giriş yapın.'
                });
            }
            
            // User ID'yi al
            let userId = null;
            if (req.headers) {
                const userHeader = req.headers['x-user-id'] || req.headers['X-User-ID'];
                if (userHeader) {
                    userId = parseInt(userHeader);
                    if (isNaN(userId) || userId <= 0) {
                        userId = null;
                    }
                }
            }
            
            if (!userId) {
                return res.status(401).json({
                    success: false,
                    error: 'Kullanıcı ID bulunamadı. Lütfen giriş yapın.'
                });
            }
            
            // Kullanıcının rolünü veritabanından al
            const user = await new Promise((resolve, reject) => {
                db.get(
                    'SELECT role FROM tenants_kullanicilar WHERE id = ? AND tenant_id = ? AND is_active = 1',
                    [userId, tenantId],
                    (err, row) => {
                        if (err) reject(err);
                        else resolve(row);
                    }
                );
            });
            
            if (!user) {
                return res.status(403).json({
                    success: false,
                    error: 'Kullanıcı bulunamadı veya erişim yetkiniz yok.'
                });
            }
            
            const userRole = user.role || '';
            
            // Rol kontrolü
            if (!roles.includes(userRole)) {
                console.warn(`⚠️ Yetkisiz erişim denemesi: User ID ${userId}, Role: ${userRole}, Gerekli: ${roles.join(', ')}`);
                return res.status(403).json({
                    success: false,
                    error: 'Bu işlem için yetkiniz yok. Gerekli rol: ' + roles.join(', ')
                });
            }
            
            // req.user'a rol bilgisini ekle
            req.user = req.user || {};
            req.user.role = userRole;
            req.user.id = userId;
            req.user.tenantId = tenantId;
            
            next();
        } catch (error) {
            console.error('❌ Role guard middleware hatası:', error);
            return res.status(500).json({
                success: false,
                error: 'Sunucu hatası'
            });
        }
    };
}

// Console panel için özel middleware (Sistem Yöneticisi rolü gerekli)
const requireSystemAdmin = requireRole('SistemYonetici');

// GÜVENLİK: Cookie kontrolü helper fonksiyonu
function requireCookie(req, res) {
    if (!req.cookies || !req.cookies.floovon_user_id) {
        return res.status(401).json({ 
            success: false, 
            error: 'Kimlik doğrulama gerekli. Lütfen giriş yapın.' 
        });
    }
    return null; // Cookie var, devam et
}

// Authentication middleware (GÜVENLİK: Cookie kontrolü ile)
async function requireAuth(req, res, next) {
    try {
        // GÜVENLİK: Önce cookie kontrolü
        const cookieCheck = requireCookie(req, res);
        if (cookieCheck) return cookieCheck; // Cookie yoksa response gönderildi, dur
        
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(401).json({
                success: false,
                error: 'Tenant ID bulunamadı. Lütfen giriş yapın.'
            });
        }
        
        // req.tenantId'yi set et
        req.tenantId = tenantId;
        
        next();
    } catch (error) {
        console.error('❌ Auth middleware hatası:', error);
        return res.status(500).json({
            success: false,
            error: 'Sunucu hatası'
        });
    }
}

function query(sql, params = [], req = null) {
    return new Promise((resolve, reject) => {
        db.all(sql, params, (err, rows) => {
            if (err) {
                reject(err);
            } else {
                resolve(rows);
            }
        });
    });
}

// kullanicilar tablosunda profil kolonu (profile_image veya profil_resmi) - 500 hatası önleme
let _kullanicilarProfileCol = null;
async function getKullanicilarProfileCol() {
    if (_kullanicilarProfileCol !== null) return _kullanicilarProfileCol;
    try {
        const cols = await new Promise((resolve, reject) => {
            db.all('PRAGMA table_info(tenants_kullanicilar)', [], (err, r) => err ? reject(err) : resolve(r || []));
        });
        const names = (cols || []).map(c => c.name);
        if (names.includes('profile_image')) _kullanicilarProfileCol = 'profile_image';
        else if (names.includes('profil_resmi')) _kullanicilarProfileCol = 'profil_resmi';
        else _kullanicilarProfileCol = '';
        return _kullanicilarProfileCol;
    } catch (e) {
        _kullanicilarProfileCol = '';
        return '';
    }
}

// Tenant-safe query helper - Tüm sorgulara tenant_id filter'ı zorunlu kılar
// Kullanım: await tenantQuery(req, 'SELECT * FROM musteriler WHERE id = ?', [id])
// Otomatik olarak: 'SELECT * FROM musteriler WHERE id = ? AND tenant_id = ?' yapar
// NOT: Sistem sorguları (PRAGMA, sqlite_master vb.) için kullanmayın!
async function tenantQuery(req, sql, params = []) {
    const tenantId = req.tenantId || await getTenantId(req);
    
    if (!tenantId) {
        throw new Error('Tenant ID bulunamadı. Lütfen giriş yapın.');
    }
    
    // Sistem sorgularını atla (PRAGMA, sqlite_master, CREATE TABLE vb.)
    const sqlUpper = sql.toUpperCase().trim();
    const isSystemQuery = sqlUpper.startsWith('PRAGMA') || 
                         (sqlUpper.startsWith('SELECT') && sqlUpper.includes('SQLITE_MASTER')) ||
                         sqlUpper.startsWith('CREATE') ||
                         sqlUpper.startsWith('DROP') ||
                         sqlUpper.startsWith('ALTER');
    
    if (isSystemQuery) {
        // Sistem sorguları için tenant filter ekleme
        return query(sql, params, req);
    }
    
    // SQL'de tenant_id kontrolü var mı?
    const hasTenantFilter = sqlUpper.includes('TENANT_ID') || sqlUpper.includes('tenant_id');
    
    // Eğer tenant_id filter yoksa ekle
    if (!hasTenantFilter) {
        // WHERE clause var mı?
        if (sqlUpper.includes('WHERE')) {
            // WHERE'den sonra AND tenant_id = ? ekle
            sql = sql.replace(/WHERE/i, 'WHERE tenant_id = ? AND');
        } else {
            // WHERE yoksa ekle
            sql = sql + ' WHERE tenant_id = ?';
        }
        params.push(tenantId);
    } else {
        // Tenant filter varsa, SQL'de zaten var demektir
        // Developer'ın SQL'inde tenant_id placeholder'ı olmalı
        // NOT: Bu durumda developer sorumluluğunda
    }
    
    return query(sql, params, req);
}

// Tenant-safe run helper - UPDATE/DELETE için
// Kullanım: await tenantRun(req, 'UPDATE musteriler SET name = ? WHERE id = ?', [name, id])
// Otomatik olarak: 'UPDATE musteriler SET name = ? WHERE id = ? AND tenant_id = ?' yapar
async function tenantRun(req, sql, params = []) {
    const tenantId = req.tenantId || await getTenantId(req);
    
    if (!tenantId) {
        throw new Error('Tenant ID bulunamadı. Lütfen giriş yapın.');
    }
    
    // Sistem sorgularını atla
    const sqlUpper = sql.toUpperCase().trim();
    const isSystemQuery = sqlUpper.startsWith('PRAGMA') || 
                         sqlUpper.startsWith('CREATE') ||
                         sqlUpper.startsWith('DROP') ||
                         sqlUpper.startsWith('ALTER');
    
    if (isSystemQuery) {
        return run(sql, params);
    }
    
    // SQL'de tenant_id kontrolü var mı?
    const hasTenantFilter = sqlUpper.includes('TENANT_ID') || sqlUpper.includes('tenant_id');
    
    // Eğer tenant_id filter yoksa ekle
    if (!hasTenantFilter) {
        // WHERE clause var mı?
        if (sqlUpper.includes('WHERE')) {
            // WHERE'den sonra AND tenant_id = ? ekle
            sql = sql.replace(/WHERE/i, 'WHERE tenant_id = ? AND');
        } else {
            // UPDATE/DELETE için WHERE zorunlu olmalı ama yoksa ekle
            console.warn('⚠️ tenantRun: WHERE clause yok, tenant_id filter eklendi:', sql);
            sql = sql + ' WHERE tenant_id = ?';
        }
        params.push(tenantId);
    }
    
    return run(sql, params);
}

// Tenant-safe get helper - Tek satır için
// Kullanım: await tenantGet(req, 'SELECT * FROM musteriler WHERE id = ?', [id])
// Otomatik olarak: 'SELECT * FROM musteriler WHERE id = ? AND tenant_id = ?' yapar
async function tenantGet(req, sql, params = []) {
    const tenantId = req.tenantId || await getTenantId(req);
    
    if (!tenantId) {
        throw new Error('Tenant ID bulunamadı. Lütfen giriş yapın.');
    }
    
    // Sistem sorgularını atla
    const sqlUpper = sql.toUpperCase().trim();
    const isSystemQuery = sqlUpper.startsWith('PRAGMA') || 
                         sqlUpper.startsWith('SELECT') && sqlUpper.includes('SQLITE_MASTER');
    
    if (isSystemQuery) {
        return dbGet(sql, params);
    }
    
    // SQL'de tenant_id kontrolü var mı?
    const hasTenantFilter = sqlUpper.includes('TENANT_ID') || sqlUpper.includes('tenant_id');
    
    // Eğer tenant_id filter yoksa ekle
    if (!hasTenantFilter) {
        if (sqlUpper.includes('WHERE')) {
            sql = sql.replace(/WHERE/i, 'WHERE tenant_id = ? AND');
        } else {
            sql = sql + ' WHERE tenant_id = ?';
        }
        params.push(tenantId);
    }
    
    return dbGet(sql, params);
}

// INSERT, UPDATE, DELETE için run fonksiyonu
function run(sql, params = []) {
    return new Promise((resolve, reject) => {
        // Debug: tenant_id içeren INSERT sorguları için log
        if (sql.includes('INSERT INTO tenants_abonelikler') && sql.includes('tenant_id')) {
            const tenantIdIndex = sql.split('tenant_id')[0].split(',').length - 1;
            console.log('🔍 run() fonksiyonu - INSERT sorgusu:', {
                sql: sql.substring(0, 200) + '...',
                params_count: params.length,
                params: params,
                tenant_id_value: params[0], // İlk parametre tenant_id olmalı
                tenant_id_index: 0
            });
        }
        
        db.run(sql, params, function(err) {
            if (err) {
                console.error('❌ run() fonksiyonu SQL hatası:', {
                    error: err.message,
                    sql: sql.substring(0, 200),
                    params: params
                });
                    reject(err);
            } else {
                resolve({ lastID: this.lastID, changes: this.changes });
            }
        });
    });
}

// Tek satır döndüren query
function dbGet(sql, params = []) {
    return new Promise((resolve, reject) => {
        db.get(sql, params, (err, row) => {
            if (err) {
                    reject(err);
            } else {
                resolve(row);
            }
        });
    });
}

// INSERT/UPDATE/DELETE için
function dbRun(sql, params = []) {
    return new Promise((resolve, reject) => {
        db.run(sql, params, function(err) {
            if (err) {
                    reject(err);
            } else {
                resolve({ lastID: this.lastID, changes: this.changes });
            }
        });
    });
}

// Oturum açan kullanıcının (düzenlemeyi yapan kişi) kullanıcı adını al.
// created_by / updated_by alanlarına yazılacak değer: her zaman oturum sahibinin kullaniciadi.
async function getCurrentUsername(req) {
    try {
        // 1. req.user (JWT/middleware tarafından set edilmişse)
        if (req.user && (req.user.kullaniciadi || req.user.username)) {
            return req.user.kullaniciadi || req.user.username;
        }
        // 2. Oturum sahibi: cookie (floovon_user_id) ile tenants_kullanicilar'dan kullaniciadi al
        const sessionUsername = await getSessionUsername(req);
        if (sessionUsername) {
            return sessionUsername;
        }
        // 3. Fallback: body/query (güvenilir değil; sadece geliştirme)
        if (req.body && req.body.kullaniciadi) return req.body.kullaniciadi;
        if (req.query && req.query.kullaniciadi) return req.query.kullaniciadi;
        if (req.body && req.body.currentUser && req.body.currentUser.kullaniciadi) return req.body.currentUser.kullaniciadi;
        return 'Sistem';
    } catch (error) {
        console.warn('⚠️ getCurrentUsername hatası:', error);
        return 'Sistem';
    }
}

/** Bildirim oluştururken kullanılacak kullanıcı adı: cookie, req.user veya JWT payload'dan alır. */
async function getBildirimKullaniciAdi(req, tenantId) {
    if (!req || !tenantId) return null;
    try {
        let userId = null;
        if (req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id, 10);
            if (isNaN(userId) || userId <= 0) userId = null;
        }
        if (!userId && req.user && (req.user.id || req.user.userId)) {
            userId = req.user.id || req.user.userId;
        }
        if (!userId && req.headers && req.headers.authorization) {
            const authHeader = req.headers.authorization;
            if (authHeader.startsWith('Bearer ')) {
                const token = authHeader.substring(7);
                const parts = token.split('.');
                if (parts.length === 3) {
                    try {
                        const payload = JSON.parse(Buffer.from(parts[1], 'base64').toString());
                        userId = payload.user_id || payload.userId || payload.sub;
                        if (userId != null) userId = parseInt(userId, 10);
                        if (isNaN(userId) || userId <= 0) userId = null;
                    } catch (_) {}
                }
            }
        }
        if (userId) {
            const cols = await query('PRAGMA table_info(tenants_kullanicilar)', [], null);
            const colNames = (cols || []).map((c) => c.name);
            const usernameCol = colNames.includes('kullaniciadi') ? 'kullaniciadi' : (colNames.includes('username') ? 'username' : null);
            if (usernameCol) {
                const user = await query(
                    `SELECT ${usernameCol} FROM tenants_kullanicilar WHERE id = ? AND tenant_id = ? AND is_active = 1`,
                    [userId, tenantId]
                );
                if (user && user.length > 0 && user[0][usernameCol]) {
                    return String(user[0][usernameCol]).trim() || null;
                }
            }
        }
        if (req.user && (req.user.kullaniciadi || req.user.username)) {
            const adi = req.user.kullaniciadi || req.user.username;
            return String(adi).trim() || null;
        }
        return null;
    } catch (e) {
        console.warn('⚠️ getBildirimKullaniciAdi:', e?.message || e);
        return null;
    }
}

// Tenant aktivite kaydı oluştur (async - performans için)
// Parametreler: tenantId, userId, action, targetType, targetId, targetName, details, req (opsiyonel)
async function logTenantActivity(tenantId, userId, action, targetType, targetId, targetName, details = {}, req = null) {
    try {
        // Async olarak çalıştır - ana işlemi bloklamasın (setImmediate yerine doğrudan await kullan)
        // setImmediate(async () => {
        try {
                // Kullanıcı ID'sini al:
                // - Admin isteklerinde: requireAdmin middleware'i ile gelen req.user.id
                // - Tenant isteklerinde: userId parametresi veya floovon_user_id cookie
                let actualUserId = null;
                let isAdminUser = false;
                
                if (req) {
                    // 1) Admin route: requireAdmin set ettiği req.user.isAdmin
                    if (req.user && req.user.id && req.user.isAdmin) {
                        actualUserId = req.user.id;
                        isAdminUser = true;
                    }
                    // 2) Tenant kullanıcısı: fonksiyona gelen userId
                    else if (userId) {
                        actualUserId = userId;
                        isAdminUser = false;
                    }
                    // 3) Tenant çerezi: floovon_user_id
                    else if (req.cookies && req.cookies.floovon_user_id) {
                        const cookieUserId = parseInt(req.cookies.floovon_user_id);
                        if (!isNaN(cookieUserId) && cookieUserId > 0) {
                            actualUserId = cookieUserId;
                            isAdminUser = false;
                        }
                    }
                } else if (userId) {
                    // req yoksa userId parametresini kullan
                    actualUserId = userId;
                    isAdminUser = false;
                }
                
                // Debug: Admin kullanıcı kontrolü
                console.log('🔍 logTenantActivity çağrıldı:', {
                    tenantId,
                    userId,
                    action,
                    targetType,
                    targetId,
                    targetName,
                    hasReq: !!req,
                    hasReqUser: !!req?.user,
                    reqUserId: req?.user?.id,
                    reqUserIsAdmin: req?.user?.isAdmin,
                    hasAdminCookie: !!(req?.cookies && req?.cookies.floovon_admin_user_id),
                    adminCookieValue: req?.cookies?.floovon_admin_user_id,
                    actualUserId,
                    isAdminUser
                });
                
                if (req && !actualUserId) {
                    console.warn('⚠️ logTenantActivity: Admin kullanıcı ID bulunamadı', {
                        hasReqUser: !!req.user,
                        reqUserId: req.user?.id,
                        reqUserIsAdmin: req.user?.isAdmin,
                        hasAdminCookie: !!(req.cookies && req.cookies.floovon_admin_user_id),
                        adminCookieValue: req.cookies?.floovon_admin_user_id,
                        userIdParam: userId
                    });
                }

                // Kullanıcı bilgilerini al
                let kullaniciadi = 'Sistem'; // user kolonu için (kullanıcı adı)
                let userName = 'Sistem'; // user_name kolonu için (isim soyisim)
                
                if (actualUserId) {
                    if (isAdminUser) {
                        // ZORUNLU: Admin kullanıcı - admin_kullanicilar tablosundan al (başka seçenek yok!)
                        // NOT: admin_kullanicilar tablosunda surname kolonu yok, sadece name var
                        const adminUser = await query(
                            'SELECT name, kullaniciadi FROM admin_kullanicilar WHERE id = ?',
                            [actualUserId]
                        );
                        if (adminUser && adminUser.length > 0) {
                            const username = adminUser[0].kullaniciadi || 'Bilinmeyen Admin';
                            kullaniciadi = username;
                            // admin_kullanicilar tablosunda surname yok, sadece name kullan
                            const fullName = adminUser[0].name || username || 'Bilinmeyen Admin';
                            userName = fullName;
                        } else {
                            // Admin kullanıcı bulunamadı - Sistem olarak kaydet
                            kullaniciadi = 'Sistem';
                            userName = 'Sistem';
                        }
                    } else {
                        // Normal kullanıcı: tenants_kullanicilar tablosundan al
                        const user = await query(
                            'SELECT name, surname, username FROM tenants_kullanicilar WHERE id = ?',
                            [actualUserId]
                        );
                        if (user && user.length > 0) {
                            // user kolonu: kullanıcı adı (username)
                            const username = user[0].username || user[0].kullaniciadi; // Geriye dönük uyumluluk
                            kullaniciadi = username || 'Bilinmeyen Kullanıcı';
                            // user_name kolonu: isim soyisim (name + surname)
                            const fullName = [user[0].name, user[0].surname].filter(Boolean).join(' ');
                            userName = fullName || username || 'Bilinmeyen Kullanıcı';
                        }
                    }
                } else if (req) {
                    // Admin kullanıcı ID'si bulunamadı - Sistem olarak kaydet
                    kullaniciadi = 'Sistem';
                    userName = 'Sistem';
                }

                // IP adresi ve user agent bilgilerini al
                let ipAddress = null;
                let userAgent = null;
                if (req) {
                    ipAddress = req.ip || req.headers['x-forwarded-for'] || req.connection.remoteAddress || null;
                    userAgent = req.headers['user-agent'] || null;
                }

                // Details'i JSON string'e çevir
                const detailsJson = typeof details === 'object' ? JSON.stringify(details) : details;

                // Log kaydı oluştur (tenants_logs tablosuna)
                // Önce tablo yapısını kontrol et
                const tableInfo = await query('PRAGMA table_info(tenants_logs)', [], null);
                const columnNames = tableInfo ? tableInfo.map(col => col.name) : [];
                
                const hasNewColumns = columnNames.includes('user_id') && 
                                     columnNames.includes('user_name') && 
                                     columnNames.includes('target_type');
                
                if (hasNewColumns) {
                    // Yeni yapı: Tüm yeni kolonları kullan (tablo yapısına göre)
                    // Tablo kolonları: tenant_id, id (AUTO), user, user_name, action, target, type, ip_address, metadata, created_at, user_id, target_type, target_id, target_name, details, user_agent
                    // NOT: id kolonu AUTOINCREMENT olduğu için INSERT'te belirtilmez
                    await run(`
                        INSERT INTO tenants_logs 
                        (tenant_id, user, user_name, action, target, type, ip_address, metadata, user_id, target_type, target_id, target_name, details, user_agent, created_at)
                        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ${getTurkeyTimeSQL()})
                    `, [
                        tenantId,                    // tenant_id (INTEGER NOT NULL)
                        kullaniciadi || 'Sistem',    // user (TEXT NOT NULL) - kullanıcı adı
                        userName || 'Sistem',        // user_name (TEXT) - isim soyisim
                        action,                      // action (TEXT NOT NULL)
                        targetName || null,          // target (TEXT)
                        targetType || 'genel',       // type (TEXT NOT NULL)
                        ipAddress || null,           // ip_address (TEXT)
                        detailsJson || null,         // metadata (TEXT)
                        actualUserId || null,        // user_id (INTEGER)
                        targetType || null,          // target_type (TEXT)
                        targetId || null,            // target_id (INTEGER)
                        targetName || null,          // target_name (TEXT)
                        detailsJson || null,         // details (TEXT)
                        userAgent || null,           // user_agent (TEXT)
                        // created_at otomatik olarak ${getTurkeyTimeSQL()} ile set ediliyor
                    ]);
                } else {
                    // Eski yapı: Sadece eski kolonları kullan
                    await run(`
                        INSERT INTO tenants_logs 
                        (tenant_id, user, action, target, type, ip_address, metadata, created_at)
                        VALUES (?, ?, ?, ?, ?, ?, ?, ${getTurkeyTimeSQL()})
                    `, [
                        tenantId,
                        kullaniciadi, // user: kullanıcı adı
                        action,
                        targetName || null, // target
                        targetType || 'genel', // type
                        ipAddress,
                        detailsJson || null // metadata
                    ]);
                }
                    
                    console.log(`✅ Aktivite kaydı oluşturuldu: [${targetType || 'genel'}] ${kullaniciadi} - ${action} (Tenant: ${tenantId})`);
        } catch (error) {
            // Log kaydı oluşturulamazsa sessizce devam et (ana işlemi etkilemesin)
            // NOT: actualUserId ve diğer değişkenler try bloğunda tanımlı, catch bloğunda erişilebilir olmalı
            // Ama güvenlik için try-catch içinde kontrol edelim
            try {
                console.error('❌ Aktivite kaydı oluşturulamadı:', {
                    error: error.message,
                    stack: error.stack,
                    tenantId,
                    userId,
                    action,
                    targetType,
                    targetId,
                    targetName,
                    actualUserId: typeof actualUserId !== 'undefined' ? actualUserId : 'undefined',
                    isAdminUser: typeof isAdminUser !== 'undefined' ? isAdminUser : 'undefined',
                    userName: typeof userName !== 'undefined' ? userName : 'undefined',
                    kullaniciadi: typeof kullaniciadi !== 'undefined' ? kullaniciadi : 'undefined',
                    sqlError: error.code || error.errno || 'N/A'
                });
                // Hata detaylarını daha görünür yap
                if (error.message) {
                    console.error('❌ SQL Hatası:', error.message);
                }
            } catch (logError) {
                // Log hatası oluşursa sadece temel bilgileri göster
                console.error('❌ Aktivite kaydı oluşturulamadı:', error.message);
                console.error('❌ Log detayları gösterilemedi:', logError.message);
            }
        }
        // });
    } catch (error) {
        // Hata durumunda sessizce devam et
        console.error('❌ logTenantActivity hatası:', {
            error: error.message,
            stack: error.stack,
            tenantId,
            userId,
            action,
            targetType
        });
    }
}

// Sunucu yerel saati için helper (UTC+3 eklenmez; 3 saat ileri kayıt sorununu önler)
// SQLite: sunucu timezone'unda anı döndürür (sunucu Türkiye'deyse Türkiye saati)
function getTurkeyTimeSQL() {
    return "datetime('now', 'localtime')";
}

// JavaScript: şu anki anı ISO string olarak döndürür (ekstra +3 saat eklenmez)
function getTurkeyTimeISO() {
    return new Date().toISOString();
}

/** Türkiye saatine göre bugünün tarihi YYYY-MM-DD (fatura tarihi vb. için) */
function getTurkeyDateString() {
    try {
        return new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/Istanbul' });
    } catch (_) {
        const d = new Date();
        const y = d.getFullYear();
        const m = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        return `${y}-${m}-${day}`;
    }
}

/**
 * Tenant depolama kullanımını güncelle (dosya yükleme)
 * @param {number} tenantId - Tenant ID
 * @param {number} fileSizeBytes - Dosya boyutu (byte cinsinden)
 * @returns {Promise<void>}
 */
/**
 * Tenant depolama limiti kontrolü - yeni dosya yüklemeden önce kontrol eder
 * @param {number} tenantId - Tenant ID
 * @param {number} fileSizeBytes - Yüklenecek dosya boyutu (byte cinsinden)
 * @returns {Promise<{allowed: boolean, currentStorage: number, limit: number, available: number, message?: string}>}
 */
async function checkTenantStorageLimit(tenantId, fileSizeBytes) {
    try {
        if (!tenantId || !fileSizeBytes || fileSizeBytes <= 0) {
            return {
                allowed: false,
                currentStorage: 0,
                limit: 0,
                available: 0,
                message: 'Geçersiz dosya boyutu'
            };
        }

        // Mevcut kullanım verilerini al
        const kullanim = await query(
            'SELECT kullanilan_depolama_byte, depolama_limit_byte FROM tenants_kullanimlar WHERE tenant_id = ?',
            [tenantId]
        );

        if (!kullanim || kullanim.length === 0) {
            // Kullanım kaydı yoksa plan'dan limit al
            const abonelikForLimit = await query(`
                SELECT p.max_depolama_gb
                FROM tenants_abonelikler a
                LEFT JOIN tenants_abonelik_planlari p ON a.plan_id = p.id
                WHERE a.tenant_id = ? AND a.durum = 'aktif'
                LIMIT 1
            `, [tenantId]);

            const storageLimitGB = abonelikForLimit && abonelikForLimit.length > 0 
                ? abonelikForLimit[0].max_depolama_gb || 1000 
                : 1000;
            const storageLimitBytes = storageLimitGB * 1024 * 1024 * 1024;
            const currentStorage = 0;
            const available = storageLimitBytes - currentStorage;

            return {
                allowed: fileSizeBytes <= available,
                currentStorage: currentStorage,
                limit: storageLimitBytes,
                available: available,
                message: fileSizeBytes > available 
                    ? `Depolama limiti aşıldı. Mevcut limit: ${storageLimitGB} GB, Kullanılabilir: ${(available / (1024 * 1024 * 1024)).toFixed(2)} GB`
                    : undefined
            };
        }

        const currentStorage = kullanim[0].kullanilan_depolama_byte || 0;
        const limit = kullanim[0].depolama_limit_byte || 0;
        const available = limit - currentStorage;
        const newStorage = currentStorage + fileSizeBytes;
        const allowed = newStorage <= limit;

        const limitGB = (limit / (1024 * 1024 * 1024)).toFixed(2);
        const availableGB = (available / (1024 * 1024 * 1024)).toFixed(2);
        const fileGB = (fileSizeBytes / (1024 * 1024 * 1024)).toFixed(2);

        return {
            allowed: allowed,
            currentStorage: currentStorage,
            limit: limit,
            available: available,
            message: !allowed 
                ? `Depolama limiti aşıldı. Mevcut kullanım: ${(currentStorage / (1024 * 1024 * 1024)).toFixed(2)} GB / ${limitGB} GB. Yüklenecek dosya: ${fileGB} GB, Kullanılabilir: ${availableGB} GB`
                : undefined
        };
    } catch (error) {
        console.error(`❌ Tenant ${tenantId} depolama limiti kontrol edilirken hata:`, error);
        // Hata durumunda güvenli tarafta kal - izin verme
        return {
            allowed: false,
            currentStorage: 0,
            limit: 0,
            available: 0,
            message: 'Depolama limiti kontrol edilemedi'
        };
    }
}

async function updateTenantStorageUsage(tenantId, fileSizeBytes, req = null) {
    try {
        if (!tenantId || !fileSizeBytes || fileSizeBytes <= 0) {
            console.warn('⚠️ Geçersiz depolama güncelleme parametreleri:', { tenantId, fileSizeBytes });
            return;
        }

        // Önce limit kontrolü yap
        const limitCheck = await checkTenantStorageLimit(tenantId, fileSizeBytes);
        if (!limitCheck.allowed) {
            throw new Error(limitCheck.message || 'Depolama limiti aşıldı');
        }

        // Mevcut kullanım verilerini al
        const kullanim = await query(
            'SELECT kullanilan_depolama_byte FROM tenants_kullanimlar WHERE tenant_id = ?',
            [tenantId]
        );

        if (!kullanim || kullanim.length === 0) {
            console.warn(`⚠️ Tenant ${tenantId} için kullanım kaydı bulunamadı, oluşturuluyor...`);
            // Kullanım kaydı yoksa oluştur (depolama limitini plan'dan al)
            const abonelikForLimit = await query(`
                SELECT p.max_depolama_gb
                FROM tenants_abonelikler a
                LEFT JOIN tenants_abonelik_planlari p ON a.plan_id = p.id
                WHERE a.tenant_id = ? AND a.durum = 'aktif'
                LIMIT 1
            `, [tenantId]);

            const storageLimitGB = abonelikForLimit && abonelikForLimit.length > 0 
                ? abonelikForLimit[0].max_depolama_gb || 1000 
                : 1000;
            const storageLimitBytes = storageLimitGB * 1024 * 1024 * 1024;

            // Yeni kayıt oluştur
            await run(`
                INSERT INTO tenants_kullanimlar 
                (tenant_id, kullanici_sayisi, kullanilan_depolama_byte, depolama_limit_byte)
                VALUES (?, 0, ?, ?)
            `, [tenantId, fileSizeBytes, storageLimitBytes]);

            console.log(`✅ Tenant ${tenantId} için yeni kullanım kaydı oluşturuldu, depolama: ${fileSizeBytes} byte`);
            return;
        }

        const currentStorage = kullanim[0].kullanilan_depolama_byte || 0;
        const storageLimitBytes = kullanim[0].depolama_limit_byte || 0;
        const newStorage = currentStorage + fileSizeBytes;
        
        // Depolama limiti kontrolü - bildirim için
        const storageProgress = storageLimitBytes > 0 ? (newStorage / storageLimitBytes) * 100 : 0;
        const previousProgress = storageLimitBytes > 0 ? (currentStorage / storageLimitBytes) * 100 : 0;
        
        // %100'ü geçtiyse kritik bildirim oluştur
        if (storageProgress >= 100 && previousProgress < 100) {
            const tenant = await query('SELECT name FROM tenants WHERE id = ?', [tenantId]);
            const tenantName = tenant && tenant[0] ? tenant[0].name : `Tenant #${tenantId}`;
            const storageGB = (newStorage / (1024 * 1024 * 1024)).toFixed(2);
            const limitGB = (storageLimitBytes / (1024 * 1024 * 1024)).toFixed(2);
            
            await createAdminNotification(
                'critical',
                'tenant',
                'Depolama Limit Aşımı',
                `${tenantName} depolama limitini aştı. Kullanım: ${storageGB} GB / ${limitGB} GB`,
                tenantId,
                true, // E-posta gönder
                req
            );
        }
        // %90'ı geçtiyse uyarı bildirimi oluştur
        else if (storageProgress >= 90 && previousProgress < 90) {
            const tenant = await query('SELECT name FROM tenants WHERE id = ?', [tenantId]);
            const tenantName = tenant && tenant[0] ? tenant[0].name : `Tenant #${tenantId}`;
            const storageGB = (newStorage / (1024 * 1024 * 1024)).toFixed(2);
            const limitGB = (storageLimitBytes / (1024 * 1024 * 1024)).toFixed(2);
            
            await createAdminNotification(
                'warning',
                'tenant',
                'Depolama Limit Uyarısı',
                `${tenantName} depolama limitinin %90'ına yaklaştı. Kullanım: ${storageGB} GB / ${limitGB} GB`,
                tenantId,
                false,
                req
            );
        }
        
        // Depolama kullanımını güncelle
        await run(`
            UPDATE tenants_kullanimlar 
            SET kullanilan_depolama_byte = ?, 
                guncelleme_tarihi = ${getTurkeyTimeSQL()}
            WHERE tenant_id = ?
        `, [newStorage, tenantId]);

        const storageMB = (newStorage / (1024 * 1024)).toFixed(2);
        console.log(`📊 Tenant ${tenantId} depolama güncellendi: ${currentStorage} → ${newStorage} byte (${storageMB} MB)`);
    } catch (error) {
        console.error(`❌ Tenant ${tenantId} depolama güncellenirken hata:`, error);
        // Limit aşımı hatası ise tekrar fırlat (dosya yükleme engellensin)
        if (error.message && error.message.includes('Depolama limiti')) {
            throw error;
        }
        // Diğer hatalar için sessizce devam et
    }
}

/**
 * Tenant depolama kullanımını azalt (dosya silme)
 * @param {number} tenantId - Tenant ID
 * @param {number} fileSizeBytes - Silinen dosya boyutu (byte cinsinden)
 * @returns {Promise<void>}
 */
async function decreaseTenantStorageUsage(tenantId, fileSizeBytes) {
    try {
        if (!tenantId || !fileSizeBytes || fileSizeBytes <= 0) {
            console.warn('⚠️ Geçersiz depolama azaltma parametreleri:', { tenantId, fileSizeBytes });
            return;
        }

        // Mevcut kullanım verilerini al
        const kullanim = await query(
            'SELECT kullanilan_depolama_byte FROM tenants_kullanimlar WHERE tenant_id = ?',
            [tenantId]
        );

        if (!kullanim || kullanim.length === 0) {
            console.warn(`⚠️ Tenant ${tenantId} için kullanım kaydı bulunamadı`);
            return;
        }

        const currentStorage = kullanim[0].kullanilan_depolama_byte || 0;
        const newStorage = Math.max(0, currentStorage - fileSizeBytes); // Negatif olmasın

        // Depolama kullanımını güncelle
        await run(`
            UPDATE tenants_kullanimlar 
            SET kullanilan_depolama_byte = ?, 
                guncelleme_tarihi = ${getTurkeyTimeSQL()}
            WHERE tenant_id = ?
        `, [newStorage, tenantId]);

        const storageMB = (newStorage / (1024 * 1024)).toFixed(2);
        console.log(`📊 Tenant ${tenantId} depolama azaltıldı: ${currentStorage} → ${newStorage} byte (${storageMB} MB)`);
    } catch (error) {
        console.error(`❌ Tenant ${tenantId} depolama azaltılırken hata:`, error);
        // Hata olsa bile dosya silme işlemi devam etsin
    }
}

/**
 * Tenant'ın uploads klasöründeki tüm dosyaların toplam boyutunu hesapla
 * @param {number} tenantId - Tenant ID
 * @returns {Promise<number>} Toplam dosya boyutu (byte cinsinden)
 */
async function calculateTenantStorageUsage(tenantId) {
    try {
        if (!tenantId) {
            return 0;
        }

        // Tenant'ın tüm upload klasörünü tara: uploads/tenants/<tenantId>/
        const tenantBasePath = path.join(uploadRoot, 'tenants', String(tenantId));
        let totalSize = 0;

        // Klasör yoksa 0 döndür
        if (!fs.existsSync(tenantBasePath)) {
            console.log(`⚠️ Tenant ${tenantId} upload klasörü bulunamadı: ${tenantBasePath}`);
            return 0;
        }

        // Recursive olarak tüm dosyaları tara
        function calculateDirectorySize(dirPath) {
            try {
                const items = fs.readdirSync(dirPath);
                
                for (const item of items) {
                    const itemPath = path.join(dirPath, item);
                    const stats = fs.statSync(itemPath);
                    
                    if (stats.isDirectory()) {
                        // Alt klasörse recursive olarak devam et
                        calculateDirectorySize(itemPath);
                    } else if (stats.isFile()) {
                        // Dosyaysa boyutunu ekle
                        totalSize += stats.size;
                    }
                }
            } catch (error) {
                console.warn(`⚠️ Klasör taranırken hata (${dirPath}):`, error.message);
            }
        }

        calculateDirectorySize(tenantBasePath);
        
        const storageMB = (totalSize / (1024 * 1024)).toFixed(2);
        console.log(`📊 Tenant ${tenantId} toplam depolama hesaplandı: ${totalSize} byte (${storageMB} MB)`);
        
        return totalSize;
    } catch (error) {
        console.error(`❌ Tenant ${tenantId} depolama hesaplanırken hata:`, error);
        return 0;
    }
}

/**
 * Tenant'ın depolama kullanımını gerçek dosya boyutlarına göre güncelle (migration/initialization için)
 * @param {number} tenantId - Tenant ID
 * @returns {Promise<void>}
 */
async function syncTenantStorageUsage(tenantId) {
    try {
        if (!tenantId) {
            console.warn('⚠️ Geçersiz tenant ID');
            return;
        }

        // Gerçek dosya boyutlarını hesapla
        const actualStorage = await calculateTenantStorageUsage(tenantId);

        // Mevcut kullanım verilerini al
        const kullanim = await query(
            'SELECT kullanilan_depolama_byte FROM tenants_kullanimlar WHERE tenant_id = ?',
            [tenantId]
        );

        if (!kullanim || kullanim.length === 0) {
            // Kullanım kaydı yoksa oluştur (depolama limitini plan'dan al)
            const abonelikForLimit = await query(`
                SELECT p.max_depolama_gb
                FROM tenants_abonelikler a
                LEFT JOIN tenants_abonelik_planlari p ON a.plan_id = p.id
                WHERE a.tenant_id = ? AND a.durum = 'aktif'
                LIMIT 1
            `, [tenantId]);

            const storageLimitGB = abonelikForLimit && abonelikForLimit.length > 0 
                ? abonelikForLimit[0].max_depolama_gb || 1000 
                : 1000;
            const storageLimitBytes = storageLimitGB * 1024 * 1024 * 1024;

            // Yeni kayıt oluştur
            await run(`
                INSERT INTO tenants_kullanimlar 
                (tenant_id, kullanici_sayisi, kullanilan_depolama_byte, depolama_limit_byte)
                VALUES (?, 0, ?, ?)
            `, [tenantId, actualStorage, storageLimitBytes]);

            console.log(`✅ Tenant ${tenantId} için yeni kullanım kaydı oluşturuldu, depolama: ${actualStorage} byte`);
        } else {
            // Mevcut kaydı güncelle
            const currentStorage = kullanim[0].kullanilan_depolama_byte || 0;
            
            await run(`
                UPDATE tenants_kullanimlar 
                SET kullanilan_depolama_byte = ?, 
                    guncelleme_tarihi = ${getTurkeyTimeSQL()}
                WHERE tenant_id = ?
            `, [actualStorage, tenantId]);

            const storageMB = (actualStorage / (1024 * 1024)).toFixed(2);
            const diffMB = ((actualStorage - currentStorage) / (1024 * 1024)).toFixed(2);
            console.log(`📊 Tenant ${tenantId} depolama senkronize edildi: ${currentStorage} → ${actualStorage} byte (${storageMB} MB, fark: ${diffMB} MB)`);
        }
    } catch (error) {
        console.error(`❌ Tenant ${tenantId} depolama senkronize edilirken hata:`, error);
    }
}

function cleanUploadRelativePath(relativePath) {
    if (!relativePath || typeof relativePath !== 'string') return '';
    const withoutLeading = relativePath.replace(/^\/+/, '');
    if (withoutLeading.startsWith('uploads/')) {
        return withoutLeading.slice('uploads/'.length);
    }
    return withoutLeading;
}

// Upload URL builder - Artık relative path döndürüyor (absolute URL üretmiyor)
function buildUploadUrl(relativePath) {
    if (!relativePath || typeof relativePath !== 'string') return '';
    
    // Zaten absolute URL ise olduğu gibi döndür (backward compatibility)
    if (/^https?:\/\//i.test(relativePath)) {
        // Absolute URL'den relative path'e çevir (eğer mümkünse)
        const urlMatch = relativePath.match(/\/uploads\/.*$/);
        if (urlMatch) {
            return urlMatch[0]; // "/uploads/..." döndür
        }
        return relativePath; // Çevrilemezse olduğu gibi döndür
    }
    
    // Protocol-relative URL (//example.com/path) -> relative path'e çevir
    if (relativePath.startsWith('//')) {
        const urlMatch = relativePath.match(/\/uploads\/.*$/);
        if (urlMatch) {
            return urlMatch[0];
        }
        return relativePath;
    }
    
    // Assets için olduğu gibi döndür
    if (relativePath.startsWith('/assets/') || relativePath.startsWith('assets/')) {
        return relativePath.startsWith('/') ? relativePath : '/' + relativePath;
    }
    
    // Uploads path'leri relative olarak döndür
    if (relativePath.startsWith('/uploads/')) {
        return relativePath; // Zaten "/uploads/..." formatında
    }
    if (relativePath.startsWith('uploads/')) {
        return '/' + relativePath; // "uploads/..." -> "/uploads/..."
    }
    
    // Diğer path'ler için "/uploads/" prefix'i ekle (eğer yoksa)
    if (!relativePath.startsWith('/')) {
        return '/uploads/' + relativePath;
    }
    return relativePath;
}

function removePrintLogoFile(relativePath) {
    if (!relativePath) return;
    try {
        const cleaned = cleanUploadRelativePath(relativePath);
        if (!cleaned) return;
        const absolutePath = path.join(uploadRoot, cleaned);
        if (fs.existsSync(absolutePath)) {
            fs.unlinkSync(absolutePath);
            console.log('🗑️ Eski yazdırma logotipi silindi:', absolutePath);
        }
    } catch (error) {
        console.warn('⚠️ Eski yazdırma logotipi silinemedi:', error.message);
    }
}

// Tüm satırları döndüren query
function dbAll(sql, params = []) {
    return new Promise((resolve, reject) => {
        db.all(sql, params, (err, rows) => {
            if (err) {
                reject(err);
            } else {
                resolve(rows);
            }
        });
    });
}

// Execute (run) helper
function execute(sql, params = []) {
    return run(sql, params);
}

/** tenants_faturalar tablosu yoksa oluşturur; fatura_dongusu kolonu yoksa ekler. Her fatura öncesi çağrılır (cache yok). */
async function ensureTenantsFaturalarTable() {
    try {
        const exists = await query("SELECT name FROM sqlite_master WHERE type='table' AND name='tenants_faturalar'", [], null);
        if (!exists || exists.length === 0) {
            await run(`
                CREATE TABLE IF NOT EXISTS tenants_faturalar (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    tenant_id INTEGER NOT NULL,
                    fatura_no TEXT NOT NULL UNIQUE,
                    fatura_tarihi DATE NOT NULL,
                    plan_id INTEGER,
                    abonelik_id INTEGER,
                    ara_toplam INTEGER NOT NULL,
                    kdv_tutari INTEGER DEFAULT 0,
                    toplam_tutar INTEGER NOT NULL,
                    durum TEXT NOT NULL DEFAULT 'beklemede',
                    odeme_yontemi_id INTEGER,
                    pdf_yolu TEXT,
                    odeme_tarihi DATETIME,
                    vade_tarihi DATE,
                    olusturma_tarihi DATETIME DEFAULT CURRENT_TIMESTAMP,
                    guncelleme_tarihi DATETIME DEFAULT CURRENT_TIMESTAMP
                )
            `);
            console.log('✅ tenants_faturalar tablosu oluşturuldu');
        }
        const cols = await query('PRAGMA table_info(tenants_faturalar)', [], null);
        const colNames = (cols || []).map(c => c && c.name).filter(Boolean);
        if (!colNames.includes('fatura_dongusu')) {
            await run('ALTER TABLE tenants_faturalar ADD COLUMN fatura_dongusu TEXT DEFAULT \'aylik\'');
            console.log('✅ tenants_faturalar.fatura_dongusu kolonu eklendi');
        }
    } catch (e) {
        console.error('❌ ensureTenantsFaturalarTable:', e?.message || e, e?.stack || '');
    }
}

/**
 * Abonelik plan değişikliği/yeni abonelik sonrası tenant faturası oluşturur.
 * Yedekteki çalışan mantık: plan'dan gelen aylik_ucret (kuruş) doğrudan kullanılır; PDF senkron üretilir.
 * @param {number} tenantId
 * @param {number} abonelikId
 * @param {number} planId
 * @param {string} planAdi
 * @param {number} aylikUcretKurus - Kuruş cinsinden aylık ücret (plan.aylik_ucret aynen geçirilir)
 * @param {string} [faturaDongusu] - 'aylik' | 'yillik'
 * @returns {Promise<{ id: number, fatura_no: string }|null>}
 */
async function createTenantAbonelikFatura(tenantId, abonelikId, planId, planAdi, aylikUcretKurus, faturaDongusu) {
    if (!tenantId || !abonelikId || !planId || aylikUcretKurus == null) return null;
    await ensureTenantsFaturalarTable();
    const dongu = (faturaDongusu === 'yillik' || faturaDongusu === 'yearly') ? 'yillik' : 'aylik';
    const araToplam = Math.round(Number(aylikUcretKurus)) || 0;
    const kdvTutari = Math.round(araToplam * 0.2);
    const toplamTutar = araToplam + kdvTutari;
    const faturaNo = `FLV-${tenantId}-${Date.now()}`;
    const faturaTarihi = getTurkeyDateString();

    try {
        let odemeYontemiId = null;
        try {
            const pmRows = await query('SELECT odeme_yontemi_id FROM tenants_odeme_yontemleri WHERE tenant_id = ? ORDER BY COALESCE(varsayilan_mi, 0) DESC, id ASC LIMIT 1', [tenantId], null);
            if (pmRows && pmRows[0] && pmRows[0].odeme_yontemi_id != null) odemeYontemiId = pmRows[0].odeme_yontemi_id;
        } catch (pmErr) {
            // tenants_odeme_yontemleri yoksa veya sorgu hata verirse fatura yine oluşturulur (odeme_yontemi_id = null)
        }

        const hasFaturaDongusu = await query('PRAGMA table_info(tenants_faturalar)', [], null).then(cols => (cols || []).some(c => c && c.name === 'fatura_dongusu'));
        if (hasFaturaDongusu) {
            await run(
                `INSERT INTO tenants_faturalar (tenant_id, fatura_no, fatura_tarihi, plan_id, abonelik_id, ara_toplam, kdv_tutari, toplam_tutar, fatura_dongusu, odeme_yontemi_id, odeme_tarihi, vade_tarihi, durum, olusturma_tarihi, guncelleme_tarihi)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'odendi', datetime('now'), datetime('now'))`,
                [tenantId, faturaNo, faturaTarihi, planId, abonelikId, araToplam, kdvTutari, toplamTutar, dongu, odemeYontemiId, faturaTarihi, faturaTarihi]
            );
        } else {
            await run(
                `INSERT INTO tenants_faturalar (tenant_id, fatura_no, fatura_tarihi, plan_id, abonelik_id, ara_toplam, kdv_tutari, toplam_tutar, odeme_yontemi_id, odeme_tarihi, vade_tarihi, durum, olusturma_tarihi, guncelleme_tarihi)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'odendi', datetime('now'), datetime('now'))`,
                [tenantId, faturaNo, faturaTarihi, planId, abonelikId, araToplam, kdvTutari, toplamTutar, odemeYontemiId, faturaTarihi, faturaTarihi]
            );
        }
        const inserted = await query('SELECT id FROM tenants_faturalar WHERE fatura_no = ?', [faturaNo]);
        const faturaId = Array.isArray(inserted) && inserted[0] ? inserted[0].id : null;
        if (!faturaId) {
            console.warn('⚠️ createTenantAbonelikFatura: INSERT sonrası kayıt bulunamadı', { faturaNo });
            return { id: null, fatura_no: faturaNo };
        }

        let tenant = null;
        try {
            const cols = await query('PRAGMA table_info(tenants)', [], null);
            const names = (cols || []).map(c => c && c.name).filter(Boolean);
            const hasFirmaAdi = names.includes('firma_adi');
            const sel = hasFirmaAdi
                ? 'SELECT id, firma_adi, name, address, city, state, tax_office, tax_number FROM tenants WHERE id = ?'
                : 'SELECT id, name, address, city, state, tax_office, tax_number FROM tenants WHERE id = ?';
            const tenants = await query(sel, [tenantId]);
            tenant = Array.isArray(tenants) && tenants[0] ? tenants[0] : null;
        } catch (_) {
            try {
                const tenants = await query('SELECT id, name FROM tenants WHERE id = ?', [tenantId]);
                tenant = Array.isArray(tenants) && tenants[0] ? tenants[0] : null;
            } catch (__) {}
        }
        const companyName = (tenant && (tenant.firma_adi || tenant.name)) ? (tenant.firma_adi || tenant.name) : 'Şirket Adı';

        const invoiceHtml = generateInvoiceHtml({
            faturaNo,
            faturaTarihi,
            odemeTarihi: faturaTarihi,
            company_name: companyName,
            address: (tenant && tenant.address) || '',
            city: (tenant && tenant.city) || '',
            state: (tenant && tenant.state) || '',
            tenantInfo: tenant ? [tenant] : [],
            itemDescription: 'Floovon Abonelik Ücreti',
            itemDescriptionDetail: planAdi ? `${planAdi} - Aylık abonelik` : '',
            araToplam,
            kdvTutari,
            toplamTutar,
            kdvOrani: 20
        });

        const invoicesDir = path.join(__dirname, 'uploads', 'tenants', String(tenantId), 'invoices');
        if (!fs.existsSync(invoicesDir)) fs.mkdirSync(invoicesDir, { recursive: true });
        const pdfFileName = `${faturaNo}.pdf`;
        const pdfAbsolutePath = path.join(invoicesDir, pdfFileName);
        const pdfSaved = await generateInvoicePdfFromHtml(invoiceHtml, pdfAbsolutePath);
        if (!pdfSaved) {
            console.warn('⚠️ Fatura PDF oluşturulamadı (kayıt mevcut, pdf_yolu boş):', faturaNo);
        } else {
            const pdfYolu = `uploads/tenants/${tenantId}/invoices/${pdfFileName}`;
            await run("UPDATE tenants_faturalar SET pdf_yolu = ?, guncelleme_tarihi = datetime('now') WHERE id = ?", [pdfYolu, faturaId]);
        }
        return { id: faturaId, fatura_no: faturaNo };
    } catch (err) {
        console.error('❌ createTenantAbonelikFatura hatası:', err?.message || err);
        if (err && err.stack) console.error(err.stack);
        return null;
    }
}

// Veritabanı değişikliklerini hemen disk'e yazmak için (WAL checkpoint)
function flushDatabase() {
    return new Promise((resolve, reject) => {
        // WAL checkpoint yap (WAL modunda ise değişiklikleri ana dosyaya aktar)
        // FULL checkpoint: Tüm WAL dosyasındaki değişiklikleri ana DB dosyasına aktarır
        db.run('PRAGMA wal_checkpoint(FULL)', (err) => {
            if (err && !err.message.includes('not in WAL mode')) {
                console.warn('⚠️ WAL checkpoint hatası:', err.message);
                reject(err);
            } else {
                // Checkpoint başarılı - ana DB dosyası güncellendi
                resolve();
            }
        });
    });
}

function addColumnIfMissing(table, column, definition, callback) {
    db.run(`ALTER TABLE ${table} ADD COLUMN ${column} ${definition}`, (err) => {
        if (err) {
            if (err.message && err.message.includes('duplicate column name')) {
                console.log(`⏭️ ${table}.${column} kolonu zaten mevcut`);
                if (typeof callback === 'function') callback(null, 'exists');
            } else {
                console.error(`❌ ${table}.${column} kolonu eklenemedi:`, err);
                if (typeof callback === 'function') callback(err);
            }
        } else {
            console.log(`✅ ${table}.${column} kolonu eklendi`);
            if (typeof callback === 'function') callback(null, 'added');
        }
    });
}
// ============================================================================
// RATE LIMITING & BRUTE FORCE PROTECTION
// ============================================================================

// Rate limiting için IP bazlı memory store (basit implementasyon)
const loginAttempts = new Map(); // IP -> { count, firstAttempt, lastAttempt, blockedUntil }

// Rate limiting middleware - Login endpoint'leri için
const loginRateLimit = rateLimit({
    windowMs: 15 * 60 * 1000, // 15 dakika
    max: 5, // 15 dakikada maksimum 5 deneme
    message: {
        success: false,
        error: 'Çok fazla giriş denemesi. Lütfen 15 dakika sonra tekrar deneyin.'
    },
    standardHeaders: true,
    legacyHeaders: false,
    skip: (req) => {
        // Localhost'ta rate limiting'i atla (development için)
        const ip = req.ip || req.connection?.remoteAddress || 'unknown';
        return ip.includes('127.0.0.1') || ip.includes('localhost') || ip.includes('::1');
    },
    handler: (req, res) => {
        const ip = req.ip || req.connection?.remoteAddress || 'unknown';
        console.warn('⚠️ Rate limit aşıldı:', {
            ip,
            path: req.path,
            timestamp: new Date().toISOString()
        });
        res.status(429).json({
            success: false,
            error: 'Çok fazla giriş denemesi. Lütfen 15 dakika sonra tekrar deneyin.'
        });
    }
});

// Şifre sıfırlama için rate limiting (daha yumuşak)
const forgotPasswordRateLimit = rateLimit({
    windowMs: 60 * 60 * 1000, // 1 saat
    max: 3, // 1 saatte maksimum 3 deneme
    message: {
        success: false,
        error: 'Çok fazla şifre sıfırlama isteği. Lütfen 1 saat sonra tekrar deneyin.'
    },
    standardHeaders: true,
    legacyHeaders: false,
    skip: (req) => {
        const ip = req.ip || req.connection?.remoteAddress || 'unknown';
        return ip.includes('127.0.0.1') || ip.includes('localhost') || ip.includes('::1');
    }
});

// Brute force koruması - Başarısız denemeleri takip et
function trackFailedLogin(ip, identifier) {
    const key = `${ip}:${identifier}`;
    const now = Date.now();
    const attempt = loginAttempts.get(key) || { count: 0, firstAttempt: now, lastAttempt: now, blockedUntil: null };
    
    attempt.count++;
    attempt.lastAttempt = now;
    
    // 5 başarısız denemeden sonra 30 dakika blokla
    if (attempt.count >= 5) {
        attempt.blockedUntil = now + (30 * 60 * 1000); // 30 dakika
        console.warn('🚨 Brute force tespit edildi - IP bloklandı:', {
            ip,
            identifier: identifier.substring(0, 3) + '***',
            count: attempt.count,
            blockedUntil: new Date(attempt.blockedUntil).toISOString()
        });
    }
    
    loginAttempts.set(key, attempt);
    
    // Eski kayıtları temizle (1 saatten eski)
    setTimeout(() => {
        const oldAttempt = loginAttempts.get(key);
        if (oldAttempt && oldAttempt.lastAttempt < now - (60 * 60 * 1000)) {
            loginAttempts.delete(key);
        }
    }, 60 * 60 * 1000);
}

function isBlocked(ip, identifier) {
    const key = `${ip}:${identifier}`;
    const attempt = loginAttempts.get(key);
    
    if (!attempt || !attempt.blockedUntil) {
        return false;
    }
    
    if (Date.now() < attempt.blockedUntil) {
        return true;
    }
    
    // Blok süresi dolmuş, kaydı temizle
    loginAttempts.delete(key);
    return false;
}

function clearFailedLogin(ip, identifier) {
    const key = `${ip}:${identifier}`;
    loginAttempts.delete(key);
}

// Routes
// Login endpoint - Rate limiting ile korumalı
app.post('/api/auth/login', loginRateLimit, async (req, res) => {
    try {
        const { email, kullaniciadi, username, password, sifre, tenant_id, tenant_code } = req.body;
        
        // Hem email hem de kullaniciadi hem de username destekle
        const loginIdentifier = email || kullaniciadi || username;
        const loginPassword = password || sifre;
        let tenantId = tenant_id ? parseInt(tenant_id) : null;
        
        // Eğer tenant_code gönderildiyse, tenant_id'ye çevir (boş veya geçersiz ise giriş reddedilir)
        if (tenant_code !== undefined && tenant_code !== null) {
            const code = String(tenant_code).trim();
            if (code === '') {
                return res.status(400).json({
                    success: false,
                    error: 'Tenant kodu gerekli'
                });
            }
            try {
                const tenant = await query('SELECT id FROM tenants WHERE tenants_no = ?', [code]);
                if (tenant && tenant.length > 0) {
                    tenantId = tenant[0].id;
                    console.log('✅ Tenant code\'dan tenant ID bulundu:', code, '->', tenantId);
                } else {
                    console.log('❌ Geçersiz tenant kodu, giriş reddediliyor:', code);
                    return res.status(401).json({
                        success: false,
                        error: 'Geçersiz tenant kodu. Lütfen tenant kodunuzu kontrol edin.'
                    });
                }
            } catch (tenantErr) {
                console.error('❌ Tenant code sorgusu hatası:', tenantErr);
                return res.status(500).json({
                    success: false,
                    error: 'Tenant doğrulaması yapılamadı. Lütfen tekrar deneyin.'
                });
            }
        }
        
        if (!loginIdentifier || !loginPassword) {
            return res.status(400).json({
                success: false,
                error: 'Kullanıcı adı/email ve şifre gerekli'
            });
        }
        
        // Brute force koruması - IP ve identifier bazlı kontrol
        const clientIp = req.ip || req.connection?.remoteAddress || req.headers['x-forwarded-for']?.split(',')[0] || 'unknown';
        if (isBlocked(clientIp, loginIdentifier)) {
            const key = `${clientIp}:${loginIdentifier}`;
            const attempt = loginAttempts.get(key);
            const blockedUntil = attempt ? new Date(attempt.blockedUntil) : null;
            const minutesLeft = blockedUntil ? Math.ceil((attempt.blockedUntil - Date.now()) / (60 * 1000)) : 0;
            
            console.warn('🚨 Bloklanmış IP/identifier giriş denemesi:', {
                ip: clientIp,
                identifier: loginIdentifier.substring(0, 3) + '***',
                blockedUntil: blockedUntil?.toISOString(),
                minutesLeft
            });
            
            return res.status(429).json({
                success: false,
                error: `Çok fazla başarısız giriş denemesi. Lütfen ${minutesLeft} dakika sonra tekrar deneyin.`
            });
        }
        
        console.log('🔍 Login denemesi:', {
            loginIdentifier: loginIdentifier.substring(0, 3) + '***',
            tenantId,
            ip: clientIp
        });
        
        // Kullanıcıyı kontrol et - hem email hem de kullaniciadi ile, tenant_id kontrolü de yap
        // Şifre kontrolü bcrypt ile yapılacak (veritabanında bcrypt hash var)
        let sqlQuery = 'SELECT * FROM tenants_kullanicilar WHERE (email = ? OR username = ?) AND is_active = 1';
        let params = [loginIdentifier, loginIdentifier];
        
        // Eğer tenant_id gönderildiyse ve null değilse, onu da kontrol et
        if (tenantId && tenantId !== null && tenantId !== 'null' && tenantId !== '') {
            sqlQuery += ' AND tenant_id = ?';
            params.push(tenantId);
            console.log('🔍 Tenant ID kontrolü eklendi:', tenantId);
        } else {
            console.log('🔍 Tenant ID kontrolü yapılmıyor (tenantId:', tenantId, ')');
        }
        
        console.log('🔍 SQL Query:', sqlQuery);
        console.log('🔍 Params:', params.map((p, i) => {
            if (typeof p === 'string' && p.length > 20) {
                return p.substring(0, 20) + '...';
            }
            return p;
        }));
        
        db.get(sqlQuery, params, async (err, user) => {
            if (err) {
                console.error('❌ Login hatası:', err);
                return res.status(500).json({
                    success: false,
                    error: 'Sunucu hatası'
                });
            }
            
            if (!user) {
                console.log('❌ Kullanıcı bulunamadı');
                // Brute force takibi - kullanıcı bulunamadı
                trackFailedLogin(clientIp, loginIdentifier);
                return res.status(401).json({
                    success: false,
                    error: 'Kullanıcı adı/email veya şifre hatalı'
                });
            }
            
            // Şifre kontrolü - bcrypt veya SHA256 destekle
            let passwordMatch = false;
            const dbPassword = user.password;
            
            // Bcrypt hash kontrolü ($2a$, $2b$, $2y$ ile başlıyorsa)
            if (dbPassword && (dbPassword.startsWith('$2a$') || dbPassword.startsWith('$2b$') || dbPassword.startsWith('$2y$'))) {
                // bcrypt.compare kullan
                try {
                    passwordMatch = bcrypt.compareSync(loginPassword, dbPassword);
                } catch (bcryptErr) {
                    console.error('❌ Bcrypt karşılaştırma hatası:', bcryptErr);
                    passwordMatch = false;
                }
            } else {
                // SHA256 hash kontrolü
                const hashedPassword = crypto.createHash('sha256').update(loginPassword).digest('hex');
                passwordMatch = (dbPassword === hashedPassword);
            }
            
            if (!passwordMatch) {
                console.log('❌ Şifre eşleşmedi');
                // Brute force takibi - şifre hatalı
                trackFailedLogin(clientIp, loginIdentifier);
                return res.status(401).json({
                    success: false,
                    error: 'Kullanıcı adı/email veya şifre hatalı'
                });
            }
            
            // Başarılı giriş - brute force kayıtlarını temizle
            clearFailedLogin(clientIp, loginIdentifier);
            
            // Status kontrolü - pasif kullanıcılar giriş yapamaz
            const userStatus = user.status || (user.is_active === 1 ? 'aktif' : 'pasif');
            if (userStatus === 'pasif') {
                console.log('❌ Pasif kullanıcı giriş denemesi:', loginIdentifier);
                return res.status(403).json({
                    success: false,
                    error: 'Hesabınız pasif durumda. Lütfen yöneticinizle iletişime geçin.'
                });
            }
            
            // Tenant ID kontrolü
            if (tenantId && tenantId !== null && tenantId !== 'null' && tenantId !== '') {
            if (user.tenant_id !== tenantId) {
                console.log('❌ Tenant ID eşleşmedi. Kullanıcı tenant_id:', user.tenant_id, 'Gönderilen:', tenantId);
                return res.status(401).json({
                    success: false,
                        error: 'Kullanıcı bu tenant\'a ait değil'
                });
                }
            }
            
            // Tenant aktif/pasif kontrolü ve abonelik kontrolü
            if (user.tenant_id) {
                try {
                    console.log('🔍 Tenant aktif/pasif kontrolü yapılıyor, Tenant ID:', user.tenant_id);
                    
                    // query fonksiyonunu doğrudan kullan (closure'dan erişilebilir)
                    const tenant = await new Promise((resolve, reject) => {
                        db.all(
                            'SELECT id, name, is_active, status FROM tenants WHERE id = ?',
                            [user.tenant_id],
                            (err, rows) => {
                                if (err) {
                                    console.error('❌ Query hatası:', err);
                                    reject(err);
                                } else {
                                    resolve(rows);
                                }
                            }
                        );
                    });
                    
                    console.log('📋 Tenant sorgusu sonucu:', tenant);
                    
                    if (tenant && tenant.length > 0) {
                        const tenantData = tenant[0];
                        // is_active değerini sayı olarak kontrol et (string olabilir)
                        const isActiveValue = parseInt(tenantData.is_active) || 0;
                        const isActive = isActiveValue === 1;
                        
                        // ABONELİK KONTROLÜ: İptal edilmiş abonelikler için plan_id kontrolü
                        // Dashboard sayfasından giriş yapıldığında abonelik kontrolünü bypass et (yeni abonelik almak için)
                        const allowExpired = req.body.allow_expired === true || req.body.allow_expired === 'true' || 
                                           req.body.login_type === 'dashboard' || 
                                           (req.body.redirect_to && req.body.redirect_to.includes('dashboard'));
                        
                        const subscriptionCheck = await query(`
                            SELECT a.id, a.durum, a.plan_id, a.mevcut_donem_bitis
                            FROM tenants_abonelikler a
                            WHERE a.tenant_id = ? 
                            ORDER BY a.id DESC
                            LIMIT 1
                        `, [user.tenant_id], null);
                        
                        if (subscriptionCheck && subscriptionCheck.length > 0) {
                            const sub = subscriptionCheck[0];
                            const now = new Date();
                            const donemBitis = sub.mevcut_donem_bitis ? new Date(sub.mevcut_donem_bitis) : null;
                            
                            // MEVCUT_DONEM_BITIS TARİHİ GEÇMİŞSE (DURUMDAN BAĞIMSIZ) - GİRİŞ ENGELLENMELİ
                            // Ancak dashboard için allow_expired true ise bypass et
                            if (donemBitis && donemBitis < now && !allowExpired) {
                                // plan_id'yi 0 yap ve durumu iptal yap (eğer zaten iptal değilse)
                                if (sub.durum !== 'iptal' && sub.durum !== 'iptal_console') {
                                    await run(`
                                        UPDATE tenants_abonelikler 
                                        SET plan_id = 0, durum = 'iptal', guncelleme_tarihi = CURRENT_TIMESTAMP
                                        WHERE id = ?
                                    `, [sub.id], null);
                                } else {
                                    // Zaten iptal durumundaysa sadece plan_id'yi 0 yap (eğer değilse)
                                    if (sub.plan_id !== 0 && sub.plan_id !== null && sub.plan_id !== '0') {
                                        await run(`
                                            UPDATE tenants_abonelikler 
                                            SET plan_id = 0, guncelleme_tarihi = CURRENT_TIMESTAMP
                                            WHERE id = ?
                                        `, [sub.id], null);
                                    }
                                }
                                
                                console.log('❌ Abonelik süresi dolmuş - giriş engellendi (tenant panel):', {
                                    tenant_id: user.tenant_id,
                                    subscription_id: sub.id,
                                    donem_bitis: donemBitis,
                                    durum: sub.durum,
                                    allowExpired: allowExpired
                                });
                                
                                return res.status(403).json({
                                    success: false,
                                    error: 'Aboneliğiniz sona ermiş. Yeni abonelik seçmek için dashboard sayfasına gidin.',
                                    redirect_to: '/landing/dashboard.html'
                                });
                            }
                            
                            // Plan ID kontrolü - plan_id 0 veya NULL ise giriş yapamaz (tenant panel için)
                            // Dashboard için allow_expired true ise bypass et
                            if ((sub.plan_id === 0 || sub.plan_id === null || sub.plan_id === '0') && !allowExpired) {
                                console.log('❌ Plan yok - giriş engellendi (tenant panel):', {
                                    tenant_id: user.tenant_id,
                                    plan_id: sub.plan_id,
                                    allowExpired: allowExpired
                                });
                                
                                return res.status(403).json({
                                    success: false,
                                    error: 'Aktif bir aboneliğiniz bulunmuyor. Yeni plan seçmek için dashboard sayfasına gidin.',
                                    redirect_to: '/landing/dashboard.html'
                                });
                            }
                            
                            // Dashboard için allow_expired true ise log yaz ama girişe izin ver
                            if (allowExpired && (donemBitis && donemBitis < now || sub.plan_id === 0 || sub.plan_id === null || sub.plan_id === '0')) {
                                console.log('✅ Dashboard girişi - abonelik bitmiş ama erişim izni verildi:', {
                                    tenant_id: user.tenant_id,
                                    subscription_id: sub.id,
                                    donem_bitis: donemBitis,
                                    plan_id: sub.plan_id
                                });
                            }
                        } else {
                            // Abonelik yoksa giriş yapamaz (tenant panel için)
                            // Dashboard için allow_expired true ise bypass et
                            if (!allowExpired) {
                                console.log('❌ Abonelik bulunamadı - giriş engellendi (tenant panel):', {
                                    tenant_id: user.tenant_id,
                                    allowExpired: allowExpired
                                });
                                
                                return res.status(403).json({
                                    success: false,
                                    error: 'Aktif bir aboneliğiniz bulunmuyor. Yeni plan seçmek için dashboard sayfasına gidin.',
                                    redirect_to: '/landing/dashboard.html'
                                });
                            } else {
                                console.log('✅ Dashboard girişi - abonelik yok ama erişim izni verildi:', {
                                    tenant_id: user.tenant_id
                                });
                            }
                        }
                        
                        // status kontrolü - "pasif" ise giriş yapılamaz
                        const tenantStatus = tenantData.status || (isActive ? 'aktif' : 'pasif');
                        const isStatusActive = tenantStatus === 'aktif';
                        
                        console.log('🔍 Tenant durumu:', {
                            tenantId: tenantData.id,
                            tenantName: tenantData.name,
                            is_active: tenantData.is_active,
                            parsed: isActiveValue,
                            isActive: isActive,
                            status: tenantData.status,
                            tenantStatus: tenantStatus,
                            isStatusActive: isStatusActive
                        });
                        
                        // Hem is_active hem de status kontrolü yap
                        if (!isActive || !isStatusActive) {
                            console.log('❌ Tenant pasif, giriş yapılamaz. Tenant ID:', user.tenant_id, 'Tenant Name:', tenantData.name, 'is_active:', tenantData.is_active, 'status:', tenantData.status);
                            // 200 OK döndür (403 yerine) - console'da hata görünmesin
                            return res.status(200).json({
                                success: false,
                                error: 'Bu tenant hesabı pasif durumda. Lütfen yöneticinizle iletişime geçin.'
                            });
                        }
                        console.log('✅ Tenant aktif, girişe izin veriliyor');
                    } else {
                        console.warn('⚠️ Tenant bulunamadı (ID:', user.tenant_id, '), girişe izin veriliyor (geriye dönük uyumluluk)');
                        // Tenant bulunamadığında girişe izin ver (geriye dönük uyumluluk)
                    }
                } catch (tenantError) {
                    console.error('❌ Tenant kontrolü hatası:', tenantError);
                    console.error('❌ Tenant Error Details:', {
                        message: tenantError.message,
                        stack: tenantError.stack,
                        code: tenantError.code,
                        name: tenantError.name
                    });
                    // Hata durumunda girişe izin ver (geriye dönük uyumluluk için)
                    // Ama log'da uyarı ver
                    console.warn('⚠️ Tenant kontrolü başarısız, girişe izin veriliyor (geriye dönük uyumluluk)');
                }
            } else {
                console.warn('⚠️ Kullanıcının tenant_id\'si yok, girişe izin veriliyor (geriye dönük uyumluluk)');
            }
            
            // last_login'i güncelle
            try {
                db.run(
                    'UPDATE kullanicilar SET last_login = datetime("now") WHERE id = ?',
                    [user.id],
                    (updateErr) => {
                        if (updateErr) {
                            console.error('⚠️ last_login güncellenirken hata (devam ediliyor):', updateErr);
                        } else {
                            console.log('✅ last_login güncellendi:', user.id);
                        }
                    }
                );
            } catch (updateError) {
                console.error('⚠️ last_login güncellenirken hata (devam ediliyor):', updateError);
            }
            
            // Kullanıcı bilgilerini döndür (şifre hariç)
            const { password: _, ...userWithoutPassword } = user;
            
            // Token oluştur
            const token = 'dummy-token-' + Date.now();
            
            // Cookie ayarları (panel.floovon.com ve localhost için)
            const isPanelDomain = req.get('host') && req.get('host').includes('panel.floovon.com');
            const isLocalhost = req.get('host') && (req.get('host').includes('localhost') || req.get('host').includes('127.0.0.1'));
            
            if (isPanelDomain || isLocalhost) {
                // HttpOnly cookie set et (güvenlik için)
                const cookieOptions = {
                    httpOnly: true,
                    sameSite: 'Lax',
                    maxAge: 7 * 24 * 60 * 60 * 1000 // 7 gün
                };
                
                // Panel domain için secure ve domain ayarla
                if (isPanelDomain) {
                    cookieOptions.domain = 'panel.floovon.com';
                    cookieOptions.secure = true; // HTTPS için
                }
                // Localhost için domain yok, secure false (HTTP için)
                
                res.cookie('floovon_token', token, cookieOptions);
                res.cookie('floovon_user_id', user.id.toString(), cookieOptions);
                
                console.log('✅ Cookie set edildi:', {
                    user_id: user.id,
                    domain: cookieOptions.domain || 'localhost',
                    httpOnly: cookieOptions.httpOnly,
                    secure: cookieOptions.secure || false
                });
            }
            
            res.json({
                success: true,
                message: 'Giriş başarılı',
                data: {
                    user: userWithoutPassword,
                    token: token
                }
            });
            
            console.log('✅ Kullanıcı giriş yaptı:', user.email || user.kullaniciadi, 'Tenant ID:', user.tenant_id);
        });
        
    } catch (error) {
        console.error('❌ Login endpoint hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Sunucu hatası'
        });
    }
});

// Tenant panel çıkış – cookie'leri temizle (tüm sekmelerde oturum kapansın)
app.post('/api/auth/logout', (req, res) => {
    const cookieOptions = { path: '/', httpOnly: true, sameSite: 'lax' };
    const isPanelDomain = req.get('X-Frontend-Origin') && String(req.get('X-Frontend-Origin')).includes('panel.floovon.com');
    if (isPanelDomain) {
        cookieOptions.domain = 'panel.floovon.com';
    }
    res.clearCookie('floovon_token', cookieOptions);
    res.clearCookie('floovon_user_id', cookieOptions);
    res.json({ success: true, message: 'Çıkış yapıldı' });
});

// Frontend / kullanım hatalarını veritabanına kaydet (sunucu ortamında takip için)
app.post('/api/log-client-error', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        const userId = (req.user && req.user.id) || (req.cookies && req.cookies.floovon_user_id) ? parseInt(req.cookies.floovon_user_id, 10) : null;
        const { message, stack, url, http_status, endpoint, source } = req.body || {};
        const errorMessage = (message && String(message).trim()) || 'Bilinmeyen hata';
        const userAgent = req.get('user-agent') || null;
        await run(
            `INSERT INTO proje_kullanim_hata_logs (tenant_id, user_id, source, error_message, error_stack, url, http_status, endpoint, user_agent) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
            [
                tenantId || null,
                userId || null,
                (source && String(source).trim()) || 'frontend',
                errorMessage.substring(0, 2000),
                (stack && String(stack).trim()) ? String(stack).substring(0, 8000) : null,
                (url && String(url).trim()) ? String(url).substring(0, 500) : null,
                http_status != null ? parseInt(http_status, 10) : null,
                (endpoint && String(endpoint).trim()) ? String(endpoint).substring(0, 500) : null,
                userAgent ? String(userAgent).substring(0, 500) : null
            ]
        );
        res.json({ success: true });
    } catch (err) {
        console.error('❌ log-client-error kayıt hatası:', err?.message || err);
        res.status(500).json({ success: false });
    }
});

// Session check - tenant/abonelik geçerliliği (periyodik kontrol için)
app.get('/api/auth/session-check', async (req, res) => {
    try {
        const requestTenantId = req.tenantId || await getTenantId(req);
        if (!requestTenantId) {
            return res.status(403).json({
                success: false,
                valid: false,
                error: 'Oturum geçersiz. Lütfen tekrar giriş yapın.'
            });
        }

        // Tenant var mı?
        const tenantExists = await query('SELECT id FROM tenants WHERE id = ?', [requestTenantId], null);
        if (!tenantExists || tenantExists.length === 0) {
            return res.status(403).json({
                success: false,
                valid: false,
                error: 'Firma bulunamadı. Oturumunuz sonlandırıldı.'
            });
        }

        // Abonelik kontrolü
        const subRows = await query(`
            SELECT a.id, a.durum, a.plan_id, a.mevcut_donem_bitis
            FROM tenants_abonelikler a
            WHERE a.tenant_id = ?
            ORDER BY a.id DESC
            LIMIT 1
        `, [requestTenantId], null);

        if (!subRows || subRows.length === 0) {
            return res.status(403).json({
                success: false,
                valid: false,
                error: 'Aktif bir aboneliğiniz bulunmuyor.'
            });
        }

        const sub = subRows[0];
        const now = new Date();
        const donemBitis = sub.mevcut_donem_bitis ? new Date(sub.mevcut_donem_bitis) : null;

        if (donemBitis && donemBitis < now) {
            return res.status(403).json({
                success: false,
                valid: false,
                error: 'Aboneliğiniz sona ermiş.'
            });
        }

        if (sub.durum === 'iptal' || sub.durum === 'iptal_console') {
            return res.status(403).json({
                success: false,
                valid: false,
                error: 'Aboneliğiniz iptal edilmiş.'
            });
        }

        if (sub.plan_id === 0 || sub.plan_id === null || sub.plan_id === '0') {
            return res.status(403).json({
                success: false,
                valid: false,
                error: 'Aktif bir aboneliğiniz bulunmuyor.'
            });
        }

        return res.json({ success: true, valid: true });
    } catch (error) {
        console.error('❌ session-check hatası:', error);
        return res.status(500).json({
            success: false,
            valid: false,
            error: 'Oturum kontrolü yapılamadı.'
        });
    }
});

// SSE: Tüm açık oturumlara anında güncelleme yayını (bir kullanıcı güncelleme yapınca diğerleri anında görür)
app.get('/api/sse', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            res.setHeader('Content-Type', 'text/plain');
            return res.status(401).end('Unauthorized');
        }
        res.setHeader('Content-Type', 'text/event-stream');
        res.setHeader('Cache-Control', 'no-cache, no-transform');
        res.setHeader('Connection', 'keep-alive');
        res.setHeader('X-Accel-Buffering', 'no');
        res.flushHeaders();
        if (!sseTenantClients.has(tenantId)) sseTenantClients.set(tenantId, new Set());
        sseTenantClients.get(tenantId).add(res);
        res.write('data: {"type":"connected"}\n\n');
        const keepalive = setInterval(() => {
            try { res.write(': keepalive\n\n'); } catch (_) { clearInterval(keepalive); }
        }, 25000);
        req.on('close', () => {
            clearInterval(keepalive);
            const set = sseTenantClients.get(tenantId);
            if (set) { set.delete(res); if (set.size === 0) sseTenantClients.delete(tenantId); }
        });
    } catch (e) {
        try { res.status(500).end(); } catch (_) {}
    }
});

// Kullanıcı bilgilerini getir
app.get('/api/auth/me', async (req, res) => {
    try {
        // Tenant ID'yi token'dan al (güvenlik için zorunlu)
        const requestTenantId = req.tenantId || await getTenantId(req);
        if (!requestTenantId) {
            return res.status(401).json({
                success: false,
                error: 'Tenant ID bulunamadı. Lütfen giriş yapın.'
            });
        }
        
        // User ID'yi cookie'den al (güvenli yöntem)
        let userId = null;
        if (req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id);
            if (isNaN(userId) || userId <= 0) {
                userId = null;
            }
        }
        
        // User ID yoksa query veya header'dan al (ama fallback 1 kullanma!)
        if (!userId) {
            userId = req.query.id || req.userId || req.headers['x-user-id'];
            if (userId) {
                userId = parseInt(userId);
                if (isNaN(userId) || userId <= 0) {
                    userId = null;
                }
            }
        }
        
        // User ID yoksa hata döndür (fallback 1 kullanma!)
        if (!userId) {
            return res.status(401).json({
                success: false,
                error: 'Kullanıcı ID bulunamadı. Lütfen giriş yapın.'
            });
        }
        
        // Profil kolonu (profile_image veya profil_resmi) - tablo şemasına göre dinamik
        const profileCol = await getKullanicilarProfileCol();
        const profileSelect = profileCol ? `${profileCol} as profile_image` : 'NULL as profile_image';
        const userSql = `SELECT id, email, password, name, surname, role, is_active, last_login, created_at, updated_at, username, phone, ${profileSelect}, tenant_id FROM tenants_kullanicilar WHERE id = ? AND tenant_id = ? AND is_active = 1`;
        
        // Tenant filtresi - SADECE tenant_id ile sorgu yap (güvenlik)
        db.get(userSql, [userId, requestTenantId], async (err, user) => {
                if (err) {
                    console.error('❌ Kullanıcı getirme hatası:', err);
                    return res.status(500).json({
                        success: false,
                        error: 'Sunucu hatası',
                        ...(isDevelopment && { message: err.message })
                    });
                }
                
                if (!user) {
                    return res.status(404).json({
                        success: false,
                        error: 'Kullanıcı bulunamadı'
                    });
                }
                
                // Kullanıcıyı işle (async fonksiyon olduğu için await kullan)
                await processUser(user);
            }
        );
        
        // Kullanıcı işleme fonksiyonu
        async function processUser(user) {
            try {
                // Telefon numarasını formatla
                try {
                    if (user.phone) {
                        user.phone = formatPhoneNumber(user.phone);
                    }
                    // Geriye dönük uyumluluk için telefon da kontrol et
                    if (!user.phone && user.telefon) {
                        user.phone = formatPhoneNumber(user.telefon);
                    }
                } catch (phoneError) {
                    console.warn('⚠️ Telefon formatlama hatası:', phoneError);
                    // Hata olsa bile devam et
                }
                
                // Şifreyi response'dan çıkar
                delete user.password;
                
                // Tenant ID'yi al (kullanıcının tenant_id'si)
                const userTenantId = user.tenant_id || await getTenantId(req);
                
                // Tenant bilgisini al (tenant adı için)
                let tenantInfo = null;
                if (userTenantId) {
                    try {
                        const tenantTableExists = await query("SELECT name FROM sqlite_master WHERE type='table' AND name='tenants'");
                        if (tenantTableExists && tenantTableExists.length > 0) {
                            const tenantResult = await query(
                                'SELECT id, name FROM tenants WHERE id = ?',
                                [userTenantId],
                                null
                            );
                            if (tenantResult && tenantResult[0]) {
                                tenantInfo = {
                                    id: tenantResult[0].id,
                                    name: tenantResult[0].name
                                };
                            }
                        }
                    } catch (tenantError) {
                        console.warn('⚠️ Tenant bilgisi alınamadı:', tenantError?.message || tenantError);
                    }
                }
                
                // Profil resmi kontrolü - default resim döndürme kaldırıldı, direkt DB'den gelen değer kullanılacak
                // Geriye dönük uyumluluk için hem profile_image hem profil_resmi kontrol et
                const profileImage = user.profile_image || user.profil_resmi;
                if (isDevelopment) {
                    console.log('🔍 /api/auth/me - Kullanıcı profile_image (DB\'den):', profileImage, 'type:', typeof profileImage);
                }
                
                // Profile_image varsa işle (default resim path'i de dahil - kaldır butonuna basıldığında default resim kaydedilir)
                // ÖNEMLİ: /assets/profil-default.jpg path'i de döndürülmeli, null'a çevrilmemeli
                if (profileImage && 
                    profileImage !== 'undefined' && 
                    profileImage !== 'null' && 
                    profileImage !== '') {
                    
                    // Eğer profile_image default resim path'i ise, direkt döndür (işleme gerek yok)
                    if (profileImage === '/assets/profil-default.jpg' || 
                        profileImage === 'assets/profil-default.jpg' ||
                        profileImage.trim() === '/assets/profil-default.jpg' ||
                        profileImage.trim() === 'assets/profil-default.jpg') {
                        if (isDevelopment) {
                            console.log('✅ Profil resmi default resim path\'i, direkt döndürülüyor:', profileImage);
                        }
                        user.profile_image = '/assets/profil-default.jpg'; // Normalize et
                        user.profil_resmi = '/assets/profil-default.jpg'; // Geriye dönük uyumluluk
                        // Devam etme, direkt response'a geç
                    } else {
                    // Profil resmi yolu var, tenant-based path'e çevir
                    let profilePath = profileImage;
                    // Timestamp parametrelerini temizle (veritabanından gelen URL'de olabilir)
                    profilePath = profilePath.split('?')[0];
                    
                    // Absolute URL'den relative path'e çevir
                    if (profilePath.startsWith('http://') || profilePath.startsWith('https://')) {
                        // URL'den /uploads/... kısmını çıkar
                        const urlMatch = profilePath.match(/\/uploads\/.*$/);
                        if (urlMatch) {
                            profilePath = urlMatch[0];
                        } else {
                            // Çevrilemezse NULL yap (default resim döndürme kaldırıldı)
                            profilePath = null;
                        }
                    } else if (profilePath.includes('localhost:3001') || profilePath.includes('localhost:3000') || profilePath.includes('127.0.0.1:3001')) {
                        // localhost URL'lerini relative path'e çevir
                        const urlMatch = profilePath.match(/\/uploads\/.*$/);
                        if (urlMatch) {
                            profilePath = urlMatch[0];
                        } else {
                            // Çevrilemezse NULL yap (default resim döndürme kaldırıldı)
                            profilePath = null;
                        }
                    }
                    
                    // Eski path formatını tenant-based yapıya çevir
                    // /uploads/profiles/... -> /uploads/tenants/<tenantId>/profiles/<userSlug>/...
                    if (profilePath.startsWith('/uploads/profiles/') && !profilePath.startsWith('/uploads/tenants/')) {
                        const username = user.username || user.kullaniciadi; // Geriye dönük uyumluluk
                        if (userTenantId && username) {
                            // Eski path'ten dosya adını çıkar: /uploads/profiles/akifbircan/profil-akifbircan.jpg
                            const oldPathMatch = profilePath.match(/\/uploads\/profiles\/(.+)$/);
                            if (oldPathMatch) {
                                const subPath = oldPathMatch[1];
                                
                                // Eğer default profil ise: NULL yap (default resim döndürme kaldırıldı)
                                if (subPath.startsWith('default/')) {
                                    profilePath = null;
                                } else {
                                    // Kullanıcı adını (userSlug) kullanarak yeni path oluştur
                                    const userSlug = username.replace(/[^a-zA-Z0-9_-]/g, '');
                                    // Dosya adını çıkar
                                    const fileName = subPath.includes('/') ? subPath.split('/').pop() : subPath;
                                    profilePath = getTenantRelativePath(userTenantId, 'profiles', userSlug, fileName);
                                }
                            } else {
                                // Path parse edilemezse NULL yap (default resim döndürme kaldırıldı)
                                profilePath = null;
                            }
                        }
                    }
                    
                    // Relative path'i normalize et - SADECE /uploads/ ile başlamıyorsa / ekle
                    // Eğer zaten /uploads/ ile başlıyorsa, dokunma
                    if (profilePath) {
                        if (!profilePath.startsWith('/')) {
                            profilePath = '/' + profilePath;
                        }
                        // Path'i direkt kullan - dosya kontrolü yapma (dosya fiziksel olarak var olmayabilir ama path doğru olabilir)
                        // Örneğin production'da dosya farklı bir sunucuda olabilir veya Nginx tarafından serve edilebilir
                        if (isDevelopment) {
                            console.log('✅ Profil resmi path döndürülüyor (dosya kontrolü yapılmadan):', profilePath);
                        }
                        user.profile_image = profilePath;
                        user.profil_resmi = profilePath; // Geriye dönük uyumluluk
                    } else {
                        // Path NULL ise NULL olarak bırak (default resim döndürme kaldırıldı)
                        console.log('⚠️ Profil resmi path NULL, NULL olarak döndürülüyor');
                        user.profile_image = null;
                        user.profil_resmi = null; // Geriye dönük uyumluluk
                    }
                    } // else bloğu (default resim değilse normal işleme devam et)
                } else {
                    // Profil resmi yoksa NULL olarak bırak (default resim döndürme kaldırıldı)
                    console.log('⚠️ Profil resmi yok, NULL olarak döndürülüyor');
                    user.profile_image = null;
                    user.profil_resmi = null; // Geriye dönük uyumluluk
                }
                
                // Tenant bilgisini user objesine ekle
                if (tenantInfo) {
                    user.tenant = tenantInfo;
                }
                
                // Geriye dönük uyumluluk için username ve phone ekle
                if (!user.username && user.kullaniciadi) {
                    user.username = user.kullaniciadi;
                }
                if (!user.phone && user.telefon) {
                    user.phone = user.telefon;
                }
                
                res.json({
                    success: true,
                    data: user
                });
            } catch (error) {
                console.error('❌ processUser hatası:', error);
                res.status(500).json({
                    success: false,
                    error: 'Kullanıcı işlenirken hata oluştu',
                    message: error.message
                });
            }
        }
        
    } catch (error) {
        console.error('❌ /api/auth/me hatası:', error?.message || error);
        console.error('❌ Stack:', error?.stack);
        res.status(500).json({
            success: false,
            error: 'Sunucu hatası',
            message: error?.message || String(error)
        });
    }
});

// Kullanıcı sayfa erişim izinlerini getir
app.get('/api/user/page-permissions', async (req, res) => {
    try {
        // Tenant ID'yi token'dan al (güvenlik için zorunlu)
        const requestTenantId = req.tenantId || await getTenantId(req);
        if (!requestTenantId) {
            return res.status(401).json({
                success: false,
                error: 'Tenant ID bulunamadı. Lütfen giriş yapın.'
            });
        }
        
        // User ID'yi cookie'den al (güvenli yöntem)
        let userId = null;
        if (req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id);
            if (isNaN(userId) || userId <= 0) {
                userId = null;
            }
        }
        
        // User ID yoksa query veya header'dan al
        if (!userId) {
            userId = req.query.id || req.userId || req.headers['x-user-id'];
            if (userId) {
                userId = parseInt(userId);
                if (isNaN(userId) || userId <= 0) {
                    userId = null;
                }
            }
        }
        
        // User ID yoksa hata döndür
        if (!userId) {
            return res.status(401).json({
                success: false,
                error: 'Kullanıcı ID bulunamadı. Lütfen giriş yapın.'
            });
        }
        
        // Kullanıcının rolünü al
        const user = await new Promise((resolve, reject) => {
            db.get(
                'SELECT role FROM tenants_kullanicilar WHERE id = ? AND tenant_id = ? AND is_active = 1',
                [userId, requestTenantId],
                (err, row) => {
                    if (err) reject(err);
                    else resolve(row);
                }
            );
        });
        
        if (!user) {
            return res.status(404).json({
                success: false,
                error: 'Kullanıcı bulunamadı'
            });
        }
        
        const userRoleRaw = (user.role || '').trim();
        
        // Rol normalizasyon fonksiyonu - Türkçe rol adlarını kebab-case formatına çevir
        function normalizeRole(role) {
            if (!role) return role;
            const roleLower = role.toLowerCase().trim();
            
            // Sistem yöneticisi kontrolü
            if (roleLower === 'sistem yöneticisi' || roleLower === 'sistem-yoneticisi' || 
                roleLower === 'sistem_yoneticisi' || roleLower === 'admin') {
                return 'sistem-yoneticisi';
            }
            
            // Sipariş Operatörü kontrolü
            if (roleLower === 'sipariş operatörü' || roleLower === 'siparis-operatörü' || 
                roleLower === 'siparis-operatoru' || roleLower === 'sipariş operatörü') {
                return 'siparis-operatörü';
            }
            
            // Teslimat / Sipariş Sorumlusu kontrolü (DB'de ikisi de olabilir)
            if (roleLower === 'teslimat sorumlusu' || roleLower === 'teslimat-sorumlusu' ||
                roleLower === 'sipariş sorumlusu' || roleLower === 'siparis-sorumlusu') {
                return 'teslimat-sorumlusu';
            }
            
            // Eğer zaten kebab-case formatındaysa olduğu gibi döndür
            if (role.includes('-')) {
                return role.toLowerCase();
            }
            
            // Fallback: Türkçe karakterleri değiştir ve kebab-case'e çevir
            return role.toLowerCase()
                .replace(/\s+/g, '-')
                .replace(/ı/g, 'i')
                .replace(/ğ/g, 'g')
                .replace(/ü/g, 'u')
                .replace(/ş/g, 's')
                .replace(/ö/g, 'o')
                .replace(/ç/g, 'c');
        }
        
        const userRole = normalizeRole(userRoleRaw);
        
        console.log(`📋 Rol normalizasyonu: "${userRoleRaw}" -> "${userRole}"`);
        
        // Sistem yöneticisi için tüm sayfalara erişim (rol kontrolü - çoklu format desteği)
        const isSystemAdmin = userRole === 'sistem-yoneticisi' || 
                             userRoleRaw === 'sistem-yoneticisi' || 
                             userRoleRaw === 'sistem_yoneticisi' || 
                             userRoleRaw === 'Sistem Yöneticisi' ||
                             userRoleRaw === 'admin' ||
                             userRoleRaw === 'Admin' ||
                             userRoleRaw === 'ADMIN';
        
        if (isSystemAdmin) {
            // all_roles=1: Tüm rollerin izinlerini döndür (profil yetkilendirme tablosu için)
            const allRolesParam = req.query.all_roles === '1' || req.query.all_roles === 'true';
            if (allRolesParam) {
                const allPages = [
                    'index', 'musteriler', 'musteriler-cari', 'partner-firmalar',
                    'partner-firmalar-cari', 'partnerler-potansiyel', 'kampanya-yonetimi',
                    'raporlar', 'arsiv-siparisler', 'ayarlar'
                ];
                const editableRoles = ['siparis-operatörü', 'teslimat-sorumlusu'];
                const resultByRole = {};
                const tableExistsForAll = await query(`
                    SELECT name FROM sqlite_master WHERE type='table' AND name='tenants_sayfa_izinleri'
                `, [], null);
                const hasTable = tableExistsForAll && tableExistsForAll.length > 0;
                const columns = hasTable ? await query('PRAGMA table_info(tenants_sayfa_izinleri)', [], null) : [];
                const colNames = columns.map(c => c.name);
                const hasTenantId = colNames.includes('tenant_id');
                for (const roleId of editableRoles) {
                    let perms = [];
                    if (hasTable) {
                        if (hasTenantId) {
                            perms = await query(`
                                SELECT page_id, CAST(has_access AS INTEGER) as has_access
                                FROM tenants_sayfa_izinleri WHERE role_id = ? AND tenant_id = ?
                            `, [roleId, requestTenantId], null);
                        } else {
                            perms = await query(`
                                SELECT page_id, CAST(has_access AS INTEGER) as has_access
                                FROM tenants_sayfa_izinleri WHERE role_id = ?
                            `, [roleId], null);
                        }
                    }
                    const map = {};
                    allPages.forEach(p => { map[p] = false; });
                    perms.forEach(p => {
                        const v = p.has_access;
                        map[p.page_id] = v === 1 || v === true || v === '1' || v === 'true';
                    });
                    resultByRole[roleId] = map;
                }
                editableRoles.forEach((r) => { resultByRole[r]['index'] = true; });
                return res.json({ success: true, data: resultByRole });
            }
            const allPages = [
                'index', 'musteriler', 'musteriler-cari', 'partner-firmalar',
                'partner-firmalar-cari', 'partnerler-potansiyel', 'kampanya-yonetimi',
                'raporlar', 'arsiv-siparisler', 'ayarlar'
            ];
            console.log('✅ Sistem yöneticisi tespit edildi, tüm sayfalara erişim veriliyor:', userRoleRaw);
            return res.json({
                success: true,
                data: allPages.map(pageId => ({
                    page_id: pageId,
                    has_access: true
                }))
            });
        }
        
        // tenants_sayfa_izinleri (eski ad: page_permissions) - migration
        const oldPagePermExists = await query(`SELECT name FROM sqlite_master WHERE type='table' AND name='page_permissions'`, [], null);
        if (oldPagePermExists && oldPagePermExists.length > 0) {
            try { await run('ALTER TABLE page_permissions RENAME TO tenants_sayfa_izinleri'); } catch (e) { /* ignore */ }
        }
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='tenants_sayfa_izinleri'
        `, [], null);
        
        if (!tableExists || tableExists.length === 0) {
            // Tablo yoksa: Sadece index (Siparişler) her zaman erişilebilir, diğerleri kapalı
            const defaultPages = [
                { id: 'index', access: true },
                { id: 'musteriler', access: false },
                { id: 'musteriler-cari', access: false },
                { id: 'partner-firmalar', access: false },
                { id: 'partner-firmalar-cari', access: false },
                { id: 'partnerler-potansiyel', access: false },
                { id: 'kampanya-yonetimi', access: false },
                { id: 'raporlar', access: false },
                { id: 'arsiv-siparisler', access: false },
                { id: 'ayarlar', access: false }
            ];
            return res.json({
                success: true,
                data: defaultPages.map(page => ({
                    page_id: page.id,
                    has_access: page.access
                }))
            });
        }
        
        // Tenant ID kontrolü - tenants_sayfa_izinleri tablosunda tenant_id var mı?
        const columns = await query('PRAGMA table_info(tenants_sayfa_izinleri)', [], null);
        const columnNames = columns.map(c => c.name);
        const hasTenantId = columnNames.includes('tenant_id');
        
        // Kullanıcının rolüne göre sayfa izinlerini al - NORMALIZE EDİLMİŞ rol ile sorgula
        let permissions = [];
        console.log(`🔍 İzin sorgusu: role_id="${userRole}", tenant_id=${requestTenantId}, hasTenantId=${hasTenantId}`);
        
        if (hasTenantId) {
            permissions = await query(`
                SELECT page_id, CAST(has_access AS INTEGER) as has_access
                FROM tenants_sayfa_izinleri 
                WHERE role_id = ? AND tenant_id = ?
            `, [userRole, requestTenantId], null);
            
            if ((!permissions || permissions.length === 0) && userRole !== userRoleRaw) {
                permissions = await query(`
                    SELECT page_id, CAST(has_access AS INTEGER) as has_access
                    FROM tenants_sayfa_izinleri 
                    WHERE role_id = ? AND tenant_id = ?
                `, [userRoleRaw, requestTenantId], null);
            }
        } else {
            permissions = await query(`
                SELECT page_id, CAST(has_access AS INTEGER) as has_access
                FROM tenants_sayfa_izinleri 
                WHERE role_id = ?
            `, [userRole], null);
            
            if ((!permissions || permissions.length === 0) && userRole !== userRoleRaw) {
                permissions = await query(`
                    SELECT page_id, CAST(has_access AS INTEGER) as has_access
                    FROM tenants_sayfa_izinleri 
                    WHERE role_id = ?
                `, [userRoleRaw], null);
            }
        }
        
        console.log(`📋 Veritabanından ${permissions ? permissions.length : 0} izin kaydı bulundu`);
        
        // Tüm sayfaları kontrol et ve eksik olanları varsayılan değerlerle ekle
        const allPages = [
            'index', 'musteriler', 'musteriler-cari', 'partner-firmalar', 
            'partner-firmalar-cari', 'partnerler-potansiyel', 'kampanya-yonetimi', 
            'raporlar', 'arsiv-siparisler', 'ayarlar'
        ];
        
        const permissionMap = {};
        if (permissions && permissions.length > 0) {
            console.log('📋 Veritabanından okunan izinler:', JSON.stringify(permissions, null, 2));
            permissions.forEach(p => {
                // has_access değerini kontrol et - CAST ile INTEGER'a çevrildi, artık 0 veya 1 olmalı
                const hasAccessValue = p.has_access;
                // TÜM olasılıkları kontrol et
                let accessValue = false;
                if (hasAccessValue === 1 || hasAccessValue === true || hasAccessValue === '1' || hasAccessValue === 'true') {
                    accessValue = true;
                } else if (hasAccessValue === 0 || hasAccessValue === false || hasAccessValue === '0' || hasAccessValue === 'false') {
                    accessValue = false;
                }
                permissionMap[p.page_id] = accessValue;
                console.log(`📋 İzin map'e eklendi: ${p.page_id} = ${accessValue} (has_access: ${hasAccessValue}, type: ${typeof hasAccessValue}, raw: ${JSON.stringify(hasAccessValue)})`);
            });
        } else {
            console.log('⚠️ Veritabanından izin bulunamadı, permissionMap boş');
            console.log(`⚠️ Sorgu parametreleri: role_id=${userRole}, tenant_id=${requestTenantId}, hasTenantId=${hasTenantId}`);
        }
        
        console.log('📋 PermissionMap:', JSON.stringify(permissionMap, null, 2));
        console.log('📋 Kullanıcı rolü:', userRole);
        console.log('📋 Tenant ID:', requestTenantId);
        
        // Sistem yöneticisi için tüm sayfalara erişim (fallback kontrolü)
        const isSystemAdminFallback = userRole === 'sistem-yoneticisi' || 
                                     userRoleRaw === 'sistem-yoneticisi' || 
                                     userRoleRaw === 'sistem_yoneticisi' || 
                                     userRoleRaw === 'Sistem Yöneticisi' ||
                                     userRoleRaw === 'admin' ||
                                     userRoleRaw === 'Admin' ||
                                     userRoleRaw === 'ADMIN';
        
        const result = allPages.map(pageId => {
            // Sistem yöneticisi için her zaman true
            if (isSystemAdminFallback) {
                return {
                    page_id: pageId,
                    has_access: true
                };
            }
            // index (Siparişler) her zaman erişilebilir - değiştirilemez
            if (pageId === 'index') {
                return { page_id: pageId, has_access: true };
            }
            // Diğer roller için permissionMap'ten kontrol et
            const hasAccess = permissionMap.hasOwnProperty(pageId)
                ? permissionMap[pageId]
                : false;
            console.log(`📋 Sayfa: ${pageId}, İzin: ${hasAccess}, Map değeri: ${permissionMap[pageId]}, Map'te var mı: ${permissionMap.hasOwnProperty(pageId)}`);
            return {
                page_id: pageId,
                has_access: hasAccess
            };
        });
        
        console.log('📋 Sonuç:', JSON.stringify(result, null, 2));
        
        res.json({
            success: true,
            data: result
        });
        
    } catch (error) {
        console.error('❌ Sayfa erişim izinleri yükleme hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Sayfa erişim izinleri yüklenemedi',
            message: error.message
        });
    }
});

// ========== BİLDİRİMLER ==========
app.get('/api/bildirimler', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(401).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const { kullanici_adi, limit = 20 } = req.query;
        if (!kullanici_adi || typeof kullanici_adi !== 'string') {
            return res.json({ success: true, data: [] });
        }
        const tableExists = await query(`SELECT name FROM sqlite_master WHERE type='table' AND name='bildirimler'`, [], null);
        if (!tableExists || tableExists.length === 0) {
            return res.json({ success: true, data: [] });
        }
        const cols = await query('PRAGMA table_info(bildirimler)', [], null);
        const colNames = cols.map((c) => c.name);
        const hasTenantId = colNames.includes('tenant_id');
        let sql = `SELECT * FROM bildirimler WHERE kullanici_adi = ?`;
        const params = [String(kullanici_adi).trim()];
        if (hasTenantId) {
            sql += ` AND (tenant_id = ? OR tenant_id IS NULL)`;
            params.push(tenantId);
        }
        sql += ` ORDER BY created_at DESC LIMIT ?`;
        params.push(Math.min(parseInt(limit, 10) || 20, 100));
        const rows = await query(sql, params);
        const data = rows.map((r) => ({
            id: r.id,
            tip: r.tip,
            baslik: r.baslik,
            musteri_unvani: r.musteri_unvani ?? r.musteri_adi,
            teslim_kisisi: r.teslim_kisisi,
            siparis_adi: r.siparis_adi,
            organizasyon_adi: r.organizasyon_adi,
            organizasyon_alt_tur: r.organizasyon_alt_tur,
            siparis_teslim_kisisi_baskasi: r.siparis_teslim_kisisi_baskasi,
            urun_resmi: r.urun_resmi,
            arsivleme_sebebi: r.arsivleme_sebebi,
            siparis_id: r.siparis_id,
            organizasyon_id: r.organizasyon_id,
            // Sadece açıkça 1/true ise okundu; null/0/undefined = okunmamış
            is_read: Number(r.is_read) === 1 || r.is_read === true,
            created_at: r.created_at,
        }));
        res.json({ success: true, data });
    } catch (error) {
        console.error('❌ Bildirimler yüklenirken hata:', error);
        res.status(500).json({ success: false, error: 'Bildirimler yüklenemedi', message: error.message });
    }
});

app.put('/api/bildirimler/:id/read', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(401).json({ success: false, error: 'Tenant ID bulunamadı.' });
        }
        const { id } = req.params;
        const tableExists = await query(`SELECT name FROM sqlite_master WHERE type='table' AND name='bildirimler'`, [], null);
        if (!tableExists || tableExists.length === 0) {
            return res.json({ success: true });
        }
        const cols = await query('PRAGMA table_info(bildirimler)', [], null);
        const hasReadAt = cols.map((c) => c.name).includes('read_at');
        if (hasReadAt) {
            await run(`UPDATE bildirimler SET is_read = 1, read_at = datetime('now'), updated_by = ? WHERE id = ?`, [await getCurrentUsername(req), parseInt(id, 10)]);
        } else {
            await run(`UPDATE bildirimler SET is_read = 1, updated_by = ? WHERE id = ?`, [await getCurrentUsername(req), parseInt(id, 10)]);
        }
        res.json({ success: true });
    } catch (error) {
        console.error('❌ Bildirim okundu işaretleme hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

app.put('/api/bildirimler/read-all', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(401).json({ success: false, error: 'Tenant ID bulunamadı.' });
        }
        const { kullanici_adi } = req.query;
        if (!kullanici_adi || typeof kullanici_adi !== 'string') {
            return res.json({ success: true });
        }
        const tableExists = await query(`SELECT name FROM sqlite_master WHERE type='table' AND name='bildirimler'`, [], null);
        if (!tableExists || tableExists.length === 0) {
            return res.json({ success: true });
        }
        const cols = await query('PRAGMA table_info(bildirimler)', [], null);
        const colNames = cols.map((c) => c.name);
        const hasReadAt = colNames.includes('read_at');
        const hasTenantId = colNames.includes('tenant_id');
        const ub = await getCurrentUsername(req);
        let sql = `UPDATE bildirimler SET is_read = 1`;
        if (hasReadAt) sql += `, read_at = datetime('now')`;
        if (colNames.includes('updated_by')) { sql += `, updated_by = ?`; }
        sql += ` WHERE kullanici_adi = ?`;
        const params = [];
        if (colNames.includes('updated_by')) params.push(ub);
        params.push(String(kullanici_adi).trim());
        if (hasTenantId) {
            sql += ` AND (tenant_id = ? OR tenant_id IS NULL)`;
            params.push(tenantId);
        }
        await run(sql, params);
        res.json({ success: true });
    } catch (error) {
        console.error('❌ Tüm bildirimler okundu işaretleme hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

