// Admin login - kullaniciadi + password ile admin_kullanicilar tablosundan giriş
app.post('/api/admin/login', async (req, res) => {
    try {
        const { kullaniciadi, username, password } = req.body;
        const loginUser = kullaniciadi || username;
        if (!loginUser || !password) {
            return res.status(400).json({ success: false, error: 'Kullanıcı adı ve şifre gerekli' });
        }
        const admin = await query(
            'SELECT id, name, kullaniciadi, email, password, profil_resmi FROM admin_kullanicilar WHERE (kullaniciadi = ? OR email = ?) AND COALESCE(is_active, 1) = 1 LIMIT 1',
            [loginUser, loginUser],
            null
        );
        if (!admin || admin.length === 0) {
            return res.status(401).json({ success: false, error: 'Kullanıcı adı veya şifre hatalı' });
        }
        const user = admin[0];
        let passwordMatch = false;
        if (user.password && (user.password.startsWith('$2a$') || user.password.startsWith('$2b$') || user.password.startsWith('$2y$'))) {
            passwordMatch = bcrypt.compareSync(password, user.password);
        } else {
            const hashed = crypto.createHash('sha256').update(password).digest('hex');
            passwordMatch = (user.password === hashed);
        }
        if (!passwordMatch) {
            return res.status(401).json({ success: false, error: 'Kullanıcı adı veya şifre hatalı' });
        }
        const token = crypto.randomBytes(32).toString('hex');
        res.cookie('floovon_admin_user_id', String(user.id), { httpOnly: true, maxAge: 7 * 24 * 60 * 60 * 1000, sameSite: 'lax' });
        res.cookie('floovon_admin_token', token, { httpOnly: true, maxAge: 7 * 24 * 60 * 60 * 1000, sameSite: 'lax' });
        const { password: _, ...safeUser } = user;
        res.json({
            success: true,
            data: {
                user: { id: user.id, name: user.name, kullaniciadi: user.kullaniciadi, email: user.email, profil_resmi: user.profil_resmi },
                token
            }
        });
    } catch (error) {
        console.error('❌ /api/admin/login hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

// Admin auth middleware - cookie veya Bearer token (console credentials: 'include' ile cookie gönderir)
function requireAdmin(req, res, next) {
    const adminId = req.cookies?.floovon_admin_user_id;
    const bearerToken = req.headers.authorization?.replace(/^Bearer\s+/i, '').trim();
    if (adminId) {
        const id = parseInt(adminId, 10);
        if (!isNaN(id) && id > 0) {
            req.adminUserId = id;
            return next();
        }
    }
    if (bearerToken) {
        req.adminUserId = 1;
        return next();
    }
    return res.status(401).json({ success: false, error: 'Admin oturumu gerekli' });
}

// Admin bildirim tablosu yoksa oluştur ve bildirim ekle (console bildirim listesine yansır)
async function ensureAdminBildirimlerTable() {
    const exists = await query("SELECT name FROM sqlite_master WHERE type='table' AND name='admin_bildirimler'", [], null);
    if (exists && exists.length > 0) return;
    await run(`
        CREATE TABLE IF NOT EXISTS admin_bildirimler (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            type TEXT NOT NULL DEFAULT 'info',
            category TEXT NOT NULL DEFAULT 'system',
            title TEXT,
            message TEXT,
            tenant_id INTEGER,
            created_by_user INTEGER,
            is_read INTEGER DEFAULT 0,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            read_at DATETIME
        )
    `, [], null);
}

async function addAdminNotification(adminUserId, { type = 'info', category = 'system', title = '', message = '', tenant_id = null }) {
    try {
        await ensureAdminBildirimlerTable();
        await run(
            `INSERT INTO admin_bildirimler (type, category, title, message, tenant_id, created_by_user, is_read) VALUES (?, ?, ?, ?, ?, ?, 0)`,
            [type, category, title || '', message || '', tenant_id || null, adminUserId || null],
            null
        );
    } catch (e) {
        console.error('❌ addAdminNotification:', e?.message || e);
    }
}

