// Admin tenant kullanıcı oluştur / güncelle
app.post('/api/admin/tenants/:tenantId/users', requireAdmin, async (req, res) => {
    try {
        const tenantId = parseInt(req.params.tenantId, 10);
        if (!tenantId || isNaN(tenantId)) {
            return res.status(400).json({ success: false, error: 'Geçersiz tenant ID' });
        }

        const { name, surname, username, kullaniciadi, email, password, role, phone, status, is_active } = req.body || {};

        if (!name || !surname || !username || !email || !password) {
            return res.status(400).json({ success: false, error: 'Ad, soyad, kullanıcı adı, e-posta ve şifre zorunludur' });
        }

        const hashedPassword = await bcrypt.hash(password, 10);
        const finalStatus = status === 'pasif' ? 'pasif' : 'aktif';
        const isActiveValue = typeof is_active === 'number' ? is_active : (finalStatus === 'aktif' ? 1 : 0);

        await run(
            `INSERT INTO tenants_kullanicilar (tenant_id, name, surname, username, email, password, role, phone, status, is_active, created_at, updated_at)
             VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, datetime('now'), datetime('now'))`,
            [tenantId, name, surname, username, email, hashedPassword, role || null, phone || null, finalStatus, isActiveValue],
            null
        );

        const users = await query(
            `SELECT id, username, email, name, surname, role, phone, is_active, status, created_at
             FROM tenants_kullanicilar
             WHERE tenant_id = ?
             ORDER BY id DESC
             LIMIT 1`,
            [tenantId],
            null
        );
        const newUser = users?.[0] || null;
        if (newUser) {
            const tenantRow = await query('SELECT name, tenants_no FROM tenants WHERE id = ?', [tenantId], null).then(r => r?.[0]);
            const tenantName = (tenantRow?.name || tenantRow?.tenants_no || `Tenant #${tenantId}`).toString();
            await addAdminNotification(req.adminUserId, {
                type: 'info',
                category: 'user',
                title: 'Kullanıcı eklendi',
                message: `${tenantName}: ${(newUser.name || '')} ${(newUser.surname || '')} (${newUser.username || newUser.email}) eklendi.`,
                tenant_id: tenantId
            });
        }
        return res.json({ success: true, data: newUser, notificationCreated: true });
    } catch (error) {
        console.error('❌ /api/admin/tenants/:tenantId/users (POST) hatası:', error);
        res.status(500).json({ success: false, error: error.message || 'Kullanıcı oluşturulamadı' });
    }
});

app.put('/api/admin/tenants/:tenantId/users/:userId', requireAdmin, async (req, res) => {
    try {
        const tenantId = parseInt(req.params.tenantId, 10);
        const userId = parseInt(req.params.userId, 10);
        if (!tenantId || isNaN(tenantId) || !userId || isNaN(userId)) {
            return res.status(400).json({ success: false, error: 'Geçersiz tenant ID veya user ID' });
        }

        const { name, surname, username, kullaniciadi, email, password, role, phone, status, is_active, is_admin } = req.body || {};

        // Kullanıcının gerçekten bu tenant'a ait olduğunu ve is_admin bilgisini al
        const existing = await query(
            'SELECT id, is_admin FROM tenants_kullanicilar WHERE id = ? AND tenant_id = ?',
            [userId, tenantId],
            null
        );
        if (!existing || existing.length === 0) {
            return res.status(404).json({ success: false, error: 'Kullanıcı bulunamadı' });
        }
        const existingUser = existing[0];
        const isPrimaryUser = existingUser.is_admin === 1 || existingUser.is_admin === '1';
        if (isPrimaryUser && typeof is_active !== 'undefined' && !is_active) {
            return res.status(403).json({ success: false, error: 'Bu kullanıcı varsayılan/ana kullanıcı olduğu için silinemez.' });
        }
        if (isPrimaryUser && typeof status !== 'undefined' && status === 'pasif') {
            return res.status(403).json({ success: false, error: 'Bu kullanıcı varsayılan/ana kullanıcı olduğu için durumu pasif yapılamaz.' });
        }

        const fields = [];
        const params = [];

        if (typeof name !== 'undefined') {
            fields.push('name = ?');
            params.push(name);
        }
        if (typeof surname !== 'undefined') {
            fields.push('surname = ?');
            params.push(surname);
        }
        const finalUsername = username || kullaniciadi;
        if (typeof finalUsername !== 'undefined') {
            fields.push('username = ?');
            params.push(finalUsername);
        }
        if (typeof email !== 'undefined') {
            fields.push('email = ?');
            params.push(email);
        }
        if (typeof role !== 'undefined') {
            fields.push('role = ?');
            params.push(role || null);
        }
        if (typeof phone !== 'undefined') {
            fields.push('phone = ?');
            params.push(phone || null);
        }
        if (typeof status !== 'undefined') {
            const newStatus = status === 'pasif' ? 'pasif' : 'aktif';
            fields.push('status = ?');
            params.push(newStatus);
        }
        if (typeof is_active !== 'undefined') {
            fields.push('is_active = ?');
            params.push(is_active ? 1 : 0);
        }
        if (typeof is_admin !== 'undefined') {
            fields.push('is_admin = ?');
            params.push(is_admin ? 1 : 0);
        }
        if (password && password.trim() !== '') {
            const hashedPassword = await bcrypt.hash(password, 10);
            fields.push('password = ?');
            params.push(hashedPassword);
        }

        if (fields.length === 0) {
            return res.status(400).json({ success: false, error: 'Güncellenecek alan bulunamadı' });
        }

        const kullaniciAdi = await getCurrentUsername(req);
        fields.push('updated_at = CURRENT_TIMESTAMP', 'updated_by = ?');

        const sql = `UPDATE tenants_kullanicilar SET ${fields.join(', ')} WHERE id = ? AND tenant_id = ?`;
        params.push(kullaniciAdi, userId, tenantId);

        await run(sql, params, null);

        const users = await query(
            `SELECT id, username, email, name, surname, role, phone, is_active, status, is_admin, created_at
             FROM tenants_kullanicilar
             WHERE id = ? AND tenant_id = ?
             LIMIT 1`,
            [userId, tenantId],
            null
        );
        const updatedUser = users?.[0] || null;
        if (updatedUser) {
            const tenantRow = await query('SELECT name, tenants_no FROM tenants WHERE id = ?', [tenantId], null).then(r => r?.[0]);
            const tenantName = (tenantRow?.name || tenantRow?.tenants_no || `Tenant #${tenantId}`).toString();
            const userName = `${(updatedUser.name || '')} ${(updatedUser.surname || '')}`.trim() || (updatedUser.username || updatedUser.email);
            if (typeof is_active !== 'undefined' && !is_active) {
                await addAdminNotification(req.adminUserId, {
                    type: 'warning',
                    category: 'user',
                    title: 'Kullanıcı silindi',
                    message: `${tenantName}: ${userName} kullanıcısı kaldırıldı.`,
                    tenant_id: tenantId
                });
            } else {
                await addAdminNotification(req.adminUserId, {
                    type: 'info',
                    category: 'user',
                    title: 'Kullanıcı güncellendi',
                    message: `${tenantName}: ${userName} bilgileri güncellendi.`,
                    tenant_id: tenantId
                });
            }
        }
        return res.json({ success: true, data: updatedUser, notificationCreated: true });
    } catch (error) {
        console.error('❌ /api/admin/tenants/:tenantId/users/:userId (PUT) hatası:', error);
        res.status(500).json({ success: false, error: error.message || 'Kullanıcı güncellenemedi' });
    }
});

// Admin tenant kullanıcı şifre değiştir (console-tenant-manage: PUT .../users/:userId/password)
app.put('/api/admin/tenants/:id/users/:userId/password', requireAdmin, async (req, res) => {
    try {
        const tenantId = parseInt(req.params.id, 10);
        const userId = parseInt(req.params.userId, 10);
        if (!tenantId || isNaN(tenantId) || !userId || isNaN(userId)) {
            return res.status(400).json({ success: false, error: 'Geçersiz tenant veya kullanıcı ID' });
        }
        const { password } = req.body || {};
        if (!password || typeof password !== 'string' || password.trim().length < 6) {
            return res.status(400).json({ success: false, error: 'Şifre en az 6 karakter olmalıdır' });
        }
        const existing = await query('SELECT id FROM tenants_kullanicilar WHERE id = ? AND tenant_id = ?', [userId, tenantId], null);
        if (!existing || existing.length === 0) {
            return res.status(404).json({ success: false, error: 'Kullanıcı bulunamadı' });
        }
        const hashedPassword = await bcrypt.hash(password.trim(), 10);
        const kullaniciAdi = await getCurrentUsername(req);
        await run('UPDATE tenants_kullanicilar SET password = ?, updated_at = datetime(\'now\'), updated_by = ? WHERE id = ? AND tenant_id = ?', [hashedPassword, kullaniciAdi, userId, tenantId], null);
        const tenantRow = await query('SELECT name, tenants_no FROM tenants WHERE id = ?', [tenantId], null).then(r => r?.[0]);
        const userRow = await query('SELECT name, surname, username FROM tenants_kullanicilar WHERE id = ? AND tenant_id = ?', [userId, tenantId], null).then(r => r?.[0]);
        const tenantName = (tenantRow?.name || tenantRow?.tenants_no || `Tenant #${tenantId}`).toString();
        const userName = (userRow ? `${(userRow.name || '')} ${(userRow.surname || '')}`.trim() || userRow.username : 'Kullanıcı').toString();
        await addAdminNotification(req.adminUserId, {
            type: 'info',
            category: 'user',
            title: 'Şifre değiştirildi',
            message: `${tenantName}: ${userName} şifresi güncellendi.`,
            tenant_id: tenantId
        });
        return res.json({ success: true, message: 'Şifre güncellendi', notificationCreated: true });
    } catch (error) {
        console.error('❌ /api/admin/tenants/:id/users/:userId/password hatası:', error);
        res.status(500).json({ success: false, error: error.message || 'Şifre güncellenemedi' });
    }
});

