// Admin tenant abonelik iptal (console-tenant-manage için)
app.post('/api/admin/tenants/:id/abonelik/cancel', requireAdmin, async (req, res) => {
    try {
        const id = parseInt(req.params.id, 10);
        if (!id || isNaN(id)) {
            return res.status(400).json({ success: false, error: 'Geçersiz tenant ID' });
        }

        // Son abonelik kaydını al
        const rows = await query(`
            SELECT a.*
            FROM tenants_abonelikler a
            WHERE a.tenant_id = ?
            ORDER BY a.id DESC
            LIMIT 1
        `, [id], null);

        const sub = rows?.[0] || null;

        // Hiç abonelik yoksa idempotent şekilde success döndür
        if (!sub) {
            return res.json({ success: true, message: 'Aktif abonelik bulunmuyor' });
        }

        // Zaten iptal edilmişse yine success dön (idempotent)
        if (sub.durum === 'iptal' || sub.durum === 'iptal_console') {
            return res.json({ success: true, message: 'Abonelik zaten iptal edilmiş' });
        }

        await run(`
            UPDATE tenants_abonelikler
            SET plan_id = 0,
                durum = 'iptal_console',
                iptal_tarihi = datetime('now'),
                islem_sahibi = 'superadmin',
                guncelleme_tarihi = datetime('now')
            WHERE id = ?
        `, [sub.id], null);

        try {
            const planRow = sub.plan_id ? await query('SELECT plan_adi FROM tenants_abonelik_planlari WHERE id = ?', [sub.plan_id], null) : null;
            const planAdi = (planRow && planRow[0] && planRow[0].plan_adi) ? planRow[0].plan_adi : 'Abonelik Planı';
            const tenantCols = await query('PRAGMA table_info(tenants)', [], null);
            const tNames = (tenantCols || []).map(c => c && c.name).filter(Boolean);
            const hasFirmaAdi = tNames.includes('firma_adi');
            const sel = hasFirmaAdi
                ? 'SELECT id, name, email, firma_adi, tenants_no FROM tenants WHERE id = ?'
                : 'SELECT id, name, email, tenants_no FROM tenants WHERE id = ?';
            const tenantRows = await query(sel, [id], null);
            const tenantRow = tenantRows && tenantRows[0] ? tenantRows[0] : null;
            if (tenantRow) {
                await sendAbonelikMail('iptal', {
                    tenantId: id,
                    tenant: tenantRow,
                    planAdi,
                    donemBitis: sub.mevcut_donem_bitis || null,
                    cancel_reason: 'Console üzerinden iptal edildi',
                    baseUrl: getBaseUrlFromRequest(req)
                });
            }
        } catch (mailErr) {
            console.warn('⚠️ admin/abonelik/cancel: Abonelik iptal maili atlandı:', mailErr?.message || mailErr);
        }

        res.json({ success: true, message: 'Abonelik başarıyla iptal edildi' });
    } catch (error) {
        console.error('❌ /api/admin/tenants/:id/abonelik/cancel hatası:', error);
        res.status(500).json({ success: false, error: error.message || 'Abonelik iptal edilemedi' });
    }
});

