// Admin tenant ödeme yöntemi ekle (yoksa oluştur)
app.post('/api/admin/tenants/:tenantId/odeme-yontemleri', requireAdmin, async (req, res) => {
    try {
        const tenantId = parseInt(req.params.tenantId, 10);
        if (!tenantId || isNaN(tenantId)) {
            return res.status(400).json({ success: false, error: 'Geçersiz tenant ID' });
        }
        const { kart_sahibi_adi, kart_numarasi, son_kullanim_ayi, son_kullanim_yili, kart_tipi } = req.body || {};
        let sonDortRakam = '0000';
        if (kart_numarasi && String(kart_numarasi).replace(/\s/g, '').length >= 4) {
            const num = String(kart_numarasi).replace(/\s/g, '');
            sonDortRakam = num.slice(-4);
            if (!/^\d{4}$/.test(sonDortRakam)) sonDortRakam = '0000';
        }
        let ayStr = '12';
        let yilInt = 2030;
        if (son_kullanim_ayi != null && son_kullanim_ayi !== '') {
            ayStr = String(son_kullanim_ayi).padStart(2, '0');
            if (parseInt(ayStr, 10) < 1 || parseInt(ayStr, 10) > 12) ayStr = '12';
        }
        if (son_kullanim_yili != null && son_kullanim_yili !== '') {
            yilInt = parseInt(son_kullanim_yili, 10);
            if (yilInt < 100) yilInt = 2000 + yilInt;
            if (isNaN(yilInt) || yilInt < 2020) yilInt = 2030;
        }
        const kartTipi = (kart_tipi && String(kart_tipi).trim()) || 'Kredi Kartı';
        const kartSahibi = (kart_sahibi_adi && String(kart_sahibi_adi).trim()) || null;
        const kullaniciAdi = await getCurrentUsername(req);
        await run(
            `INSERT INTO tenants_odeme_yontemleri (tenant_id, odeme_yontemi_id, kart_tipi, son_dort_rakam, son_kullanim_ayi, son_kullanim_yili, kart_sahibi_adi, varsayilan_mi, aktif_mi, created_by, updated_by) VALUES (?, 1, ?, ?, ?, ?, ?, 1, 1, ?, ?)`,
            [tenantId, kartTipi, sonDortRakam, ayStr, yilInt, kartSahibi, kullaniciAdi, kullaniciAdi]
        );
        const inserted = await query('SELECT id FROM tenants_odeme_yontemleri WHERE tenant_id = ? ORDER BY id DESC LIMIT 1', [tenantId], null);
        const newId = inserted && inserted[0] ? inserted[0].id : null;
        const row = newId ? (await query('SELECT * FROM tenants_odeme_yontemleri WHERE id = ?', [newId], null))?.[0] : null;
        return res.json({ success: true, data: row });
    } catch (error) {
        console.error('❌ POST /api/admin/tenants/:tenantId/odeme-yontemleri hatası:', error);
        res.status(500).json({ success: false, error: error.message || 'Ödeme yöntemi eklenemedi' });
    }
});

// Admin tenant ödeme yöntemi güncelle
app.put('/api/admin/tenants/:tenantId/odeme-yontemleri/:paymentId', requireAdmin, async (req, res) => {
    try {
        const tenantId = parseInt(req.params.tenantId, 10);
        const paymentId = parseInt(req.params.paymentId, 10);

        if (!tenantId || isNaN(tenantId) || !paymentId || isNaN(paymentId)) {
            return res.status(400).json({ success: false, error: 'Geçersiz tenant ID veya ödeme yöntemi ID' });
        }

        const { kart_sahibi_adi, kart_numarasi, son_kullanim_ayi, son_kullanim_yili } = req.body || {};

        const existing = await query(
            'SELECT * FROM tenants_odeme_yontemleri WHERE id = ? AND tenant_id = ?',
            [paymentId, tenantId],
            null
        );
        if (!existing || existing.length === 0) {
            return res.status(404).json({ success: false, error: 'Ödeme yöntemi bulunamadı' });
        }

        const fields = [];
        const params = [];

        if (typeof kart_sahibi_adi !== 'undefined') {
            fields.push('kart_sahibi_adi = ?');
            params.push(kart_sahibi_adi || null);
        }

        // Kart numarasından sadece son 4 haneyi sakla (son_dort_rakam)
        if (typeof kart_numarasi !== 'undefined' && kart_numarasi) {
            const num = kart_numarasi.toString().replace(/\s+/g, '');
            const last4 = num.slice(-4);
            if (last4 && last4.length === 4 && /^\d{4}$/.test(last4)) {
                fields.push('son_dort_rakam = ?');
                params.push(last4);
            }
        }

        // SKT: ay (TEXT olarak, 2 hane) ve yıl (INTEGER)
        if (typeof son_kullanim_ayi !== 'undefined') {
            const ayStr = son_kullanim_ayi === null || son_kullanim_ayi === '' ? null : son_kullanim_ayi.toString().padStart(2, '0');
            fields.push('son_kullanim_ayi = ?');
            params.push(ayStr);
        }
        if (typeof son_kullanim_yili !== 'undefined') {
            const yilInt = son_kullanim_yili === null || son_kullanim_yili === '' ? null : parseInt(son_kullanim_yili, 10);
            fields.push('son_kullanim_yili = ?');
            params.push(isNaN(yilInt) ? null : yilInt);
        }

        if (fields.length === 0) {
            return res.status(400).json({ success: false, error: 'Güncellenecek alan bulunamadı' });
        }

        const kullaniciAdi = await getCurrentUsername(req);
        fields.push('guncelleme_tarihi = datetime(\'now\')', 'updated_by = ?');

        const sql = `UPDATE tenants_odeme_yontemleri SET ${fields.join(', ')} WHERE id = ? AND tenant_id = ?`;
        params.push(kullaniciAdi, paymentId, tenantId);

        await run(sql, params, null);

        // Güncellenen kaydı geri döndür
        const odemeler = await query(
            'SELECT * FROM tenants_odeme_yontemleri WHERE id = ? AND tenant_id = ? LIMIT 1',
            [paymentId, tenantId],
            null
        );

        return res.json({ success: true, data: odemeler?.[0] || null });
    } catch (error) {
        console.error('❌ /api/admin/tenants/:tenantId/odeme-yontemleri/:paymentId hatası:', error);
        res.status(500).json({ success: false, error: error.message || 'Ödeme yöntemi güncellenemedi' });
    }
});

// Admin tenant faturalar - plan ve fatura_dongusu bilgileriyle birlikte
app.get('/api/admin/tenants/:id/faturalar', requireAdmin, async (req, res) => {
    try {
        const id = parseInt(req.params.id, 10);
        const limit = Math.min(parseInt(req.query.limit, 10) || 100, 1000);
        if (!id || isNaN(id)) {
            return res.status(400).json({ success: false, error: 'Geçersiz tenant ID' });
        }

        const faturalar = await query(
            `SELECT f.*, p.plan_adi, COALESCE(f.fatura_dongusu, a.fatura_dongusu) AS fatura_dongusu
             FROM tenants_faturalar f
             LEFT JOIN tenants_abonelik_planlari p ON f.plan_id = p.id
             LEFT JOIN tenants_abonelikler a ON f.abonelik_id = a.id
             WHERE f.tenant_id = ?
             ORDER BY f.fatura_tarihi DESC
             LIMIT ?`,
            [id, limit],
            null
        );

        const invoices = (faturalar || []).map(f => ({
            ...f,
            plan_adi: f.plan_adi || 'Bilinmeyen Plan',
            fatura_dongusu: (f.fatura_dongusu || 'aylik').toString().toLowerCase(),
            odeme_periyodu: f.fatura_dongusu || 'aylik',
            fatura_tarihi: f.fatura_tarihi,
            toplam_tutar: f.toplam_tutar,
            durum: f.durum,
            fatura_no: f.fatura_no,
            pdf_yolu: f.pdf_yolu
        }));

        res.json({ success: true, data: invoices });
    } catch (error) {
        console.error('❌ /api/admin/tenants/:id/faturalar hatası:', error);
        res.json({ success: true, data: [] });
    }
});

// Admin tenant güncelle (status + temel bilgiler)
app.put('/api/admin/tenants/:id', requireAdmin, async (req, res) => {
    try {
        const id = parseInt(req.params.id, 10);
        if (!id || isNaN(id)) {
            return res.status(400).json({ success: false, error: 'Geçersiz tenant ID' });
        }

        const { status, name, email, phone, city, state } = req.body || {};

        // tenants tablosunda sadece 'phone' kullan (telefon kolonu kullanma - yoksa SQLITE_ERROR)
        const tenantCols = await query('PRAGMA table_info(tenants)', [], null);
        const colNames = (tenantCols || []).map(c => (c && c.name) ? c.name : '');
        const hasPhone = colNames.includes('phone');

        const fields = [];
        const params = [];

        if (typeof status !== 'undefined') {
            const newStatus = (status === 'aktif' || status === 'pasif') ? status : null;
            if (!newStatus) {
                return res.status(400).json({ success: false, error: 'status: aktif veya pasif olmalı' });
            }
            fields.push('status = ?');
            params.push(newStatus);
        }

        if (typeof name !== 'undefined') {
            fields.push('name = ?');
            params.push(name);
        }

        if (typeof email !== 'undefined') {
            fields.push('email = ?');
            params.push(email);
        }

        if (typeof phone !== 'undefined' && hasPhone) {
            fields.push('phone = ?');
            params.push(phone || null);
        }

        if (typeof city !== 'undefined') {
            fields.push('city = ?');
            params.push(city || null);
        }

        if (typeof state !== 'undefined') {
            fields.push('state = ?');
            params.push(state || null);
        }

        if (fields.length === 0) {
            return res.status(400).json({ success: false, error: 'Güncellenecek alan bulunamadı' });
        }

        fields.push('updated_at = CURRENT_TIMESTAMP');

        const sql = `UPDATE tenants SET ${fields.join(', ')} WHERE id = ?`;
        params.push(id);

        await run(sql, params);

        const selectPhone = hasPhone ? 'phone as phone' : 'NULL as phone';
        const updated = await query(`SELECT id, name, tenants_no, status, email, ${selectPhone}, city, state FROM tenants WHERE id = ?`, [id], null);
        const tenant = updated?.[0] || {};
        const tenantName = tenant.name || tenant.tenants_no || `Tenant #${id}`;
        await addAdminNotification(req.adminUserId, {
            type: 'info',
            category: 'tenant',
            title: 'Tenant güncellendi',
            message: `${tenantName} bilgileri güncellendi.`,
            tenant_id: id
        });
        res.json({ success: true, data: tenant, notificationCreated: true });
    } catch (error) {
        console.error('❌ /api/admin/tenants/:id hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

