// Müşteri tahsilatı oluştur (React cari - /api/customers path)
app.post('/api/customers/:id/tahsilatlar', async (req, res) => {
    try {
        const customerId = parseInt(req.params.id);
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(401).json({ success: false, error: 'Kimlik doğrulama gerekli.' });
        }
        if (!customerId) {
            return res.status(400).json({ success: false, error: 'Geçersiz müşteri ID' });
        }
        const customer = await query('SELECT * FROM musteriler WHERE id = ? AND tenant_id = ?', [customerId, tenantId]);
        if (customer.length === 0) {
            return res.status(404).json({ success: false, error: 'Müşteri bulunamadı' });
        }
        const {
            islem_tarihi_saati,
            odeme_yontemi,
            tahsil_edilen_tutar,
            odeme_yapan_kisi,
            tahsilat_yapan_kisi,
            aciklama,
            tahsilat_makbuz_no,
            fatura_id,
            fatura_no
        } = req.body;
        if (!islem_tarihi_saati || tahsil_edilen_tutar === undefined || tahsil_edilen_tutar === null) {
            return res.status(400).json({ success: false, error: 'islem_tarihi_saati ve tahsil_edilen_tutar zorunludur' });
        }
        const makbuzNo = (tahsilat_makbuz_no != null && String(tahsilat_makbuz_no).trim() !== '')
            ? String(tahsilat_makbuz_no).trim()
            : `T-${Date.now()}`;
        const kullaniciAdi = await getCurrentUsername(req);
        const result = await execute(`
            INSERT INTO musteri_tahsilatlar (
                musteri_id, tenant_id, fatura_id, fatura_no,
                islem_tarihi_saati, odeme_yontemi, tahsil_edilen_tutar,
                odeme_yapan_kisi, tahsilat_yapan_kisi, tahsilat_makbuz_no, aciklama, created_by, updated_by
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `, [
            customerId, tenantId, fatura_id || null, fatura_no || null,
            islem_tarihi_saati, normalizeOdemeYontemi(odeme_yontemi), parseFloat(tahsil_edilen_tutar),
            odeme_yapan_kisi || null, tahsilat_yapan_kisi || null, makbuzNo, aciklama || null,
            kullaniciAdi, kullaniciAdi
        ]);
        const created = await query('SELECT * FROM musteri_tahsilatlar WHERE id = ?', [result.lastID]);
        res.json({ success: true, data: created[0] });
    } catch (error) {
        console.error('❌ Tahsilat oluşturulurken hata:', error);
        res.status(500).json({ success: false, error: 'Tahsilat oluşturulamadı', message: error.message });
    }
});

// Müşteri siparişleri endpoint - /customers route'undan ÖNCE tanımlanmalı
app.get('/api/customers/:id/siparisler', async (req, res) => {
    try {
        const customerId = req.params.id;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // Müşteri bilgilerini al
        const customer = await query(
            'SELECT * FROM musteriler WHERE id = ? AND tenant_id = ?',
            [customerId, tenantId]
        );
        
        if (customer.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Müşteri bulunamadı'
            });
        }
        
        const customerInfo = customer[0];
        const musteriUnvan = customerInfo.musteri_unvani;
        const musteriIsimSoyisim = customerInfo.musteri_ad_soyad;
        const customerPhone = customerInfo.musteri_telefon;
        
        console.log(`\n🔍 ========== MÜŞTERİ SİPARİŞLERİ SORGUSU ==========`);
        console.log(`📋 Müşteri ID: ${customerId}`);
        console.log(`📋 Müşteri Unvan: ${musteriUnvan || '(yok)'}`);
        console.log(`📋 Müşteri İsim Soyisim: ${musteriIsimSoyisim || '(yok)'}`);
        console.log(`📋 Telefon: ${customerPhone || '(yok)'}`);
        
        // Telefon numarası normalizasyonu (sadece rakamları al)
        const normalizePhone = (phone) => {
            if (!phone) return '';
            return phone.replace(/\D/g, ''); // Sadece rakamları al
        };
        const normalizedCustomerPhone = normalizePhone(customerPhone);
        console.log(`📋 Normalize edilmiş telefon: ${normalizedCustomerPhone || '(yok)'}`);
        
        // Önce musteri_id kolonunun var olup olmadığını kontrol et
        const columns = await query('PRAGMA table_info(siparisler)');
        const columnNames = columns.map(col => col.name);
        const hasMusteriId = columnNames.includes('musteri_id');
        console.log(`📋 musteri_id kolonu var mı: ${hasMusteriId}`);
        
        // DEBUG: Veritabanındaki tüm siparişleri kontrol et (musteri_id, unvan, telefon ile)
        const allSiparislerDebug = await query(`
            SELECT id, musteri_id, musteri_unvan, musteri_isim_soyisim, siparis_veren_telefon, is_active, tenant_id
            FROM siparisler
            WHERE tenant_id = ?
            AND (is_active = 1 OR is_active IS NULL)
            ORDER BY created_at DESC
            LIMIT 100
        `, [tenantId]);
        console.log(`📋 Veritabanındaki son 100 sipariş (musteri_id kontrolü):`);
        const matchingSiparisler = allSiparislerDebug.filter(s => {
            const matchesId = s.musteri_id == customerId;
            const matchesUnvan = (s.musteri_unvan && musteriUnvan && s.musteri_unvan.toLowerCase().trim() === musteriUnvan.toLowerCase().trim());
            const matchesIsim = (s.musteri_isim_soyisim && musteriIsimSoyisim && s.musteri_isim_soyisim.toLowerCase().trim() === musteriIsimSoyisim.toLowerCase().trim());
            const matchesPhone = (s.siparis_veren_telefon && normalizedCustomerPhone && normalizePhone(s.siparis_veren_telefon) === normalizedCustomerPhone);
            return matchesId || matchesUnvan || matchesIsim || matchesPhone;
        });
        if (matchingSiparisler.length > 0) {
            console.log(`📋 Eşleşen siparişler (${matchingSiparisler.length} adet):`);
            matchingSiparisler.forEach(s => {
                const matchesId = s.musteri_id == customerId;
                const matchesUnvan = (s.musteri_unvan && musteriUnvan && s.musteri_unvan.toLowerCase().trim() === musteriUnvan.toLowerCase().trim());
                const matchesIsim = (s.musteri_isim_soyisim && musteriIsimSoyisim && s.musteri_isim_soyisim.toLowerCase().trim() === musteriIsimSoyisim.toLowerCase().trim());
                const matchesPhone = (s.siparis_veren_telefon && normalizedCustomerPhone && normalizePhone(s.siparis_veren_telefon) === normalizedCustomerPhone);
                console.log(`  → Sipariş ID ${s.id}: musteri_id=${s.musteri_id} (eşleşme: id=${matchesId}, unvan=${matchesUnvan}, isim=${matchesIsim}, telefon=${matchesPhone})`);
            });
        } else {
            console.log(`⚠️ Veritabanında eşleşen sipariş bulunamadı!`);
        }
        
        let siparisler = [];
        
        if (hasMusteriId) {
            // ÖNCE: musteri_id ile direkt sorgu yap (en doğru ve performanslı yöntem)
            console.log(`🔍 musteri_id ile sorgu yapılıyor: customerId=${customerId}, tenantId=${tenantId}`);
            let siparislerWithMusteriId = await query(`
                SELECT 
                    sk.*,
                    ok.organizasyon_kart_tur,
                    ok.organizasyon_kart_etiket,
                    ok.organizasyon_alt_tur,
                    ok.organizasyon_teslim_tarih,
                    ok.organizasyon_teslim_saat,
                    ok.organizasyon_teslimat_konumu as organizasyon_konum,
                    ok.organizasyon_teslim_kisisi as organizasyon_sahip,
                    ok.organizasyon_acik_adres,
                    ok.organizasyon_teslim_kisisi,
                    ok.organizasyon_il,
                    ok.organizasyon_ilce,
                    ok.organizasyon_mahalle,
                    sk.teslim_mahalle,
                    sk.teslim_ilce,
                    sk.teslim_il,
                    (SELECT p.urun_gorseli FROM urunler p
                     WHERE (sk.siparis_urun_id = p.id OR sk.siparis_urun = p.urun_adi)
                     AND (p.tenant_id = sk.tenant_id OR p.tenant_id IS NULL)
                     LIMIT 1) as product_gorsel
                FROM siparisler sk
                LEFT JOIN organizasyon_kartlar ok ON sk.organizasyon_kart_id = ok.id
                WHERE sk.musteri_id = ?
                    AND sk.musteri_id IS NOT NULL
                    AND sk.tenant_id = ?
                    AND (sk.is_active = 1 OR sk.is_active IS NULL)
                ORDER BY sk.id ASC
            `, [customerId, tenantId]);
            
            console.log(`✅ musteri_id ile ${siparislerWithMusteriId.length} sipariş bulundu`);
            if (siparislerWithMusteriId.length > 0) {
                console.log(`📋 Bulunan sipariş ID'leri:`, siparislerWithMusteriId.map(s => s.id));
            }
            
            // SADECE musteri_id ile eşleşen siparişleri kullan (fallback sorgu kaldırıldı - yanlış eşleşmelere neden oluyordu)
            siparisler = siparislerWithMusteriId;
            
            console.log(`✅ Müşteri ${customerId} toplam ${siparisler.length} sipariş bulundu`);
            
            // Fatura kesilmiş siparişleri filtrele (eğer includeFaturaKesilmis parametresi yoksa)
            const includeFaturaKesilmis = req.query.includeFaturaKesilmis === 'true';
            
            try {
                // Müşteriye ait faturaları çek
                const tableExists = await query(`
                    SELECT name FROM sqlite_master 
                    WHERE type='table' AND name='musteri_faturalar'
                `);
                
                if (tableExists.length > 0 && !includeFaturaKesilmis) {
                    const columns = await query('PRAGMA table_info(musteri_faturalar)');
                    const columnNames = columns.map(c => c.name);
                    const hasTenantId = columnNames.includes('tenant_id');
                    
                    let faturalar = [];
                    if (hasTenantId) {
                        // Sadece iptal edilmemiş faturaları kontrol et (iptal edilen faturaların siparişleri tekrar görünmeli)
                        faturalar = await query(
                            'SELECT siparis_idler FROM musteri_faturalar WHERE musteri_id = ? AND tenant_id = ? AND (durum IS NULL OR LOWER(durum) != ?)',
                            [customerId, tenantId, 'iptal']
                        );
                    } else {
                        // Sadece iptal edilmemiş faturaları kontrol et
                        faturalar = await query(
                            'SELECT siparis_idler FROM musteri_faturalar WHERE musteri_id = ? AND (durum IS NULL OR LOWER(durum) != ?)',
                            [customerId, 'iptal']
                        );
                    }
                    
                    // Tüm fatura kesilmiş sipariş ID'lerini topla (sadece aktif faturalardan)
                    const faturaKesilmisSiparisIdleri = new Set();
                    faturalar.forEach(fatura => {
                        if (fatura.siparis_idler) {
                            const siparisIdler = fatura.siparis_idler.split(',').map(id => id.trim()).filter(Boolean);
                            siparisIdler.forEach(id => {
                                // Hem string hem number formatında kontrol edebilmek için her iki formatı da ekle
                                faturaKesilmisSiparisIdleri.add(String(id));
                                const numId = parseInt(id, 10);
                                if (!isNaN(numId)) {
                                    faturaKesilmisSiparisIdleri.add(String(numId));
                                }
                            });
                        }
                    });
                    
                    if (faturaKesilmisSiparisIdleri.size > 0) {
                        console.log(`📋 Fatura kesilmiş sipariş ID'leri (${faturaKesilmisSiparisIdleri.size} adet):`, Array.from(faturaKesilmisSiparisIdleri));
                        // Fatura kesilmiş siparişleri filtrele (hem string hem number formatında kontrol et)
                        const oncekiSayi = siparisler.length;
                        siparisler = siparisler.filter(siparis => {
                            const siparisIdStr = String(siparis.id);
                            const siparisIdNum = String(parseInt(siparis.id, 10));
                            return !faturaKesilmisSiparisIdleri.has(siparisIdStr) && 
                                   !faturaKesilmisSiparisIdleri.has(siparisIdNum);
                        });
                        console.log(`✅ Fatura kesilmiş siparişler filtrelendi: ${oncekiSayi} → ${siparisler.length} sipariş kaldı`);
                    } else {
                        console.log(`📋 Fatura kesilmiş sipariş bulunamadı, tüm siparişler gösterilecek`);
                    }
                }
            } catch (faturaFilterError) {
                console.warn('⚠️ Fatura filtreleme hatası (devam ediliyor):', faturaFilterError.message);
            }
            
            if (siparisler.length === 0) {
                console.log(`⚠️ UYARI: Müşteri ${customerId} için hiç sipariş bulunamadı!`);
                console.log(`⚠️ Kontrol edilmesi gerekenler:`);
                console.log(`   - Veritabanında bu müşteriye ait sipariş var mı?`);
                console.log(`   - Siparişlerde musteri_id değeri doğru mu?`);
                console.log(`   - Siparişlerde müşteri adı/telefon eşleşiyor mu?`);
            }
            console.log(`📋 Tüm sipariş ID'leri:`, siparisler.map(s => s.id));
            console.log(`🔍 ========== SORGUSU TAMAMLANDI ==========\n`);
        } else {
            // musteri_id kolonu yoksa boş liste döndür
            // Fallback sorgu çok geniş ve yanlış siparişleri getiriyor
            siparisler = [];
            console.log(`⚠️ Müşteri ${customerId}: musteri_id kolonu yok, sipariş listesi boş`);
        }
        
        res.json({
            success: true,
            data: siparisler,
            count: siparisler.length
        });
    } catch (error) {
        console.error('❌ Müşteri siparişleri yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Müşteri siparişleri yüklenemedi',
            message: error.message
        });
    }
});

// Mevcut siparişlerde musteri_id güncelleme endpoint'i
app.post('/api/siparisler/update-musteri-ids', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        console.log('🔧 Mevcut siparişlerde musteri_id güncelleme başlatılıyor...');
        
        // musteri_id NULL olan tüm siparişleri al
        const siparislerNull = await query(`
            SELECT 
                id,
                musteri_unvan,
                musteri_isim_soyisim,
                siparis_veren_telefon,
                tenant_id
            FROM siparisler
            WHERE (musteri_id IS NULL OR musteri_id = '')
                AND tenant_id = ?
                AND (is_active = 1 OR is_active IS NULL)
        `, [tenantId]);
        
        console.log(`📋 ${siparislerNull.length} adet musteri_id NULL olan sipariş bulundu`);
        
        let guncellenenSayisi = 0;
        let bulunamayanSayisi = 0;
        
        // Telefon normalizasyon fonksiyonu (sadece rakamları al)
        const normalizePhone = (phone) => {
            if (!phone) return '';
            return phone.replace(/\D/g, '');
        };
        
        // Her sipariş için müşteri eşleştirmesi yap
        for (const siparis of siparislerNull) {
            const musteri_unvan = siparis.musteri_unvan || '';
            const musteri_isim_soyisim = siparis.musteri_isim_soyisim || '';
            const siparis_veren_telefon = siparis.siparis_veren_telefon || '';
            
            const hasUnvan = musteri_unvan && musteri_unvan.trim() !== '';
            const hasIsimSoyisim = musteri_isim_soyisim && musteri_isim_soyisim.trim() !== '';
            const hasPhone = siparis_veren_telefon && siparis_veren_telefon.trim() !== '';
            const hasName = hasUnvan || hasIsimSoyisim;
            
            let musteriId = null;
            
            // Müşteri adı VE telefon numarası ikisi de olmalı
            if (hasName && hasPhone) {
                const normalizedSiparisPhone = normalizePhone(siparis_veren_telefon);
                
                // Önce müşteri adı ile eşleştirme yap
                const whereConditions = [];
                const whereParams = [tenantId];
                
                // Müşteri adı kontrolü
                const nameConditions = [];
                if (hasUnvan) {
                    nameConditions.push('(musteri_unvani = ? OR musteri_unvani LIKE ?)');
                    whereParams.push(musteri_unvan, `%${musteri_unvan}%`);
                }
                if (hasIsimSoyisim) {
                    nameConditions.push('(musteri_ad_soyad = ? OR musteri_ad_soyad LIKE ?)');
                    whereParams.push(musteri_isim_soyisim, `%${musteri_isim_soyisim}%`);
                }
                if (nameConditions.length > 0) {
                    whereConditions.push(`(${nameConditions.join(' OR ')})`);
                }
                
                let musteriMatch = [];
                if (whereConditions.length > 0) {
                    const musteriQuery = `
                        SELECT id, musteri_telefon FROM musteriler 
                        WHERE tenant_id = ?
                            AND ${whereConditions.join(' AND ')}
                    `;
                    musteriMatch = await query(musteriQuery, whereParams);
                }
                
                // Telefon numarası ile eşleştirme (normalize edilmiş)
                if (musteriMatch.length > 0 && normalizedSiparisPhone) {
                    const matchedMusteri = musteriMatch.find(m => {
                        const normalizedMusteriPhone = normalizePhone(m.musteri_telefon || '');
                        return normalizedMusteriPhone === normalizedSiparisPhone || 
                               normalizedMusteriPhone.endsWith(normalizedSiparisPhone) ||
                               normalizedSiparisPhone.endsWith(normalizedMusteriPhone);
                    });
                    
                    if (matchedMusteri) {
                        musteriId = matchedMusteri.id;
                    }
                }
            }
            
            // musteri_id güncelle
            if (musteriId) {
                await query(`
                    UPDATE siparisler
                    SET musteri_id = ?
                    WHERE id = ? AND tenant_id = ?
                `, [musteriId, siparis.id, tenantId]);
                guncellenenSayisi++;
                console.log(`✅ Sipariş ${siparis.id} → Müşteri ${musteriId} ile eşleştirildi`);
            } else {
                bulunamayanSayisi++;
                console.log(`⚠️ Sipariş ${siparis.id} için müşteri bulunamadı (Unvan: ${musteri_unvan}, İsim: ${musteri_isim_soyisim}, Telefon: ${siparis_veren_telefon})`);
            }
        }
        
        console.log(`✅ Güncelleme tamamlandı: ${guncellenenSayisi} sipariş güncellendi, ${bulunamayanSayisi} sipariş için müşteri bulunamadı`);
        
        res.json({
            success: true,
            message: 'Müşteri ID güncelleme tamamlandı',
            data: {
                toplamSiparis: siparislerNull.length,
                guncellenenSayisi: guncellenenSayisi,
                bulunamayanSayisi: bulunamayanSayisi
            }
        });
    } catch (error) {
        console.error('❌ Müşteri ID güncelleme hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Müşteri ID güncellenemedi',
            message: error.message
        });
    }
});

// Müşteri ürün yazı dosyaları endpoint - /customers route'undan ÖNCE tanımlanmalı
app.get('/api/customers/:id/urun-yazi-dosyalari', async (req, res) => {
    try {
        console.log('🔍 /api/customers/:id/urun-yazi-dosyalari çağrıldı, ID:', req.params.id);
        const customerId = req.params.id;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // Müşteri bilgilerini al - tenant_id kontrolü ile (NULL tenant_id'yi de kontrol et)
        let customer = await query(
            'SELECT * FROM musteriler WHERE id = ? AND tenant_id = ?',
            [customerId, tenantId]
        );
        
        // Eğer hala bulunamazsa, tenant_id kontrolü yapmadan ara (son çare)
        if (customer.length === 0) {
            customer = await query(
                'SELECT * FROM musteriler WHERE id = ?',
                [customerId]
            );
            
            if (customer.length === 0) {
                console.log('❌ Müşteri bulunamadı:', customerId);
                return res.status(404).json({
                    success: false,
                    error: 'Müşteri bulunamadı'
                });
            }
            
            // NOT: Global müşteri kayıtları (tenant_id IS NULL) ASLA tenant'a çevrilmez (güvenlik)
            // Eğer müşteri global ise, tenant_id'yi null olarak bırak
            // Tenant kendi müşterisini oluşturmalı
        }
        
        console.log(`✅ Müşteri bulundu: ${customerId}, tenant_id: ${customer[0].tenant_id || 'NULL'}`);
        
        const customerData = customer[0];
        const customerUnvan = customerData.musteri_unvani || 'musteri';
        const cleanUnvan = customerUnvan
            .replace(/ç/g, 'c').replace(/ğ/g, 'g').replace(/ı/g, 'i')
            .replace(/ö/g, 'o').replace(/ş/g, 's').replace(/ü/g, 'u')
            .replace(/Ç/g, 'C').replace(/Ğ/g, 'G').replace(/İ/g, 'I')
            .replace(/Ö/g, 'O').replace(/Ş/g, 'S').replace(/Ü/g, 'U')
            .replace(/[^a-zA-Z0-9_-]/g, '-')
            .toLowerCase();
        
        const customerFolder = `${customerId}-${cleanUnvan}`;
        // Tenant ID zaten üstte tanımlanmış (satır 4909), tekrar tanımlama
        // Tenant-based path kullan
        const urunYaziDir = getTenantUploadPath(tenantId, 'customers', customerFolder, 'urun_yazi_dosyalari');
        
        console.log('📁 Ürün yazı dosyaları klasörü:', urunYaziDir);
        
        let files = [];
        if (fs.existsSync(urunYaziDir)) {
            try {
                // Tenant ID zaten üstte tanımlanmış, tekrar tanımlama
                const fileList = fs.readdirSync(urunYaziDir);
                files = fileList.map(fileName => {
                    const filePath = path.join(urunYaziDir, fileName);
                    const stats = fs.statSync(filePath);
                    return {
                        name: fileName,
                        // Tenant-based path kullan
                        path: `/uploads/tenants/${tenantId}/customers/${customerFolder}/urun_yazi_dosyalari/${fileName}`,
                        url: `/uploads/tenants/${tenantId}/customers/${customerFolder}/urun_yazi_dosyalari/${fileName}`, // Relative path
                        size: stats.size,
                        modified: stats.mtime.toISOString()
                    };
                });
                
                // Dosyaları son yüklenen en altta olacak şekilde tarihe göre sırala (eski → yeni)
                files.sort((a, b) => {
                    const ta = new Date(a.modified).getTime();
                    const tb = new Date(b.modified).getTime();
                    return ta - tb;
                });

                console.log(`✅ ${files.length} dosya bulundu (tarihe göre sıralandı)`);
            } catch (dirError) {
                console.error('❌ Dosya listesi okunurken hata:', dirError);
            }
        } else {
            console.log('⚠️ Klasör bulunamadı:', urunYaziDir);
        }
        
        res.json({
            success: true,
            data: files
        });
    } catch (error) {
        console.error('❌ Müşteri ürün yazı dosyaları yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Ürün yazı dosyaları yüklenemedi',
            message: error.message
        });
    }
});

// Müşteri dosyası silme endpoint'i
app.delete('/api/customers/:id/files', async (req, res) => {
    try {
        const customerId = req.params.id;
        let fileName = req.query.fileName;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        if (!fileName) {
            return res.status(400).json({ success: false, error: 'Dosya adı gerekli (fileName parametresi)' });
        }
        
        // URL decode - frontend'den encode edilmiş olarak geliyor
        try {
            fileName = decodeURIComponent(fileName);
        } catch (e) {
            console.log('⚠️ URL decode hatası, orijinal dosya adı kullanılıyor:', fileName);
        }
        
        console.log(`🗑️ Dosya silme isteği - Müşteri ID: ${customerId}, Dosya Adı: ${fileName}`);
        
        // Müşteri bilgilerini al
        let customer = await query(
            'SELECT * FROM musteriler WHERE id = ? AND tenant_id = ?',
            [customerId, tenantId]
        );
        
        if (customer.length === 0) {
            customer = await query(
                'SELECT * FROM musteriler WHERE id = ?',
                [customerId]
            );
            
            if (customer.length === 0) {
                return res.status(404).json({
                    success: false,
                    error: 'Müşteri bulunamadı'
                });
            }
        }
        
        const customerData = customer[0];
        const customerUnvan = customerData.musteri_unvani || 'musteri';
        const cleanUnvan = customerUnvan
            .replace(/ç/g, 'c').replace(/ğ/g, 'g').replace(/ı/g, 'i')
            .replace(/ö/g, 'o').replace(/ş/g, 's').replace(/ü/g, 'u')
            .replace(/Ç/g, 'C').replace(/Ğ/g, 'G').replace(/İ/g, 'I')
            .replace(/Ö/g, 'O').replace(/Ş/g, 'S').replace(/Ü/g, 'U')
            .replace(/[^a-zA-Z0-9_-]/g, '-')
            .toLowerCase();
        
        // Önce veritabanındaki dosya listesini kontrol et ve kaldır
        let dosyalar = [];
        let dosyaBulundu = false;
        
        try {
            if (customerData.musteri_urun_yazi_dosyalar) {
                try {
                    dosyalar = JSON.parse(customerData.musteri_urun_yazi_dosyalar);
                } catch (e) {
                    console.log('⚠️ Mevcut dosya listesi parse edilemedi');
                    dosyalar = [];
                }
            }
            
            // Dosya adını normalize et (karşılaştırma için)
            const normalizeFileName = (name) => {
                if (!name) return '';
                try {
                    // Önce decode et, sonra normalize et
                    const decoded = decodeURIComponent(String(name));
                    return decoded.trim().toLowerCase();
                } catch (e) {
                    // Decode edilemezse direkt normalize et
                    return String(name).trim().toLowerCase();
                }
            };
            const normalizedFileName = normalizeFileName(fileName);
            
            // Dosyayı listeden kaldır (esnek eşleştirme: name, filename, originalname, path)
            const dosyaSayisiOnce = dosyalar.length;
            dosyalar = dosyalar.filter(dosya => {
                // Dosya objesi veya string olabilir
                const dosyaObj = typeof dosya === 'object' ? dosya : { name: dosya, filename: dosya, originalname: dosya };
                
                // Tüm olası alanları kontrol et (originalname, originalName, filename, name, adi, path)
                const dosyaOriginalName = dosyaObj.originalname || dosyaObj.originalName || '';
                const dosyaFileName = dosyaObj.filename || dosyaObj.name || '';
                const dosyaAdi = dosyaObj.adi || '';
                const dosyaPath = dosyaObj.path || '';
                const dosyaString = typeof dosya === 'string' ? dosya : '';
                
                // Tüm olası dosya adı varyasyonlarını kontrol et
                const dosyaAdlari = [
                    dosyaOriginalName,
                    dosyaFileName,
                    dosyaAdi,
                    dosyaPath.split('/').pop(), // Path'ten dosya adını çıkar
                    dosyaString
                ].filter(ad => ad && ad.trim() !== '');
                
                // Her bir dosya adı varyasyonunu kontrol et
                let eslesme = false;
                for (const dosyaAdiVaryasyon of dosyaAdlari) {
                    const normalizedDosyaAdi = normalizeFileName(dosyaAdiVaryasyon);
                    
                    // Tam eşleşme veya kısmi eşleşme kontrolü
                    if (normalizedDosyaAdi === normalizedFileName ||
                        normalizedDosyaAdi.includes(normalizedFileName) ||
                        normalizedFileName.includes(normalizedDosyaAdi) ||
                        dosyaAdiVaryasyon === fileName ||
                        dosyaAdiVaryasyon.includes(fileName) ||
                        fileName.includes(dosyaAdiVaryasyon)) {
                        eslesme = true;
                        break;
                    }
                }
                
                if (eslesme) {
                    dosyaBulundu = true;
                    console.log(`✅ Dosya listede bulundu ve kaldırılıyor: ${dosyaOriginalName || dosyaFileName || dosyaAdi || dosyaString}`);
                    return false; // Bu dosyayı listeden çıkar
                }
                return true; // Bu dosyayı tut
            });
            
            // Eğer dosya listede bulunduysa veya fiziksel dosya varsa, veritabanını güncelle
            if (dosyaBulundu || dosyalar.length < dosyaSayisiOnce) {
                const kullaniciAdi = await getCurrentUsername(req);
                await run(
                    'UPDATE musteriler SET musteri_urun_yazi_dosyalar = ?, updated_by = ? WHERE id = ? AND tenant_id = ?',
                    [JSON.stringify(dosyalar), kullaniciAdi, customerId, tenantId]
                );
                console.log(`✅ Veritabanı güncellendi, kalan dosya sayısı: ${dosyalar.length} (önceki: ${dosyaSayisiOnce})`);
            }
        } catch (dbError) {
            console.error('❌ Veritabanı güncelleme hatası:', dbError);
            // Hata olsa bile devam et, fiziksel dosyayı silmeye çalış
        }
        
        // Fiziksel dosyayı sil (varsa)
        const customerFolder = `${customerId}-${cleanUnvan}`;
        const urunYaziDir = getTenantUploadPath(tenantId, 'customers', customerFolder, 'urun_yazi_dosyalari');
        const filePath = path.join(urunYaziDir, fileName);
        
        // Dosya var mı kontrol et ve sil
        if (fs.existsSync(filePath)) {
            try {
                fs.unlinkSync(filePath);
                console.log(`✅ Fiziksel dosya silindi: ${filePath}`);
            } catch (unlinkError) {
                console.error('❌ Fiziksel dosya silme hatası:', unlinkError);
                // Fiziksel dosya silinemese bile, veritabanından kaldırıldıysa başarılı say
            }
        } else {
            console.log(`⚠️ Fiziksel dosya bulunamadı: ${filePath}, ama veritabanından kaldırıldı`);
            // Dosya fiziksel olarak yok ama veritabanından kaldırıldıysa, başarılı say (idempotent)
        }
        
        // Eğer dosya ne listede ne de fiziksel olarak bulunduysa, yine de başarı döndür (idempotent)
        if (!dosyaBulundu && !fs.existsSync(filePath)) {
            console.log(`⚠️ Dosya ne listede ne de fiziksel olarak bulunamadı: ${fileName}, idempotent olarak başarılı sayılıyor`);
        }
        
        // Aktivite kaydı oluştur
        let userId = null;
        if (req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id);
        }
        if (!userId) {
            userId = req.userId || req.user?.id || null;
        }
        const customerName = customerData.musteri_unvani || customerData.musteri_ad_soyad || `Müşteri #${customerId}`;
        await logTenantActivity(
            tenantId,
            userId,
            'Dosya silindi',
            'file',
            customerId,
            `${customerName} - ${fileName}`,
            {
                dosya_adi: fileName,
                musteri_id: customerId,
                musteri_adi: customerName
            },
            req
        );
        
        res.json({
            success: true,
            message: 'Dosya başarıyla silindi'
        });
    } catch (error) {
        console.error('❌ Müşteri dosyası silme hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Dosya silinemedi',
            message: error.message
        });
    }
});

app.get('/api/customers', async (req, res) => {
    try {
        // GÜVENLİK: Cookie kontrolü
        const cookieCheck = requireCookie(req, res);
        if (cookieCheck) return cookieCheck;
        
        // Tenant ID'yi al
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(401).json({ 
                success: false, 
                error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' 
            });
        }
        console.log(`🔍 /api/customers çağrıldı - Tenant ID: ${tenantId}`);
        
        // musteriler tablosu kolon isimleri migration (Türkçe/spesifik isimlere)
        try {
            const cols = await query('PRAGMA table_info(musteriler)', [], req);
            const colNames = cols.map(c => c.name);
            const rename = (oldName, newName) => {
                if (colNames.includes(oldName) && !colNames.includes(newName)) {
                    return run(`ALTER TABLE musteriler RENAME COLUMN ${oldName} TO ${newName}`).then(() => { colNames.push(newName); colNames.splice(colNames.indexOf(oldName), 1); });
                }
                return Promise.resolve();
            };
            await rename('musteri_no', 'musteri_kodu');
            await rename('musteri_unvan', 'musteri_unvani');
            await rename('musteri_isim_soyisim', 'musteri_ad_soyad');
            await rename('phone', 'musteri_telefon');
            await rename('email', 'musteri_eposta');
            await rename('address', 'musteri_acik_adres');
            await rename('neighborhood', 'musteri_mahalle');
            await rename('district', 'musteri_ilce');
            await rename('city', 'musteri_il');
            await rename('customer_type', 'musteri_tipi');
            await rename('vergi_kimlik_no', 'musteri_vergi_kimlik_numarasi');
            await rename('vergi_dairesi', 'musteri_vergi_dairesi');
            if (colNames.includes('logo_url')) {
                try { await run('ALTER TABLE musteriler DROP COLUMN logo_url'); } catch (e) { console.warn('⚠️ musteriler logo_url DROP:', e.message); }
            }
        } catch (migErr) {
            console.warn('⚠️ musteriler migration:', migErr.message);
        }
        
        const { search } = req.query;
        
        let customers;
        
        if (search) {
            // Arama parametresi varsa müşteri unvanı VEYA isim-soyisim ile ara (yeni kolon: musteri_unvani, musteri_ad_soyad)
            customers = await query(
                'SELECT * FROM musteriler WHERE is_active = 1 AND tenant_id = ? AND (musteri_unvani LIKE ? OR musteri_ad_soyad LIKE ?) ORDER BY id ASC',
                [tenantId, `%${search}%`, `%${search}%`],
                req
            );
        } else {
            // SADECE AKTİF müşterileri çek (is_active = 1) - Silinen müşteriler görünmemeli
            const activeCustomersQuery = 'SELECT * FROM musteriler WHERE is_active = 1 AND tenant_id = ? ORDER BY id ASC';
            console.log(`🔍 SQL Sorgusu: ${activeCustomersQuery}`);
            console.log(`🔍 Veritabanı dosya yolu: ${dbPath}`);
            
            // Önce COUNT ile kontrol et
            const totalCount = await query('SELECT COUNT(*) as total FROM musteriler WHERE is_active = 1 AND tenant_id = ?', [tenantId], req);
            console.log(`📊 Veritabanındaki aktif müşteri sayısı (COUNT): ${totalCount[0]?.total || 0}`);
            
            // Sadece aktif müşterileri çek
            customers = await query(activeCustomersQuery, [tenantId], req);
            console.log(`📊 SQL Sorgusu sonucu: ${customers.length} aktif müşteri döndü`);
            
            // ID'leri listele
            const customerIds = customers.map(c => c.id).sort((a, b) => a - b);
            console.log(`📋 Dönen aktif müşteri ID'leri: ${customerIds.join(', ')}`);
            
            if (customers.length !== (totalCount[0]?.total || 0)) {
                console.error(`❌ KRİTİK HATA: Sorgu ${customers.length} müşteri döndü ama veritabanında ${totalCount[0]?.total} aktif müşteri var!`);
                console.error(`❌ Eksik müşteri sayısı: ${(totalCount[0]?.total || 0) - customers.length}`);
                
                // Eksik ID'leri bul
                const allIds = await query('SELECT id FROM musteriler WHERE is_active = 1 AND tenant_id = ? ORDER BY id ASC', [tenantId], req);
                const allIdList = allIds.map(r => r.id).sort((a, b) => a - b);
                const missingIds = allIdList.filter(id => !customerIds.includes(id));
                if (missingIds.length > 0) {
                    console.error(`❌ Eksik aktif müşteri ID'leri: ${missingIds.join(', ')}`);
                }
            }
        }
        
        console.log(`📊 Toplam ${customers.length} aktif müşteri bulundu (is_active = 1)`);
        
        // Her müşteri için sipariş sayısını hesapla
        // Önce musteri_id kolonunun var olup olmadığını kontrol et
        let hasMusteriId = false;
        try {
            const columns = await query('PRAGMA table_info(siparisler)');
            const columnNames = columns.map(c => c.name);
            hasMusteriId = columnNames.includes('musteri_id');
        } catch (error) {
            // Tablo yoksa veya hata varsa devam et
            console.log('⚠️ siparisler tablosu kontrol edilemedi:', error.message);
        }
        
        const customersWithOrderCount = await Promise.all(customers.map(async (customer) => {
            try {
                let orderCount = 0;
                let bakiye = 0;
                
                // Debug: Müşteri bilgilerini logla
                console.log(`🔍 Müşteri ${customer.id} (${customer.musteri_unvani || customer.musteri_ad_soyad}): hasMusteriId=${hasMusteriId}`);
                
                // Sipariş sayısı ve toplam sipariş tutarını al - cari-ozet endpoint'i ile aynı mantık
                // ÖNEMLİ: Fatura kesilmiş siparişleri filtrele
                let toplamSiparis = 0;
                let faturaKesilmisSiparisIdleri = new Set();
                
                // Önce fatura kesilmiş sipariş ID'lerini al
                try {
                    const tableExists = await query(`
                        SELECT name FROM sqlite_master 
                        WHERE type='table' AND name='musteri_faturalar'
                    `);
                    
                    if (tableExists.length > 0) {
                        const columns = await query('PRAGMA table_info(musteri_faturalar)');
                        const columnNames = columns.map(c => c.name);
                        const hasTenantId = columnNames.includes('tenant_id');
                        
                        let faturalar = [];
                        if (hasTenantId) {
                            // Sadece iptal edilmemiş faturaları kontrol et
                            faturalar = await query(
                                'SELECT siparis_idler FROM musteri_faturalar WHERE musteri_id = ? AND tenant_id = ? AND (durum IS NULL OR LOWER(durum) != ?)',
                                [customer.id, tenantId, 'iptal'],
                                req
                            );
                        } else {
                            // Sadece iptal edilmemiş faturaları kontrol et
                            faturalar = await query(
                                'SELECT siparis_idler FROM musteri_faturalar WHERE musteri_id = ? AND (durum IS NULL OR LOWER(durum) != ?)',
                                [customer.id, 'iptal'],
                                req
                            );
                        }
                        
                        // Tüm fatura kesilmiş sipariş ID'lerini topla
                        faturalar.forEach(fatura => {
                            if (fatura.siparis_idler) {
                                const siparisIdler = fatura.siparis_idler.split(',').map(id => id.trim()).filter(Boolean);
                                siparisIdler.forEach(id => {
                                    faturaKesilmisSiparisIdleri.add(String(id));
                                    const numId = parseInt(id, 10);
                                    if (!isNaN(numId)) {
                                        faturaKesilmisSiparisIdleri.add(String(numId));
                                    }
                                });
                            }
                        });
                    }
                } catch (faturaError) {
                    // Fatura kontrolü hatası - devam et
                    console.log(`⚠️ Müşteri ${customer.id} için fatura kontrolü yapılamadı:`, faturaError.message);
                }
                
                if (hasMusteriId) {
                    // musteri_id varsa onu kullan (daha doğru ve performanslı)
                    try {
                        // SADECE musteri_id ile eşleşen siparişleri al (fallback sorgu kaldırıldı - yanlış eşleşmelere neden oluyordu)
                        let allSiparisler = await query(`
                            SELECT 
                                id,
                                siparis_tutari,
                                toplam_tutar
                            FROM siparisler
                            WHERE musteri_id = ? AND tenant_id = ? 
                            AND (is_active = 1 OR is_active IS NULL)
                        `, [customer.id, tenantId], req);
                        
                        // Fatura kesilmiş siparişleri filtrele
                        const filtrelenmisSiparisler = allSiparisler.filter(siparis => {
                            const siparisIdStr = String(siparis.id);
                            const siparisIdNum = String(parseInt(siparis.id, 10));
                            return !faturaKesilmisSiparisIdleri.has(siparisIdStr) && 
                                   !faturaKesilmisSiparisIdleri.has(siparisIdNum);
                        });
                        
                        orderCount = filtrelenmisSiparisler.length;
                        
                        // Toplam tutarı hesapla
                        filtrelenmisSiparisler.forEach(siparis => {
                            const tutar = siparis.siparis_tutari || siparis.toplam_tutar || 0;
                            toplamSiparis += Number(tutar) || 0;
                        });
                        
                        console.log(`  → Sorgu sonucu: ${orderCount} sipariş bulundu (${faturaKesilmisSiparisIdleri.size} fatura kesilmiş filtrelendi), toplam=${toplamSiparis}`);
                    } catch (error) {
                        // Hata durumunda sipariş sayısını 0 olarak ayarla
                        orderCount = 0;
                        toplamSiparis = 0;
                        console.log(`  → Sorgu hatası:`, error.message);
                    }
                } else {
                    // musteri_id kolonu yoksa sipariş sayısı 0
                    orderCount = 0;
                    toplamSiparis = 0;
                    console.log(`  → musteri_id kolonu yok, sipariş sayısı 0`);
                }
                
                // Bakiye hesaplama - cari-ozet endpoint'i ile aynı mantık
                // Sipariş sayısı 0 ise bakiye de 0
                if (orderCount === 0) {
                    bakiye = 0;
                } else {
                    // Sipariş varsa bakiye hesapla: Toplam alacak - Toplam tahsilat = Bakiye
                    let toplamAlacak = 0;
                    let toplamTahsilat = 0;
                    let toplamFatura = 0;
                    
                    try {
                        // Fatura toplamı (eğer musteri_faturalar tablosu varsa) - iptal edilmiş faturalar hariç
                        // ÖNEMLİ: genel_toplam kullan, tutar değil (tutar ara toplam, genel_toplam KDV dahil toplam)
                        try {
                            const faturalar = await query(`
                                SELECT COALESCE(SUM(CAST(genel_toplam AS REAL)), 0) as toplam
                                FROM musteri_faturalar
                                WHERE musteri_id = ? AND tenant_id = ?
                                    AND (durum IS NULL OR LOWER(durum) != 'iptal')
                            `, [customer.id, tenantId], req);
                            toplamFatura = faturalar[0]?.toplam || 0;
                        } catch (error) {
                            // Tablo yoksa veya hata varsa 0 kullan
                            console.log(`⚠️ Müşteri ${customer.id} için musteri_faturalar tablosu bulunamadı veya hata:`, error.message);
                        }
                        
                        // toplamAlacak hesaplaması - eğer sipariş sayısı 0 ise, toplam alacak da 0 olmalı
                        // Eğer sipariş sayısı 0 değilse: fatura varsa onu kullan, yoksa sipariş tutarını kullan
                        // ÖNEMLI: || operatörü 0 değerini falsy olarak görür, bu yüzden explicit kontrol gerekiyor
                        if (orderCount > 0) {
                            // Sipariş varsa fatura veya sipariş tutarını kullan
                            toplamAlacak = (toplamFatura && toplamFatura > 0) ? toplamFatura : (toplamSiparis || 0);
                        } else {
                            // Sipariş yoksa toplam alacak 0 olmalı (fatura olsa bile, eğer sipariş yoksa alacak yok)
                            toplamAlacak = 0;
                        }
                        
                        // Toplam tahsilat
                        try {
                            const tahsilatTableExists = await query(`
                                SELECT name FROM sqlite_master 
                                WHERE type='table' AND name='musteri_tahsilatlar'
                            `);
                            
                            if (tahsilatTableExists.length > 0) {
                                const columns = await query('PRAGMA table_info(musteri_tahsilatlar)');
                                const hasTenantId = columns.some(col => col.name === 'tenant_id');
                                
                                if (hasTenantId) {
                                    const tahsilatlar = await query(`
                                        SELECT COALESCE(SUM(CAST(tahsil_edilen_tutar AS REAL)), 0) as toplam
                                        FROM musteri_tahsilatlar
                                        WHERE musteri_id = ? AND tenant_id = ?
                                    `, [customer.id, tenantId], req);
                                    toplamTahsilat = tahsilatlar[0]?.toplam || 0;
                                } else {
                                    const tahsilatlar = await query(`
                                        SELECT COALESCE(SUM(CAST(tahsil_edilen_tutar AS REAL)), 0) as toplam
                                        FROM musteri_tahsilatlar
                                        WHERE musteri_id = ?
                                    `, [customer.id], req);
                                    toplamTahsilat = tahsilatlar[0]?.toplam || 0;
                                }
                            }
                        } catch (e) {
                            // Tahsilat tablosu yoksa veya hata varsa 0
                        }
                        
                        bakiye = toplamAlacak - toplamTahsilat;
                    } catch (bakiyeError) {
                        // Bakiye hesaplanamazsa 0
                        console.error(`❌ Müşteri ${customer.id} için bakiye hesaplanamadı:`, bakiyeError.message);
                        bakiye = 0;
                    }
                }
                
                // Debug: TÜM müşteriler için sipariş sayısı ve bakiye değerlerini logla
                console.log(`📊 Müşteri ${customer.id} (${customer.musteri_unvani || customer.musteri_ad_soyad}): Sipariş sayısı=${orderCount}, Bakiye=${bakiye}, hasMusteriId=${hasMusteriId}`);
                
                return {
                    ...customer,
                    order_count: orderCount,
                    bakiye: bakiye
                };
            } catch (error) {
                // Hata durumunda sipariş sayısını 0 olarak döndür
                console.error(`❌ Müşteri ${customer.id} için sipariş sayısı hesaplanamadı:`, error.message);
                return {
                    ...customer,
                    order_count: 0,
                    bakiye: 0
                };
            }
        }));
        
        console.log(`✅ İşlenen müşteri sayısı: ${customersWithOrderCount.length} (beklenen: ${customers.length})`);
        
        // Eğer müşteri sayısı eşleşmiyorsa uyar
        if (customersWithOrderCount.length !== customers.length) {
            console.error(`❌ KRİTİK HATA: Müşteri sayısı eşleşmiyor! Başlangıç: ${customers.length}, Son: ${customersWithOrderCount.length}`);
        }
        
        res.json({
            success: true,
            data: customersWithOrderCount,
            total: customersWithOrderCount.length
        });
    } catch (error) {
        console.error('❌ Müşteriler yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Veritabanı hatası'
        });
    }
});

// Müşteri oluştur (POST)
app.post('/api/customers', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        // getTenantId her zaman bir değer döndürür (fallback: 1), kontrol gereksiz
        
        const b = req.body;
        const musteri_unvani = b.musteri_unvani ?? b.musteri_unvan;
        const musteri_ad_soyad = b.musteri_ad_soyad ?? b.musteri_isim_soyisim;
        const musteri_telefon = b.musteri_telefon ?? b.phone;
        const musteri_eposta = b.musteri_eposta ?? b.email;
        const musteri_acik_adres = b.musteri_acik_adres ?? b.address;
        const musteri_mahalle = b.musteri_mahalle ?? b.neighborhood;
        const musteri_ilce = b.musteri_ilce ?? b.district;
        const musteri_il = b.musteri_il ?? b.city;
        const musteri_tipi = b.musteri_tipi ?? b.customer_type;
        const musteri_vergi_kimlik_numarasi = b.musteri_vergi_kimlik_numarasi ?? b.vergi_kimlik_no;
        const musteri_vergi_dairesi = b.musteri_vergi_dairesi ?? b.vergi_dairesi;
        const musteri_kodu = b.musteri_kodu ?? b.musteri_no;
        
        if (!musteri_unvani && !musteri_ad_soyad) {
            return res.status(400).json({
                success: false,
                error: 'Müşteri unvanı veya isim-soyisim gereklidir'
            });
        }
        
        // Müşteri numarası oluştur - en son müşteri numarasına bakarak artan numara ver
        let musteriKoduValue = musteri_kodu;
        if (!musteriKoduValue) {
            const existingCustomers = await query(
                `SELECT musteri_kodu FROM musteriler 
                 WHERE tenant_id = ? AND musteri_kodu IS NOT NULL AND musteri_kodu != ''`, 
                [tenantId], req
            );
            
            let maxNum = 0;
            if (existingCustomers.length > 0) {
                existingCustomers.forEach(customer => {
                    const kod = customer.musteri_kodu;
                    if (kod && kod.startsWith('MUS')) {
                        const numStr = kod.replace('MUS', '').replace(/^0+/, '') || '0';
                        const num = parseInt(numStr, 10) || 0;
                        if (num > maxNum) maxNum = num;
                    }
                });
            }
            const nextNum = maxNum + 1;
            musteriKoduValue = `MUS${String(nextNum).padStart(5, '0')}`;
            console.log('📊 Müşteri kodu oluşturuldu:', { maxNum, nextNum, musteriKoduValue, existingCount: existingCustomers.length });
        }
        
        console.log('📝 Yeni müşteri kaydediliyor:', { tenantId, musteri_unvani, musteri_ad_soyad, musteriKoduValue });
        const kullaniciAdi = await getCurrentUsername(req);
        const result = await run(`
            INSERT INTO musteriler (
                musteri_unvani, musteri_ad_soyad, musteri_telefon, musteri_eposta, musteri_acik_adres,
                musteri_mahalle, musteri_ilce, musteri_il, musteri_tipi, musteri_grubu,
                musteri_vergi_kimlik_numarasi, musteri_vergi_dairesi, musteri_urun_yazisi,
                tenant_id, is_active, created_at, updated_at, musteri_kodu, created_by, updated_by
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 1, ${getTurkeyTimeSQL()}, ${getTurkeyTimeSQL()}, ?, ?, ?)
        `, [
            musteri_unvani || null,
            musteri_ad_soyad || null,
            musteri_telefon || null,
            musteri_eposta || null,
            musteri_acik_adres || null,
            musteri_mahalle || null,
            musteri_ilce || null,
            musteri_il || null,
            musteri_tipi || 'bireysel',
            b.musteri_grubu || null,
            musteri_vergi_kimlik_numarasi || null,
            musteri_vergi_dairesi || null,
            b.musteri_urun_yazisi || null,
            tenantId,
            musteriKoduValue,
            kullaniciAdi,
            kullaniciAdi
        ]);
        
        console.log('✅ Müşteri veritabanına kaydedildi:', {
            lastID: result.lastID,
            changes: result.changes,
            tenantId
        });
        
        // Veritabanında gerçekten kaydedildiğini doğrula
        const newCustomer = await query('SELECT * FROM musteriler WHERE id = ? AND tenant_id = ?', [result.lastID, tenantId]);
        
        if (!newCustomer || newCustomer.length === 0) {
            console.error('❌ Müşteri kaydedildi ama veritabanında bulunamadı!', {
                lastID: result.lastID,
                tenantId
            });
            return res.status(500).json({
                success: false,
                error: 'Müşteri kaydedildi ama doğrulanamadı',
                message: 'Veritabanı hatası'
            });
        }
        
        console.log('✅ Müşteri doğrulandı:', {
            id: newCustomer[0].id,
            musteri_unvani: newCustomer[0].musteri_unvani,
            tenant_id: newCustomer[0].tenant_id
        });
        
        // Aktivite kaydı oluştur
        let userId = null;
        if (req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id);
        }
        if (!userId) {
            userId = req.userId || req.user?.id || null;
        }
        const targetName = newCustomer[0].musteri_unvani || newCustomer[0].musteri_ad_soyad || `Müşteri #${result.lastID}`;
        await logTenantActivity(
            tenantId,
            userId,
            'Yeni müşteri oluşturuldu',
            'musteri',
            result.lastID,
            targetName,
            {
                musteri_unvani: newCustomer[0].musteri_unvani || null,
                musteri_ad_soyad: newCustomer[0].musteri_ad_soyad || null,
                musteri_telefon: newCustomer[0].musteri_telefon || null,
                musteri_eposta: newCustomer[0].musteri_eposta || null,
                musteri_kodu: newCustomer[0].musteri_kodu || null
            },
            req
        );
        
        res.json({
            success: true,
            message: 'Müşteri başarıyla oluşturuldu',
            customer: newCustomer[0],
            id: result.lastID
        });
    } catch (error) {
        console.error('❌ Müşteri oluşturulurken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Müşteri oluşturulamadı',
            message: error.message
        });
    }
});

// Müşteri güncelleme endpoint'i
app.put('/api/customers/:id', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        const { id } = req.params;
        const b = req.body;
        const existingCustomer = await query(
            'SELECT * FROM musteriler WHERE id = ? AND tenant_id = ?',
            [id, tenantId],
            req
        );
        
        if (!existingCustomer || existingCustomer.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Müşteri bulunamadı veya bu müşteriye erişim yetkiniz yok'
            });
        }
        
        const e = existingCustomer[0];
        const musteri_unvani = b.musteri_unvani !== undefined ? b.musteri_unvani : (b.musteri_unvan !== undefined ? b.musteri_unvan : e.musteri_unvani);
        const musteri_ad_soyad = b.musteri_ad_soyad !== undefined ? b.musteri_ad_soyad : (b.musteri_isim_soyisim !== undefined ? b.musteri_isim_soyisim : e.musteri_ad_soyad);
        const musteri_telefon = b.musteri_telefon !== undefined ? b.musteri_telefon : (b.phone !== undefined ? b.phone : e.musteri_telefon);
        const musteri_eposta = b.musteri_eposta !== undefined ? b.musteri_eposta : (b.email !== undefined ? b.email : e.musteri_eposta);
        const musteri_acik_adres = b.musteri_acik_adres !== undefined ? b.musteri_acik_adres : (b.address !== undefined ? b.address : e.musteri_acik_adres);
        const musteri_mahalle = b.musteri_mahalle !== undefined ? b.musteri_mahalle : (b.neighborhood !== undefined ? b.neighborhood : e.musteri_mahalle);
        const musteri_ilce = b.musteri_ilce !== undefined ? b.musteri_ilce : (b.district !== undefined ? b.district : e.musteri_ilce);
        const musteri_il = b.musteri_il !== undefined ? b.musteri_il : (b.city !== undefined ? b.city : e.musteri_il);
        const musteri_tipi = b.musteri_tipi !== undefined ? b.musteri_tipi : (b.customer_type !== undefined ? b.customer_type : e.musteri_tipi);
        const musteri_vergi_kimlik_numarasi = b.musteri_vergi_kimlik_numarasi !== undefined ? b.musteri_vergi_kimlik_numarasi : (b.vergi_kimlik_no !== undefined ? b.vergi_kimlik_no : e.musteri_vergi_kimlik_numarasi);
        const musteri_vergi_dairesi = b.musteri_vergi_dairesi !== undefined ? b.musteri_vergi_dairesi : (b.vergi_dairesi !== undefined ? b.vergi_dairesi : e.musteri_vergi_dairesi);
        const musteri_kodu = b.musteri_kodu !== undefined ? b.musteri_kodu : (b.musteri_no !== undefined ? b.musteri_no : e.musteri_kodu);
        
        const kullaniciAdi = await getCurrentUsername(req);
        const result = await run(`
            UPDATE musteriler SET
                musteri_unvani = ?,
                musteri_ad_soyad = ?,
                musteri_telefon = ?,
                musteri_eposta = ?,
                musteri_acik_adres = ?,
                musteri_mahalle = ?,
                musteri_ilce = ?,
                musteri_il = ?,
                musteri_tipi = ?,
                musteri_grubu = ?,
                musteri_vergi_kimlik_numarasi = ?,
                musteri_vergi_dairesi = ?,
                musteri_urun_yazisi = ?,
                musteri_kodu = ?,
                updated_at = ${getTurkeyTimeSQL()},
                updated_by = ?
            WHERE id = ? AND tenant_id = ?
        `, [
            musteri_unvani,
            musteri_ad_soyad,
            musteri_telefon,
            musteri_eposta,
            musteri_acik_adres,
            musteri_mahalle,
            musteri_ilce,
            musteri_il,
            musteri_tipi,
            b.musteri_grubu !== undefined ? b.musteri_grubu : e.musteri_grubu,
            musteri_vergi_kimlik_numarasi,
            musteri_vergi_dairesi,
            b.musteri_urun_yazisi !== undefined ? b.musteri_urun_yazisi : e.musteri_urun_yazisi,
            musteri_kodu,
            kullaniciAdi,
            id,
            tenantId
        ]);
        
        if (result.changes === 0) {
            return res.status(404).json({
                success: false,
                error: 'Müşteri güncellenemedi'
            });
        }
        
        const updatedCustomer = await query(
            'SELECT * FROM musteriler WHERE id = ? AND tenant_id = ?',
            [id, tenantId],
            req
        );
        
        let userId = null;
        if (req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id);
        }
        if (!userId) {
            userId = req.userId || req.user?.id || null;
        }
        const targetName = updatedCustomer[0].musteri_unvani || updatedCustomer[0].musteri_ad_soyad || `Müşteri #${id}`;
        await logTenantActivity(
            tenantId,
            userId,
            'Müşteri güncellendi',
            'musteri',
            id,
            targetName,
            {
                musteri_unvani: updatedCustomer[0].musteri_unvani || null,
                musteri_ad_soyad: updatedCustomer[0].musteri_ad_soyad || null,
                musteri_telefon: updatedCustomer[0].musteri_telefon || null,
                musteri_eposta: updatedCustomer[0].musteri_eposta || null
            },
            req
        );
        
        res.json({
            success: true,
            message: 'Müşteri başarıyla güncellendi',
            customer: updatedCustomer[0]
        });
    } catch (error) {
        console.error('❌ Müşteri güncellenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Müşteri güncellenemedi',
            message: error.message
        });
    }
});

// Müşteri sil (soft delete - is_active = 0)
app.delete('/api/customers/:id', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        const { id } = req.params;
        
        if (!tenantId) {
            return res.status(400).json({ 
                success: false, 
                error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' 
            });
        }
        
        // Müşterinin var olup olmadığını ve tenant'a ait olduğunu kontrol et
        const existingCustomer = await query(
            'SELECT * FROM musteriler WHERE id = ? AND tenant_id = ?',
            [id, tenantId]
        );
        
        if (!existingCustomer || existingCustomer.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Müşteri bulunamadı veya bu müşteriye erişim yetkiniz yok'
            });
        }
        
        // Soft delete - is_active = 0 yap
        const kullaniciAdi = await getCurrentUsername(req);
        const result = await run(
            'UPDATE musteriler SET is_active = 0, updated_at = datetime(\'now\'), updated_by = ? WHERE id = ? AND tenant_id = ?',
            [kullaniciAdi, id, tenantId]
        );
        
        if (result.changes === 0) {
            return res.status(404).json({
                success: false,
                error: 'Müşteri silinemedi'
            });
        }
        
        // Aktivite kaydı oluştur
        let userId = null;
        if (req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id);
        }
        if (!userId) {
            userId = req.userId || req.user?.id || null;
        }
        const targetName = existingCustomer[0].musteri_unvani || existingCustomer[0].musteri_ad_soyad || `Müşteri #${id}`;
        await logTenantActivity(
            tenantId,
            userId,
            'Müşteri silindi',
            'musteri',
            id,
            targetName,
            {
                musteri_unvani: existingCustomer[0].musteri_unvani || null,
                musteri_ad_soyad: existingCustomer[0].musteri_ad_soyad || null,
                musteri_telefon: existingCustomer[0].musteri_telefon || null,
                musteri_eposta: existingCustomer[0].musteri_eposta || null
            },
            req
        );
        
        console.log(`✅ Müşteri soft delete yapıldı: ID ${id}, Tenant ${tenantId}`);
        
        res.json({
            success: true,
            message: 'Müşteri başarıyla silindi',
            customerId: id
        });
    } catch (error) {
        console.error('❌ Müşteri silinirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Müşteri silinemedi',
            message: error.message
        });
    }
});

// Teknik destek formu gönderimi
app.post('/api/teknik-destek', async (req, res) => {
    try {
        const { konu, mesaj, email, telefon, oncelik } = req.body;
        
        if (!konu || !mesaj || !email) {
            return res.status(400).json({
                success: false,
                error: 'Konu, mesaj ve e-posta adresi zorunludur'
            });
        }
        
        // Kullanıcı bilgisini al (eğer varsa)
        let kullaniciAdi = await getCurrentUsername(req);
        
        // Eğer varsayılan 'akifbircan' döndüyse, email'den kullanıcıyı bul
        if (kullaniciAdi === 'akifbircan') {
            try {
                // Önce users tablosunda email ile kullanıcıyı bul
                const user = await query(
                    'SELECT kullaniciadi, username, name FROM tenants_kullanicilar WHERE email = ? AND is_active = 1 LIMIT 1',
                    [email],
                    null
                );
                
                if (user && user[0]) {
                    kullaniciAdi = user[0].kullaniciadi || user[0].username || null;
                } else {
                    // users tablosunda yoksa admin_kullanicilar tablosunda kontrol et
                    const adminUser = await query(
                        'SELECT kullaniciadi FROM admin_kullanicilar WHERE email = ? LIMIT 1',
                        [email],
                        null
                    );
                    
                    if (adminUser && adminUser[0]) {
                        kullaniciAdi = adminUser[0].kullaniciadi || null;
                    }
                }
            } catch (userError) {
                console.warn('⚠️ Kullanıcı adı bulunamadı:', userError);
            }
        }
        
        // Eğer hala kullanıcı adı bulunamadıysa, email'in @ öncesi kısmını kullan
        if (!kullaniciAdi || kullaniciAdi === 'akifbircan') {
            kullaniciAdi = email.split('@')[0] || 'Bilinmeyen Kullanıcı';
        }
        
        // Öncelik değerini Türkçe'ye çevir
        let oncelikTurkce = oncelik || 'Normal';
        const oncelikMap = {
            'high': 'Yüksek',
            'normal': 'Normal',
            'urgent': 'Acil',
            'Yüksek': 'Yüksek',
            'Normal': 'Normal',
            'Acil': 'Acil'
        };
        oncelikTurkce = oncelikMap[oncelik] || oncelik || 'Normal';
        
        await run(`
            INSERT INTO teknik_destek_kayitlari (konu, mesaj, email, telefon, oncelik, created_by, updated_by, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ${getTurkeyTimeSQL()}, ${getTurkeyTimeSQL()})
        `, [konu, mesaj, email, telefon || null, oncelikTurkce, kullaniciAdi, kullaniciAdi]);
        
        console.log('✅ Teknik destek talebi kaydedildi:', { konu, email, kullaniciAdi, oncelik: oncelikTurkce });
        
        // Mail gönder
        const mailGonderildi = await sendTeknikDestekMail({
            konu,
            mesaj,
            email,
            telefon: telefon || null,
            oncelik: oncelikTurkce,
            kullaniciAdi
        });
        
        if (!mailGonderildi) {
            console.error('❌ Mail gönderilemedi - Mail Service durumunu kontrol edin!');
            console.error('❌ SMTP_USER ve SMTP_PASS environment variable\'larının ayarlı olduğundan emin olun');
            // Hata olmasına rağmen başarılı dönüyoruz çünkü talep veritabanına kaydedildi
            // Ancak log'da uyarı veriyoruz
        } else {
            console.log('✅ Teknik destek maili başarıyla gönderildi');
        }
        
        res.json({
            success: true,
            message: 'Teknik destek talebiniz başarıyla gönderildi'
        });
    } catch (error) {
        console.error('❌ Teknik destek talebi gönderme hatası:', error);
        console.error('❌ Hata detayları:', {
            message: error.message,
            stack: error.stack,
            name: error.name
        });
        res.status(500).json({
            success: false,
            error: error.message || 'Teknik destek talebi gönderilemedi',
            details: process.env.NODE_ENV === 'development' ? error.stack : undefined
        });
    }
});

// TÜM müşterileri getir (aktif ve pasif - is_active kontrolü yok)
app.get('/api/customers/all', async (req, res) => {
    try {
        // Tenant ID'yi al
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        console.log(`🔍 /api/customers/all çağrıldı - Tenant ID: ${tenantId}`);
        
        const { search } = req.query;
        
        let customers;
        
        if (search) {
            // Arama parametresi varsa müşteri unvanı VEYA isim-soyisim ile ara (tüm müşteriler)
            customers = await query(
                'SELECT * FROM musteriler WHERE tenant_id = ? AND (musteri_unvan LIKE ? OR musteri_isim_soyisim LIKE ?) ORDER BY id ASC',
                [tenantId, `%${search}%`, `%${search}%`],
                req
            );
        } else {
            // Gerçek veritabanından TÜM müşterileri çek (aktif ve pasif) - tenant_id ile filtrele
            customers = await query('SELECT * FROM musteriler WHERE tenant_id = ? ORDER BY id ASC', [tenantId], req);
        }
        
        // Her müşteri için sipariş sayısını hesapla
        const customersWithOrderCount = await Promise.all(customers.map(async (customer) => {
            try {
                // Müşteri için sipariş sayısını hesapla
                const siparisSayisi = await query(
                    'SELECT COUNT(*) as count FROM siparisler WHERE musteri_id = ? AND tenant_id = ?',
                    [customer.id, tenantId],
                    req
                );
                return {
                    ...customer,
                    order_count: siparisSayisi[0]?.count || 0
                };
            } catch (error) {
                console.error(`❌ Müşteri ${customer.id} için sipariş sayısı hesaplanamadı:`, error);
                return {
                    ...customer,
                    order_count: 0
                };
            }
        }));
        
        res.json({
            success: true,
            data: customersWithOrderCount,
            total: customersWithOrderCount.length
        });
    } catch (error) {
        console.error('❌ Tüm müşteriler yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Veritabanı hatası'
        });
    }
});

// Tenants endpoint - Tüm tenant'ları listele
app.get('/api/tenants', async (req, res) => {
    try {
        // Users tablosundan unique tenant_id'leri al ve her tenant için bir kayıt oluştur
        const tenants = await query(`
            SELECT DISTINCT 
                COALESCE(u.tenant_id, 1) as id,
                COALESCE(u.tenant_id, 1) as tenant_id,
                'Tenant ' || COALESCE(u.tenant_id, 1) as name
            FROM tenants_kullanicilar u
            WHERE u.tenant_id IS NOT NULL
            ORDER BY u.tenant_id ASC
        `);
        
        // Eğer hiç tenant yoksa, varsayılan tenant'ı ekle
        if (tenants.length === 0) {
            tenants.push({
                id: 1,
                tenant_id: 1,
                name: 'Tenant 1'
            });
        }
        
        res.json({
            success: true,
            data: tenants
        });
    } catch (error) {
        console.error('❌ Tenant listesi yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Veritabanı hatası'
        });
    }
});

// Yazdırma ayarları endpoint (tenantId yoksa varsayılan döndür – giriş yapılmamış sayfada 400 vermeyelim)
app.get('/api/ayarlar/yazdirma', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req).catch(() => null);
        
        if (!tenantId) {
            return res.json({
                success: true,
                data: { id: 1, logo_png_path: null, logo_png_url: null, is_active: 1 }
            });
        }
        
        // ayarlar_genel_yazdirma_ayarlari tablosunu kontrol et
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='ayarlar_genel_yazdirma_ayarlari'
        `);
        
        if (!tableExists || !Array.isArray(tableExists) || tableExists.length === 0) {
            // Tablo yoksa varsayılan ayarları döndür
            return res.json({
                success: true,
                data: {
                    id: 1,
                    logo_png_path: null,
                    logo_png_url: null,
                    is_active: 1
                }
            });
        }
        
        // tenant_id kolonunu kontrol et
        const columns = await query('PRAGMA table_info(ayarlar_genel_yazdirma_ayarlari)');
        const hasTenantId = columns.some(col => col.name === 'tenant_id');
        
        let settings;
        if (hasTenantId) {
            // SADECE tenant_id ile eşleşen kaydı getir (NULL kontrolü yok)
            settings = await query(
                'SELECT * FROM ayarlar_genel_yazdirma_ayarlari WHERE tenant_id = ? LIMIT 1',
                [tenantId]
            );
        } else {
            settings = await query('SELECT * FROM ayarlar_genel_yazdirma_ayarlari WHERE id = 1');
        }
        
        if (!settings || !Array.isArray(settings) || settings.length === 0) {
            // Varsayılan ayarları döndür (oluşturma)
            return res.json({
                success: true,
                data: {
                    id: 1,
                    logo_png_path: null,
                    logo_png_url: null,
                    is_active: 1
                }
            });
        }
        
        const setting = settings[0] || {};
        let logoUrl = null;
        
        if (setting.logo_png_path) {
            let cleanPath = setting.logo_png_path;
            console.log('🔍 Logo path düzeltme öncesi:', cleanPath);
            
            // Tüm yazdirma referanslarını kaldır ve print-settings'e çevir
            // Önce en spesifik pattern'leri kontrol et (global replace kullan)
            if (cleanPath.includes('yazdirma')) {
                // /uploads/yazdirma/uploads/print-settings/... -> /uploads/print-settings/...
                cleanPath = cleanPath.replace(/\/uploads\/yazdirma\/uploads\/print-settings\//g, '/uploads/print-settings/');
                // /uploads/yazdirma/uploads/... -> /uploads/print-settings/...
                cleanPath = cleanPath.replace(/\/uploads\/yazdirma\/uploads\//g, '/uploads/print-settings/');
                // /uploads/yazdirma/... -> /uploads/print-settings/... (global replace)
                cleanPath = cleanPath.replace(/\/uploads\/yazdirma\//g, '/uploads/print-settings/');
                // yazdirma/uploads/... -> print-settings/...
                cleanPath = cleanPath.replace(/yazdirma\/uploads\//g, 'print-settings/');
                // yazdirma/... -> print-settings/... (global replace)
                cleanPath = cleanPath.replace(/yazdirma\//g, 'print-settings/');
                // yazdirma kelimesini tamamen kaldır (eğer hala varsa)
                cleanPath = cleanPath.replace(/yazdirma/g, 'print-settings');
            }
            
            // Eski /uploads/print-settings/ path'lerini tenant-based yapıya çevir
            if (cleanPath.includes('/uploads/print-settings/') && !cleanPath.includes('/uploads/tenants/')) {
                const fileName = cleanPath.split('/uploads/print-settings/')[1] || cleanPath.split('print-settings/')[1];
                cleanPath = getTenantRelativePath(tenantId, 'print-settings', fileName);
                console.log('✅ Logo path tenant-based yapıya çevrildi:', cleanPath);
            }
            
            // Çift uploads sorununu düzelt (tüm varyasyonlar - global replace)
            cleanPath = cleanPath.replace(/\/uploads\/print-settings\/uploads\//g, '/uploads/print-settings/');
            cleanPath = cleanPath.replace(/\/uploads\/uploads\//g, '/uploads/');
            // Çift print-settings sorununu düzelt (global replace)
            cleanPath = cleanPath.replace(/\/print-settings\/print-settings\//g, '/print-settings/');
            
            console.log('✅ Logo path düzeltme sonrası:', cleanPath);
            
            // Relative path kullan - absolute URL üretme
            logoUrl = buildUploadUrl(cleanPath);
        }
        
        // İşletme bilgileri (yazdırma footer için): ayarlar_genel_isletme_ayarlari tablosundan
        let company_address = '';
        let company_phone = '';
        let company_email = '';
        let company_web = '';
        let company_il = '';
        let company_ilce = '';
        try {
            const isletmeTableExists = await query(`SELECT name FROM sqlite_master WHERE type='table' AND name='ayarlar_genel_isletme_ayarlari'`);
            if (isletmeTableExists.length > 0) {
                let isletmeRow = await query('SELECT adres, il, ilce, telefon, eposta, website FROM ayarlar_genel_isletme_ayarlari WHERE tenant_id = ? LIMIT 1', [tenantId]);
                if (!isletmeRow || isletmeRow.length === 0) {
                    isletmeRow = await query('SELECT adres, il, ilce, telefon, eposta, website FROM ayarlar_genel_isletme_ayarlari WHERE tenant_id IS NULL LIMIT 1');
                }
                if (isletmeRow && isletmeRow[0]) {
                    const t = isletmeRow[0];
                    company_address = t.adres ? String(t.adres).trim() : '';
                    company_phone = t.telefon ? String(t.telefon).trim() : '';
                    company_email = t.eposta ? String(t.eposta).trim() : '';
                    company_web = t.website ? String(t.website).trim() : '';
                    company_il = (t.il != null && t.il !== '') ? String(t.il).trim() : '';
                    company_ilce = (t.ilce != null && t.ilce !== '') ? String(t.ilce).trim() : '';
                }
            }
        } catch (e) {
            // ignore
        }
        res.json({
            success: true,
            data: {
                ...setting,
                logo_png_url: logoUrl,
                company_address: company_address || '',
                company_il: company_il || '',
                company_ilce: company_ilce || '',
                company_phone: company_phone || '',
                company_email: company_email || '',
                company_web: company_web || ''
            }
        });
    } catch (error) {
        console.error('❌ Yazdırma ayarları yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Yazdırma ayarları yüklenemedi',
            message: error.message
        });
    }
});

// Yazdırma ayarları güncelleme endpoint (PUT)
app.put('/api/ayarlar/yazdirma', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const { logo_png_path, is_active } = req.body;
        
        console.log('🔍 Yazdırma ayarları güncelleniyor, tenantId:', tenantId);
        console.log('📋 Gelen veri:', { logo_png_path, is_active });
        
        // Tablo kontrolü
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='ayarlar_genel_yazdirma_ayarlari'
        `);
        
        if (tableExists.length === 0) {
            console.log('⚠️ Tablo yok, oluşturuluyor...');
            await initializeYazdirmaAyarlar();
            console.log('✅ Tablo oluşturuldu');
        }
        
        // tenant_id kolonunu kontrol et
        const columns = await query('PRAGMA table_info(ayarlar_genel_yazdirma_ayarlari)');
        const hasTenantId = columns.some(col => col.name === 'tenant_id');
        
        let result;
        if (hasTenantId) {
            // Mevcut kaydı bul (SADECE tenant_id ile eşleşen)
            const existing = await query(
                'SELECT id FROM ayarlar_genel_yazdirma_ayarlari WHERE tenant_id = ? LIMIT 1',
                [tenantId]
            );
            
            if (existing.length > 0) {
                // Mevcut kaydı güncelle – logo_png_path gönderilmediyse mevcut değeri koru
                const current = await query('SELECT logo_png_path, is_active FROM ayarlar_genel_yazdirma_ayarlari WHERE tenant_id = ? LIMIT 1', [tenantId]);
                const newLogoPath = logo_png_path === undefined && current[0]?.logo_png_path ? current[0].logo_png_path : (logo_png_path || null);
                const newIsActive = is_active !== undefined ? (is_active ? 1 : 0) : (current[0]?.is_active ?? 1);
                console.log('✅ Mevcut kayıt güncelleniyor, ID:', existing[0].id, 'Tenant ID:', tenantId);
                const kullaniciAdi = await getCurrentUsername(req);
                await run(
                    'UPDATE ayarlar_genel_yazdirma_ayarlari SET logo_png_path = ?, is_active = ?, updated_at = CURRENT_TIMESTAMP, updated_by = ? WHERE tenant_id = ?',
                    [newLogoPath, newIsActive, kullaniciAdi, tenantId]
                );
                result = await query('SELECT * FROM ayarlar_genel_yazdirma_ayarlari WHERE tenant_id = ?', [tenantId]);
            } else {
                // Yeni kayıt oluştur (id otomatik artacak)
                console.log('⚠️ Mevcut kayıt yok, yeni kayıt oluşturuluyor, Tenant ID:', tenantId);
                try {
                    const kullaniciAdi = await getCurrentUsername(req);
                    const insertResult = await run(
                        'INSERT INTO ayarlar_genel_yazdirma_ayarlari (logo_png_path, is_active, tenant_id, created_at, updated_at, created_by, updated_by) VALUES (?, ?, ?, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, ?, ?)',
                        [logo_png_path || null, is_active ? 1 : 0, tenantId, kullaniciAdi, kullaniciAdi]
                    );
                    // Yeni eklenen kaydı getir (lastID kullan)
                    result = await query('SELECT * FROM ayarlar_genel_yazdirma_ayarlari WHERE tenant_id = ?', [tenantId]);
                    console.log('✅ Yeni yazdırma ayarları kaydı oluşturuldu, Tenant ID:', tenantId);
                } catch (insertError) {
                    console.error('❌ INSERT hatası:', insertError);
                    throw insertError;
                }
            }
        } else {
            // tenant_id kolonu yoksa eski yöntem
            const existing = await query('SELECT id, logo_png_path, is_active FROM ayarlar_genel_yazdirma_ayarlari WHERE id = 1');
            if (existing.length > 0) {
                const current = existing[0];
                const newLogoPath = logo_png_path === undefined ? (current.logo_png_path || null) : (logo_png_path || null);
                const newIsActive = is_active !== undefined ? (is_active ? 1 : 0) : (current.is_active ?? 1);
                const kullaniciAdi = await getCurrentUsername(req);
                await run(
                    'UPDATE ayarlar_genel_yazdirma_ayarlari SET logo_png_path = ?, is_active = ?, updated_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = 1',
                    [newLogoPath, newIsActive, kullaniciAdi]
                );
                result = await query('SELECT * FROM ayarlar_genel_yazdirma_ayarlari WHERE id = 1');
            } else {
                const kullaniciAdi = await getCurrentUsername(req);
                await run(
                    'INSERT INTO ayarlar_genel_yazdirma_ayarlari (id, logo_png_path, is_active, created_at, updated_at, created_by, updated_by) VALUES (1, ?, ?, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, ?, ?)',
                    [logo_png_path || null, is_active ? 1 : 0, kullaniciAdi, kullaniciAdi]
                );
                result = await query('SELECT * FROM ayarlar_genel_yazdirma_ayarlari WHERE id = 1');
            }
        }
        
        // Logo URL'ini oluştur
        let logoUrl = null;
        if (result[0]?.logo_png_path) {
            let cleanPath = result[0].logo_png_path;
            
            // Path düzeltmeleri (GET endpoint'teki gibi)
            if (cleanPath.includes('yazdirma')) {
                cleanPath = cleanPath.replace(/\/uploads\/yazdirma\/uploads\/print-settings\//g, '/uploads/print-settings/');
                cleanPath = cleanPath.replace(/\/uploads\/yazdirma\/uploads\//g, '/uploads/print-settings/');
                cleanPath = cleanPath.replace(/\/uploads\/yazdirma\//g, '/uploads/print-settings/');
                cleanPath = cleanPath.replace(/yazdirma\/uploads\//g, 'print-settings/');
                cleanPath = cleanPath.replace(/yazdirma\//g, 'print-settings/');
                cleanPath = cleanPath.replace(/yazdirma/g, 'print-settings');
            }
            
            cleanPath = cleanPath.replace(/\/uploads\/print-settings\/uploads\//g, '/uploads/print-settings/');
            cleanPath = cleanPath.replace(/\/uploads\/uploads\//g, '/uploads/');
            cleanPath = cleanPath.replace(/\/print-settings\/print-settings\//g, '/print-settings/');
            
            // Relative path kullan - absolute URL üretme
            logoUrl = buildUploadUrl(cleanPath);
        }
        
        console.log('✅ Yazdırma ayarları güncellendi');
        res.json({
            success: true,
            data: {
                ...result[0],
                logo_png_url: logoUrl
            }
        });
    } catch (error) {
        console.error('❌ Yazdırma ayarları güncellenirken hata:', error);
        console.error('❌ Hata stack:', error.stack);
        res.status(500).json({
            success: false,
            error: 'Yazdırma ayarları güncellenemedi',
            message: error.message,
            stack: error.stack
        });
    }
});

