// Organizasyon grupları endpoint
// Organizasyon grupları handler fonksiyonu (hem /api/organizasyon-gruplari hem de /api/ayarlar/organizasyon-gruplari için)
async function handleOrganizasyonGruplari(req, res) {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        // Tenant ID yoksa boş array döndür (400 yerine 200)
        if (!tenantId) {
            return res.json({
                success: true,
                data: [],
                count: 0
            });
        }
        
        // organizasyon_turleri tablosunu kontrol et
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='organizasyon_turleri'
        `);
        
        if (tableExists.length === 0) {
            return res.json({
                success: true,
                data: [],
                count: 0
            });
        }
        
        // organizasyon_turleri tablosundan veri çek
        let groups = [];
        try {
            const columns = await query('PRAGMA table_info(organizasyon_turleri)');
            const columnNames = columns.map(c => c.name);
            
            let querySql = 'SELECT * FROM organizasyon_turleri WHERE 1=1';
            const params = [];
            
            if (columnNames.includes('tenant_id')) {
                querySql += ' AND tenant_id = ?';
                params.push(tenantId);
            }
            
            if (columnNames.includes('is_active')) {
                querySql += ' AND (is_active = 1 OR is_active IS NULL)';
            } else if (columnNames.includes('durum')) {
                querySql += ' AND (durum = 1 OR durum IS NULL)';
            }
            
            if (columnNames.includes('grup_adi')) {
                querySql += ' ORDER BY grup_adi';
            } else {
                querySql += ' ORDER BY id';
            }
            
            groups = await query(querySql, params);
            
            // Frontend'in beklediği formata dönüştür
            groups = groups.map(group => ({
                ...group,
                grup_adi: group.grup_adi || group.tur_adi || group.name || '',
                tur_adi: group.grup_adi || group.tur_adi || group.name || ''
            }));
        } catch (queryError) {
            console.error('❌ Organizasyon grupları sorgu hatası:', queryError);
            groups = [];
        }
        
        res.json({
            success: true,
            data: groups || [],
            count: groups ? groups.length : 0
        });
    } catch (error) {
        console.error('❌ Organizasyon grupları yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Organizasyon grupları yüklenemedi',
            message: error.message
        });
    }
}

app.get('/api/organizasyon-gruplari', handleOrganizasyonGruplari);

// Frontend uyumluluğu için alias endpoint
app.get('/api/ayarlar/organizasyon-gruplari', handleOrganizasyonGruplari);

