        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // Tenant kontrolü ile organizasyon grubunu getir
        const columns = await query('PRAGMA table_info(organizasyon_turleri)');
        const columnNames = columns.map(c => c.name);
        
        let querySql = 'SELECT * FROM organizasyon_turleri WHERE id = ?';
        const params = [id];
        
        if (columnNames.includes('tenant_id')) {
            querySql += ' AND tenant_id = ?';
            params.push(tenantId);
        }
        
        const grup = await query(querySql, params);
        
        if (grup.length === 0) {
            return res.status(404).json({ success: false, error: 'Organizasyon grubu bulunamadı veya yetkiniz yok' });
        }
        
        res.json({ success: true, data: grup[0] });
