        const tableExists = await query(`SELECT name FROM sqlite_master WHERE type='table' AND name='ayarlar_genel_isletme_ayarlari'`);
        if (tableExists.length === 0) {
            return res.status(500).json({ success: false, error: 'İşletme ayarları tablosu bulunamadı.' });
        }
        const cols = await query('PRAGMA table_info(ayarlar_genel_isletme_ayarlari)');
        const hasLogoPath = cols.some(c => c.name === 'logo_path');
        const logoPathInBody = Object.prototype.hasOwnProperty.call(req.body, 'logo_path');
