// ---------- Çiçek Sepeti: sipariş kaydet (test/onay akışı) ----------
// Tablo: organizasyon_siparisler_ciceksepeti (eski adı ciceksepeti_orders)
app.post('/api/ciceksepeti/test-order', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı.' });
        const body = req.body || {};
        const siparis_no = body.siparis_no || null;
        if (!siparis_no) return res.status(400).json({ success: false, error: 'siparis_no gerekli.' });
        const existing = await query(
            'SELECT id FROM organizasyon_siparisler_ciceksepeti WHERE tenant_id = ? AND siparis_no = ? LIMIT 1',
            [tenantId, siparis_no]
        );
        if (existing && existing.length > 0) {
            res.status(201).json({ success: true, message: 'Sipariş zaten kayıtlı.' });
            return;
        }
        const siparis_veren = body.siparis_veren || null;
        const siparis_veren_telefon = body.siparis_veren_telefon || null;
        const teslim_kisi = body.teslim_kisi || null;
        const teslim_kisi_telefon = body.teslim_kisi_telefon || null;
        const teslim_il = body.teslim_il || body.receiverCity || null;
        const teslim_ilce = body.teslim_ilce || body.receiverDistrict || null;
        const teslim_mahalle = body.teslim_mahalle || body.receiverRegion || null;
        const teslim_adresi = body.teslim_adresi || null;
        const urun_adi = body.urun_adi || null;
        const urun_yazisi = body.urun_yazisi || null;
        const fiyat = body.fiyat != null ? body.fiyat : null;
        const teslim_tarihi = body.teslim_tarihi || null;
        const teslim_saati = body.teslim_saati || null;
        const kullaniciAdi = await getCurrentUsername(req).catch(() => null);
        await execute(`
            INSERT INTO organizasyon_siparisler_ciceksepeti (
                tenant_id, siparis_no, siparis_veren, siparis_veren_telefon,
                teslim_kisi, teslim_kisi_telefon, teslim_il, teslim_ilce, teslim_mahalle, teslim_adresi,
                urun_adi, urun_yazisi, fiyat, teslim_tarihi, teslim_saati,
                durum, kaynak, created_at, updated_at, created_by, updated_by, is_active
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'beklemede', 'Çiçeksepeti', ${getTurkeyTimeSQL()}, ${getTurkeyTimeSQL()}, ?, ?, 1)
        `, [
            tenantId, siparis_no, siparis_veren, siparis_veren_telefon,
            teslim_kisi, teslim_kisi_telefon, teslim_il, teslim_ilce, teslim_mahalle, teslim_adresi,
            urun_adi, urun_yazisi, fiyat, teslim_tarihi, teslim_saati,
            kullaniciAdi, kullaniciAdi
        ]);
        broadcastSseToTenant(tenantId, { type: 'invalidate' });
        broadcastSseToTenant(tenantId, { type: 'ciceksepeti_new_order', siparis_no, urun_adi, teslim_tarihi, teslim_saati });
        res.status(201).json({ success: true, message: 'Sipariş kaydedildi.' });
    } catch (error) {
        console.error('❌ Çiçek Sepeti test-order hatası:', error);
        res.status(500).json({ success: false, error: 'Sipariş kaydedilemedi', message: error.message });
    }
});

// ---------- Çiçek Sepeti: siparişi onayla, organizasyon kartı oluştur ----------
app.post('/api/ciceksepeti/accept-order', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı.' });
        const { siparis_no } = req.body || {};
        if (!siparis_no) return res.status(400).json({ success: false, error: 'siparis_no gerekli.' });
        const rows = await query(
            'SELECT id, teslim_tarihi, teslim_saati, teslim_il, teslim_ilce, teslim_mahalle, teslim_adresi, teslim_kisi, teslim_kisi_telefon FROM organizasyon_siparisler_ciceksepeti WHERE siparis_no = ? AND tenant_id = ?',
            [siparis_no, tenantId]
        );
        if (!rows || rows.length === 0) return res.status(404).json({ success: false, error: 'Sipariş bulunamadı.' });
        const row = rows[0];
        const kullaniciAdi = await getCurrentUsername(req).catch(() => null);
        await run(
            `UPDATE organizasyon_siparisler_ciceksepeti SET durum = 'kabul_edildi', updated_at = ${getTurkeyTimeSQL()}, updated_by = ? WHERE id = ? AND tenant_id = ?`,
            [kullaniciAdi, row.id, tenantId]
        );
        const teslimTarih = row.teslim_tarihi;
        let kartId = null;
        const mevcutKart = await query(
            `SELECT id FROM organizasyon_kartlar WHERE tenant_id = ? AND organizasyon_teslim_tarih = ? AND organizasyon_kart_tur = 'Çiçek Sepeti' AND (organizasyon_status = 'aktif' OR organizasyon_status IS NULL) AND is_active = 1 LIMIT 1`,
            [tenantId, teslimTarih]
        );
        if (mevcutKart && mevcutKart.length > 0) {
            kartId = mevcutKart[0].id;
        } else {
            const kullaniciAdi = await getCurrentUsername(req).catch(() => null);
            const result = await execute(`
                INSERT INTO organizasyon_kartlar (
                    organizasyon_kart_tur, organizasyon_kart_etiket, organizasyon_alt_tur,
                    organizasyon_il, organizasyon_ilce, organizasyon_mahalle, organizasyon_acik_adres,
                    organizasyon_teslim_kisisi, organizasyon_teslim_kisisi_telefon,
                    organizasyon_teslim_tarih, organizasyon_teslim_saat,
                    organizasyon_davetiye_gorsel, organizasyon_teslimat_konumu, organizasyon_toplam_siparis_sayisi,
                    organizasyon_status, is_active, tenant_id, created_at, updated_at, created_by, updated_by
                ) VALUES ('Çiçek Sepeti', ?, NULL, ?, ?, ?, ?, ?, ?, ?, ?, NULL, NULL, 0, 'aktif', 1, ?, ${getTurkeyTimeSQL()}, ${getTurkeyTimeSQL()}, ?, ?)
            `, [
                (teslimTarih ? 'Çiçek Sepeti - ' + teslimTarih : 'Çiçek Sepeti'),
                row.teslim_il || '', row.teslim_ilce || '', row.teslim_mahalle || '', row.teslim_adresi || '',
                row.teslim_kisi || '', row.teslim_kisi_telefon || '',
                teslimTarih, row.teslim_saati || '',
                tenantId, kullaniciAdi, kullaniciAdi
            ]);
            kartId = result && result.lastID ? result.lastID : null;
        }
        res.json({ success: true, message: 'Sipariş onaylandı.', data: { organizasyon_id: kartId } });
    } catch (error) {
        console.error('❌ Çiçek Sepeti accept-order hatası:', error);
        res.status(500).json({ success: false, error: 'Sipariş onaylanamadı', message: error.message });
    }
});

