app.get('/api/araclar/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        const columns = await query('PRAGMA table_info(araclar)');
        const columnNames = columns.map(c => c.name);
        
        let querySql = 'SELECT * FROM araclar WHERE id = ?';
        const params = [id];
        
        if (columnNames.includes('tenant_id')) {
            querySql += ' AND tenant_id = ?';
            params.push(tenantId);
        }
        
        const vehicles = await query(querySql, params);
        
        if (vehicles.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Araç bulunamadı'
            });
        }
        
        const vehicle = vehicles[0];
        // Frontend'in beklediği formata dönüştür
        const formatted = { ...vehicle };
        
        res.json({
            success: true,
            data: formatted
        });
    } catch (error) {
        console.error('❌ Araç yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Araç yüklenemedi',
            message: error.message
        });
    }
});

// Yeni organizasyon türü ekle (POST)
app.post('/api/organizasyon-turleri', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const { tur_adi, renk_kodu, grup_id } = req.body;
        
        if (!tur_adi || !tur_adi.trim()) {
            return res.status(400).json({
                success: false,
                error: 'Tür adı gereklidir'
            });
        }
        
        // grup_id kontrolü - eğer grup_id varsa, bu tenant'a ait olduğunu kontrol et
        let grupIdNum = null;
        if (grup_id !== undefined && grup_id !== null && grup_id !== '') {
            grupIdNum = parseInt(grup_id);
            if (isNaN(grupIdNum)) {
                return res.status(400).json({
                    success: false,
                    error: 'Geçersiz grup ID'
                });
            }
            const grupCheck = await query(
                'SELECT id FROM organizasyon_turleri WHERE id = ? AND tenant_id = ?',
                [grupIdNum, tenantId]
            );
            if (grupCheck.length === 0) {
                return res.status(400).json({
                    success: false,
                    error: 'Seçilen organizasyon grubu bulunamadı veya yetkiniz yok'
                });
            }
        }
        
        // Tablo kontrolü ve kolon yapısını kontrol et
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='organizasyon_alt_turleri'
        `);
        
        let hasRenkKodu = false;
        if (tableExists.length > 0) {
            const columns = await query('PRAGMA table_info(organizasyon_alt_turleri)');
            hasRenkKodu = columns.some(c => c.name === 'renk_kodu');
            // base_id kolonu yoksa ekle (migration)
            const hasBaseId = columns.some(c => c.name === 'base_id');
            if (!hasBaseId) {
                await run('ALTER TABLE organizasyon_alt_turleri ADD COLUMN base_id INTEGER');
                console.log('✅ organizasyon_alt_turleri tablosuna base_id kolonu eklendi');
            }
        } else {
            await run(`
                CREATE TABLE IF NOT EXISTS organizasyon_alt_turleri (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    tur_adi TEXT NOT NULL,
                    grup_id INTEGER,
                    tur_aciklama TEXT,
                    sira_no INTEGER,
                    tenant_id INTEGER DEFAULT 1,
                    base_id INTEGER,
                    is_active INTEGER DEFAULT 1,
                    durum INTEGER DEFAULT 1,
                    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
                )
            `);
        }
        
        // INSERT sorgusu oluştur (grup_id, renk_kodu varsa ekle)
        const columns = await query('PRAGMA table_info(organizasyon_alt_turleri)');
        const columnNames = columns.map(c => c.name);
        const hasGrupId = columnNames.includes('grup_id');
        
        let insertFields = ['tur_adi', 'tenant_id', 'is_active'];
        let insertValues = [tur_adi.trim(), tenantId, 1];
        
        if (hasGrupId && grupIdNum !== null) {
            insertFields.push('grup_id');
            insertValues.push(grupIdNum);
        }
        
        if (hasRenkKodu && renk_kodu) {
            insertFields.push('renk_kodu');
            insertValues.push(renk_kodu);
        }
        
        const kullaniciAdi = await getCurrentUsername(req);
        if (columnNames.includes('created_by')) { insertFields.push('created_by'); insertValues.push(kullaniciAdi); }
        if (columnNames.includes('updated_by')) { insertFields.push('updated_by'); insertValues.push(kullaniciAdi); }
        insertFields.push('created_at', 'updated_at');
        insertValues.push('CURRENT_TIMESTAMP', 'CURRENT_TIMESTAMP');
        
        const placeholders = insertFields.map(field => field === 'created_at' || field === 'updated_at' ? 'CURRENT_TIMESTAMP' : '?').join(', ');
        const fieldsList = insertFields.join(', ');
        
        const insertSql = `INSERT INTO organizasyon_alt_turleri (${fieldsList}) VALUES (${placeholders})`;
        const finalValues = insertValues.filter(v => v !== 'CURRENT_TIMESTAMP');
        
        const result = await run(insertSql, finalValues);
        
        const newTur = await query('SELECT * FROM organizasyon_alt_turleri WHERE id = ?', [result.lastID]);
        
        res.json({
            success: true,
            data: newTur[0]
        });
    } catch (error) {
        console.error('❌ Organizasyon türü eklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Organizasyon türü eklenemedi',
            message: error.message
        });
    }
});

// Organizasyon türü güncelle (PUT)
app.put('/api/organizasyon-turleri/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const { tur_adi, renk_kodu, is_active, durum, grup_id } = req.body;
        
        // Mevcut kaydı kontrol et - sadece kendi tenant_id'sine ait kaydı güncelleyebilir
        const existing = await query(
            'SELECT * FROM organizasyon_alt_turleri WHERE id = ? AND tenant_id = ?',
            [id, tenantId]
        );
        
        if (existing.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Organizasyon türü bulunamadı veya yetkiniz yok'
            });
        }
        
        // tur_adi kontrolü
        if (tur_adi !== undefined && (!tur_adi || !tur_adi.trim())) {
            return res.status(400).json({
                success: false,
                error: 'Tür adı boş olamaz'
            });
        }
        
        // grup_id kontrolü - eğer grup_id varsa, bu tenant'a ait olduğunu kontrol et
        let grupIdNum = null;
        if (grup_id !== undefined && grup_id !== null && grup_id !== '') {
            grupIdNum = parseInt(grup_id);
            if (isNaN(grupIdNum)) {
                return res.status(400).json({
                    success: false,
                    error: 'Geçersiz grup ID'
                });
            }
            const grupCheck = await query(
                'SELECT id FROM organizasyon_turleri WHERE id = ? AND tenant_id = ?',
                [grupIdNum, tenantId]
            );
            if (grupCheck.length === 0) {
                return res.status(400).json({
                    success: false,
                    error: 'Seçilen organizasyon grubu bulunamadı veya yetkiniz yok'
                });
            }
        }
        
        const columns = await query('PRAGMA table_info(organizasyon_alt_turleri)');
        const columnNames = columns.map(c => c.name);
        const hasGrupId = columnNames.includes('grup_id');
        
        const updateFields = [];
        const updateValues = [];
        
        if (tur_adi !== undefined && tur_adi !== null && tur_adi !== '') {
            updateFields.push('tur_adi = ?');
            updateValues.push(tur_adi.trim());
        }
        if (renk_kodu !== undefined && renk_kodu !== null && renk_kodu !== '') {
            updateFields.push('renk_kodu = ?');
            updateValues.push(renk_kodu);
        }
        if (is_active !== undefined) {
            updateFields.push('is_active = ?');
            updateValues.push(is_active ? 1 : 0);
        }
        if (durum !== undefined && durum !== null) {
            updateFields.push('durum = ?');
            updateValues.push(durum === 1 ? 1 : 0);
        }
        if (hasGrupId && grupIdNum !== null) {
            updateFields.push('grup_id = ?');
            updateValues.push(grupIdNum);
        } else if (hasGrupId && grup_id === null) {
            // grup_id'yi null yapmak istiyorsa
            updateFields.push('grup_id = ?');
            updateValues.push(null);
        }
        
        if (updateFields.length === 0) {
            return res.status(400).json({
                success: false,
                error: 'Güncellenecek alan bulunamadı'
            });
        }
        
        // Güvenlik kontrolü: Güncellenmek istenen kayıt global kayıt mı kontrol et
        const recordCheck = await query(
            'SELECT id, tenant_id, base_id FROM organizasyon_alt_turleri WHERE id = ?',
            [id]
        );
        
        if (recordCheck.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Organizasyon türü bulunamadı'
            });
        }
        
        // Global kayıt (tenant_id IS NULL) ASLA güncellenemez
        if (recordCheck[0].tenant_id === null) {
            return res.status(403).json({
                success: false,
                error: 'Sistem tanımları güncellenemez. Özelleştirmek için kopyalayabilirsiniz.'
            });
        }
        
        // Sadece tenant'a ait kayıtlar güncellenebilir
        if (recordCheck[0].tenant_id !== tenantId) {
            return res.status(403).json({
                success: false,
                error: 'Bu kayıt size ait değil'
            });
        }
        
        const kullaniciAdi = await getCurrentUsername(req);
        updateFields.push('updated_at = CURRENT_TIMESTAMP');
        if (columnNames.includes('updated_by')) { updateFields.push('updated_by = ?'); updateValues.push(kullaniciAdi); }
        updateValues.push(id, tenantId);
        
        await run(
            `UPDATE organizasyon_alt_turleri SET ${updateFields.join(', ')} WHERE id = ? AND tenant_id = ?`,
            updateValues
        );
        
        const updated = await query(
            'SELECT * FROM organizasyon_alt_turleri WHERE id = ?',
            [id]
        );
        
        res.json({
            success: true,
            data: updated[0]
        });
    } catch (error) {
        console.error('❌ Organizasyon türü güncellenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Organizasyon türü güncellenemedi',
            message: error.message
        });
    }
});

// Global organizasyon türünü kopyalayarak tenant override oluştur (POST)
app.post('/api/organizasyon-turleri/copy-from-global/:id', async (req, res) => {
    try {
        const { id } = req.params; // Global kaydın ID'si
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // Global kaydı bul (tenant_id IS NULL)
        const globalRecord = await query(
            'SELECT * FROM organizasyon_alt_turleri WHERE id = ? AND tenant_id IS NULL',
            [id]
        );
        
        if (globalRecord.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Global organizasyon türü bulunamadı'
            });
        }
        
        // Bu tenant için zaten override var mı kontrol et
        const existingOverride = await query(
            'SELECT id FROM organizasyon_alt_turleri WHERE base_id = ? AND tenant_id = ?',
            [id, tenantId]
        );
        
        if (existingOverride.length > 0) {
            return res.status(400).json({
                success: false,
                error: 'Bu global kayıt için zaten bir override mevcut'
            });
        }
        
        const global = globalRecord[0];
        
        // Tenant override oluştur (base_id ile)
        const columns = await query('PRAGMA table_info(organizasyon_alt_turleri)');
        const columnNames = columns.map(c => c.name);
        
        const insertFields = ['tenant_id', 'base_id', 'tur_adi', 'is_active'];
        const insertValues = [tenantId, id, global.tur_adi, global.is_active || 1];
        
        // Opsiyonel alanları ekle
        if (columnNames.includes('grup_id') && global.grup_id) {
            insertFields.push('grup_id');
            insertValues.push(global.grup_id);
        }
        if (columnNames.includes('tur_aciklama') && global.tur_aciklama) {
            insertFields.push('tur_aciklama');
            insertValues.push(global.tur_aciklama);
        }
        if (columnNames.includes('sira_no') && global.sira_no) {
            insertFields.push('sira_no');
            insertValues.push(global.sira_no);
        }
        if (columnNames.includes('renk_kodu') && global.renk_kodu) {
            insertFields.push('renk_kodu');
            insertValues.push(global.renk_kodu);
        }
        if (columnNames.includes('durum') && global.durum) {
            insertFields.push('durum');
            insertValues.push(global.durum);
        }
        
        insertFields.push('created_at', 'updated_at');
        insertValues.push('CURRENT_TIMESTAMP', 'CURRENT_TIMESTAMP');
        
        const placeholders = insertFields.map(field => 
            field === 'created_at' || field === 'updated_at' ? 'CURRENT_TIMESTAMP' : '?'
        ).join(', ');
        const fieldsList = insertFields.join(', ');
        
        const insertSql = `INSERT INTO organizasyon_alt_turleri (${fieldsList}) VALUES (${placeholders})`;
        const finalValues = insertValues.filter(v => v !== 'CURRENT_TIMESTAMP');
        
        const result = await run(insertSql, finalValues);
        
        // Oluşturulan kaydı getir
        const newRecord = await query(
            'SELECT * FROM organizasyon_alt_turleri WHERE id = ?',
            [result.lastID]
        );
        
        console.log(`✅ Global organizasyon türü kopyalandı: Base ID ${id} -> Tenant Override ID ${result.lastID} (Tenant: ${tenantId})`);
        
        res.json({
            success: true,
            data: newRecord[0],
            message: 'Global kayıt tenant override olarak kopyalandı'
        });
    } catch (error) {
        console.error('❌ Global organizasyon türü kopyalama hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Global kayıt kopyalanamadı',
            message: error.message
        });
    }
});

// Organizasyon türü sil
app.delete('/api/organizasyon-turleri/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // Güvenlik kontrolü: Global kayıtlar ASLA silinemez
        const existing = await query(
            'SELECT id, tenant_id, base_id FROM organizasyon_alt_turleri WHERE id = ?',
            [id]
        );
        
        if (existing.length === 0) {
            return res.status(404).json({ success: false, error: 'Organizasyon türü bulunamadı' });
        }
        
        // Global kayıt (tenant_id IS NULL) ASLA silinemez
        if (existing[0].tenant_id === null) {
            return res.status(403).json({
                success: false,
                error: 'Sistem tanımları silinemez. Özelleştirmek için kopyalayabilirsiniz.'
            });
        }
        
        // Sadece tenant'a ait kayıtlar silinebilir
        if (existing[0].tenant_id !== tenantId) {
            return res.status(403).json({
                success: false,
                error: 'Bu kayıt size ait değil'
            });
        }
        
        const kullaniciAdi = await getCurrentUsername(req);
        await query('UPDATE organizasyon_alt_turleri SET is_active = 0, updated_at = datetime(\'now\'), updated_by = ? WHERE id = ? AND tenant_id = ?', [kullaniciAdi, id, tenantId]);
        console.log(`✅ Organizasyon türü silindi: ID ${id}, Tenant: ${tenantId}`);
        res.json({ success: true, message: 'Organizasyon türü silindi' });
    } catch (error) {
        console.error('❌ Organizasyon türü silme hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

// Araç güncelle/ekle (PUT/POST)
app.put('/api/araclar/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const { plaka, marka, model, renk, yil, arac_tipi, is_active } = req.body;
        
        // Mevcut kaydı kontrol et - sadece kendi tenant_id'sine ait aracı güncelleyebilir
        const existing = await query(
            'SELECT * FROM araclar WHERE id = ? AND tenant_id = ?',
            [id, tenantId]
        );
        
        if (existing.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Araç bulunamadı veya yetkiniz yok'
            });
        }
        
        // Güncelle
        const columns = await query('PRAGMA table_info(araclar)');
        const columnNames = columns.map(c => c.name);
        
        const updateFields = [];
        const updateValues = [];
        
        // Kolon isimlerini kontrol et - sadece doğru kolonları kullan
        // Plaka zorunlu alan, eğer gönderilmişse güncelle
        if (plaka !== undefined && plaka !== null && plaka !== '') {
            if (columnNames.includes('plaka')) {
                updateFields.push('plaka = ?');
                updateValues.push(plaka);
            }
        }
        if (marka !== undefined && marka !== null) {
            if (columnNames.includes('marka')) {
                updateFields.push('marka = ?');
                updateValues.push(marka || null);
            }
        }
        if (model !== undefined && model !== null) {
            if (columnNames.includes('model')) {
                updateFields.push('model = ?');
                updateValues.push(model || null);
            }
        }
        if (renk !== undefined && renk !== null) {
            if (columnNames.includes('renk')) {
                updateFields.push('renk = ?');
                updateValues.push(renk || null);
            }
        }
        if (yil !== undefined && yil !== null) {
            if (columnNames.includes('yil')) {
                updateFields.push('yil = ?');
                updateValues.push(yil);
            }
        }
        if (arac_tipi !== undefined && arac_tipi !== null) {
            if (columnNames.includes('arac_tipi')) {
                updateFields.push('arac_tipi = ?');
                updateValues.push(arac_tipi || null);
            }
        }
        if (is_active !== undefined) {
            if (columnNames.includes('is_active')) {
                updateFields.push('is_active = ?');
                updateValues.push(is_active ? 1 : 0);
            }
        }
        
        // Eğer hiçbir alan güncellenmeyecekse, en azından updated_at güncelle
        if (updateFields.length === 0) {
            updateFields.push('updated_at = CURRENT_TIMESTAMP');
        }
        
        const kullaniciAdi = await getCurrentUsername(req);
        updateFields.push('updated_at = CURRENT_TIMESTAMP');
        if (columnNames.includes('updated_by')) {
            updateFields.push('updated_by = ?');
            updateValues.push(kullaniciAdi);
        }
        updateValues.push(id);
        
        if (columnNames.includes('tenant_id')) {
            await run(
                `UPDATE araclar SET ${updateFields.join(', ')} WHERE id = ? AND tenant_id = ?`,
                [...updateValues, tenantId]
            );
        } else {
            await run(
                `UPDATE araclar SET ${updateFields.join(', ')} WHERE id = ?`,
                updateValues
            );
        }
        
        const updated = await query('SELECT * FROM araclar WHERE id = ?', [id]);
        
        res.json({
            success: true,
            data: updated[0]
        });
    } catch (error) {
        console.error('❌ Araç güncellenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Araç güncellenemedi',
            message: error.message
        });
    }
});

