// WhatsApp status endpoint
app.get('/api/whatsapp/status', async (req, res) => {
    if (!getWhatsAppService) {
        // getWhatsAppService null ise, servis yüklenmemiş demektir
        // Ama frontend'de installed kontrolü yapmıyoruz, sadece success: false döndürüyoruz
        return res.json({
            success: false,
            message: 'WhatsApp servisi şu anda kullanılamıyor. Lütfen backend sunucusunu kontrol edin.',
            installed: true, // Frontend'de installed kontrolü yapmıyoruz
            isReady: false,
            isAuthenticated: false,
            hasQRCode: false,
            qrCode: null
        });
    }

    try {
        // Tenant ID kontrolü
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        // Tenant bazlı WhatsApp servisi instance'ını al (DB kullanılmıyor – sadece servis/bellek)
        const whatsappService = getWhatsAppService(tenantId);
        const sessionUser = await getSessionUsername(req);
        if (sessionUser) whatsappService.setSessionOwnerUser(sessionUser);

        const inQrOrInitializing = !!(whatsappService.qrCode || whatsappService.initializing);

        // Client yoksa: DB’de son satır 'connected' ise disconnected yaz (telefondan çıkış restart sonrası da loglansın)
        if (!inQrOrInitializing && !whatsappService.client) {
            await whatsappService.ensureDisconnectLogFromDb(tenantId);
            if (whatsappService._hadConnectedSession && !whatsappService._hasLoggedDisconnectThisSession) {
                whatsappService.logDisconnectEvent(whatsappService.lastDisconnectReason || 'CLOSED');
                whatsappService.lastLogoutAt = Date.now();
            }
        }

        const logoutCooldownMs = 60000;
        const withinLogoutCooldown = whatsappService.lastLogoutAt && (Date.now() - whatsappService.lastLogoutAt < logoutCooldownMs);
        const manualInitCooldownMs = 20000;
        const withinManualInitCooldown = whatsappService.lastManualInitAt && (Date.now() - whatsappService.lastManualInitAt < manualInitCooldownMs);
        const needsAutoInit = !whatsappService.client && 
                             !whatsappService.qrCode && 
                             !whatsappService.isReady && 
                             !whatsappService.isAuthenticated &&
                             !whatsappService.initializing &&
                             !withinLogoutCooldown &&
                             !withinManualInitCooldown;
        
        if (needsAutoInit) {
            console.log(`🔄 WhatsApp servisi başlatılıyor (Tenant ${tenantId})...`);
            whatsappService.initialize(tenantId).catch(err => {
                console.error('❌ WhatsApp servisi başlatılamadı:', err);
            });
            await new Promise(resolve => setTimeout(resolve, 500));
        }

        if (!inQrOrInitializing && !whatsappService.client) {
            console.log(`🔌 [Status] Client yok – disconnected (Tenant ${tenantId})`);
            return res.json({
                success: true,
                installed: true,
                status: 'disconnected',
                isReady: false,
                isAuthenticated: false,
                hasQRCode: false,
                qrCode: null,
                qr: null,
                actualState: 'DISCONNECTED',
                browserSessionActive: false,
                connectedAt: null,
                phoneNumber: null,
                userName: null,
                lastDisconnectReason: whatsappService.lastDisconnectReason || 'Bağlantı yok',
                warning: null,
                initializing: false
            });
        }

        // ÖNCE getState() – telefondan çıkışı anında yakala; timeout ile takılı bağlantıyı CLOSED say (QR varken atlama – okutunca ready dönmeli)
        const GETSTATE_TIMEOUT_MS = 4000;
        let stateFromClient = null;
        if (whatsappService.client && typeof whatsappService.client.getState === 'function') {
            try {
                stateFromClient = await Promise.race([
                    whatsappService.client.getState(),
                    new Promise((_, reject) => setTimeout(() => reject(new Error('getState timeout')), GETSTATE_TIMEOUT_MS))
                ]);
            } catch (e) {
                if (whatsappService.isReady || whatsappService.phoneNumber || whatsappService.userName) {
                    stateFromClient = 'CLOSED';
                    console.log('🔌 [Status] getState() hata veya timeout (telefondan çıkış):', e?.message);
                } else {
                    stateFromClient = null;
                    console.log('⚠️ [Status] getState() henüz hazır değil (client yükleniyor):', e?.message);
                }
            }
        }
        const ONLY_CONNECTED_STATES = ['CONNECTED', 'READY'];
        const DISCONNECTED_STATES_FOR_DESTROY = ['DISCONNECTED', 'UNPAIRED', 'CONFLICT', 'CLOSED', 'UNLAUNCHED', 'UNPAIRED_IDLE'];
        let isActuallyConnected = stateFromClient && ONLY_CONNECTED_STATES.includes(String(stateFromClient).toUpperCase());
        // getState() CONNECTED/READY dönse bile session kapanmış olabilir; client.info ile doğrula (telefondan çıkışı yakala)
        if (isActuallyConnected && whatsappService.client) {
            try {
                const info = whatsappService.client.info;
                if (info && typeof info.then === 'function') await info;
            } catch (e) {
                isActuallyConnected = false;
                stateFromClient = 'CLOSED';
                console.log('🔌 [Status] client.info hata (oturum kapalı):', e?.message);
            }
        }
        // QR varken veya initializing iken ASLA client yok etme – getState() sayfa yüklenirken DISCONNECTED/CLOSED dönebilir, karekod kaybolmasın
        const readyGraceMs = 45000;
        const justConnected = !!(whatsappService.lastConnectedDbWriteAt && (Date.now() - whatsappService.lastConnectedDbWriteAt < readyGraceMs));
        const authenticatedWaitingReady = whatsappService.isAuthenticated && !whatsappService.isReady;
        const hasQrNow = !!whatsappService.qrCode;
        const shouldDestroyClient = !inQrOrInitializing && !hasQrNow && stateFromClient && DISCONNECTED_STATES_FOR_DESTROY.includes(String(stateFromClient)) && !isActuallyConnected && !justConnected && !authenticatedWaitingReady;
        if (shouldDestroyClient) {
            console.log(`🔌 [Status] Telefondan çıkış veya bağlantı yok (getState=${stateFromClient}), disconnected (Tenant ${tenantId})`);
            whatsappService.logDisconnectEvent(stateFromClient || 'DISCONNECTED');
            whatsappService.lastLogoutAt = Date.now();
            whatsappService.isReady = false;
            whatsappService.isAuthenticated = false;
            const clientToDestroy = whatsappService.client;
            whatsappService.client = null;
            if (clientToDestroy) {
                try {
                    await clientToDestroy.logout();
                } catch (e) { /* ignore */ }
                clientToDestroy.destroy().catch(() => {});
            }
            return res.json({
                success: true,
                installed: true,
                status: 'disconnected',
                isReady: false,
                isAuthenticated: false,
                hasQRCode: false,
                qrCode: null,
                qr: null,
                actualState: stateFromClient,
                browserSessionActive: false,
                connectedAt: null,
                phoneNumber: null,
                userName: null,
                lastDisconnectReason: 'Telefondan çıkış yapıldı',
                warning: null,
                initializing: false
            });
        }

        const whatsappStatus = await whatsappService.getStatus();
        const qrCode = whatsappService.getQRCode();
        
        let finalStatus = {
            isReady: false,
            isAuthenticated: false,
            hasQRCode: false,
            qrCode: null,
            browserSessionActive: false,
            connectedAt: null,
            phoneNumber: null,
            userName: null,
            lastDisconnectReason: null,
            warning: null
        };
        
        const actualState = stateFromClient || whatsappStatus.actualState || null;
        const isDisconnectedFromPhone = actualState && ['DISCONNECTED', 'UNPAIRED', 'CONFLICT', 'CLOSED', 'UNLAUNCHED', 'UNPAIRED_IDLE'].includes(String(actualState).toUpperCase());
        const recentlyLoggedOut = whatsappService.lastLogoutAt && (Date.now() - whatsappService.lastLogoutAt < 15000);
        const stateOkForReady = !stateFromClient || stateFromClient === 'CONNECTED' || stateFromClient === 'READY' || stateFromClient === 'PAIRING' || stateFromClient === 'CONNECTING';
        const treatAsReady = justConnected && whatsappService.client && stateOkForReady && !recentlyLoggedOut;
        const isStateConnected = stateFromClient === 'CONNECTED' || stateFromClient === 'READY';
        const serviceConnected = isActuallyConnected && (
            (whatsappStatus.isReady && whatsappStatus.isAuthenticated) ||
            (whatsappStatus.actualState === 'CONNECTED' || whatsappStatus.actualState === 'READY') ||
            isStateConnected
        );
        const pairingButReady = (stateFromClient === 'PAIRING' || stateFromClient === 'CONNECTING') && whatsappStatus.isReady && whatsappStatus.isAuthenticated && whatsappService.client;

        if (treatAsReady) {
            let ph = whatsappStatus.phoneNumber || null;
            let un = whatsappStatus.userName || null;
            if ((!ph || !un) && whatsappService.client) {
                try {
                    let info = whatsappService.client.info;
                    if (info && typeof info.then === 'function') info = await info;
                    if (info) { ph = info.wid?.user || info.me?.user || ph; un = info.pushname || info.name || un; }
                } catch (e) { /* ignore */ }
            }
            const connAt = whatsappStatus.connectedAt || new Date().toISOString().replace('T', ' ').substring(0, 19);
            finalStatus = { isReady: true, isAuthenticated: true, hasQRCode: false, qrCode: null, browserSessionActive: whatsappStatus.browserSessionActive || false, connectedAt: connAt, phoneNumber: ph, userName: un, lastDisconnectReason: null, warning: whatsappStatus.browserSessionActive ? 'Tarayıcıda WhatsApp Web açık!' : null, installed: true };
        } else if (serviceConnected || pairingButReady) {
            let finalPhoneNumber = whatsappStatus.phoneNumber || null;
            let finalUserName = whatsappStatus.userName || null;
            if ((!finalPhoneNumber || !finalUserName) && whatsappService.client) {
                try {
                    let info = whatsappService.client.info;
                    if (info && typeof info.then === 'function') info = await info;
                    if (info) { finalPhoneNumber = info.wid?.user || info.me?.user || finalPhoneNumber; finalUserName = info.pushname || info.name || finalUserName; }
                } catch (e) { /* ignore */ }
            }
            finalStatus = { isReady: true, isAuthenticated: true, hasQRCode: false, qrCode: null, browserSessionActive: whatsappStatus.browserSessionActive || false, connectedAt: whatsappStatus.connectedAt || null, phoneNumber: finalPhoneNumber, userName: finalUserName, lastDisconnectReason: null, warning: whatsappStatus.browserSessionActive ? 'Tarayıcıda WhatsApp Web açık!' : null, installed: true };
        } else if (isDisconnectedFromPhone) {
            finalStatus = { isReady: false, isAuthenticated: false, hasQRCode: !!qrCode, qrCode: qrCode || null, browserSessionActive: false, connectedAt: null, phoneNumber: null, userName: null, lastDisconnectReason: whatsappStatus.lastDisconnectReason || 'Telefondan çıkış yapıldı', warning: null, installed: true };
        } else if (whatsappStatus.isAuthenticated && !whatsappStatus.isReady) {
            finalStatus = { isReady: false, isAuthenticated: true, hasQRCode: false, qrCode: null, browserSessionActive: false, connectedAt: null, phoneNumber: null, userName: null, lastDisconnectReason: null, warning: null, installed: true };
        } else {
            finalStatus = { isReady: whatsappStatus.isReady, isAuthenticated: whatsappStatus.isAuthenticated, hasQRCode: !!qrCode, qrCode: qrCode || null, browserSessionActive: whatsappStatus.browserSessionActive, connectedAt: null, phoneNumber: null, userName: null, lastDisconnectReason: whatsappStatus.lastDisconnectReason, warning: null, installed: true };
        }

        if (finalStatus.isReady && whatsappService.client && (!finalStatus.phoneNumber || !finalStatus.userName)) {
            try {
                let info = whatsappService.client.info;
                if (info && typeof info.then === 'function') info = await info;
                if (info) {
                    const ph = info.wid?.user || info.me?.user || info.id?.user || (info.wid && typeof info.wid === 'object' && info.wid.user) || null;
                    const un = info.pushname || info.name || info.formattedName || null;
                    if (ph || un) {
                        finalStatus.phoneNumber = finalStatus.phoneNumber || ph;
                        finalStatus.userName = finalStatus.userName || un;
                        whatsappService.phoneNumber = whatsappService.phoneNumber || ph;
                        whatsappService.userName = whatsappService.userName || un;
                        console.log(`✅ [Status] client.info: ${finalStatus.phoneNumber} (${finalStatus.userName})`);
                    }
                }
            } catch (e) { /* ignore */ }
        }
        if (justConnected && whatsappService.client && !finalStatus.isReady && (stateFromClient === 'CONNECTED' || stateFromClient === 'READY')) {
            finalStatus = { isReady: true, isAuthenticated: true, hasQRCode: false, qrCode: null, browserSessionActive: whatsappService.browserSessionActive || false, connectedAt: whatsappService.connectedAt || new Date().toISOString().replace('T', ' ').substring(0, 19), phoneNumber: whatsappService.phoneNumber || null, userName: whatsappService.userName || null, lastDisconnectReason: null, warning: whatsappStatus.browserSessionActive ? 'Tarayıcıda WhatsApp Web açık!' : null, installed: true };
        }

        // Karekod popup'ta bir kez gösterildiyse kaybolmasın: serviste QR varken asla 'disconnected' dönme, hep 'qr' dön
        const qrStillInService = !!(whatsappService.qrCode || (typeof whatsappService.getQRCode === 'function' && whatsappService.getQRCode()));
        const forceQrStatus = qrStillInService && whatsappService.client && !finalStatus.isReady;
        if (forceQrStatus) {
            finalStatus.isReady = false;
            finalStatus.isAuthenticated = false;
            finalStatus.hasQRCode = true;
            finalStatus.qrCode = finalStatus.qrCode || whatsappService.qrCode || (whatsappService.getQRCode && whatsappService.getQRCode()) || null;
            finalStatus.phoneNumber = null;
            finalStatus.userName = null;
            finalStatus.connectedAt = null;
        }
        // QR/initializing akışında asla 'pairing' dönme – popup "Bağlantı kuruluyor" takılı kalmasın, karekod görünsün
        const isInitializingNoQr = whatsappService.initializing && !finalStatus.isReady && !finalStatus.hasQRCode;
        const statusForResponse = isInitializingNoQr
            ? 'initializing'
            : (finalStatus.isReady ? 'ready' : (finalStatus.hasQRCode ? 'qr' : (finalStatus.isAuthenticated && !finalStatus.isReady && !whatsappService.initializing && !finalStatus.hasQRCode ? 'pairing' : (forceQrStatus ? 'qr' : (whatsappStatus.status || 'disconnected')))));
        res.json({
            success: true,
            installed: true,
            status: statusForResponse,
            isReady: finalStatus.isReady,
            isAuthenticated: isInitializingNoQr ? false : finalStatus.isAuthenticated,
            hasQRCode: finalStatus.hasQRCode,
            qrCode: finalStatus.qrCode,
            qr: finalStatus.qrCode || null,
            error: whatsappStatus.error || null,
            updatedAt: whatsappStatus.updatedAt || null,
            phone_number: finalStatus.phoneNumber || null,
            username: finalStatus.userName || null,
            initializing: whatsappService.initializing || false,
            browserSessionActive: finalStatus.browserSessionActive,
            connectedAt: finalStatus.connectedAt,
            phoneNumber: finalStatus.phoneNumber,
            userName: finalStatus.userName,
            lastDisconnectReason: finalStatus.lastDisconnectReason,
            warning: finalStatus.warning,
            actualState: whatsappStatus.actualState || null
        });
    } catch (error) {
        console.error('❌ WhatsApp status kontrolü hatası:', error);
        res.status(500).json({
            success: false,
            error: 'WhatsApp status kontrol edilemedi',
            message: error.message
        });
    }
});

// WhatsApp servisini başlat
app.post('/api/whatsapp/initialize', async (req, res) => {
    if (!getWhatsAppService) {
        // getWhatsAppService null ise, servis yüklenmemiş demektir
        // Backend sunucusunu yeniden başlatmayı öner
        return res.status(503).json({
            success: false,
            message: 'WhatsApp servisi şu anda kullanılamıyor. Lütfen backend sunucusunu yeniden başlatın.'
        });
    }

    try {
        // Tenant ID kontrolü
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // ✅ PLAN KONTROL: Başlangıç paketi için WhatsApp engelle
        const planAccess = await checkWhatsAppPlanAccess(tenantId);
        if (!planAccess.allowed) {
            console.log('🚫 WhatsApp initialize engellendi - Plan ID:', planAccess.planId, '- Tenant ID:', tenantId);
            return res.status(403).json({ 
                success: false, 
                error: planAccess.error,
                planId: planAccess.planId
            });
        }
        
        console.log('🔍 /api/whatsapp/initialize çağrıldı - Tenant ID:', tenantId);
        
        // Tenant bazlı WhatsApp servisi instance'ını al
        const whatsappService = getWhatsAppService(tenantId);
        const sessionUser = await getSessionUsername(req);
        if (sessionUser) whatsappService.setSessionOwnerUser(sessionUser);
        
        // Manuel QR/tekrar bağlanma: cooldown kaldır; disconnect sonrası kafası yerine gelsin, karekod hemen istensin
        const justDisconnected = whatsappService.lastLogoutAt && (Date.now() - whatsappService.lastLogoutAt < 20000);
        if (!whatsappService.client) {
            whatsappService.initializing = false;
            whatsappService.firstQrStoredAt = null;
            if (justDisconnected) {
                console.log('⏳ Disconnect sonrası 2 sn bekleniyor, yeni QR akışı için...');
                await new Promise(r => setTimeout(r, 2000));
            }
        }
        whatsappService.lastLogoutAt = null;
        whatsappService.lastManualInitAt = Date.now();
        
        // Eğer client zaten başlatılmışsa, gerçek durumunu kontrol et
        if (whatsappService.client) {
            // ÖNCE: Eğer LOGOUT nedeniyle kesilmişse, client'ı temizle ve yeniden başlat
            if (whatsappService.lastDisconnectReason === 'LOGOUT') {
                console.log('⚠️ ⚠️ ⚠️ Client LOGOUT nedeniyle kesilmiş, temizlenip yeniden başlatılıyor...');
                try {
                    if (whatsappService.client) {
                        // Client'ı destroy et - Puppeteer target'ının tamamen kapanması için bekle
                        await whatsappService.client.destroy().catch((destroyErr) => {
                            console.warn('⚠️ Client destroy hatası (normal olabilir):', destroyErr.message);
                        });
                        // Puppeteer browser process'inin tamamen kapanması için bekle
                        await new Promise(resolve => setTimeout(resolve, 2000));
                    }
                    // State'leri temizle
                    whatsappService.client = null;
                    whatsappService.isReady = false;
                    whatsappService.isAuthenticated = false;
                    whatsappService.qrCode = null;
                    whatsappService.lastDisconnectReason = null;
                    whatsappService.browserSessionActive = false;
                    console.log('✅ LOGOUT nedeniyle eski client temizlendi, yeni client başlatılacak...');
                } catch (err) {
                    console.error('⚠️ Eski client temizlenirken hata:', err.message);
                    // Hata olsa bile state'leri temizle
                    whatsappService.client = null;
                    whatsappService.isReady = false;
                    whatsappService.isAuthenticated = false;
                    whatsappService.qrCode = null;
                    whatsappService.lastDisconnectReason = null;
                    whatsappService.browserSessionActive = false;
                }
            } else {
                // Client'ın gerçek durumunu kontrol et - güvenli şekilde
                try {
                    // Client'ın hala geçerli olup olmadığını kontrol et
                    if (whatsappService.client && typeof whatsappService.client.info !== 'undefined') {
                        const state = whatsappService.client.info;
                        if (state && whatsappService.isReady && whatsappService.isAuthenticated) {
                            return res.json({
                                success: true,
                                message: 'WhatsApp servisi zaten başlatılmış ve bağlı. QR kodu için /api/whatsapp/status endpoint\'ini kontrol edin.',
                                alreadyInitialized: true,
                                isReady: true,
                                isAuthenticated: true
                            });
                        }
                    }
                } catch (infoErr) {
                    // Client info'ya erişilemiyorsa, client kapalı demektir
                    console.warn('⚠️ Client info erişilemedi (client kapalı olabilir):', infoErr.message);
                    // Client'ı null yap ve devam et
                    whatsappService.client = null;
                    whatsappService.isReady = false;
                    whatsappService.isAuthenticated = false;
                }
                
                // QR kod kontrolü
                if (whatsappService.qrCode) {
                    return res.json({
                        success: true,
                        message: 'WhatsApp servisi zaten başlatılmış, QR kod bekleniyor. QR kodu için /api/whatsapp/status endpoint\'ini kontrol edin.',
                        alreadyInitialized: true,
                        isReady: false,
                        isAuthenticated: false,
                        hasQRCode: true
                    });
                }
            }
        }

        // Yeni client başlat (DB kullanılmıyor – sadece servis) - async olarak başlat, hemen response döndür (timeout önlemek için)
        // initialize() işlemi uzun sürebilir, bu yüzden await etmeden başlat ve hemen response döndür
        // AMA: QR kod oluşana kadar biraz bekleyelim (maksimum 10 saniye)
        const initializePromise = whatsappService.initialize(tenantId).catch(err => {
            console.error('❌ WhatsApp initialize hatası (async):', err);
        });
        
        // Hemen response döndür (client başlatma işlemi arka planda devam edecek)
        res.json({
            success: true,
            message: 'WhatsApp servisi başlatılıyor. QR kodu için /api/whatsapp/status endpoint\'ini kontrol edin.'
        });
        
        // Arka planda QR kod oluşmasını bekle (non-blocking)
        initializePromise.then(() => {
            // Initialize başarılı, QR kod oluşmasını bekle (maksimum 15 saniye)
            let qrWaitCount = 0;
            const maxQrWait = 30; // 30 * 500ms = 15 saniye
            
            const waitForQR = setInterval(() => {
                qrWaitCount++;
                if (whatsappService.qrCode) {
                    console.log('✅ QR kod oluşturuldu ve hazır!');
                    clearInterval(waitForQR);
                } else if (qrWaitCount >= maxQrWait) {
                    console.warn('⚠️ QR kod oluşturulması uzun sürüyor (15 saniye geçti)');
                    clearInterval(waitForQR);
                }
            }, 500); // Her 500ms'de bir kontrol et
        });
    } catch (error) {
        console.error('❌ WhatsApp servisi başlatma hatası:', error);
        res.status(500).json({
            success: false,
            error: 'WhatsApp servisi başlatılamadı',
            message: error.message
        });
    }
});

// WhatsApp bağlantısını kes
app.post('/api/whatsapp/disconnect', async (req, res) => {
    if (!getWhatsAppService) {
        return res.status(503).json({
            success: false,
            message: 'WhatsApp servisi kurulu değil.'
        });
    }

    try {
        // Tenant ID kontrolü
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        console.log('🔌 /api/whatsapp/disconnect çağrıldı - Tenant ID:', tenantId);
        
        const whatsappService = getWhatsAppService(tenantId);
        const sessionUser = await getSessionUsername(req);
        if (sessionUser) whatsappService.setSessionOwnerUser(sessionUser);
        // State temizlenmeden önce tabloya disconnected log yaz (API üzerinden kesinti)
        if (whatsappService.client && (whatsappService.phoneNumber || whatsappService.userName)) {
            whatsappService.logDisconnectEvent('LOGOUT');
        }
        // Hemen işaretle: status "bağlantı başarılı" dönmesin (kullanıcı hemen popup açarsa sahte ready olmasın)
        whatsappService.lastLogoutAt = Date.now();
        whatsappService.lastConnectedDbWriteAt = null;
        whatsappService.isReady = false;
        whatsappService.isAuthenticated = false;
        
        // Tek instance: client varsa logout + destroy; bitince serviste client=null ve lastLogoutAt set et ki bir sonraki status anında disconnected dönsün
        if (whatsappService.client) {
            try {
                console.log('🔌 WhatsApp Web\'den çıkış yapılıyor (telefondan da çıkış yapılacak)...');
                await whatsappService.client.logout();
                console.log('✅ WhatsApp Web\'den çıkış yapıldı');
                await new Promise(resolve => setTimeout(resolve, 1500));
            } catch (logoutErr) {
                console.warn('⚠️ WhatsApp logout hatası:', logoutErr.message);
            }
        }
        await whatsappService.destroy();

        // Kesin temizlik – popup tekrar açıldığında init takılmasın, karekod hemen istensin
        whatsappService.client = null;
        whatsappService.initializing = false;
        whatsappService.qrCode = null;
        whatsappService.firstQrStoredAt = null;
        whatsappService.lastLogoutAt = Date.now();
        whatsappService.isReady = false;
        whatsappService.isAuthenticated = false;

        res.json({
            success: true,
            message: 'WhatsApp bağlantısı başarıyla kesildi ve telefondan çıkış yapıldı'
        });
    } catch (error) {
        console.error('❌ WhatsApp bağlantı kesme hatası:', error);
        res.status(500).json({
            success: false,
            error: 'WhatsApp bağlantısı kesilemedi',
            message: error.message
        });
    }
});

// Yeni karekod al (QR gösterilirken / popup yeniden açıldığında – mevcut client temizlenir, yeni QR üretilir)
app.post('/api/whatsapp/refresh-qr', async (req, res) => {
    if (!getWhatsAppService) {
        return res.status(503).json({ success: false, message: 'WhatsApp servisi kurulu değil.' });
    }
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı.' });
        }
        const whatsappService = getWhatsAppService(tenantId);
        if (whatsappService.isReady) {
            return res.json({
                success: true,
                message: 'Zaten bağlı – yeni karekod gerekmez.',
                alreadyConnected: true
            });
        }
        await whatsappService.refreshQR();
        whatsappService.initialize(tenantId).catch(err => {
            console.error('❌ refresh-qr sonrası initialize:', err?.message);
        });
        res.json({
            success: true,
            message: 'Yeni karekod isteniyor...',
            alreadyConnected: false
        });
    } catch (error) {
        console.error('❌ WhatsApp refresh-qr hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Yeni karekod alınamadı',
            message: error.message
        });
    }
});

// WhatsApp logout: destroy + clear session, status=disconnected (alias for disconnect)
app.post('/api/whatsapp/logout', async (req, res) => {
    if (!getWhatsAppService) {
        return res.status(503).json({ success: false, message: 'WhatsApp servisi kurulu değil.' });
    }
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı.' });
        }
        const whatsappService = getWhatsAppService(tenantId);
        const sessionUser = await getSessionUsername(req);
        if (sessionUser) whatsappService.setSessionOwnerUser(sessionUser);
        if (whatsappService.client && (whatsappService.phoneNumber || whatsappService.userName)) {
            whatsappService.logDisconnectEvent('LOGOUT');
        }
        if (whatsappService.client) {
            try {
                await whatsappService.client.logout();
                await new Promise(r => setTimeout(r, 2000));
            } catch (e) { /* ignore */ }
        }
        await whatsappService.destroy();
        res.json({ success: true, message: 'WhatsApp çıkış yapıldı', status: 'disconnected' });
    } catch (error) {
        res.status(500).json({ success: false, error: error.message });
    }
});

//#region whatsapp-send (sendSeen non-blocking)
app.post("/api/whatsapp/send", async (req, res) => {
  const requestId = `wa_${Date.now()}_${Math.random().toString(16).slice(2)}`;
  let warning = null;
  
  try {
    const { phone, message } = req.body || {};
    if (!phone || !message) {
      return res.status(400).json({ success: false, error: "BAD_REQUEST", message: "phone/message zorunlu", requestId });
    }

    // Tenant ID kontrolü
    const tenantId = req.tenantId || await getTenantId(req);
    if (!tenantId) {
      console.error(`❌ [WhatsApp Send] Tenant ID bulunamadı - Request ID: ${requestId}`);
      return res.status(400).json({ success: false, error: "TENANT_ID_REQUIRED", message: "Tenant ID bulunamadı", requestId });
    }
    
    // ✅ PLAN KONTROL: Başlangıç paketi için WhatsApp engelle
    const planAccess = await checkWhatsAppPlanAccess(tenantId);
    if (!planAccess.allowed) {
      console.log(`🚫 [WhatsApp Send] Engellendi - Plan ID: ${planAccess.planId} - Tenant ID: ${tenantId}`);
      return res.status(403).json({ 
        success: false, 
        error: "PLAN_RESTRICTION", 
        message: planAccess.error,
        planId: planAccess.planId,
        requestId 
      });
    }
    
    console.log(`🔍 [WhatsApp Send] Tenant ID: ${tenantId}, Request ID: ${requestId}`);
    
    // Tenant bazlı WhatsApp servisi instance'ını al
    const whatsappService = getWhatsAppService ? getWhatsAppService(tenantId) : null;
    
    console.log(`🔍 [WhatsApp Send] WhatsApp servisi:`, {
      hasGetWhatsAppService: !!getWhatsAppService,
      hasWhatsappService: !!whatsappService,
      hasClient: whatsappService ? !!whatsappService.client : false,
      isReady: whatsappService ? whatsappService.isReady : false,
      isAuthenticated: whatsappService ? whatsappService.isAuthenticated : false
    });

    if (!getWhatsAppService) {
      return res.status(503).json({
        success: false,
        error: "SERVICE_UNAVAILABLE",
        message: "WhatsApp servisi kurulu değil",
        requestId
      });
    }

    if (!whatsappService) {
      return res.status(503).json({
        success: false,
        error: "SERVICE_UNAVAILABLE",
        message: "WhatsApp servisi instance'ı oluşturulamadı",
        requestId
      });
    }

    // Gönderim kuralı: sadece servis hazır ve client var (DB kullanılmıyor)
    const sendAllowed = !!whatsappService.client && whatsappService.isReady && whatsappService.isAuthenticated;

    if (!sendAllowed) {
      if (whatsappService.qrCode) {
        return res.status(503).json({
          success: false,
          error: "SERVICE_UNAVAILABLE",
          message: "WhatsApp QR kod bekleniyor. Lütfen QR kodu tarayın.",
          hasQRCode: true,
          needsQRScan: true,
          requestId
        });
      }
      if (!whatsappService.client) {
        whatsappService.initialize(tenantId).catch(() => {});
        return res.status(503).json({
          success: false,
          error: "SERVICE_UNAVAILABLE",
          message: "WhatsApp bağlantısı yeniden başlatılıyor. Lütfen birkaç saniye sonra tekrar deneyin.",
          needsInitialization: true,
          requestId
        });
      }
      return res.status(503).json({
        success: false,
        error: "SERVICE_UNAVAILABLE",
        message: "WhatsApp bağlantısı yok. Lütfen önce QR kodu ile bağlanın.",
        requestId
      });
    }

    try {
      const result = await whatsappService.sendMessage(phone, message);

    return res.json({
      success: true,
      message: "Mesaj gönderildi",
      requestId,
      data: {
          messageId: result.messageId || null,
          timestamp: result.timestamp || Math.floor(Date.now() / 1000),
          phoneNumber: result.phoneNumber || phone,
        warning: warning
      },
    });
    } catch (sendError) {
      // sendMessage içindeki hataları yakala ve uygun şekilde döndür
      const errorMessage = sendError?.message || sendError?.toString() || 'Bilinmeyen hata';
      console.error(`[${requestId}] WhatsApp sendMessage hatası:`, errorMessage);
      
      // ProtocolError: Browser bağlantısı kesildi
      if (errorMessage.includes('Protocol error') || 
          errorMessage.includes('Target closed') || 
          errorMessage.includes('getResponseBody') ||
          errorMessage.includes('browser bağlantısı kesildi') ||
          sendError?.name === 'ProtocolError') {
        console.error(`[${requestId}] ProtocolError tespit edildi, client temizleniyor...`);
        // Client'ı temizle (whatsapp-service.js zaten temizlemiş olabilir ama emin olmak için)
        if (whatsappService) {
          whatsappService.isReady = false;
          whatsappService.isAuthenticated = false;
          if (whatsappService.client) {
            whatsappService.client.destroy().catch(() => {});
            whatsappService.client = null;
          }
        }
        return res.status(503).json({
          success: false,
          error: "SERVICE_UNAVAILABLE",
          message: "WhatsApp browser bağlantısı kesildi. Lütfen servisi yeniden başlatın.",
          needsReconnect: true,
          requestId
        });
      }
      
      if (errorMessage.includes('hazır değil') || errorMessage.includes('bağlantıyı kurun') || errorMessage.includes('başlatılmamış')) {
        return res.status(503).json({
          success: false,
          error: "SERVICE_UNAVAILABLE",
          message: errorMessage || "WhatsApp bağlantısı hazır değil.",
          requestId
        });
      }
      
      // Diğer hatalar için 500 döndür
      return res.status(500).json({
        success: false,
        error: "SEND_FAILED",
        message: sendError?.message || "Mesaj gönderilemedi",
        requestId,
      });
    }
  } catch (err) {
    console.error(`[${requestId}] WhatsApp send endpoint genel hatası:`, err?.message || err);
    
    // Eğer servis hazır değil hatası ise, 503 döndür
    if (err?.message && (
      err.message.includes('hazır değil') || 
      err.message.includes('bağlantıyı kurun') ||
      err.message.includes('başlatılmamış') ||
      err.message.includes('SERVICE_UNAVAILABLE')
    )) {
      return res.status(503).json({
        success: false,
        error: "SERVICE_UNAVAILABLE",
        message: err.message || "WhatsApp bağlantısı hazır değil. Lütfen birkaç saniye bekleyip tekrar deneyin.",
        requestId,
      });
    }
    
    return res.status(500).json({
      success: false,
      error: "SEND_FAILED",
      message: err?.message || "Mesaj gönderilemedi",
      requestId,
    });
  }
});
//#endregion

// getNumberId uyumluluk fonksiyonu
async function getNumberIdCompat(client, normalized) {
    // normalized: "905075751219"
    // 1) düz numara ile dene
    try {
        const a = await client.getNumberId(normalized);
        if (a?._serialized) return a;
    } catch (e) {
        // Ignore
    }

    // 2) @c.us ile dene
    try {
        const b = await client.getNumberId(`${normalized}@c.us`);
        if (b?._serialized) return b;
    } catch (e) {
        // Ignore
    }

    // 3) bazı sürümlerde getNumberId yerine isRegisteredUser olur
    if (typeof client.isRegisteredUser === 'function') {
        try {
            const isReg = await client.isRegisteredUser(`${normalized}@c.us`);
            if (isReg) return { _serialized: `${normalized}@c.us` };
        } catch (e) {
            // Ignore
        }
    }

    return null;
}
// #endregion

// #region WhatsApp Test Endpoint
app.post('/api/whatsapp/test-send', async (req, res) => {
    if (!getWhatsAppService) {
        return res.status(503).json({
            success: false,
            message: 'WhatsApp servisi kurulu değil. Lütfen önce npm install whatsapp-web.js qrcode-terminal komutunu çalıştırın.'
        });
    }

    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // ✅ PLAN KONTROL: Başlangıç paketi için WhatsApp engelle
        const planAccess = await checkWhatsAppPlanAccess(tenantId);
        if (!planAccess.allowed) {
            console.log('🚫 WhatsApp test-send engellendi - Plan ID:', planAccess.planId, '- Tenant ID:', tenantId);
            return res.status(403).json({ 
                success: false, 
                error: planAccess.error,
                planId: planAccess.planId
            });
        }
        
        // Tenant bazlı WhatsApp servisi instance'ını al
        const whatsappService = getWhatsAppService(tenantId);
        
        // Servis instance'ı kontrolü
        if (!whatsappService) {
            return res.status(503).json({
                success: false,
                message: 'WhatsApp servisi instance\'ı oluşturulamadı.'
            });
        }
        
        // Client ve durum kontrolü
        if (!whatsappService.client) {
            // Client yoksa otomatik olarak initialize etmeyi dene
            console.log(`🔄 WhatsApp client yok, otomatik başlatma deneniyor (Tenant ${tenantId})...`);
            try {
                // Initialize işlemini başlat
                const initPromise = whatsappService.initialize(tenantId);
                
                // Maksimum 5 saniye bekle (initialize işlemi uzun sürebilir)
                let waited = 0;
                const maxWait = 5000; // 5 saniye
                const checkInterval = 500; // Her 500ms'de bir kontrol et
                
                while (waited < maxWait) {
                    await new Promise(resolve => setTimeout(resolve, checkInterval));
                    waited += checkInterval;
                    
                    // Client oluştu mu kontrol et
                    if (whatsappService.client) {
                        // Client oluştu, biraz daha bekle (ready olması için)
                        await new Promise(resolve => setTimeout(resolve, 1000));
                        break;
                    }
                }
                
                // Hala client yoksa veya hazır değilse
                if (!whatsappService.client) {
                    // Initialize işlemi devam ediyor olabilir, kullanıcıya bilgi ver
                    return res.status(503).json({
                        success: false,
                        message: 'WhatsApp bağlantısı başlatılıyor. Lütfen birkaç saniye bekleyip tekrar deneyin.',
                        needsInitialization: true,
                        initializing: true
                    });
                }
                
                // Client oluştu ama henüz hazır olmayabilir, kontrol et
                if (!whatsappService.isReady || !whatsappService.isAuthenticated) {
                    if (whatsappService.qrCode) {
                        return res.status(503).json({
                            success: false,
                            message: 'WhatsApp QR kod bekleniyor. Lütfen QR kodu tarayın.',
                            hasQRCode: true,
                            needsQRScan: true
                        });
                    }
                    
                    return res.status(503).json({
                        success: false,
                        message: 'WhatsApp bağlantısı hazır değil. Lütfen birkaç saniye bekleyip tekrar deneyin.',
                        isReady: whatsappService.isReady,
                        isAuthenticated: whatsappService.isAuthenticated
                    });
                }
                
                // Client hazır, devam et
                console.log(`✅ WhatsApp client başlatıldı ve hazır (Tenant ${tenantId})`);
            } catch (initError) {
                console.error('❌ WhatsApp otomatik başlatma hatası:', initError);
                return res.status(503).json({
                    success: false,
                    message: 'WhatsApp bağlantısı kurulmamış ve otomatik başlatma başarısız oldu. Lütfen manuel olarak /api/whatsapp/initialize endpoint\'ini çağırın.',
                    needsInitialization: true,
                    initializing: false
                });
            }
        }
        
        // Client hazır mı kontrol et
        if (!whatsappService.isReady || !whatsappService.isAuthenticated) {
            // QR kod bekleniyor olabilir
            if (whatsappService.qrCode) {
                return res.status(503).json({
                    success: false,
                    message: 'WhatsApp QR kod bekleniyor. Lütfen QR kodu tarayın.',
                    hasQRCode: true,
                    needsQRScan: true
                });
            }
            
            return res.status(503).json({
                success: false,
                message: 'WhatsApp bağlantısı hazır değil. Lütfen önce bağlantıyı kurun.',
                isReady: whatsappService.isReady,
                isAuthenticated: whatsappService.isAuthenticated
            });
        }
        
        const { phone, message } = req.body;
        
        console.log('📱 Test mesajı gönderiliyor:', { phone, message });
        
        // Formatla
        const formatted = whatsappService.formatPhoneNumber(phone);
        console.log('📱 Formatlanmış numara:', formatted);
        
        // Direkt client ile gönder (test için)
        const result = await whatsappService.client.sendMessage(formatted, message);
        console.log('📱 Sonuç:', result);
        
        return res.json({ 
            success: true, 
            message: 'Test başarılı',
            data: result,
            formatted: formatted
        });
        
    } catch (error) {
        console.error('📱 Test hatası:', error);
        return res.status(500).json({ 
            success: false, 
            error: error.message,
            stack: error.stack
        });
    }
});
// #endregion

