app.post('/api/whatsapp/send-media', async (req, res) => {
    if (!getWhatsAppService) {
        return res.status(503).json({
            success: false,
            message: 'WhatsApp servisi kurulu değil. Lütfen önce npm install whatsapp-web.js qrcode-terminal komutunu çalıştırın.'
        });
    }

    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // ✅ PLAN KONTROL: Başlangıç paketi için WhatsApp engelle
        const planAccess = await checkWhatsAppPlanAccess(tenantId);
        if (!planAccess.allowed) {
            console.log('🚫 WhatsApp send-media engellendi - Plan ID:', planAccess.planId, '- Tenant ID:', tenantId);
            return res.status(403).json({ 
                success: false, 
                error: planAccess.error,
                planId: planAccess.planId
            });
        }
        
        // Tenant bazlı WhatsApp servisi instance'ını al
        const whatsappService = getWhatsAppService(tenantId);
        
        // Servis instance'ı kontrolü
        if (!whatsappService) {
            return res.status(503).json({
                success: false,
                message: 'WhatsApp servisi instance\'ı oluşturulamadı.'
            });
        }
        
        // Client ve durum kontrolü
        if (!whatsappService.client) {
            // Client yoksa otomatik olarak initialize etmeyi dene
            console.log(`🔄 WhatsApp client yok, otomatik başlatma deneniyor (Tenant ${tenantId})...`);
            try {
                // Initialize işlemini başlat
                const initPromise = whatsappService.initialize(tenantId);
                
                // Maksimum 5 saniye bekle (initialize işlemi uzun sürebilir)
                let waited = 0;
                const maxWait = 5000; // 5 saniye
                const checkInterval = 500; // Her 500ms'de bir kontrol et
                
                while (waited < maxWait) {
                    await new Promise(resolve => setTimeout(resolve, checkInterval));
                    waited += checkInterval;
                    
                    // Client oluştu mu kontrol et
                    if (whatsappService.client) {
                        // Client oluştu, biraz daha bekle (ready olması için)
                        await new Promise(resolve => setTimeout(resolve, 1000));
                        break;
                    }
                }
                
                // Hala client yoksa veya hazır değilse
                if (!whatsappService.client) {
                    // Initialize işlemi devam ediyor olabilir, kullanıcıya bilgi ver
                    return res.status(503).json({
                        success: false,
                        message: 'WhatsApp bağlantısı başlatılıyor. Lütfen birkaç saniye bekleyip tekrar deneyin.',
                        needsInitialization: true,
                        initializing: true
                    });
                }
                
                // Client oluştu ama henüz hazır olmayabilir, gerçek zamanlı durum kontrolü yap
                const initStatus = await whatsappService.getStatus();
                if (!initStatus.isReady || !initStatus.isAuthenticated) {
                    if (whatsappService.qrCode) {
                        return res.status(503).json({
                            success: false,
                            message: 'WhatsApp QR kod bekleniyor. Lütfen QR kodu tarayın.',
                            hasQRCode: true,
                            needsQRScan: true
                        });
                    }
                    
                    return res.status(503).json({
                        success: false,
                        message: 'WhatsApp bağlantısı hazır değil. Lütfen birkaç saniye bekleyip tekrar deneyin.',
                        isReady: initStatus.isReady,
                        isAuthenticated: initStatus.isAuthenticated
                    });
                }
                
                // Client hazır, devam et
                console.log(`✅ WhatsApp client başlatıldı ve hazır (Tenant ${tenantId})`);
            } catch (initError) {
                console.error('❌ WhatsApp otomatik başlatma hatası:', initError);
                return res.status(503).json({
                    success: false,
                    message: 'WhatsApp bağlantısı kurulmamış ve otomatik başlatma başarısız oldu. Lütfen manuel olarak /api/whatsapp/initialize endpoint\'ini çağırın.',
                    needsInitialization: true,
                    initializing: false
                });
            }
        }
        
        // Gerçek zamanlı durum kontrolü için getStatus() kullan
        // Servis hazır olana kadar kısa bir süre beklemeyi dene (maksimum 3 saniye)
        let status = await whatsappService.getStatus();
        let retryCount = 0;
        const maxRetries = 6; // 6 * 500ms = 3 saniye
        const retryDelay = 500; // 500ms
        
        while ((!status.isReady || !status.isAuthenticated) && retryCount < maxRetries) {
            if (whatsappService.qrCode) {
                return res.status(503).json({
                    success: false,
                    message: 'WhatsApp QR kod bekleniyor. Lütfen QR kodu tarayın.',
                    hasQRCode: true,
                    needsQRScan: true
                });
            }
            
            // Servis hazır değilse kısa bir süre bekle ve tekrar kontrol et
            await new Promise(resolve => setTimeout(resolve, retryDelay));
            status = await whatsappService.getStatus();
            retryCount++;
        }
        
        // Hala hazır değilse hata döndür
        if (!status.isReady || !status.isAuthenticated) {
            if (whatsappService.qrCode) {
                return res.status(503).json({
                    success: false,
                    message: 'WhatsApp QR kod bekleniyor. Lütfen QR kodu tarayın.',
                    hasQRCode: true,
                    needsQRScan: true
                });
            }
            
            return res.status(503).json({
                success: false,
                message: 'WhatsApp bağlantısı hazır değil. Lütfen birkaç saniye bekleyip tekrar deneyin.',
                isReady: status.isReady,
                isAuthenticated: status.isAuthenticated
            });
        }
        
        const { phoneNumber, phone, message, mediaPath } = req.body;
        
        console.log(`📤 [API send-media] İstek alındı - Tenant: ${tenantId}`);
        console.log(`📤 [API send-media] Body:`, { phoneNumber, phone, message: message?.substring(0, 50), mediaPath });
        
        // phoneNumber veya phone parametresini al
        const phoneNum = phoneNumber || phone;
        
        if (!phoneNum || !message || !mediaPath) {
            console.log(`❌ [API send-media] Eksik parametre - phone: ${phoneNum}, message: ${!!message}, mediaPath: ${mediaPath}`);
            return res.status(400).json({
                success: false,
                error: 'phoneNumber (veya phone), message ve mediaPath gereklidir'
            });
        }
        
        // mediaPath mutlak yol veya relative olabilir
        // Format: uploads/tenants/<tenantId>/organizations/<orgId>/teslim-fotolar/...
        const path = require('path');
        let absoluteMediaPath = mediaPath;
        if (!path.isAbsolute(mediaPath)) {
            // Relative path ise backend klasörüne göre çöz (uploads backend klasörünün içinde)
            // mediaPath zaten "uploads/tenants/..." formatında geliyor
            absoluteMediaPath = path.join(__dirname, mediaPath);
        }
        
        console.log(`📤 [API send-media] Dosya yolu: ${absoluteMediaPath}`);
        console.log(`📤 [API send-media] sendMedia çağrılıyor...`);
        
        // WhatsApp servisinin sendMedia metodunu kullan (tüm kontroller ve retry logic içerir)
        const result = await whatsappService.sendMedia(phoneNum, absoluteMediaPath, message);
        
        console.log(`✅ [API send-media] Başarılı! Result:`, result);
        
        res.json({
            success: true,
            message: 'Medya mesajı başarıyla gönderildi',
            messageId: result.messageId,
            timestamp: result.timestamp
        });
    } catch (error) {
        const errorMessage = error?.message || error?.toString() || 'Bilinmeyen hata';
        console.error('❌ WhatsApp medya mesaj gönderme hatası:', errorMessage);
        
        // ProtocolError: Browser bağlantısı kesildi
        if (errorMessage.includes('Protocol error') || 
            errorMessage.includes('Target closed') || 
            errorMessage.includes('getResponseBody') ||
            errorMessage.includes('browser bağlantısı kesildi') ||
            error?.name === 'ProtocolError') {
            console.error('❌ ProtocolError tespit edildi (send-media), client temizleniyor...');
            // Client'ı temizle
            if (whatsappService) {
                whatsappService.isReady = false;
                whatsappService.isAuthenticated = false;
                if (whatsappService.client) {
                    whatsappService.client.destroy().catch(() => {});
                    whatsappService.client = null;
                }
            }
            return res.status(503).json({
                success: false,
                error: 'SERVICE_UNAVAILABLE',
                message: 'WhatsApp browser bağlantısı kesildi. Lütfen servisi yeniden başlatın.',
                needsReconnect: true
            });
        }
        
        res.status(500).json({
            success: false,
            error: 'Medya mesajı gönderilemedi',
            message: errorMessage
        });
    }
});

// Araçlar endpoint
app.get('/api/araclar', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const { aktif_only } = req.query;
        
        // araclar tablosunu kontrol et, yoksa oluştur
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='araclar'
        `);
        
        if (tableExists.length === 0) {
            await run(`
                CREATE TABLE IF NOT EXISTS araclar (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    plaka TEXT NOT NULL,
                    marka TEXT,
                    model TEXT,
                    renk TEXT,
                    yil INTEGER,
                    arac_tipi TEXT,
                    tenant_id INTEGER DEFAULT 1,
                    is_active INTEGER DEFAULT 1,
                    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
                )
            `);
        } else {
            // Tablo varsa kolon yapısını kontrol et
            let columns = await query('PRAGMA table_info(araclar)');
            let columnNames = columns.map(c => c.name);
            
            // durum kolonunu kaldır (eğer varsa)
            if (columnNames.includes('durum')) {
                try {
                    // SQLite 3.35.0+ DROP COLUMN desteği
                    await run('ALTER TABLE araclar DROP COLUMN durum');
                    console.log('✅ araclar tablosundan durum kolonu kaldırıldı');
                    // Kolonu listeden çıkar
                    columns = await query('PRAGMA table_info(araclar)');
                    columnNames = columns.map(c => c.name);
                } catch (dropError) {
                    // Eski SQLite sürümlerinde DROP COLUMN desteklenmiyorsa
                    // Bu durumda kolon kullanılmayacak, sadece uyarı ver
                    console.warn('⚠️ durum kolonu kaldırılamadı (SQLite sürümü eski olabilir):', dropError.message);
                    console.warn('⚠️ Kolon veritabanında kalacak ama kod tarafında kullanılmayacak');
                }
            }
            
            // Eski kolonları kontrol et
            const columnsToDrop = ['arac_plaka', 'arac_marka', 'arac_model', 'surucu_adi', 'surucu_telefon'];
            const hasOldColumns = columnsToDrop.some(col => columnNames.includes(col));
            
            // Migration'ı devre dışı bırak - sadece uyarı ver
            if (false && hasOldColumns) {
                console.log('🔄 Eski kolonlar tespit edildi, tablo yeniden oluşturuluyor...');
                
                try {
                    // 1. Mevcut verileri yedekle - dinamik SELECT sorgusu oluştur
                    let selectFields = ['id'];
                    
                    // Plaka için
                    if (columnNames.includes('plaka')) {
                        selectFields.push('plaka');
                    } else if (columnNames.includes('arac_plaka')) {
                        selectFields.push('arac_plaka as plaka');
                    } else {
                        selectFields.push("'' as plaka");
                    }
                    
                    // Marka için
                    if (columnNames.includes('marka')) {
                        selectFields.push('marka');
                    } else if (columnNames.includes('arac_marka')) {
                        selectFields.push('arac_marka as marka');
                    } else {
                        selectFields.push('NULL as marka');
                    }
                    
                    // Model için
                    if (columnNames.includes('model')) {
                        selectFields.push('model');
                    } else if (columnNames.includes('arac_model')) {
                        selectFields.push('arac_model as model');
                    } else {
                        selectFields.push('NULL as model');
                    }
                    
                    // Diğer kolonlar
                    if (columnNames.includes('renk')) selectFields.push('renk');
                    else selectFields.push('NULL as renk');
                    
                    if (columnNames.includes('yil')) selectFields.push('yil');
                    else selectFields.push('NULL as yil');
                    
                    if (columnNames.includes('arac_tipi')) selectFields.push('arac_tipi');
                    else selectFields.push('NULL as arac_tipi');
                    
                    if (columnNames.includes('tenant_id')) selectFields.push('tenant_id');
                    else selectFields.push('1 as tenant_id');
                    
                    if (columnNames.includes('is_active')) selectFields.push('is_active');
                    else selectFields.push('1 as is_active');
                    
                    if (columnNames.includes('created_at')) selectFields.push('created_at');
                    else selectFields.push("datetime('now') as created_at");
                    
                    if (columnNames.includes('updated_at')) selectFields.push('updated_at');
                    else selectFields.push("datetime('now') as updated_at");
                    
                    const selectSql = `SELECT ${selectFields.join(', ')} FROM araclar`;
                    console.log('🔍 Migration SELECT sorgusu:', selectSql);
                    const existingData = await query(selectSql);
                    
                    // 2. Eski tabloyu yedekle
                    await run('DROP TABLE IF EXISTS araclar_old');
                    await run('ALTER TABLE araclar RENAME TO araclar_old');
                    
                    // 3. Yeni tabloyu oluştur (eski kolonlar olmadan)
                    await run(`
                        CREATE TABLE araclar (
                            id INTEGER PRIMARY KEY AUTOINCREMENT,
                            plaka TEXT NOT NULL,
                            marka TEXT,
                            model TEXT,
                            renk TEXT,
                            yil INTEGER,
                            arac_tipi TEXT,
                            tenant_id INTEGER DEFAULT 1,
                            is_active INTEGER DEFAULT 1,
                            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
                        )
                    `);
                    
                    // 4. Verileri geri yükle
                    if (existingData && existingData.length > 0) {
                        for (const row of existingData) {
                            await run(`
                                INSERT INTO araclar (id, plaka, marka, model, renk, yil, arac_tipi, tenant_id, is_active, created_at, updated_at)
                                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                            `, [
                                row.id,
                                row.plaka || null,
                                row.marka || null,
                                row.model || null,
                                row.renk || null,
                                row.yil || null,
                                row.arac_tipi || null,
                                row.tenant_id || 1,
                                (row.is_active !== undefined && row.is_active !== null) ? (row.is_active ? 1 : 0) : 1,
                                row.created_at || new Date().toISOString(),
                                row.updated_at || new Date().toISOString()
                            ]);
                        }
                    }
                    
                    // 5. Eski tabloyu sil
                    await run('DROP TABLE IF EXISTS araclar_old');
                    
                    console.log('✅ araclar tablosu başarıyla yeniden oluşturuldu, eski kolonlar kaldırıldı');
                    if (existingData && existingData.length > 0) {
                        console.log(`✅ ${existingData.length} kayıt başarıyla taşındı`);
                    }
                } catch (error) {
                    console.error('❌ Tablo yeniden oluşturulurken hata:', error);
                    console.error('❌ Hata detayı:', error.message);
                    if (error.stack) {
                        console.error('❌ Stack:', error.stack);
                    }
                    
                    // Hata durumunda eski tabloyu geri yükle
                    try {
                        const oldTableExists = await query(`SELECT name FROM sqlite_master WHERE type='table' AND name='araclar_old'`);
                        if (oldTableExists.length > 0) {
                            const currentTableExists = await query(`SELECT name FROM sqlite_master WHERE type='table' AND name='araclar'`);
                            if (currentTableExists.length > 0) {
                                await run('DROP TABLE IF EXISTS araclar');
                            }
                            await run('ALTER TABLE araclar_old RENAME TO araclar');
                            console.log('⚠️ Hata nedeniyle eski tablo geri yüklendi');
                        }
                    } catch (restoreError) {
                        console.error('❌ Eski tablo geri yüklenirken hata:', restoreError);
                    }
                    
                    // Hata olsa bile devam et, sadece logla - migration hatası kritik değil
                    console.warn('⚠️ Migration hatası, mevcut tablo yapısı ile devam ediliyor');
                }
            } else {
                // Eski kolon yoksa, sadece eksik kolonları ekle
                const requiredColumns = {
                    'plaka': 'TEXT',
                    'marka': 'TEXT',
                    'model': 'TEXT',
                    'renk': 'TEXT',
                    'yil': 'INTEGER',
                    'arac_tipi': 'TEXT',
                    'tenant_id': 'INTEGER DEFAULT 1',
                    'is_active': 'INTEGER DEFAULT 1',
                    'created_at': 'DATETIME DEFAULT CURRENT_TIMESTAMP',
                    'updated_at': 'DATETIME DEFAULT CURRENT_TIMESTAMP'
                };
                
                for (const [colName, colDef] of Object.entries(requiredColumns)) {
                    if (!columnNames.includes(colName)) {
                        try {
                            await run(`ALTER TABLE araclar ADD COLUMN ${colName} ${colDef}`);
                            console.log(`✅ araclar tablosuna ${colName} kolonu eklendi`);
                        } catch (err) {
                            if (!err.message.includes('duplicate column')) {
                                console.error(`❌ ${colName} kolonu eklenemedi:`, err);
                            }
                        }
                    }
                }
            }
        }
        
        // Kolon yapısını tekrar kontrol et
        const columns = await query('PRAGMA table_info(araclar)');
        const columnNames = columns.map(c => c.name);
        
        // SELECT sorgusu oluştur - mevcut kolonları kullan, alias kullanma
        let selectCols = ['id'];
        
        // Plaka için - önce yeni, sonra eski
        if (columnNames.includes('plaka')) {
            selectCols.push('plaka');
        } else if (columnNames.includes('arac_plaka')) {
            selectCols.push('arac_plaka');
        }
        
        // Marka için
        if (columnNames.includes('marka')) {
            selectCols.push('marka');
        } else if (columnNames.includes('arac_marka')) {
            selectCols.push('arac_marka');
        }
        
        // Model için
        if (columnNames.includes('model')) {
            selectCols.push('model');
        } else if (columnNames.includes('arac_model')) {
            selectCols.push('arac_model');
        }
        
        // Diğer kolonlar
        if (columnNames.includes('renk')) selectCols.push('renk');
        if (columnNames.includes('yil')) selectCols.push('yil');
        if (columnNames.includes('arac_tipi')) selectCols.push('arac_tipi');
        if (columnNames.includes('tenant_id')) selectCols.push('tenant_id');
        if (columnNames.includes('is_active')) selectCols.push('is_active');
        if (columnNames.includes('created_at')) selectCols.push('created_at');
        if (columnNames.includes('updated_at')) selectCols.push('updated_at');
        
        let querySql = `SELECT ${selectCols.join(', ')} FROM araclar WHERE 1=1`;
        const params = [];
        
        // tenant_id kontrolü - sadece kendi tenant_id'sine ait araçları göster
        if (columnNames.includes('tenant_id')) {
            querySql += ' AND tenant_id = ?';
            params.push(tenantId);
        }
        
        if (aktif_only === 'true') {
            if (columnNames.includes('is_active')) {
                querySql += ' AND (is_active = 1 OR is_active IS NULL)';
            }
        }
        
        // Sıralama için plaka kullan (doğru kolon adını kullan)
        if (columnNames.includes('plaka')) {
            querySql += ' ORDER BY plaka';
        } else if (columnNames.includes('arac_plaka')) {
            querySql += ' ORDER BY arac_plaka';
        } else {
            querySql += ' ORDER BY id';
        }
        
        const vehicles = await query(querySql, params);
        
        // Frontend'in beklediği formata dönüştür
        const formattedVehicles = vehicles.map(vehicle => {
            const formatted = { ...vehicle };
            
            // Eski kolon isimlerini yeni isimlere dönüştür (eğer varsa)
            if (vehicle.arac_plaka !== undefined && !vehicle.plaka) {
                formatted.plaka = vehicle.arac_plaka;
                delete formatted.arac_plaka;
            }
            if (vehicle.arac_marka !== undefined && !vehicle.marka) {
                formatted.marka = vehicle.arac_marka;
                delete formatted.arac_marka;
            }
            if (vehicle.arac_model !== undefined && !vehicle.model) {
                formatted.model = vehicle.arac_model;
                delete formatted.arac_model;
            }
            
            return formatted;
        });
        
        res.json({
            success: true,
            data: formattedVehicles
        });
    } catch (error) {
        console.error('❌ Araçlar yüklenirken hata:', error);
        console.error('❌ Hata detayı:', error.stack);
        res.status(500).json({
            success: false,
            error: 'Araçlar yüklenemedi',
            message: error.message
        });
    }
});

// Tüm ürünleri getir (Ayarlar sayfası için - EN ÖNCE, spesifik route)
app.get('/api/urunler/all', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        console.log(`🔍 /api/urunler/all - Tenant ID: ${tenantId}, req.tenantId: ${req.tenantId}, headers:`, req.headers['x-tenant-id']);
        
        // Sadece kullanıcının tenant_id'sine ait kayıtları getir
        // JOIN'de tenant kontrolü YAP - sadece aynı tenant'tan kategori adını göster
        // Sadece aktif ürünleri getir (is_active = 1, NULL değil)
        let urunler = await query(`
            SELECT p.*, pc.name as kategori_adi, pc.tenant_id as kategori_tenant_id
            FROM urunler p
            LEFT JOIN urunler_kategoriler pc ON p.urun_kategori_id = pc.id AND pc.tenant_id = p.tenant_id
            WHERE p.tenant_id = ? AND p.is_active = 1
            ORDER BY p.id ASC
        `, [tenantId]);
        
        // Kategori adı olmayan ürünler için kategori bilgisini tekrar çek (sadece aynı tenant'tan)
        const kategoriAdiOlmayanUrunler = urunler.filter(u => !u.kategori_adi && u.urun_kategori_id);
        
        if (kategoriAdiOlmayanUrunler.length > 0) {
            console.warn(`⚠️ Kategori adı olmayan ${kategoriAdiOlmayanUrunler.length} ürün bulundu (Tenant: ${tenantId})`);
            
            // Kategori adı olmayan ürünler için kategori bilgisini tekrar çek (SADECE aynı tenant'tan)
            for (const urun of kategoriAdiOlmayanUrunler) {
                if (urun.urun_kategori_id) {
                    // SADECE aynı tenant'tan kategori ara
                    const kategori = await query(
                        'SELECT name FROM urunler_kategoriler WHERE id = ? AND tenant_id = ?',
                        [urun.urun_kategori_id, tenantId]
                    );
                    
                    if (kategori.length > 0) {
                        // Tenant suffix'lerini temizle
                        let cleanName = kategori[0].name || '';
                        cleanName = cleanName.replace(/\s*\(Tenant\s+\d+\)\s*$/i, '').trim();
                        urun.kategori_adi = cleanName;
                        console.log(`✅ Kategori adı bulundu: ${urun.kategori_adi} (Ürün ID: ${urun.id})`);
                    } else {
                        console.warn(`⚠️ Kategori bulunamadı: ID ${urun.urun_kategori_id} (Tenant: ${tenantId}) - Ürün kategori ID'si yanlış tenant'a ait olabilir`);
                    }
                }
            }
        }
        
        // Kategori adı olan ürünler için de tenant suffix'lerini temizle
        urunler = urunler.map(u => {
            if (u.kategori_adi) {
                let cleanName = u.kategori_adi;
                cleanName = cleanName.replace(/\s*\(Tenant\s+\d+\)\s*$/i, '').trim();
                u.kategori_adi = cleanName;
            }
            // kategori_tenant_id'yi response'dan kaldır (frontend'e gerek yok)
            const { kategori_tenant_id, ...rest } = u;
            return rest;
        });
        
        // Son kontrol: Hala kategori adı olmayan ürünler var mı?
        const halaKategoriAdiOlmayan = urunler.filter(u => !u.kategori_adi && u.urun_kategori_id);
        if (halaKategoriAdiOlmayan.length > 0) {
            console.error(`❌ Hala kategori adı olmayan ${halaKategoriAdiOlmayan.length} ürün var (Tenant: ${tenantId}):`, 
                halaKategoriAdiOlmayan.map(u => ({ id: u.id, urun_adi: u.urun_adi, urun_kategori_id: u.urun_kategori_id }))
            );
        }
        
        console.log(`✅ Tüm ürünler listelendi (Ayarlar): ${urunler.length} adet (Tenant: ${tenantId}), Kategori adı olmayan: ${halaKategoriAdiOlmayan.length}`);
        res.json({ success: true, data: urunler, count: urunler.length });
    } catch (error) {
        console.error('❌ Ürünler listeleme hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

// Ürün grupları (kategori) listesi – Ayarlar > Veri Tanımları > Ürün Grupları için
// Liste: sadece silinmemiş (is_active=1) kayıtlar; durum (AKTİF/PASİF) ile filtre yok – hepsi gelir
app.get('/api/urun-gruplari', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);

        if (!tenantId) {
            return res.status(400).json({
                success: false,
                error: 'Tenant ID bulunamadı. Lütfen giriş yapın.'
            });
        }

        const cols = await query('PRAGMA table_info(urunler_kategoriler)');
        const hasDurum = cols && cols.some(c => c.name === 'durum');
        if (!hasDurum) {
            await run('ALTER TABLE urunler_kategoriler ADD COLUMN durum INTEGER DEFAULT 1');
        }

        // Sadece silinmemiş (is_active=1) kayıtlar; durum değeri ayrı kolon (AKTİF/PASİF tabloda kalır)
        let rows = await query(`
            SELECT id, name AS ad, COALESCE(durum, 1) AS durum
            FROM urunler_kategoriler
            WHERE tenant_id = ? AND (is_active = 1 OR is_active IS NULL)
            ORDER BY name ASC
        `, [tenantId]);

        // Güvenlik: rows falsy gelirse boş diziye çevir
        rows = Array.isArray(rows) ? rows : [];

        res.json({
            success: true,
            data: rows,
            count: rows.length
        });
    } catch (error) {
        console.error('❌ Ürün grupları listeleme hatası:', error);
        res.status(500).json({
            success: false,
            error: error.message || 'Ürün grupları yüklenemedi'
        });
    }
});

// Ürün grubu ekle (Ayarlar > Veri Tanımları)
app.post('/api/urun-gruplari', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const { name } = req.body;
        const ad = name != null ? String(name).trim() : '';
        if (!ad) {
            return res.status(400).json({ success: false, error: 'Ürün grubu adı gereklidir.' });
        }
        const kullaniciAdi = await getCurrentUsername(req);
        await run(
            'INSERT INTO urunler_kategoriler (tenant_id, name, is_active, created_by, updated_by) VALUES (?, ?, 1, ?, ?)',
            [tenantId, ad, kullaniciAdi, kullaniciAdi]
        );
        const inserted = await query(
            'SELECT id, name AS ad, 1 AS durum FROM urunler_kategoriler WHERE id = last_insert_rowid()'
        );
        res.json({ success: true, data: inserted[0] });
    } catch (error) {
        console.error('❌ Ürün grubu ekleme hatası:', error);
        res.status(500).json({
            success: false,
            error: error.message || 'Ürün grubu eklenemedi'
        });
    }
});

// Ürün grubu güncelle (ad ve/veya durum)
app.put('/api/urun-gruplari/:id', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const id = parseInt(req.params.id, 10);
        if (isNaN(id)) {
            return res.status(400).json({ success: false, error: 'Geçersiz ID.' });
        }
        const { name, is_active, durum } = req.body;
        const updates = [];
        const values = [];
        if (name !== undefined && name !== null) {
            const ad = String(name).trim();
            if (ad) {
                updates.push('name = ?');
                values.push(ad);
            }
        }
        if (is_active !== undefined && is_active !== null) {
            updates.push('is_active = ?');
            values.push(is_active ? 1 : 0);
        }
        if (durum !== undefined && durum !== null) {
            updates.push('durum = ?');
            values.push(durum === 1 ? 1 : 0);
        }
        if (updates.length === 0) {
            return res.status(400).json({ success: false, error: 'Güncellenecek alan bulunamadı.' });
        }
        const kullaniciAdi = await getCurrentUsername(req);
        updates.push('updated_by = ?');
        values.push(kullaniciAdi, id, tenantId);
        await run(
            `UPDATE urunler_kategoriler SET ${updates.join(', ')} WHERE id = ? AND tenant_id = ?`,
            values
        );
        const updated = await query(
            `SELECT id, name AS ad, COALESCE(durum, 1) AS durum FROM urunler_kategoriler WHERE id = ? AND tenant_id = ?`,
            [id, tenantId]
        );
        if (updated.length === 0) {
            return res.status(404).json({ success: false, error: 'Ürün grubu bulunamadı.' });
        }
        res.json({ success: true, data: updated[0] });
    } catch (error) {
        console.error('❌ Ürün grubu güncelleme hatası:', error);
        res.status(500).json({
            success: false,
            error: error.message || 'Ürün grubu güncellenemedi'
        });
    }
});

// Ürün grubu sil (soft delete: is_active = 0)
app.delete('/api/urun-gruplari/:id', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const id = parseInt(req.params.id, 10);
        if (isNaN(id)) {
            return res.status(400).json({ success: false, error: 'Geçersiz ID.' });
        }
        const check = await query('SELECT id FROM urunler_kategoriler WHERE id = ? AND tenant_id = ?', [id, tenantId]);
        if (check.length === 0) {
            return res.status(404).json({ success: false, error: 'Ürün grubu bulunamadı.' });
        }
        const kullaniciAdi = await getCurrentUsername(req);
        await run('UPDATE urunler_kategoriler SET is_active = 0, updated_by = ? WHERE id = ? AND tenant_id = ?', [kullaniciAdi, id, tenantId]);
        res.json({ success: true, message: 'Ürün grubu silindi.' });
    } catch (error) {
        console.error('❌ Ürün grubu silme hatası:', error);
        res.status(500).json({
            success: false,
            error: error.message || 'Ürün grubu silinemedi'
        });
    }
});

// Sadece aktif ürünleri listele (Sipariş formları için - sadece durum=1)
app.get('/api/urunler', async (req, res) => {
    try {
        // GÜVENLİK: Cookie kontrolü
        const cookieCheck = requireCookie(req, res);
        if (cookieCheck) return cookieCheck;
        
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(401).json({ 
                success: false, 
                error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' 
            });
        }
        
        // Sadece kullanıcının tenant_id'sine ait kayıtları getir
        // JOIN'de de tenant_id kontrolü yap - doğru tenant'ın kategori adını göster
        const urunler = await query(`
            SELECT p.*, pc.name as kategori_adi 
            FROM urunler p
            LEFT JOIN urunler_kategoriler pc ON p.urun_kategori_id = pc.id AND pc.tenant_id = p.tenant_id
            WHERE p.tenant_id = ? AND p.is_active = 1 AND p.durum = 1
            ORDER BY p.id ASC
        `, [tenantId]);
        
        console.log(`✅ Aktif ürünler listelendi (Formlar): ${urunler.length} adet (durum=1, Tenant: ${tenantId})`);
        res.json({ success: true, data: urunler, count: urunler.length });
    } catch (error) {
        console.error('❌ Ürünler listeleme hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

// Tek ürün getir (/:id route'u EN SON, parametreli route)
app.get('/api/urunler/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // Tenant kontrolü - sadece kendi tenant_id'sine ait ürünü getirebilir
        // JOIN'de de tenant_id kontrolü yap - doğru tenant'ın kategori adını göster
        const urun = await query(`
            SELECT 
                p.*,
                pc.name as kategori_adi
            FROM urunler p
            LEFT JOIN urunler_kategoriler pc ON p.urun_kategori_id = pc.id AND pc.tenant_id = p.tenant_id
            WHERE p.id = ? AND p.tenant_id = ?
        `, [id, tenantId]);
        
        if (urun.length === 0) {
            return res.status(404).json({ success: false, error: 'Ürün bulunamadı veya yetkiniz yok' });
        }
        
        // Eğer kategori_adi null ise, tekrar çek
        if (!urun[0].kategori_adi && urun[0].urun_kategori_id) {
            const kategori = await query(
                'SELECT name FROM urunler_kategoriler WHERE id = ? AND tenant_id = ?',
                [urun[0].urun_kategori_id, tenantId]
            );
            if (kategori.length > 0) {
                urun[0].kategori_adi = kategori[0].name;
            }
        }
        
        res.json({ success: true, data: urun[0] });
    } catch (error) {
        console.error('❌ Ürün getirme hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

// Yeni ürün ekle (POST)
app.post('/api/urunler', productUpload.single('urun_gorseli'), async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        const { urun_kategori_id, urun_adi, urun_fiyati, durum } = req.body;
        
        if (!urun_adi) {
            return res.status(400).json({ success: false, error: 'Ürün adı zorunludur' });
        }
        
        if (!urun_kategori_id) {
            return res.status(400).json({ success: false, error: 'Ürün grubu seçmelisiniz' });
        }
        
        // Ürün grubunun bu tenant'a ait olduğunu kontrol et
        const kategori = await query(
            'SELECT id FROM urunler_kategoriler WHERE id = ? AND tenant_id = ?',
            [urun_kategori_id, tenantId]
        );
        
        if (kategori.length === 0) {
            return res.status(404).json({ success: false, error: 'Ürün grubu bulunamadı veya yetkiniz yok' });
        }
        
        // Görsel yolu - Tenant-based
        let urun_gorseli = null;
        if (req.file) {
            urun_gorseli = getTenantRelativePath(tenantId, 'products', req.file.filename);
        } else if (req.body.urun_gorseli_default) {
            urun_gorseli = req.body.urun_gorseli_default;
        }
        
        // Depolama kullanımını güncelle (yeni görsel yüklendiyse)
        if (req.file && req.file.size) {
            await updateTenantStorageUsage(tenantId, req.file.size, req);
        }
        
        // Ürünü ekle
        const kullaniciAdi = await getCurrentUsername(req);
        const result = await query(
            `INSERT INTO urunler (tenant_id, urun_kategori_id, urun_adi, urun_fiyati, urun_gorseli, durum, is_active, created_at, updated_at, created_by, updated_by)
             VALUES (?, ?, ?, ?, ?, ?, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, ?, ?)`,
            [
                tenantId,
                urun_kategori_id,
                urun_adi,
                urun_fiyati || 0,
                urun_gorseli,
                durum !== undefined ? durum : 1,
                kullaniciAdi,
                kullaniciAdi
            ]
        );
        
        const newProductId = result.lastID;
        
        console.log(`✅ Yeni ürün eklendi: ID ${newProductId}, Tenant: ${tenantId}`);
        
        // Aktivite kaydı oluştur
        let userId = null;
        if (req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id);
        }
        if (!userId) {
            userId = req.userId || req.user?.id || null;
        }
        await logTenantActivity(
            tenantId,
            userId,
            'Yeni ürün oluşturuldu',
            'urun',
            newProductId,
            urun_adi,
            {
                urun_adi: urun_adi,
                urun_fiyati: urun_fiyati || 0,
                urun_kategori_id: urun_kategori_id
            },
            req
        );
        
        res.json({ 
            success: true, 
            message: 'Ürün eklendi',
            data: { id: newProductId }
        });
    } catch (error) {
        console.error('❌ Ürün ekleme hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

// Ürün güncelle
app.put('/api/urunler/:id', productUpload.single('urun_gorseli'), async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const updates = req.body;
        
        // Tenant_id kontrolü - sadece kendi tenant_id'sine ait ürünü güncelleyebilir
        const existing = await query(
            'SELECT id, tenant_id, urun_gorseli FROM urunler WHERE id = ? AND tenant_id = ?',
            [id, tenantId]
        );
        
        if (existing.length === 0) {
            return res.status(404).json({ success: false, error: 'Ürün bulunamadı veya yetkiniz yok' });
        }
        
        const fields = [];
        const values = [];
        
        // Ürün kategori ID güncelleniyorsa, yeni kategorinin de aynı tenant'a ait olduğunu kontrol et
        if (updates.urun_kategori_id !== undefined) {
            // Yeni kategorinin bu tenant'a ait olduğunu kontrol et
            const yeniKategori = await query(
                'SELECT id FROM urunler_kategoriler WHERE id = ? AND tenant_id = ?',
                [updates.urun_kategori_id, tenantId]
            );
            
            if (yeniKategori.length === 0) {
                return res.status(404).json({ success: false, error: 'Ürün grubu bulunamadı veya yetkiniz yok' });
            }
            
            fields.push('urun_kategori_id = ?');
            values.push(updates.urun_kategori_id);
        }
        // Eski ürün adını al (güncellemeden önce)
        let eskiUrunAdi = null;
        if (updates.urun_adi !== undefined) {
            const mevcutUrun = await query('SELECT urun_adi FROM urunler WHERE id = ? AND tenant_id = ?', [id, tenantId]);
            if (mevcutUrun.length > 0) {
                eskiUrunAdi = mevcutUrun[0].urun_adi;
            }
            fields.push('urun_adi = ?');
            values.push(updates.urun_adi);
        }
        
        // Yüklenen dosya varsa güncelle - Tenant-based
        if (req.file) {
            // Eski görseli kontrol et ve depolamadan çıkar
            const existingProduct = existing[0];
            if (existingProduct.urun_gorseli) {
                try {
                    const oldImagePath = path.join(__dirname, '..', existingProduct.urun_gorseli.replace(/^\//, ''));
                    if (fs.existsSync(oldImagePath)) {
                        const oldImageStats = fs.statSync(oldImagePath);
                        await decreaseTenantStorageUsage(tenantId, oldImageStats.size);
                        // Eski görseli sil
                        fs.unlinkSync(oldImagePath);
                        console.log('🗑️ Eski ürün görseli silindi:', oldImagePath);
                    }
                } catch (oldImageError) {
                    console.warn('⚠️ Eski görsel silinirken hata:', oldImageError);
                }
            }
            
            const newGorsel = getTenantRelativePath(tenantId, 'products', req.file.filename);
            fields.push('urun_gorseli = ?');
            values.push(newGorsel);
            console.log('✅ Ürün görseli güncellendi:', newGorsel);
            
            // Yeni görsel için depolama kullanımını artır
            if (req.file.size) {
                await updateTenantStorageUsage(tenantId, req.file.size, req);
            }
        } else if (updates.urun_gorseli !== undefined) {
            fields.push('urun_gorseli = ?');
            values.push(updates.urun_gorseli);
        }
        if (updates.urun_fiyati !== undefined) { fields.push('urun_fiyati = ?'); values.push(updates.urun_fiyati); }
        if (updates.durum !== undefined) { fields.push('durum = ?'); values.push(updates.durum); }
        if (updates.is_active !== undefined) { fields.push('is_active = ?'); values.push(updates.is_active ? 1 : 0); }
        
        // Tenant_id yoksa ekle
        if (existing[0].tenant_id === null) {
            fields.push('tenant_id = ?');
            values.push(tenantId);
        }
        
        fields.push('updated_at = ?');
        values.push(new Date().toISOString());
        const kullaniciAdi = await getCurrentUsername(req);
        fields.push('updated_by = ?');
        values.push(kullaniciAdi);
        values.push(id);
        
        await query(`UPDATE urunler SET ${fields.join(', ')} WHERE id = ? AND tenant_id = ?`, [...values, tenantId]);
        
        // ✅ DÜZELTME: Eğer ürün adı güncellendiyse, bu ürünü kullanan tüm sipariş kartlarındaki siparis_urun kolonunu da güncelle
        if (updates.urun_adi !== undefined && eskiUrunAdi && eskiUrunAdi !== updates.urun_adi) {
            try {
                const yeniUrunAdi = updates.urun_adi;
                
                // 1. siparis_urun_id ile eşleşen kayıtları güncelle (yeni sistem)
                const guncellenenSiparisSayisi1 = await run(`
                    UPDATE siparisler 
                    SET siparis_urun = ?, updated_at = CURRENT_TIMESTAMP
                    WHERE siparis_urun_id = ? AND tenant_id = ?
                `, [yeniUrunAdi, id, tenantId]);
                
                // 2. siparis_urun_id olmayan ama eski ürün adıyla eşleşen kayıtları da güncelle (eski sistem - geriye dönük uyumluluk)
                const guncellenenSiparisSayisi2 = await run(`
                    UPDATE siparisler 
                    SET siparis_urun = ?, siparis_urun_id = ?, updated_at = CURRENT_TIMESTAMP
                    WHERE siparis_urun = ? AND (siparis_urun_id IS NULL OR siparis_urun_id = 0) AND tenant_id = ?
                `, [yeniUrunAdi, id, eskiUrunAdi, tenantId]);
                
                const toplamGuncellenen = (guncellenenSiparisSayisi1?.changes || 0) + (guncellenenSiparisSayisi2?.changes || 0);
                
                console.log(`✅ Ürün adı güncellendi: "${eskiUrunAdi}" -> "${yeniUrunAdi}"`);
                console.log(`✅ ${toplamGuncellenen} adet sipariş kartındaki siparis_urun kolonu güncellendi`);
                if (guncellenenSiparisSayisi2?.changes > 0) {
                    console.log(`   - ${guncellenenSiparisSayisi2.changes} adet eski kayıt için siparis_urun_id de eklendi`);
                }
            } catch (siparisUpdateError) {
                console.error('⚠️ Sipariş kartlarındaki siparis_urun kolonu güncellenirken hata:', siparisUpdateError);
                // Hata olsa bile ürün güncellemesi başarılı, devam et
            }
        }
        
        // Aktivite kaydı oluştur
        let userId = null;
        if (req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id);
        }
        if (!userId) {
            userId = req.userId || req.user?.id || null;
        }
        const updatedProduct = await query('SELECT urun_adi FROM urunler WHERE id = ? AND tenant_id = ?', [id, tenantId]);
        const targetName = updatedProduct[0]?.urun_adi || `Ürün #${id}`;
        await logTenantActivity(
            tenantId,
            userId,
            'Ürün güncellendi',
            'urun',
            id,
            targetName,
            {
                urun_adi: updates.urun_adi || targetName,
                guncellenen_alanlar: Object.keys(updates).filter(key => ['urun_adi', 'urun_fiyati', 'urun_kategori_id', 'durum', 'is_active'].includes(key))
            },
            req
        );
        
        res.json({ success: true, message: 'Ürün güncellendi' });
    } catch (error) {
        console.error('❌ Ürün güncelleme hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

// Ürün sil (soft delete)
app.delete('/api/urunler/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // ID'yi integer'a çevir
        const productId = parseInt(id);
        const tenantIdInt = parseInt(tenantId);
        
        if (isNaN(productId) || productId <= 0) {
            return res.status(400).json({ success: false, error: 'Geçersiz ürün ID' });
        }
        
        // Tenant_id kontrolü - sadece kendi tenant_id'sine ait ürünü silebilir
        // ✅ ÖNCE id ile kontrol et (tenant kontrolsüz)
        const checkById = await query('SELECT id, tenant_id, is_active, durum FROM urunler WHERE id = ?', [productId]);
        
        if (checkById.length === 0) {
            console.error(`❌ Ürün bulunamadı: ID ${productId}`);
            return res.status(404).json({ success: false, error: 'Ürün bulunamadı' });
        }
        
        const existing = checkById[0];
        const existingTenantId = parseInt(existing.tenant_id);
        const existingIsActive = parseInt(existing.is_active);
        
        // Tenant kontrolü
        if (existingTenantId !== tenantIdInt) {
            console.error(`❌ Tenant uyumsuzluğu: Ürün tenant_id=${existingTenantId}, İstek tenant_id=${tenantIdInt}`);
            return res.status(403).json({ success: false, error: 'Bu ürüne erişim yetkiniz yok' });
        }
        
        // Zaten silinmiş mi kontrol et
        if (existingIsActive === 0) {
            console.log(`⚠️ Ürün zaten silinmiş: ID=${productId}, is_active=${existingIsActive}`);
            return res.json({ success: true, message: 'Ürün zaten silinmiş' });
        }
        
        // Ürün bilgilerini al (log için)
        const productInfo = await query('SELECT urun_adi, urun_fiyati FROM urunler WHERE id = ?', [productId]);
        const targetName = productInfo[0]?.urun_adi || `Ürün #${productId}`;
        
        console.log(`🔄 Ürün siliniyor: ID=${productId}, Tenant=${tenantIdInt}, Mevcut is_active=${existing.is_active}, durum=${existing.durum}`);
        console.log(`🔄 Tenant ID karşılaştırması: DB=${existingTenantId} (type: ${typeof existingTenantId}), İstek=${tenantIdInt} (type: ${typeof tenantIdInt}), Eşit mi? ${existingTenantId === tenantIdInt}`);
        
        // ✅ DÜZELTME: Tenant kontrolü zaten yapıldı, sadece ID ile güncelle (daha güvenilir)
        // Silme işlemlerinde yalnızca is_active alanı pasife çekilir; durum alanı değiştirilmez
        // WHERE koşulunda tenant_id kullanmıyoruz çünkü zaten kontrol ettik
        const kullaniciAdi = await getCurrentUsername(req);
        const updateSql = 'UPDATE urunler SET is_active = 0, updated_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = ?';
        
        console.log(`🔄 UPDATE sorgusu:`, updateSql);
        console.log(`🔄 UPDATE parametreleri: [${productId}]`);
        console.log(`🔄 Mevcut ürün durumu:`, {
            id: existing.id,
            tenant_id: existing.tenant_id,
            is_active: existing.is_active,
            durum: existing.durum
        });
        
        // ✅ DÜZELTME: run helper fonksiyonunu kullan (tenant-safe ve daha güvenilir)
        let updateResult;
        try {
            // run helper fonksiyonu Promise döndürür ve changes'i kontrol eder
            updateResult = await run(updateSql, [kullaniciAdi, productId]);
            console.log(`✅ UPDATE sonucu (run helper):`, updateResult);
        } catch (updateError) {
            console.error(`❌ UPDATE hatası (catch):`, updateError);
            console.error(`❌ UPDATE hatası stack:`, updateError.stack);
            throw updateError;
        }
        
        if (!updateResult) {
            console.error(`❌ UPDATE sonucu null!`);
            return res.status(500).json({ success: false, error: 'Ürün silme işlemi başarısız oldu (UPDATE sonucu null)' });
        }
        
        if (updateResult.changes === 0) {
            console.error(`❌ Ürün silme başarısız! Hiçbir satır güncellenmedi. ID: ${productId}`);
            console.error(`❌ Mevcut ürün:`, existing);
            console.error(`❌ UPDATE sonucu:`, updateResult);
            
            // Tekrar kontrol et
            const recheck = await query('SELECT id, tenant_id, is_active, durum FROM urunler WHERE id = ?', [productId]);
            console.error(`❌ Tekrar kontrol sonucu:`, recheck);
            
            if (recheck.length === 0) {
                console.error(`❌ Ürün artık yok! (başka bir işlem tarafından silinmiş olabilir)`);
                return res.status(404).json({ success: false, error: 'Ürün bulunamadı' });
            }
            
            if (parseInt(recheck[0].is_active) === 0) {
                console.log(`⚠️ Ürün zaten silinmiş (is_active=0)`);
                return res.json({ success: true, message: 'Ürün zaten silinmiş' });
            }
            
            return res.status(500).json({ success: false, error: 'Ürün silme işlemi başarısız oldu (hiçbir satır güncellenmedi)' });
        }
        
        console.log(`✅ UPDATE başarılı! ${updateResult.changes} satır güncellendi`);
        
        // ✅ Doğrulama: Güncellemenin gerçekten yapıldığını kontrol et
        const verifyAfterUpdate = await query('SELECT id, is_active, durum FROM urunler WHERE id = ?', [productId]);
        if (verifyAfterUpdate.length > 0) {
            const verifiedIsActive = parseInt(verifyAfterUpdate[0].is_active);
            console.log(`🔍 Güncelleme doğrulama: is_active=${verifiedIsActive} (beklenen: 0)`);
            
            if (verifiedIsActive !== 0) {
                console.error(`❌ Güncelleme doğrulama başarısız! is_active hala ${verifiedIsActive}`);
                // WAL checkpoint yap ve tekrar dene
                try {
                    await flushDatabase();
                    await new Promise(resolve => setTimeout(resolve, 300));
                    
                    // Checkpoint sonrası tekrar kontrol
                    const verifyAfterCheckpoint = await query('SELECT id, is_active, durum FROM urunler WHERE id = ?', [productId]);
                    if (verifyAfterCheckpoint.length > 0) {
                        const finalIsActive = parseInt(verifyAfterCheckpoint[0].is_active);
                        console.log(`🔍 Checkpoint sonrası doğrulama: is_active=${finalIsActive}`);
                        
                        if (finalIsActive !== 0) {
                            console.error(`❌ Checkpoint sonrası hala is_active=${finalIsActive}! UPDATE tekrar deneniyor...`);
                            // UPDATE'i tekrar dene
                            const retryResult = await run(updateSql, [kullaniciAdi, productId]);
                            console.log(`🔄 Retry UPDATE sonucu:`, retryResult);
                            
                            if (retryResult.changes === 0) {
                                return res.status(500).json({ success: false, error: 'Ürün silme işlemi başarısız oldu (güncelleme yapılamadı)' });
                            }
                        }
                    }
                } catch (flushError) {
                    console.warn(`⚠️ WAL checkpoint hatası (devam ediliyor):`, flushError.message);
                }
            }
        }
        
        // ✅ WAL modunda değişikliklerin hemen görünmesi için checkpoint yap
        try {
            await flushDatabase();
            console.log(`✅ WAL checkpoint tamamlandı`);
        } catch (flushError) {
            console.warn(`⚠️ WAL checkpoint hatası (devam ediliyor):`, flushError.message);
        }
        
        // ✅ Final doğrulama: Güncellemenin başarılı olduğunu kontrol et
        const finalVerify = await query('SELECT id, is_active, durum FROM urunler WHERE id = ?', [productId]);
        console.log(`🔍 Final doğrulama:`, finalVerify);
        
        if (finalVerify.length === 0) {
            console.error(`❌ Ürün bulunamadı (final doğrulama): ID ${productId}`);
            return res.status(500).json({ success: false, error: 'Ürün silme işlemi sonrası doğrulama başarısız' });
        }
        
        // is_active değerini kontrol et
        const finalIsActive = parseInt(finalVerify[0].is_active);
        console.log(`🔍 Final is_active değeri: ${finalIsActive} (beklenen: 0)`);
        
        if (finalIsActive !== 0) {
            console.error(`❌ Ürün silme başarısız! is_active hala ${finalIsActive}. Update result:`, updateResult);
            console.error(`❌ Final ürün durumu:`, finalVerify[0]);
            return res.status(500).json({ success: false, error: `Ürün silme işlemi başarısız oldu (is_active hala ${finalIsActive})` });
        }
        
        console.log(`✅ Ürün başarıyla silindi: ID ${productId}, is_active: ${finalIsActive}`);
        
        // Aktivite kaydı oluştur
        let userId = null;
        if (req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id);
        }
        if (!userId) {
            userId = req.userId || req.user?.id || null;
        }
        await logTenantActivity(
            tenantId,
            userId,
            'Ürün silindi',
            'urun',
            productId,
            targetName,
            {
                urun_adi: productInfo[0]?.urun_adi || null,
                urun_fiyati: productInfo[0]?.urun_fiyati || null
            },
            req
        );
        
        res.json({ success: true, message: 'Ürün silindi' });
    } catch (error) {
        console.error('❌ Ürün silme hatası:', error);
        console.error('❌ Hata detayı:', error.stack);
        res.status(500).json({ success: false, error: error.message });
    }
});

// Araç takip güncel konumlar endpoint
app.get('/api/arac-takip/guncel-konumlar', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // araclar_takip tablosunu kontrol et, yoksa oluştur
        try {
            const tableExists = await query(`
                SELECT name FROM sqlite_master WHERE type='table' AND name='araclar_takip'
            `);
            
            if (tableExists.length === 0) {
                await run(`
                    CREATE TABLE IF NOT EXISTS araclar_takip (
                        id INTEGER PRIMARY KEY AUTOINCREMENT,
                        arac_id INTEGER,
                        enlem REAL,
                        boylam REAL,
                        hiz REAL,
                        yon REAL,
                        timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,
                        tenant_id INTEGER DEFAULT 1
                    )
                `);
            }
            
            // araclar tablosunun var olduğundan emin ol
            const aracTableExists = await query(`
                SELECT name FROM sqlite_master WHERE type='table' AND name='araclar'
            `);
            
            if (aracTableExists.length === 0) {
                // araclar tablosu yoksa sadece araclar_takip verilerini döndür
                const locations = await query(`
                    SELECT * FROM araclar_takip
                    WHERE tenant_id = ? AND (is_active = 1 OR is_active IS NULL)
                    ORDER BY timestamp DESC
                    LIMIT 100
                `, [tenantId]);
                
                return res.json({
                    success: true,
                    data: locations || []
                });
            }
        } catch (tableError) {
            console.error('❌ Araç takip tablosu oluşturulurken hata:', tableError);
            // Tablo oluşturma hatası olsa bile devam et
        }
        
        // araclar tablosunun kolonlarını kontrol et
        const aracTableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='araclar'
        `);
        
        if (aracTableExists.length > 0) {
            const aracColumns = await query('PRAGMA table_info(araclar)');
            const aracColumnNames = aracColumns.map(c => c.name);
            
            // LEFT JOIN ile araç bilgilerini al (sadece mevcut kolonları kullan)
            try {
                // Hangi kolonların kullanılacağını belirle - sadece doğru kolonları kullan
                let selectColumns = 'at.*';
                if (aracColumnNames.includes('plaka')) {
                    selectColumns += ', a.plaka';
                }
                if (aracColumnNames.includes('marka')) {
                    selectColumns += ', a.marka';
                }
                if (aracColumnNames.includes('model')) {
                    selectColumns += ', a.model';
                }
                if (aracColumnNames.includes('renk')) {
                    selectColumns += ', a.renk';
                }
                if (aracColumnNames.includes('yil')) {
                    selectColumns += ', a.yil';
                }
                if (aracColumnNames.includes('arac_tipi')) {
                    selectColumns += ', a.arac_tipi';
                }
                
                const locations = await query(`
                    SELECT 
                        ${selectColumns}
                    FROM araclar_takip at
                    LEFT JOIN araclar a ON at.arac_id = a.id AND a.tenant_id = ?
                    WHERE at.tenant_id = ?
                    ORDER BY at.timestamp DESC
                    LIMIT 100
                `, [tenantId, tenantId]);
                
                // Debug: Araç sayısını logla
                console.log(`✅ Araç takip konumları yüklendi: ${locations?.length || 0} konum (Tenant: ${tenantId})`);
                
                // Eğer konum yoksa veya az konum varsa, araçlar tablosundan aktif araçları da ekle
                const aracColumns = await query('PRAGMA table_info(araclar)');
                const aracColumnNames = aracColumns.map(c => c.name);
                const hasTenantId = aracColumnNames.includes('tenant_id');
                const hasDurum = aracColumnNames.includes('durum');
                const hasIsActive = aracColumnNames.includes('is_active');
                
                // araclar tablosundan tüm araçları çek
                let araclarQuery = 'SELECT * FROM araclar WHERE tenant_id = ?';
                if (hasIsActive) {
                    araclarQuery += ' AND is_active = 1';
                }
                const araclar = await query(araclarQuery, [tenantId]);
                
                console.log(`ℹ️ Araçlar tablosundan ${araclar.length} araç bulundu (Tenant: ${tenantId})`);
                
                // Konum verilerini araçlarla birleştir
                const aracMap = new Map();
                
                // Önce konum verilerini işle
                if (locations && locations.length > 0) {
                    for (const loc of locations) {
                        const aracId = loc.arac_id || loc.id;
                        if (aracId) {
                            // Aktif teslimat kontrolü - araclar_takip_teslimatlar tablosunda aktif kayıt var mı?
                            let durum = 'beklemede';
                            
                            try {
                                const aktifTeslimat = await query(`
                                    SELECT * FROM araclar_takip_teslimatlar
                                    WHERE arac_id = ? AND tenant_id = ? AND durum = 'aktif'
                                    ORDER BY baslangic_zamani DESC
                                    LIMIT 1
                                `, [aracId, tenantId]);
                                
                                if (aktifTeslimat && aktifTeslimat.length > 0) {
                                    durum = 'teslimatta';
                                    if (window.FLOOVON_DEBUG) {
                                        console.log(`🔍 Araç ${aracId}: Aktif teslimat bulundu, durum = 'teslimatta'`);
                                    }
                                } else {
                                    // Aktif teslimat yok - beklemede olmalı
                                    durum = 'beklemede';
                                    if (window.FLOOVON_DEBUG) {
                                        console.log(`🔍 Araç ${aracId}: Aktif teslimat yok, durum = 'beklemede'`);
                                    }
                                }
                            } catch (teslimatError) {
                                // Tablo yoksa veya hata varsa, beklemede kabul et (güvenli varsayılan)
                                durum = 'beklemede';
                                console.warn(`⚠️ Araç ${aracId} için teslimat kontrolü hatası:`, teslimatError.message);
                            }
                            
                            // Son güncelleme zamanını belirle - öncelik sırası: kayit_zamani > timestamp
                            const lastUpdateTime = loc.kayit_zamani || loc.timestamp || loc.son_guncelleme || loc.guncelleme_zamani;
                            
                            aracMap.set(aracId, {
                                id: aracId,
                                arac_id: aracId,
                                plaka: loc.plaka || '',
                                durum: durum,
                                konum_lat: loc.enlem || loc.konum_lat || null,
                                konum_lng: loc.boylam || loc.konum_lng || null,
                                konum_adi: loc.konum_adi || null,
                                hiz: loc.hiz || null,
                                timestamp: lastUpdateTime,
                                kayit_zamani: loc.kayit_zamani || null,
                                son_guncelleme: loc.son_guncelleme || null,
                                guncelleme_zamani: loc.guncelleme_zamani || null
                            });
                        }
                    }
                }
                
                // Sonra araçlar tablosundaki araçları ekle (konum yoksa)
                for (const arac of araclar) {
                    const aracId = arac.id;
                    if (!aracMap.has(aracId)) {
                        // Durum kontrolü - önce araclar_takip_teslimatlar tablosunda aktif teslimat var mı kontrol et
                        let durum = 'beklemede';
                        try {
                            const aktifTeslimat = await query(`
                                SELECT * FROM araclar_takip_teslimatlar
                                WHERE arac_id = ? AND tenant_id = ? AND durum = 'aktif'
                                ORDER BY baslangic_zamani DESC
                                LIMIT 1
                            `, [aracId, tenantId]);
                            
                            if (aktifTeslimat && aktifTeslimat.length > 0) {
                                durum = 'teslimatta';
                            } else {
                                // Aktif teslimat yok - kesinlikle beklemede olmalı
                                durum = 'beklemede';
                            }
                        } catch (teslimatError) {
                            // Hata durumunda beklemede kabul et (güvenli varsayılan)
                            durum = 'beklemede';
                        }
                        
                        aracMap.set(aracId, {
                            id: aracId,
                            arac_id: aracId,
                            plaka: arac.plaka || '',
                            durum: durum,
                            konum_lat: null,
                            konum_lng: null,
                            konum_adi: null,
                            hiz: null,
                            timestamp: null
                        });
                    } else {
                        // Konum varsa ama plaka eksikse ekle
                        const existing = aracMap.get(aracId);
                        if (!existing.plaka && arac.plaka) {
                            existing.plaka = arac.plaka;
                        }
                    }
                }
                
                // Map'ten array'e çevir
                const finalData = Array.from(aracMap.values());
                
                console.log(`✅ Toplam ${finalData.length} araç döndürülüyor (${finalData.filter(a => a.durum === 'teslimatta').length} aktif)`);
                
                return res.json({
                    success: true,
                    data: finalData
                });
            } catch (joinError) {
                console.warn('⚠️ JOIN hatası, sadece araclar_takip verileri döndürülüyor:', joinError.message);
            }
        }
        
        // JOIN yapılamazsa veya araclar tablosu yoksa sadece araclar_takip verilerini döndür
        const locations = await query(`
            SELECT * FROM araclar_takip
            WHERE tenant_id = ?
            ORDER BY timestamp DESC
            LIMIT 100
        `, [tenantId]);
        
        // araclar tablosundan da araçları çek
        const aracTableExistsFallback = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='araclar'
        `);
        
        if (aracTableExistsFallback.length > 0) {
            const aracColumns = await query('PRAGMA table_info(araclar)');
            const aracColumnNames = aracColumns.map(c => c.name);
            const hasTenantId = aracColumnNames.includes('tenant_id');
            const hasDurum = aracColumnNames.includes('durum');
            const hasIsActive = aracColumnNames.includes('is_active');
            
            let araclarQuery = 'SELECT * FROM araclar';
            const params = [];
            if (hasTenantId) {
                araclarQuery += ' WHERE tenant_id = ?';
                params.push(tenantId);
                if (hasIsActive) {
                    araclarQuery += ' AND is_active = 1';
                }
            } else if (hasIsActive) {
                araclarQuery += ' WHERE is_active = 1';
            }
            
            const araclar = await query(araclarQuery, params);
            
            // Konum verilerini araçlarla birleştir
            const aracMap = new Map();
            
            // Önce konum verilerini işle
            if (locations && locations.length > 0) {
                for (const loc of locations) {
                    const aracId = loc.arac_id || loc.id;
                    if (aracId) {
                        // Aktif teslimat kontrolü
                        let durum = 'beklemede';
                        try {
                            const aktifTeslimat = await query(`
                                SELECT * FROM araclar_takip_teslimatlar
                                WHERE arac_id = ? AND tenant_id = ? AND durum = 'aktif'
                                ORDER BY baslangic_zamani DESC
                                LIMIT 1
                            `, [aracId, tenantId]);
                            
                            if (aktifTeslimat && aktifTeslimat.length > 0) {
                                durum = 'teslimatta';
                            }
                        } catch (teslimatError) {
                            // Tablo yoksa veya hata varsa, beklemede kabul et (güvenli varsayılan)
                            durum = 'beklemede';
                        }
                        
                        aracMap.set(aracId, {
                            id: aracId,
                            arac_id: aracId,
                            plaka: loc.plaka || '',
                            durum: durum,
                            konum_lat: loc.enlem || loc.konum_lat || null,
                            konum_lng: loc.boylam || loc.konum_lng || null,
                            konum_adi: loc.konum_adi || null,
                            hiz: loc.hiz || null,
                            timestamp: loc.timestamp || null
                        });
                    }
                }
            }
            
            // Sonra araçlar tablosundaki araçları ekle (konum yoksa)
            for (const arac of araclar) {
                const aracId = arac.id;
                if (!aracMap.has(aracId)) {
                    // Durum kontrolü - önce araclar_takip_teslimatlar tablosunda aktif teslimat var mı kontrol et
                    let durum = 'beklemede';
                    try {
                        const aktifTeslimat = await query(`
                            SELECT * FROM araclar_takip_teslimatlar
                            WHERE arac_id = ? AND tenant_id = ? AND durum = 'aktif'
                            ORDER BY baslangic_zamani DESC
                            LIMIT 1
                        `, [aracId, tenantId]);
                        
                        if (aktifTeslimat && aktifTeslimat.length > 0) {
                            durum = 'teslimatta';
                        } else {
                            // Aktif teslimat yok - kesinlikle beklemede olmalı
                            durum = 'beklemede';
                        }
                    } catch (teslimatError) {
                        // Hata durumunda beklemede kabul et (güvenli varsayılan)
                        durum = 'beklemede';
                    }
                    
                    aracMap.set(aracId, {
                        id: aracId,
                        arac_id: aracId,
                        plaka: arac.plaka || '',
                        durum: durum,
                        konum_lat: null,
                        konum_lng: null,
                        konum_adi: null,
                        hiz: null,
                        timestamp: null
                    });
                } else {
                    // Konum varsa ama plaka eksikse ekle
                    const existing = aracMap.get(aracId);
                    if (!existing.plaka && arac.plaka) {
                        existing.plaka = arac.plaka;
                    }
                }
            }
            
            const finalData = Array.from(aracMap.values());
            console.log(`✅ Araç takip konumları yüklendi (fallback): ${finalData.length} araç (Tenant: ${tenantId})`);
            
            return res.json({
                success: true,
                data: finalData
            });
        }
        
        // Debug: Konum sayısını logla
        console.log(`✅ Araç takip konumları yüklendi (fallback): ${locations?.length || 0} konum (Tenant: ${tenantId})`);
        
        res.json({
            success: true,
            data: locations || []
        });
    } catch (error) {
        console.error('❌ Araç takip konumları yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Araç takip konumları yüklenemedi',
            message: error.message
        });
    }
});

// araclar_takip tablosunu temizle (debug/cleanup için)
app.delete('/api/arac-takip/cleanup', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // araclar_takip tablosundaki tüm kayıtları soft delete (is_active = 0)
        const result = await run(`UPDATE araclar_takip SET is_active = 0 WHERE tenant_id = ? AND (is_active = 1 OR is_active IS NULL)`, [tenantId]);
        
        console.log(`✅ araclar_takip tablosu temizlendi (soft): ${result.changes} kayıt (Tenant: ${tenantId})`);
        
        res.json({
            success: true,
            message: `araclar_takip tablosu temizlendi: ${result.changes} kayıt silindi`,
            deletedCount: result.changes
        });
    } catch (error) {
        console.error('❌ araclar_takip temizleme hatası:', error);
        res.status(500).json({
            success: false,
            error: 'araclar_takip tablosu temizlenemedi',
            message: error.message
        });
    }
});

// Mevcut kullanıcının araç takip durumu (teslimatta mı / beklemede mi) – mobil header için
app.get('/api/arac-takip/durum', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        let userId = req.userId || req.user?.id || null;
        if (!userId && req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id, 10);
            if (isNaN(userId) || userId <= 0) userId = null;
        }
        if (!userId) {
            return res.json({ success: true, data: { durum: 'beklemede' } });
        }
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='araclar_takip_teslimatlar'
        `);
        if (tableExists.length === 0) {
            return res.json({ success: true, data: { durum: 'beklemede' } });
        }
        const aktif = await query(`
            SELECT id, arac_id, baslangic_zamani FROM araclar_takip_teslimatlar
            WHERE tenant_id = ? AND user_id = ? AND durum = 'aktif'
            ORDER BY baslangic_zamani DESC LIMIT 1
        `, [tenantId, userId]);
        if (aktif && aktif.length > 0) {
            let plaka = null;
            let marka = null;
            let model = null;
            try {
                const aracRows = await query(
                    'SELECT plaka, marka, model FROM araclar WHERE id = ? AND tenant_id = ?',
                    [aktif[0].arac_id, tenantId]
                );
                if (aracRows && aracRows.length > 0) {
                    plaka = aracRows[0].plaka || null;
                    marka = aracRows[0].marka || null;
                    model = aracRows[0].model || null;
                }
            } catch (lookupError) {
                console.warn('⚠️ Araç bilgisi okunamadı (durum endpoint) :', lookupError.message);
            }
            return res.json({
                success: true,
                data: {
                    durum: 'teslimatta',
                    teslimat_id: aktif[0].id,
                    arac_id: aktif[0].arac_id,
                    baslangic_zamani: aktif[0].baslangic_zamani,
                    plaka,
                    marka,
                    model
                }
            });
        }
        return res.json({ success: true, data: { durum: 'beklemede' } });
    } catch (error) {
        console.error('❌ Araç takip durum hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Araç takip durumu alınamadı',
            message: error.message
        });
    }
});

// Teslimat başlatma endpoint'i
app.post('/api/arac-takip/:id/teslimat/baslat', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // user_id: body (surucu_id), cookie (floovon_user_id), veya oturum
        const { surucu_id, baslangic_konum_lat, baslangic_konum_lng } = req.body;
        let userId = surucu_id || req.userId || req.user?.id;
        if (!userId && req.cookies && req.cookies.floovon_user_id) {
            userId = parseInt(req.cookies.floovon_user_id, 10);
            if (isNaN(userId) || userId <= 0) userId = null;
        }
        
        if (!userId || baslangic_konum_lat === undefined || baslangic_konum_lng === undefined) {
            return res.status(400).json({ 
                success: false, 
                error: 'Eksik parametreler: surucu_id (veya oturum user_id), baslangic_konum_lat, baslangic_konum_lng gerekli' 
            });
        }
        
        // araclar_takip_teslimatlar tablosunu kontrol et ve oluştur
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='araclar_takip_teslimatlar'
        `);
        
        if (tableExists.length === 0) {
            await run(`
                CREATE TABLE IF NOT EXISTS araclar_takip_teslimatlar (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    arac_id INTEGER NOT NULL,
                    user_id INTEGER NOT NULL,
                    baslangic_konum_lat REAL,
                    baslangic_konum_lng REAL,
                    bitis_konum_lat REAL,
                    bitis_konum_lng REAL,
                    baslangic_zamani DATETIME DEFAULT CURRENT_TIMESTAMP,
                    bitis_zamani DATETIME,
                    durum TEXT DEFAULT 'aktif',
                    tenant_id INTEGER DEFAULT 1,
                    kayit_zamani DATETIME DEFAULT CURRENT_TIMESTAMP,
                    son_guncelleme DATETIME,
                    guncelleme_zamani DATETIME
                )
            `);
        } else {
            // Tablo varsa, mevcut kolonları kontrol et ve eksik olanları ekle
            const columns = await query('PRAGMA table_info(araclar_takip_teslimatlar)');
            const columnNames = columns.map(c => c.name);
            
            // kayit_zamani kolonu yoksa ekle
            if (!columnNames.includes('kayit_zamani')) {
                try {
                    await run(`ALTER TABLE araclar_takip_teslimatlar ADD COLUMN kayit_zamani DATETIME DEFAULT CURRENT_TIMESTAMP`);
                } catch (alterError) {
                    // Kolon zaten varsa veya başka bir hata varsa görmezden gel
                    console.warn('⚠️ kayit_zamani kolonu eklenirken hata (normal olabilir):', alterError.message);
                }
            }
        }
        
        // Mevcut kolonları kontrol et - hangi kolonları kullanacağımızı belirle
        const columns = await query('PRAGMA table_info(araclar_takip_teslimatlar)');
        const columnNames = columns.map(c => c.name);
        
        // INSERT için kolonları belirle - sadece mevcut kolonları kullan
        let insertColumns = ['arac_id', 'user_id', 'baslangic_konum_lat', 'baslangic_konum_lng', 'durum', 'tenant_id'];
        let insertValues = [id, userId, baslangic_konum_lat, baslangic_konum_lng, 'aktif', tenantId];
        
        // kayit_zamani kolonu varsa ekle
        if (columnNames.includes('kayit_zamani')) {
            insertColumns.push('kayit_zamani');
            insertValues.push(new Date().toISOString());
        }
        
        // Yeni teslimat kaydı oluştur
        const placeholders = insertColumns.map(() => '?').join(', ');
        const result = await run(`
            INSERT INTO araclar_takip_teslimatlar 
            (${insertColumns.join(', ')})
            VALUES (${placeholders})
        `, insertValues);
        
        const teslimatId = result.lastID;
        
        // İlk konum kaydını araclar_takip tablosuna ekle
        // Önce tablo yapısını kontrol et
        const aracTakipColumns = await query('PRAGMA table_info(araclar_takip)');
        const aracTakipColumnNames = aracTakipColumns.map(c => c.name);
        
        // INSERT için kolonları belirle - sadece mevcut kolonları kullan
        let aracTakipInsertColumns = ['arac_id', 'enlem', 'boylam', 'tenant_id'];
        let aracTakipInsertValues = [id, baslangic_konum_lat, baslangic_konum_lng, tenantId];
        
        // timestamp kolonu varsa ekle (eğer yoksa DEFAULT CURRENT_TIMESTAMP zaten çalışır)
        if (aracTakipColumnNames.includes('timestamp')) {
            // timestamp kolonu varsa ama değer vermiyoruz, DEFAULT kullanılacak
        }
        
        // kayit_zamani kolonu varsa ekle
        if (aracTakipColumnNames.includes('kayit_zamani')) {
            aracTakipInsertColumns.push('kayit_zamani');
            aracTakipInsertValues.push(new Date().toISOString());
        }
        
        const aracTakipPlaceholders = aracTakipInsertColumns.map(() => '?').join(', ');
        await run(`
            INSERT INTO araclar_takip 
            (${aracTakipInsertColumns.join(', ')})
            VALUES (${aracTakipPlaceholders})
        `, aracTakipInsertValues);
        
        res.json({
            success: true,
            data: {
                id: teslimatId,
                arac_id: parseInt(id),
                user_id: userId,
                baslangic_konum_lat: baslangic_konum_lat,
                baslangic_konum_lng: baslangic_konum_lng,
                durum: 'aktif',
                baslangic_zamani: new Date().toISOString()
            }
        });
    } catch (error) {
        console.error('❌ Teslimat başlatma hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Teslimat başlatılamadı',
            message: error.message
        });
    }
});

// Konum güncelleme endpoint'i
app.post('/api/arac-takip/:id/konum', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        const { latitude, longitude, hiz, yon, yukseklik, dogruluk, surucu_id, konum_adi } = req.body;
        
        if (latitude === undefined || longitude === undefined) {
            return res.status(400).json({ 
                success: false, 
                error: 'Eksik parametreler: latitude ve longitude gerekli' 
            });
        }
        
        // araclar_takip tablosuna konum kaydı ekle
        // Önce tablo yapısını kontrol et
        const columns = await query('PRAGMA table_info(araclar_takip)');
        const columnNames = columns.map(c => c.name);
        const hasKayitZamani = columnNames.includes('kayit_zamani');
        
        // INSERT için kolonları belirle
        let insertColumns = ['arac_id', 'enlem', 'boylam', 'hiz', 'yon', 'timestamp', 'tenant_id'];
        let insertValues = [id, latitude, longitude, hiz || null, yon || null, new Date().toISOString(), tenantId];
        
        // kayit_zamani kolonu varsa ekle
        if (hasKayitZamani) {
            insertColumns.push('kayit_zamani');
            insertValues.push(new Date().toISOString());
        }
        
        const placeholders = insertColumns.map(() => '?').join(', ');
        await run(`
            INSERT INTO araclar_takip 
            (${insertColumns.join(', ')})
            VALUES (${placeholders})
        `, insertValues);
        
        res.json({
            success: true,
            data: {
                arac_id: parseInt(id),
                enlem: latitude,
                boylam: longitude,
                hiz: hiz || null,
                yon: yon || null,
                konum_adi: konum_adi || null
            }
        });
    } catch (error) {
        console.error('❌ Konum güncelleme hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Konum güncellenemedi',
            message: error.message
        });
    }
});

// Konum alma endpoint'i
app.get('/api/arac-takip/:id/konum', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // Son konum kaydını al
        const locations = await query(`
            SELECT * FROM araclar_takip
            WHERE arac_id = ? AND tenant_id = ?
            ORDER BY timestamp DESC
            LIMIT 1
        `, [id, tenantId]);
        
        if (locations.length === 0) {
            return res.json({
                success: true,
                data: null
            });
        }
        
        const location = locations[0];
        
        // Mevcut kolonları kontrol et - kayit_zamani varsa onu kullan, yoksa timestamp kullan
        const columns = await query('PRAGMA table_info(araclar_takip)');
        const columnNames = columns.map(c => c.name);
        const hasKayitZamani = columnNames.includes('kayit_zamani');
        
        // Son güncelleme zamanını belirle - öncelik sırası: kayit_zamani > timestamp
        const lastUpdateTime = hasKayitZamani && location.kayit_zamani 
            ? location.kayit_zamani 
            : (location.timestamp || location.son_guncelleme || location.guncelleme_zamani);
        
        res.json({
            success: true,
            data: {
                arac_id: location.arac_id,
                enlem: location.enlem,
                boylam: location.boylam,
                hiz: location.hiz,
                yon: location.yon,
                timestamp: lastUpdateTime,
                kayit_zamani: hasKayitZamani ? location.kayit_zamani : null,
                son_guncelleme: location.son_guncelleme || null,
                guncelleme_zamani: location.guncelleme_zamani || null,
                konum_adi: location.konum_adi || null
            }
        });
    } catch (error) {
        console.error('❌ Konum alma hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Konum alınamadı',
            message: error.message
        });
    }
});

// Araç takip - Geçmiş konumlar
app.get('/api/arac-takip/:id/gecmis', async (req, res) => {
    try {
        const { id } = req.params;
        const { baslangic, limit = 1000, teslimat_id } = req.query;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        let querySql = `
            SELECT * FROM araclar_takip
            WHERE arac_id = ? AND tenant_id = ?
        `;
        const queryParams = [id, tenantId];
        
        // Teslimat ID varsa onu kullan (kolon kontrolü yap)
        // Önce tablo yapısını kontrol et
        const tableInfo = await query('PRAGMA table_info(araclar_takip)');
        const hasTeslimatId = tableInfo.some(col => col.name === 'teslimat_id');
        
        if (teslimat_id && hasTeslimatId) {
            querySql += ` AND teslimat_id = ?`;
            queryParams.push(teslimat_id);
        } else if (teslimat_id && !hasTeslimatId) {
            // teslimat_id kolonu yoksa, bu filtreyi atla
            console.warn('⚠️ araclar_takip tablosunda teslimat_id kolonu bulunamadı, filtre atlandı');
        }
        
        if (!teslimat_id && baslangic) {
            // Başlangıç zamanından itibaren filtrele
            querySql += ` AND timestamp >= ?`;
            queryParams.push(baslangic);
        }
        
        querySql += ` ORDER BY timestamp ASC`;
        
        if (limit) {
            querySql += ` LIMIT ?`;
            queryParams.push(parseInt(limit));
        }
        
        const locations = await query(querySql, queryParams);
        
        res.json({
            success: true,
            data: locations,
            count: locations.length
        });
    } catch (error) {
        console.error('❌ Araç takip geçmiş konumlar hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Geçmiş konumlar getirilemedi',
            message: error.message
        });
    }
});

// Teslimat tamamlama endpoint'i
app.post('/api/arac-takip/:id/teslimat/tamamla', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        const { bitis_konum_lat, bitis_konum_lng, toplam_sure } = req.body;
        
        // araclar_takip_teslimatlar tablosunu kontrol et
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='araclar_takip_teslimatlar'
        `);
        
        if (tableExists.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Teslimat kaydı bulunamadı'
            });
        }
        
        // Aktif teslimat kaydını bul ve güncelle
        const teslimatlar = await query(`
            SELECT * FROM araclar_takip_teslimatlar
            WHERE arac_id = ? AND tenant_id = ? AND durum = 'aktif'
            ORDER BY baslangic_zamani DESC
            LIMIT 1
        `, [id, tenantId]);
        
        if (teslimatlar.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Aktif teslimat kaydı bulunamadı'
            });
        }
        
        const teslimat = teslimatlar[0];
        
        // Teslimat kaydını güncelle (tabloda updated_at yok, son_guncelleme/guncelleme_zamani var)
        const columns = await query('PRAGMA table_info(araclar_takip_teslimatlar)');
        const columnNames = columns.map(c => c.name);
        let setExtras = '';
        if (columnNames.includes('son_guncelleme')) setExtras += ', son_guncelleme = CURRENT_TIMESTAMP';
        else if (columnNames.includes('guncelleme_zamani')) setExtras += ', guncelleme_zamani = CURRENT_TIMESTAMP';

        const updateResult = await run(`
            UPDATE araclar_takip_teslimatlar
            SET bitis_konum_lat = ?,
                bitis_konum_lng = ?,
                bitis_zamani = CURRENT_TIMESTAMP,
                durum = 'tamamlandi'
                ${setExtras}
            WHERE id = ? AND tenant_id = ?
        `, [bitis_konum_lat || null, bitis_konum_lng || null, teslimat.id, tenantId]);
        
        console.log(`✅ Teslimat tamamlandı: Araç ${id}, durum = 'tamamlandi' olarak güncellendi (${updateResult.changes} kayıt güncellendi)`);
        
        // Güncelleme sonrası kontrol et - hala aktif kayıt var mı?
        const aktifKontrol = await query(`
            SELECT COUNT(*) as count FROM araclar_takip_teslimatlar
            WHERE arac_id = ? AND tenant_id = ? AND durum = 'aktif'
        `, [id, tenantId]);
        
        if (aktifKontrol[0]?.count > 0) {
            console.warn(`⚠️ UYARI: Araç ${id} için hala ${aktifKontrol[0].count} aktif teslimat kaydı var!`);
        } else {
            console.log(`✅ Araç ${id} için aktif teslimat kaydı yok - durum 'beklemede' olmalı`);
        }
        
        // Son konum kaydını ekle
        if (bitis_konum_lat && bitis_konum_lng) {
            await run(`
            INSERT INTO araclar_takip 
                (arac_id, enlem, boylam, timestamp, tenant_id)
                VALUES (?, ?, ?, CURRENT_TIMESTAMP, ?)
            `, [id, bitis_konum_lat, bitis_konum_lng, tenantId]);
        }
        
        res.json({
            success: true,
            data: {
                id: teslimat.id,
                arac_id: parseInt(id),
                durum: 'tamamlandi',
                bitis_konum_lat: bitis_konum_lat || null,
                bitis_konum_lng: bitis_konum_lng || null,
                bitis_zamani: new Date().toISOString(),
                toplam_sure: toplam_sure || null
            }
        });
    } catch (error) {
        console.error('❌ Teslimat tamamlama hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Teslimat tamamlanamadı',
            message: error.message
        });
    }
});

