app.post('/api/arac-takip/temizle-aktif-teslimatlar', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // araclar_takip_teslimatlar tablosunu kontrol et
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='araclar_takip_teslimatlar'
        `);
        
        if (tableExists.length === 0) {
            return res.json({
                success: true,
                message: 'araclar_takip_teslimatlar tablosu bulunamadı, temizleme gerekmiyor',
                cleaned: 0
            });
        }
        
        // Önce aktif kayıtları say
        const aktifKayitlar = await query(`
            SELECT COUNT(*) as count FROM araclar_takip_teslimatlar
            WHERE tenant_id = ? AND durum = 'aktif'
        `, [tenantId]);
        
        const aktifSayisi = aktifKayitlar[0]?.count || 0;
        
        if (aktifSayisi === 0) {
            return res.json({
                success: true,
                message: 'Aktif teslimat kaydı bulunamadı',
                cleaned: 0
            });
        }
        
        // Tüm aktif kayıtları tamamlandi yap
        const updateResult = await run(`
            UPDATE araclar_takip_teslimatlar
            SET durum = 'tamamlandi',
                bitis_zamani = CURRENT_TIMESTAMP,
                updated_at = CURRENT_TIMESTAMP
            WHERE tenant_id = ? AND durum = 'aktif'
        `, [tenantId]);
        
        console.log(`✅ ${updateResult.changes} aktif teslimat kaydı temizlendi (Tenant: ${tenantId})`);
        
        res.json({
            success: true,
            message: `${updateResult.changes} aktif teslimat kaydı temizlendi`,
            cleaned: updateResult.changes
        });
    } catch (error) {
        console.error('❌ Aktif teslimat kayıtları temizleme hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Aktif teslimat kayıtları temizlenemedi',
            message: error.message
        });
    }
});

// OpenStreetMap Nominatim Geocoding Proxy (CORS sorunu için)
app.get('/api/geocoding/reverse', async (req, res) => {
    try {
        // Query parametrelerini al - Express query parser kullan
        // Frontend'den 'lon' parametresi gelebilir, backend 'lng' bekliyor - ikisini de kontrol et
        let lat = req.query.lat;
        let lng = req.query.lng || req.query.lon; // 'lon' parametresini de kabul et
        const zoom = req.query.zoom || 18;
        
        // Eğer query'de yoksa URL'den manuel parse et
        if (!lat || !lng || lat === 'undefined' || lng === 'undefined' || String(lat).trim() === '' || String(lng).trim() === '') {
            const urlModule = require('url');
            const parsedUrl = urlModule.parse(req.url, true);
            lat = parsedUrl.query.lat || lat;
            lng = parsedUrl.query.lng || parsedUrl.query.lon || lng; // 'lon' parametresini de kontrol et
            
            // Hala yoksa URL string'den regex ile çıkar
            if ((!lat || lat === 'undefined' || String(lat).trim() === '') || (!lng || lng === 'undefined' || String(lng).trim() === '')) {
                const latMatch = req.url.match(/[?&]lat=([^&]+)/);
                const lngMatch = req.url.match(/[?&]lng=([^&]+)/) || req.url.match(/[?&]lon=([^&]+)/);
                if (latMatch) lat = decodeURIComponent(latMatch[1]);
                if (lngMatch) lng = decodeURIComponent(lngMatch[1]);
            }
        }
        
        // String'den number'a çevir
        const latNum = parseFloat(lat);
        const lngNum = parseFloat(lng);
        
        // Debug log
        console.log('🔍 Geocoding reverse request:', { 
            lat: latNum, 
            lng: lngNum, 
            zoom, 
            rawQuery: req.query, 
            url: req.url,
            originalLat: lat,
            originalLng: lng,
            hasLon: !!req.query.lon
        });
        
        if (isNaN(latNum) || isNaN(lngNum) || latNum === 0 || lngNum === 0) {
            console.error('❌ Geocoding - Geçersiz parametreler:', { lat, lng, latNum, lngNum, url: req.url, query: req.query });
            return res.status(400).json({
                success: false,
                error: 'lat ve lng parametreleri gerekli ve geçerli sayısal değerler olmalı',
                received: { lat, lng, latNum, lngNum }
            });
        }
        
        // Nominatim API'ye istek gönder
        const nominatimUrl = `https://nominatim.openstreetmap.org/reverse?format=json&lat=${latNum}&lon=${lngNum}&zoom=${zoom}&addressdetails=1`;
        
        // Node.js için https modülü kullan
        const https = require('https');
        const urlModule = require('url');
        
        const response = await new Promise((resolve, reject) => {
            const parsedUrl = urlModule.parse(nominatimUrl);
            const options = {
                hostname: parsedUrl.hostname,
                path: parsedUrl.path,
                method: 'GET',
                headers: {
                    'User-Agent': 'Floovon-Arac-Takip/1.0'
                }
            };
            
            const httpsReq = https.request(options, (httpsRes) => {
                let data = '';
                httpsRes.on('data', (chunk) => { data += chunk; });
                httpsRes.on('end', () => {
                    resolve({
                        ok: httpsRes.statusCode === 200,
                        status: httpsRes.statusCode,
                        json: () => Promise.resolve(JSON.parse(data))
                    });
                });
            });
            
            httpsReq.on('error', reject);
            httpsReq.end();
        });
        
        if (!response.ok) {
            return res.status(response.status).json({
                success: false,
                error: 'Geocoding servisi hatası'
            });
        }
        
        const data = await response.json();
        
        // Adres bilgisini formatla
        let address = null;
        if (data && data.address) {
            const addr = data.address;
            const parts = [];
            
            if (addr.road) parts.push(addr.road);
            if (addr.house_number) parts.push(addr.house_number);
            if (addr.neighbourhood || addr.suburb) parts.push(addr.neighbourhood || addr.suburb);
            if (addr.city || addr.town || addr.village) parts.push(addr.city || addr.town || addr.village);
            if (addr.district) parts.push(addr.district);
            if (addr.state) parts.push(addr.state);
            
            address = parts.filter(Boolean).join(', ');
        }
        
        res.json({
            success: true,
            data: {
                address: address || data.display_name || null,
                raw: data
            }
        });
    } catch (error) {
        console.error('❌ Geocoding proxy hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Geocoding servisi hatası',
            message: error.message
        });
    }
});

