app.post('/api/sicak-satislar', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı.' });
        }
        const { urun_adi, miktar, tutar, satis_turu } = req.body || {};
        if (!urun_adi || !urun_adi.trim()) {
            return res.status(400).json({ success: false, error: 'Ürün adı zorunludur.' });
        }
        const tableExists = await query("SELECT name FROM sqlite_master WHERE type='table' AND name='sicak_satislar'");
        if (tableExists.length === 0) {
            await run(`
                CREATE TABLE IF NOT EXISTS sicak_satislar (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    urun_adi TEXT NOT NULL,
                    miktar INTEGER DEFAULT 1,
                    aciklama TEXT,
                    satis_turu TEXT DEFAULT 'nakit',
                    tutar DECIMAL(10,2),
                    is_active INTEGER DEFAULT 1,
                    tenant_id INTEGER NOT NULL,
                    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
                )
            `);
        }
        const miktarVal = parseInt(miktar, 10) || 1;
        const tutarVal = parseFloat(tutar) || 0;
        const satisTuru = (satis_turu === 'havale' ? 'havale_eft' : (satis_turu || 'nakit'));
        const kullaniciAdi = await getCurrentUsername(req);
        await run(
            'INSERT INTO sicak_satislar (urun_adi, miktar, aciklama, satis_turu, tutar, tenant_id, created_by, updated_by) VALUES (?, ?, ?, ?, ?, ?, ?, ?)',
            [urun_adi.trim(), miktarVal, 'Sıcak Satış', satisTuru, tutarVal, tenantId, kullaniciAdi, kullaniciAdi]
        );
        const newRow = await query('SELECT * FROM sicak_satislar WHERE id = last_insert_rowid()');
        res.json({ success: true, data: newRow[0] });
    } catch (error) {
        console.error('❌ Sıcak satış ekleme hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

app.put('/api/sicak-satislar/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı.' });
        }
        const { urun_adi, miktar, tutar, satis_turu } = req.body || {};
        const existing = await query('SELECT id FROM sicak_satislar WHERE id = ? AND (tenant_id = ? OR tenant_id IS NULL)', [id, tenantId]);
        if (!existing.length) {
            return res.status(404).json({ success: false, error: 'Sıcak satış bulunamadı' });
        }
        const updates = [];
        const values = [];
        if (urun_adi != null) { updates.push('urun_adi = ?'); values.push(urun_adi.trim()); }
        if (miktar != null) { updates.push('miktar = ?'); values.push(parseInt(miktar, 10) || 1); }
        if (tutar != null) { updates.push('tutar = ?'); values.push(parseFloat(tutar) || 0); }
        if (satis_turu != null) { updates.push('satis_turu = ?'); values.push(satis_turu === 'havale' ? 'havale_eft' : (satis_turu || 'nakit')); }
        if (updates.length === 0) {
            return res.status(400).json({ success: false, error: 'Güncellenecek alan yok' });
        }
        const kullaniciAdi = await getCurrentUsername(req);
        updates.push('updated_by = ?');
        values.push(kullaniciAdi, id, tenantId);
        await run(`UPDATE sicak_satislar SET ${updates.join(', ')}, updated_at = CURRENT_TIMESTAMP WHERE id = ? AND (tenant_id = ? OR tenant_id IS NULL)`, values);
        const updated = await query('SELECT * FROM sicak_satislar WHERE id = ?', [id]);
        res.json({ success: true, data: updated[0] });
    } catch (error) {
        console.error('❌ Sıcak satış güncelleme hatası:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

