// Belirli bir partner firma endpoint'i - /api/partner-firmalar route'undan ÖNCE tanımlanmalı
app.get('/api/partner-firmalar/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        console.log(`🔍 Partner firma getiriliyor: ID ${id}, Tenant: ${tenantId}`);
        
        // partner_firmalar tablosunu kontrol et
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='partner_firmalar'
        `);
        
        if (tableExists.length === 0) {
            console.log('❌ partner_firmalar tablosu bulunamadı');
            return res.status(404).json({
                success: false,
                error: 'Partner firma bulunamadı'
            });
        }

        // partner_kodu kolonunu kontrol et ve ekle
        let columns = await query(`PRAGMA table_info(partner_firmalar)`);
        let hasPartnerKodu = columns.some(col => col.name === 'partner_kodu');
        if (!hasPartnerKodu) {
            await run(`ALTER TABLE partner_firmalar ADD COLUMN partner_kodu TEXT`);
            console.log('✅ partner_firmalar tablosuna partner_kodu kolonu eklendi');
            // Kolon eklendikten sonra tekrar kontrol et
            hasPartnerKodu = true;
        }
        
        // ID ile partner firmayı bul (partner_kodu veya id ile)
        let partner = [];
        
        // id'nin sayısal olup olmadığını kontrol et (sadece rakamlardan oluşuyorsa)
        const trimmedId = id.trim();
        const numericId = parseInt(trimmedId);
        const isNumericId = !isNaN(numericId) && /^\d+$/.test(trimmedId);
        
        console.log(`🔍 ID analizi: trimmedId="${trimmedId}", numericId=${numericId}, isNumericId=${isNumericId}, hasPartnerKodu=${hasPartnerKodu}`);
        
        try {
            if (hasPartnerKodu) {
                // partner_kodu kolonu varsa hem partner_kodu hem de id ile ara
                if (isNumericId) {
                    // Sayısal id ise hem partner_kodu hem de id ile ara
                    console.log(`🔍 Sayısal ID ile arama yapılıyor: partner_kodu="${trimmedId}" veya id=${numericId}`);
                    partner = await query(
                        'SELECT * FROM partner_firmalar WHERE (partner_kodu = ? OR id = ?) AND tenant_id = ? AND is_active = 1',
                        [trimmedId, numericId, tenantId]
                    );
                } else {
                    // Sayısal değilse sadece partner_kodu ile ara (PRFP00001 gibi)
                    console.log(`🔍 Partner kodu ile arama yapılıyor: "${trimmedId}"`);
                    partner = await query(
                        'SELECT * FROM partner_firmalar WHERE partner_kodu = ? AND tenant_id = ? AND is_active = 1',
                        [trimmedId, tenantId]
                    );
                }
            } else {
                // partner_kodu kolonu yoksa sadece id ile ara (sayısal ise)
                if (isNumericId) {
                    console.log(`🔍 Sayısal ID ile arama yapılıyor (partner_kodu kolonu yok): id=${numericId}`);
                    partner = await query(
                        'SELECT * FROM partner_firmalar WHERE id = ? AND tenant_id = ? AND is_active = 1',
                        [numericId, tenantId]
                    );
                } else {
                    // partner_kodu kolonu yok ve id sayısal değilse bulunamaz
                    console.log(`❌ partner_kodu kolonu yok ve ID sayısal değil: "${trimmedId}"`);
                    return res.status(404).json({
                        success: false,
                        error: 'Partner firma bulunamadı'
                    });
                }
            }
            
            console.log(`📊 İlk sorgu sonucu: ${partner.length} kayıt bulundu`);
            
            // Bulunamazsa tenant_id olmadan dene (is_active kontrolü ile)
            if (partner.length === 0) {
                console.log('🔍 Tenant ID olmadan arama yapılıyor (is_active=1 ile)...');
                if (hasPartnerKodu) {
                    if (isNumericId) {
                        partner = await query(
                            'SELECT * FROM partner_firmalar WHERE (partner_kodu = ? OR id = ?) AND is_active = 1',
                            [trimmedId, numericId]
                        );
                    } else {
                        partner = await query(
                            'SELECT * FROM partner_firmalar WHERE partner_kodu = ? AND is_active = 1',
                            [trimmedId]
                        );
                    }
                } else if (isNumericId) {
                    partner = await query(
                        'SELECT * FROM partner_firmalar WHERE id = ? AND is_active = 1',
                        [numericId]
                    );
                }
                console.log(`📊 Tenant ID olmadan sorgu sonucu (is_active=1): ${partner.length} kayıt bulundu`);
                
                // Eğer hala bulunamadıysa, is_active kontrolü olmadan dene
                if (partner.length === 0 && hasPartnerKodu && !isNumericId) {
                    console.log('🔍 is_active kontrolü olmadan arama yapılıyor...');
                    partner = await query(
                        'SELECT * FROM partner_firmalar WHERE partner_kodu = ?',
                        [trimmedId]
                    );
                    console.log(`📊 is_active kontrolü olmadan sorgu sonucu: ${partner.length} kayıt bulundu`);
                    if (partner.length > 0) {
                        console.log(`⚠️ Partner bulundu ama is_active=${partner[0].is_active} (muhtemelen 0)`);
                    }
                }
                
                // Eğer tenant_id olmadan bulunduysa, tenant_id bilgisini logla
                if (partner.length > 0) {
                    const foundTenantId = partner[0].tenant_id;
                    const foundIsActive = partner[0].is_active;
                    console.log(`✅ Partner bulundu: tenant_id=${foundTenantId} (aranan: ${tenantId}), is_active=${foundIsActive}`);
                    console.log(`✅ Partner_kodu unique olduğu için, tenant_id/is_active uyuşmazlığında da döndürülüyor`);
                    // Partner_kodu unique olduğu için, tenant_id uyuşmazlığında da döndürelim
                    // Partner bulundu, devam et (aşağıdaki if (partner.length === 0) kontrolüne takılmayacak)
                }
            }
        } catch (error) {
            console.error('❌ Partner firma sorgu hatası:', error);
            // Son çare: sadece id ile dene (sayısal ise)
            if (isNumericId) {
                try {
                    partner = await query(
                        'SELECT * FROM partner_firmalar WHERE id = ? AND is_active = 1',
                        [numericId]
                    );
                    console.log(`📊 Son çare sorgu sonucu: ${partner.length} kayıt bulundu`);
                } catch (err) {
                    console.error('❌ Partner firma son çare sorgu hatası:', err);
                }
            }
        }
        
        if (partner.length === 0) {
            // Debug için tüm partner firmaları listele
            try {
                const allPartners = await query('SELECT id, partner_firma_adi, partner_kodu, tenant_id, is_active FROM partner_firmalar LIMIT 10');
                console.log(`📋 Veritabanındaki partner firmalar (ilk 10):`, allPartners);
                
                // Ayrıca aranan partner_kodu ile eşleşen kayıtları kontrol et (tenant_id olmadan)
                if (hasPartnerKodu && !isNumericId) {
                    const matchingPartners = await query(
                        'SELECT id, partner_firma_adi, partner_kodu, tenant_id, is_active FROM partner_firmalar WHERE partner_kodu = ?',
                        [trimmedId]
                    );
                    console.log(`🔍 Partner kodu "${trimmedId}" ile eşleşen kayıtlar (tenant_id olmadan):`, matchingPartners);
                }
            } catch (err) {
                console.error('❌ Partner firmalar listelenirken hata:', err);
            }
            
            console.error(`❌ Partner firma bulunamadı: ID="${id}", Tenant=${tenantId}, isNumericId=${isNumericId}, hasPartnerKodu=${hasPartnerKodu}`);
            
            return res.status(404).json({
                success: false,
                error: 'Partner firma bulunamadı',
                debug: {
                    searchedId: id,
                    tenantId: tenantId,
                    isNumericId: isNumericId,
                    hasPartnerKodu: hasPartnerKodu
                }
            });
        }
        
        const partnerData = partner[0];
        console.log(`✅ Partner firma bulundu: ID ${partnerData.id}, Firma: ${partnerData.partner_firma_adi || partnerData.firma_adi}`);
        console.log(`📋 Partner logo alanları:`, {
            partner_logo: partnerData.partner_logo,
            logo_url: partnerData.logo_url,
            logo: partnerData.logo,
            partner_logo_path: partnerData.partner_logo_path
        });
        
        res.json({
            success: true,
            data: partnerData
        });
    } catch (error) {
        console.error('❌ Partner firma yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Partner firma yüklenemedi',
            message: error.message
        });
    }
});

// Partner alınan siparişler endpoint
app.get('/api/partner-firmalar/:id/alinan-siparisler', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // Partner bilgisini al
        const trimmedId = id.trim();
        const numericId = parseInt(trimmedId);
        const isNumericId = !isNaN(numericId) && /^\d+$/.test(trimmedId);
        
        let partner = [];
        const columns = await query(`PRAGMA table_info(partner_firmalar)`);
        const hasPartnerKodu = columns.some(col => col.name === 'partner_kodu');
        
        if (hasPartnerKodu) {
            if (isNumericId) {
                partner = await query(
                    'SELECT * FROM partner_firmalar WHERE (partner_kodu = ? OR id = ?) AND tenant_id = ? AND is_active = 1',
                    [trimmedId, numericId, tenantId]
                );
            } else {
                partner = await query(
                    'SELECT * FROM partner_firmalar WHERE partner_kodu = ? AND tenant_id = ? AND is_active = 1',
                    [trimmedId, tenantId]
                );
            }
        } else if (isNumericId) {
            partner = await query(
                'SELECT * FROM partner_firmalar WHERE id = ? AND tenant_id = ? AND is_active = 1',
                [numericId, tenantId]
            );
        }
        
        if (partner.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Partner firma bulunamadı'
            });
        }
        
        const partnerFirmaAdi = partner[0].partner_firma_adi || partner[0].firma_adi;
        
        // Partner'den alınan siparişleri bul (partner_firma_adi ile eşleştir)
        // "Alınan siparişler" = partner_siparis_turu = 'gelen' veya 'alınan' veya NULL olan siparişler
        const siparisler = await query(`
            SELECT 
                sk.*,
                ok.organizasyon_kart_tur,
                ok.organizasyon_kart_etiket,
                ok.organizasyon_alt_tur,
                ok.organizasyon_teslim_tarih,
                ok.organizasyon_teslim_saat,
                ok.organizasyon_teslimat_konumu as organizasyon_konum,
                ok.organizasyon_teslim_kisisi as organizasyon_sahip,
                ok.organizasyon_mahalle,
                ok.organizasyon_ilce,
                ok.organizasyon_il,
                sk.teslim_mahalle,
                sk.teslim_ilce,
                sk.teslim_il,
                (SELECT p.urun_gorseli FROM urunler p
                 WHERE (sk.siparis_urun_id = p.id OR sk.siparis_urun = p.urun_adi)
                 AND (p.tenant_id = sk.tenant_id OR p.tenant_id IS NULL)
                 LIMIT 1) as product_gorsel
            FROM siparisler sk
            LEFT JOIN organizasyon_kartlar ok ON sk.organizasyon_kart_id = ok.id
            WHERE sk.partner_firma_adi = ?
                AND sk.tenant_id = ?
                AND (sk.is_active = 1 OR sk.is_active IS NULL)
                AND (sk.partner_siparis_turu IS NULL 
                     OR sk.partner_siparis_turu = '' 
                     OR LOWER(sk.partner_siparis_turu) IN ('gelen', 'alınan', 'alinan'))
            ORDER BY sk.id ASC
        `, [partnerFirmaAdi, tenantId]);
        
        res.json({
            success: true,
            data: siparisler,
            count: siparisler.length
        });
    } catch (error) {
        console.error('❌ Partner alınan siparişler yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Partner alınan siparişler yüklenemedi',
            message: error.message
        });
    }
});

