// partner_cari_hareketler tablosunu musteri_tahsilatlar ile uyumlu Türkçe kolonlara geçirir (yeni tablo Türkçe, mevcut tablo RENAME COLUMN veya tablo yeniden oluşturma)
async function ensurePartnerCariHareketlerTurkce() {
    await run(`
        CREATE TABLE IF NOT EXISTS partner_cari_hareketler (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            tenant_id INTEGER NOT NULL,
            partner_id INTEGER NOT NULL,
            islem_tipi TEXT NOT NULL,
            tutar REAL NOT NULL,
            odeme_yontemi TEXT,
            islem_tarihi_saati TEXT NOT NULL,
            odeme_yapan_kisi TEXT,
            aciklama TEXT,
            is_active INTEGER DEFAULT 1,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (partner_id) REFERENCES partner_firmalar(id),
            FOREIGN KEY (tenant_id) REFERENCES tenants(id)
        )
    `);
    const cols = await query('PRAGMA table_info(partner_cari_hareketler)');
    const names = (cols || []).map((c) => c.name);
    const hasTurkish = names.includes('islem_tipi');
    const hasEnglish = names.includes('transaction_type');
    if (hasTurkish && !hasEnglish) {
        return;
    }
    if (!hasEnglish) {
        return;
    }
    console.log('🔄 [partner_cari_hareketler] Migration: İngilizce kolonlar Türkçeye çevriliyor...');
    const renames = [
        ['transaction_type', 'islem_tipi'],
        ['amount', 'tutar'],
        ['payment_method', 'odeme_yontemi'],
        ['transaction_date', 'islem_tarihi_saati'],
        ['responsible_person', 'odeme_yapan_kisi'],
        ['description', 'aciklama']
    ];
    let renameFailed = false;
    for (const [from, to] of renames) {
        if (names.includes(from) && !names.includes(to)) {
            try {
                await execute(`ALTER TABLE partner_cari_hareketler RENAME COLUMN ${from} TO ${to}`, []);
                names[names.indexOf(from)] = to;
            } catch (e) {
                console.warn('⚠️ partner_cari_hareketler RENAME COLUMN başarısız (eski SQLite?):', from, '->', to, e.message);
                renameFailed = true;
                break;
            }
        }
    }
    if (renameFailed) {
        console.log('🔄 [partner_cari_hareketler] RENAME COLUMN desteklenmiyor; tablo kopyalama ile migration yapılıyor...');
        try {
            await run(`
                CREATE TABLE partner_cari_hareketler_yeni (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    tenant_id INTEGER NOT NULL,
                    partner_id INTEGER NOT NULL,
                    islem_tipi TEXT NOT NULL,
                    tutar REAL NOT NULL,
                    odeme_yontemi TEXT,
                    islem_tarihi_saati TEXT NOT NULL,
                    odeme_yapan_kisi TEXT,
                    aciklama TEXT,
                    is_active INTEGER DEFAULT 1,
                    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (partner_id) REFERENCES partner_firmalar(id),
                    FOREIGN KEY (tenant_id) REFERENCES tenants(id)
                )
            `);
            await run(`
                INSERT INTO partner_cari_hareketler_yeni (id, tenant_id, partner_id, islem_tipi, tutar, odeme_yontemi, islem_tarihi_saati, odeme_yapan_kisi, aciklama, is_active, created_at, updated_at)
                SELECT id, tenant_id, partner_id, transaction_type, amount, payment_method, transaction_date, responsible_person, COALESCE(description, ''), is_active, created_at, updated_at
                FROM partner_cari_hareketler
            `);
            await run('DROP TABLE partner_cari_hareketler');
            await run('ALTER TABLE partner_cari_hareketler_yeni RENAME TO partner_cari_hareketler');
            console.log('✅ [partner_cari_hareketler] Migration tamamlandı (tablo kopyalama).');
        } catch (e2) {
            console.error('❌ [partner_cari_hareketler] Tablo kopyalama migration hatası:', e2.message);
        }
    } else {
        console.log('✅ [partner_cari_hareketler] Migration tamamlandı (RENAME COLUMN).');
    }
}

// Partner ödemeler endpoint
app.get('/api/partner-firmalar/:id/odemeler', async (req, res) => {
    try {
        const { id } = req.params;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // Partner bilgisini al
        const trimmedId = id.trim();
        const numericId = parseInt(trimmedId);
        const isNumericId = !isNaN(numericId) && /^\d+$/.test(trimmedId);
        
        let partner = [];
        const columns = await query(`PRAGMA table_info(partner_firmalar)`);
        const hasPartnerKodu = columns.some(col => col.name === 'partner_kodu');
        
        if (hasPartnerKodu) {
            if (isNumericId) {
                partner = await query(
                    'SELECT * FROM partner_firmalar WHERE (partner_kodu = ? OR id = ?) AND tenant_id = ? AND is_active = 1',
                    [trimmedId, numericId, tenantId]
                );
            } else {
                partner = await query(
                    'SELECT * FROM partner_firmalar WHERE partner_kodu = ? AND tenant_id = ? AND is_active = 1',
                    [trimmedId, tenantId]
                );
            }
        } else if (isNumericId) {
            partner = await query(
                'SELECT * FROM partner_firmalar WHERE id = ? AND tenant_id = ? AND is_active = 1',
                [numericId, tenantId]
            );
        }
        
        if (partner.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Partner firma bulunamadı'
            });
        }
        
        // partner_cari_hareketler: musteri_tahsilatlar ile uyum için kolonları Türkçe kullan (migration + okuma)
        await ensurePartnerCariHareketlerTurkce();

        const pchColumns = await query('PRAGMA table_info(partner_cari_hareketler)');
        const pchNames = (pchColumns || []).map((c) => c.name);
        const orderByCol = pchNames.includes('islem_tarihi_saati') ? 'islem_tarihi_saati' : (pchNames.includes('transaction_date') ? 'transaction_date' : (pchNames.includes('created_at') ? 'created_at' : 'id'));
        const orderByCol2 = pchNames.includes('created_at') ? 'created_at' : 'id';

        const rows = await query(`
            SELECT * FROM partner_cari_hareketler
            WHERE partner_id = ? AND tenant_id = ? AND (is_active = 1 OR is_active IS NULL)
            ORDER BY id ASC
        `, [partner[0].id, tenantId]);

        const odemeler = (rows || []).map((row) => {
            const islem_tipi = String(row.islem_tipi ?? row.transaction_type ?? 'odeme');
            const tutarRaw = row.tutar ?? row.amount;
            const tutar = tutarRaw != null ? Number(tutarRaw) : null;
            const odeme_yontemi = (row.odeme_yontemi ?? row.payment_method) != null ? String(row.odeme_yontemi ?? row.payment_method) : null;
            const islem_tarihi_saati = (row.islem_tarihi_saati ?? row.transaction_date) != null ? String(row.islem_tarihi_saati ?? row.transaction_date) : null;
            const odeme_yapan_kisi = (row.odeme_yapan_kisi ?? row.responsible_person) != null ? String(row.odeme_yapan_kisi ?? row.responsible_person) : null;
            const aciklamaVal = row.aciklama ?? row.description;
            const aciklama = aciklamaVal != null ? String(aciklamaVal).trim() : null;
            return {
                id: row?.id,
                tenant_id: row?.tenant_id,
                partner_id: row?.partner_id,
                transaction_type: islem_tipi,
                amount: tutar,
                payment_method: odeme_yontemi,
                transaction_date: islem_tarihi_saati,
                responsible_person: odeme_yapan_kisi,
                description: aciklama || null,
                created_at: row?.created_at != null ? String(row.created_at) : null,
                updated_at: row?.updated_at != null ? String(row.updated_at) : null,
                is_active: row?.is_active,
                aciklama: aciklama || null,
                odeme_yapan_kisi,
                islem_tarihi: islem_tarihi_saati,
                islem_tarihi_saati,
                tutar,
                odeme_yontemi,
            };
        });

        res.json({
            success: true,
            data: odemeler,
            count: odemeler.length
        });
    } catch (error) {
        console.error('❌ Partner ödemeleri yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Partner ödemeleri yüklenemedi',
            message: error.message
        });
    }
});

