app.get('/api/partner-orders/partner/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const { order_type } = req.query;
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        // Partner bilgisini al
        const trimmedId = id.trim();
        const numericId = parseInt(trimmedId);
        const isNumericId = !isNaN(numericId) && /^\d+$/.test(trimmedId);
        
        let partner = [];
        const columns = await query(`PRAGMA table_info(partner_firmalar)`);
        const hasPartnerKodu = columns.some(col => col.name === 'partner_kodu');
        
        if (hasPartnerKodu) {
            if (isNumericId) {
                partner = await query(
                    'SELECT * FROM partner_firmalar WHERE (partner_kodu = ? OR id = ?) AND tenant_id = ? AND is_active = 1',
                    [trimmedId, numericId, tenantId]
                );
            } else {
                partner = await query(
                    'SELECT * FROM partner_firmalar WHERE partner_kodu = ? AND tenant_id = ? AND is_active = 1',
                    [trimmedId, tenantId]
                );
            }
        } else if (isNumericId) {
            partner = await query(
                'SELECT * FROM partner_firmalar WHERE id = ? AND tenant_id = ? AND is_active = 1',
                [numericId, tenantId]
            );
        }
        
        if (partner.length === 0) {
            return res.status(404).json({
                success: false,
                error: 'Partner firma bulunamadı'
            });
        }
        
        const partnerFirmaAdi = partner[0].partner_firma_adi || partner[0].firma_adi;
        
        let siparisler = [];
        
        // order_type'a göre siparişleri filtrele
        if (order_type === 'alinan') {
            // Alınan siparişler (partner'dan alınan siparişler) - bu partner'a verilen siparişler
            siparisler = await query(`
                SELECT 
                    sk.*,
                    ok.organizasyon_kart_tur,
                    ok.organizasyon_kart_etiket,
                    ok.organizasyon_teslim_tarih,
                    ok.organizasyon_teslim_saat,
                    ok.organizasyon_teslimat_konumu as organizasyon_konum,
                    ok.organizasyon_teslim_kisisi as organizasyon_sahip,
                    ok.organizasyon_mahalle,
                    ok.organizasyon_ilce,
                    ok.organizasyon_il,
                    sk.teslim_mahalle,
                    sk.teslim_ilce,
                    sk.teslim_il
                FROM siparisler sk
                LEFT JOIN organizasyon_kartlar ok ON sk.organizasyon_kart_id = ok.id
                WHERE sk.partner_firma_adi = ?
                    AND sk.tenant_id = ?
                    AND (sk.is_active = 1 OR sk.is_active IS NULL)
                    AND (sk.partner_siparis_turu IS NULL 
                         OR sk.partner_siparis_turu = '' 
                         OR LOWER(sk.partner_siparis_turu) IN ('gelen', 'alınan', 'alinan'))
                ORDER BY sk.created_at DESC
            `, [partnerFirmaAdi, tenantId]);
        } else if (order_type === 'verilen') {
            // Verilen siparişler (partner'a verilen siparişler) - bu partner'dan alınan siparişler
            siparisler = await query(`
                SELECT 
                    sk.*,
                    ok.organizasyon_kart_tur,
                    ok.organizasyon_kart_etiket,
                    ok.organizasyon_teslim_tarih,
                    ok.organizasyon_teslim_saat,
                    ok.organizasyon_teslimat_konumu as organizasyon_konum,
                    ok.organizasyon_teslim_kisisi as organizasyon_sahip,
                    ok.organizasyon_mahalle,
                    ok.organizasyon_ilce,
                    ok.organizasyon_il,
                    sk.teslim_mahalle,
                    sk.teslim_ilce,
                    sk.teslim_il
                FROM siparisler sk
                LEFT JOIN organizasyon_kartlar ok ON sk.organizasyon_kart_id = ok.id
                WHERE sk.partner_firma_adi = ?
                    AND sk.tenant_id = ?
                    AND (sk.is_active = 1 OR sk.is_active IS NULL)
                    AND LOWER(sk.partner_siparis_turu) = 'verilen'
                ORDER BY sk.created_at DESC
            `, [partnerFirmaAdi, tenantId]);
        } else {
            // order_type belirtilmemişse tüm siparişleri döndür
            siparisler = await query(`
                SELECT 
                    sk.*,
                    ok.organizasyon_kart_tur,
                    ok.organizasyon_kart_etiket,
                    ok.organizasyon_teslim_tarih,
                    ok.organizasyon_teslim_saat,
                    ok.organizasyon_teslimat_konumu as organizasyon_konum,
                    ok.organizasyon_teslim_kisisi as organizasyon_sahip,
                    ok.organizasyon_mahalle,
                    ok.organizasyon_ilce,
                    ok.organizasyon_il,
                    sk.teslim_mahalle,
                    sk.teslim_ilce,
                    sk.teslim_il
                FROM siparisler sk
                LEFT JOIN organizasyon_kartlar ok ON sk.organizasyon_kart_id = ok.id
                WHERE sk.partner_firma_adi = ?
                    AND sk.tenant_id = ?
                    AND (sk.is_active = 1 OR sk.is_active IS NULL)
                ORDER BY sk.created_at DESC
            `, [partnerFirmaAdi, tenantId]);
        }
        
        res.json({
            success: true,
            data: siparisler,
            count: siparisler.length
        });
    } catch (error) {
        console.error('❌ Partner siparişler yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Partner siparişler yüklenemedi',
            message: error.message
        });
    }
});

// Partner firmalar endpoint (genel liste) - :id route'undan SONRA tanımlanmalı
app.get('/api/partner-firmalar', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            console.error('❌ Partner firmalar: Tenant ID bulunamadı');
            console.error('❌ Request headers:', {
                'x-user-id': req.headers['x-user-id'] || req.headers['X-User-ID'],
                'authorization': req.headers['authorization'] ? 'Bearer ***' : 'yok',
                'user-agent': req.headers['user-agent']
            });
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        console.log('✅ Partner firmalar: Tenant ID =', tenantId);
        
        // partner_firmalar tablosunu kontrol et, yoksa oluştur; varsa eski kolon isimlerini yeni isimlere taşı (migration)
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='partner_firmalar'
        `);
        
        if (tableExists.length === 0) {
            await run(`
                CREATE TABLE IF NOT EXISTS partner_firmalar (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    partner_firma_adi TEXT NOT NULL,
                    partner_telefon TEXT,
                    partner_eposta TEXT,
                    partner_acik_adres TEXT,
                    partner_logo TEXT,
                    partner_kodu TEXT,
                    tenant_id INTEGER DEFAULT 1,
                    is_active INTEGER DEFAULT 1,
                    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
                )
            `);
        } else {
            const columns = await query(`PRAGMA table_info(partner_firmalar)`);
            const columnNames = columns.map(c => c.name);
            try {
                if (columnNames.includes('firma_telefon')) {
                    await run(`ALTER TABLE partner_firmalar DROP COLUMN firma_telefon`);
                    console.log('✅ partner_firmalar: firma_telefon kaldırıldı (partner_telefon kullanılıyor)');
                }
            } catch (e) {
                console.warn('⚠️ firma_telefon DROP (SQLite 3.35+ gerekir):', e.message);
            }
            try {
                if (columnNames.includes('partner_no')) {
                    await run(`ALTER TABLE partner_firmalar DROP COLUMN partner_no`);
                    console.log('✅ partner_firmalar: partner_no kaldırıldı (sadece partner_kodu kullanılıyor)');
                }
            } catch (e) {
                console.warn('⚠️ partner_no DROP (SQLite 3.35+ gerekir), tablo yeniden oluşturuluyor:', e.message);
                if (columnNames.includes('partner_no')) {
                    try {
                        const cols = await query(`PRAGMA table_info(partner_firmalar)`);
                        const keep = cols.filter(c => c.name !== 'partner_no');
                        if (keep.length < cols.length) {
                            const colDefs = keep.map(c => {
                                if (c.pk && String(c.type || '').toUpperCase().includes('INT')) {
                                    return `${c.name} INTEGER PRIMARY KEY AUTOINCREMENT`;
                                }
                                if (c.pk) return `${c.name} ${c.type || 'TEXT'} PRIMARY KEY`;
                                return `${c.name} ${c.type || 'TEXT'}`;
                            }).join(', ');
                            await run(`CREATE TABLE partner_firmalar_new (${colDefs})`);
                            const names = keep.map(c => c.name).join(', ');
                            await run(`INSERT INTO partner_firmalar_new (${names}) SELECT ${names} FROM partner_firmalar`);
                            await run(`DROP TABLE partner_firmalar`);
                            await run(`ALTER TABLE partner_firmalar_new RENAME TO partner_firmalar`);
                            console.log('✅ partner_firmalar: partner_no tablo yeniden oluşturularak kaldırıldı');
                        }
                    } catch (recreateErr) {
                        console.warn('⚠️ partner_firmalar partner_no kaldırılamadı:', recreateErr.message);
                    }
                }
            }
            try {
                if (columnNames.includes('firma_adi') && !columnNames.includes('partner_firma_adi')) {
                    await run(`ALTER TABLE partner_firmalar RENAME COLUMN firma_adi TO partner_firma_adi`);
                    console.log('✅ partner_firmalar: firma_adi → partner_firma_adi');
                }
            } catch (e) { console.warn('⚠️ RENAME firma_adi:', e.message); }
            try {
                if (columnNames.includes('firma_tel') && !columnNames.includes('partner_telefon')) {
                    await run(`ALTER TABLE partner_firmalar RENAME COLUMN firma_tel TO partner_telefon`);
                    console.log('✅ partner_firmalar: firma_tel → partner_telefon');
                }
            } catch (e) { console.warn('⚠️ RENAME firma_tel:', e.message); }
            try {
                if (columnNames.includes('firma_email') && !columnNames.includes('partner_eposta')) {
                    await run(`ALTER TABLE partner_firmalar RENAME COLUMN firma_email TO partner_eposta`);
                    console.log('✅ partner_firmalar: firma_email → partner_eposta');
                }
            } catch (e) { console.warn('⚠️ RENAME firma_email:', e.message); }
            try {
                if (columnNames.includes('firma_adres') && !columnNames.includes('partner_acik_adres')) {
                    await run(`ALTER TABLE partner_firmalar RENAME COLUMN firma_adres TO partner_acik_adres`);
                    console.log('✅ partner_firmalar: firma_adres → partner_acik_adres');
                }
            } catch (e) { console.warn('⚠️ RENAME firma_adres:', e.message); }
            try {
                if (columnNames.includes('firma_logo') && !columnNames.includes('partner_logo')) {
                    await run(`ALTER TABLE partner_firmalar RENAME COLUMN firma_logo TO partner_logo`);
                    console.log('✅ partner_firmalar: firma_logo → partner_logo');
                }
            } catch (e) { console.warn('⚠️ RENAME firma_logo:', e.message); }
            if (!columnNames.includes('partner_kodu')) {
                await run(`ALTER TABLE partner_firmalar ADD COLUMN partner_kodu TEXT`);
                console.log('✅ partner_firmalar tablosuna partner_kodu kolonu eklendi');
            }
        }
        
        let partners = await query(
            'SELECT * FROM partner_firmalar WHERE tenant_id = ? AND is_active = 1 ORDER BY id ASC',
            [tenantId]
        );
        
        // Logo path'lerini tenant-based yapıya çevir (partner_logo; eski firma_logo da olabilir)
        partners = partners.map(partner => {
            const logoPathRaw = partner.partner_logo || partner.firma_logo;
            if (logoPathRaw) {
                let logoPath = logoPathRaw;
                
                // Eski /uploads/partner-firmalar/ path'lerini tenant-based yapıya çevir
                // Örnek: /uploads/partner-firmalar/1-moon_garden_cicekcilik/logo/logo_1762372043455.jpg
                // -> /uploads/tenants/<tenantId>/partners/1-moon_garden_cicekcilik/logo/logo_1762372043455.jpg
                if (logoPath.includes('/uploads/partner-firmalar/') && !logoPath.includes('/uploads/tenants/')) {
                    const parts = logoPath.split('/uploads/partner-firmalar/');
                    if (parts.length > 1) {
                        const rest = parts[1];
                        logoPath = `/uploads/tenants/${tenantId}/partners/${rest}`;
                    }
                }
                
                // Full URL ise pathname'i al
                if (logoPath.startsWith('http://') || logoPath.startsWith('https://')) {
                    try {
                        const url = require('url');
                        const parsed = url.parse(logoPath);
                        logoPath = parsed.pathname;
                    } catch (e) {
                        console.warn('⚠️ Partner logo URL parse hatası:', e);
                    }
                }
                
                // getTenantRelativePath ile dönüştür (eğer hala eski path ise)
                if (logoPath && !logoPath.includes(`/uploads/tenants/${tenantId}/partners/`)) {
                    // Eski path formatını yeni formata çevir
                    if (logoPath.startsWith('/uploads/partners/')) {
                        logoPath = logoPath.replace('/uploads/partners/', `/uploads/tenants/${tenantId}/partners/`);
                    } else if (logoPath.startsWith('partners/')) {
                        logoPath = `/uploads/tenants/${tenantId}/partners/${logoPath.replace('partners/', '')}`;
                    } else if (logoPath.includes('/partner-firmalar/')) {
                        // Hala eski /uploads/partner-firmalar/ formatında ise çevir
                        const parts = logoPath.split('/partner-firmalar/');
                        if (parts.length > 1) {
                            const rest = parts[1];
                            logoPath = `/uploads/tenants/${tenantId}/partners/${rest}`;
                        }
                    }
                }
                
                partner.partner_logo = logoPath;
            }
            return partner;
        });
        
        res.json({
            success: true,
            data: partners
        });
    } catch (error) {
        console.error('❌ Partner firmalar yüklenirken hata:', error);
        console.error('❌ Hata stack:', error.stack);
        res.status(500).json({
            success: false,
            error: 'Partner firmalar yüklenemedi',
            message: error.message || 'Bilinmeyen hata'
        });
    }
});

// Potansiyel partnerler listesi (is_active=0 veya null; aynı tenant)
app.get('/api/potansiyel-partnerler', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const search = (req.query.search || '').toString().trim();
        const il = (req.query.il || '').toString().trim();
        const ilce = (req.query.ilce || '').toString().trim();

        let sql = `SELECT * FROM partner_firmalar WHERE tenant_id = ? AND (is_active = 0 OR is_active IS NULL)`;
        const params = [tenantId];
        if (search) {
            sql += ` AND (partner_firma_adi LIKE ? OR partner_telefon LIKE ? OR partner_eposta LIKE ?)`;
            const term = `%${search}%`;
            params.push(term, term, term);
        }
        if (il) {
            sql += ` AND partner_il = ?`;
            params.push(il);
        }
        if (ilce) {
            sql += ` AND partner_ilce = ?`;
            params.push(ilce);
        }
        sql += ` ORDER BY id ASC`;

        let partners = await query(sql, params);

        // Logo path'lerini tenant-based yapıya çevir (partner-firmalar ile aynı mantık)
        partners = partners.map(partner => {
            const logoPathRaw = partner.partner_logo || partner.firma_logo;
            if (logoPathRaw) {
                let logoPath = logoPathRaw;
                if (logoPath.includes('/uploads/partner-firmalar/') && !logoPath.includes('/uploads/tenants/')) {
                    const parts = logoPath.split('/uploads/partner-firmalar/');
                    if (parts.length > 1) {
                        logoPath = `/uploads/tenants/${tenantId}/partners/${parts[1]}`;
                    }
                }
                if (logoPath.startsWith('http://') || logoPath.startsWith('https://')) {
                    try {
                        const url = require('url');
                        const parsed = url.parse(logoPath);
                        logoPath = parsed.pathname;
                    } catch (e) {
                        console.warn('⚠️ Partner logo URL parse hatası:', e);
                    }
                }
                if (logoPath && !logoPath.includes(`/uploads/tenants/${tenantId}/partners/`)) {
                    if (logoPath.startsWith('/uploads/partners/')) {
                        logoPath = logoPath.replace('/uploads/partners/', `/uploads/tenants/${tenantId}/partners/`);
                    } else if (logoPath.startsWith('partners/')) {
                        logoPath = `/uploads/tenants/${tenantId}/partners/${logoPath.replace('partners/', '')}`;
                    } else if (logoPath.includes('/partner-firmalar/')) {
                        const parts = logoPath.split('/partner-firmalar/');
                        if (parts.length > 1) {
                            logoPath = `/uploads/tenants/${tenantId}/partners/${parts[1]}`;
                        }
                    }
                }
                partner.partner_logo = logoPath;
            }
            return partner;
        });

        res.json({
            success: true,
            data: partners
        });
    } catch (error) {
        console.error('❌ Potansiyel partnerler yüklenirken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Potansiyel partnerler yüklenemedi',
            message: error.message || 'Bilinmeyen hata'
        });
    }
});

// Potansiyel partnerler listesi (tenant-app uyumluluğu; partner_firmalar ile aynı kaynak)
app.get('/api/potansiyel-partnerler', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        const { search, il, ilce } = req.query;
        const sql = `SELECT * FROM partner_firmalar WHERE tenant_id = ? ORDER BY id ASC`;
        let rows = await query(sql, [tenantId]);
        if (search && typeof search === 'string') {
            const s = `%${search}%`;
            rows = rows.filter(r => (r.partner_firma_adi || '').toLowerCase().includes(search.toLowerCase()) ||
                (r.partner_telefon || '').includes(search) || (r.partner_eposta || '').toLowerCase().includes(search.toLowerCase()));
        }
        if (il && typeof il === 'string') {
            rows = rows.filter(r => (r.il || '').toLowerCase() === il.toLowerCase());
        }
        if (ilce && typeof ilce === 'string') {
            rows = rows.filter(r => (r.ilce || '').toLowerCase() === ilce.toLowerCase());
        }
        const partners = rows.map(partner => {
            const logoPathRaw = partner.partner_logo || partner.firma_logo;
            if (logoPathRaw && tenantId) {
                let logoPath = logoPathRaw;
                if (logoPath.includes('/uploads/partner-firmalar/') && !logoPath.includes('/uploads/tenants/')) {
                    const parts = logoPath.split('/uploads/partner-firmalar/');
                    if (parts.length > 1) logoPath = `/uploads/tenants/${tenantId}/partners/${parts[1]}`;
                }
                if (logoPath.startsWith('http://') || logoPath.startsWith('https://')) {
                    try { const url = require('url'); logoPath = url.parse(logoPath).pathname; } catch (e) {}
                }
                partner.partner_logo = logoPath;
            }
            return partner;
        });
        res.json({ success: true, data: partners });
    } catch (error) {
        console.error('❌ Potansiyel partnerler yüklenirken hata:', error);
        res.status(500).json({ success: false, error: 'Potansiyel partnerler yüklenemedi', message: error.message || 'Bilinmeyen hata' });
    }
});

// Partner sipariş oluştur (POST)
app.post('/api/partner-siparis', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        
        if (!tenantId) {
            return res.status(400).json({ success: false, error: 'Tenant ID bulunamadı. Lütfen giriş yapın.' });
        }
        
        const { siparis_id, partner_firma_adi, partner_siparis_turu } = req.body;
        
        if (!siparis_id) {
            return res.status(400).json({ success: false, error: 'Sipariş ID gereklidir' });
        }
        
        // siparisler tablosunda partner bilgilerini güncelle
        const updateFields = [];
        const updateValues = [];
        
        if (partner_firma_adi !== undefined) {
            updateFields.push('partner_firma_adi = ?');
            updateValues.push(partner_firma_adi);
        }
        
        if (partner_siparis_turu !== undefined) {
            updateFields.push('partner_siparis_turu = ?');
            updateValues.push(partner_siparis_turu);
        }
        
        if (updateFields.length === 0) {
            return res.status(400).json({ success: false, error: 'Güncellenecek alan bulunamadı' });
        }
        
        updateValues.push(siparis_id, tenantId);
        
        await run(
            `UPDATE siparisler SET ${updateFields.join(', ')}, updated_at = datetime('now') WHERE id = ? AND tenant_id = ?`,
            updateValues
        );
        
        const updated = await query('SELECT * FROM siparisler WHERE id = ? AND tenant_id = ?', [siparis_id, tenantId]);
        
        res.json({
            success: true,
            data: updated[0],
            message: 'Partner sipariş bilgileri başarıyla güncellendi'
        });
    } catch (error) {
        console.error('❌ Partner sipariş oluşturulurken hata:', error);
        res.status(500).json({
            success: false,
            error: 'Partner sipariş oluşturulamadı',
            message: error.message
        });
    }
});

