// Partner firma oluştur
app.post('/api/partner-firmalar', async (req, res) => {
    try {
        const tenantId = req.tenantId || await getTenantId(req);
        // getTenantId her zaman bir değer döndürür (fallback: 1), kontrol gereksiz
        
        const {
            partner_firma_adi,
            partner_telefon,
            partner_eposta,
            partner_acik_adres,
            partner_logo,
            partner_kodu,
            partner_yetkili_kisi,
            partner_il,
            partner_ilce,
            partner_mahalle,
            is_active
        } = req.body;
        const firma_adi = req.body.firma_adi ?? partner_firma_adi;
        const firma_tel = req.body.firma_tel ?? partner_telefon;

        console.log('➕ Partner firma oluşturuluyor:', { ...req.body, tenantId });

        // partner_firmalar tablosunu kontrol et ve oluştur
        const tableExists = await query(`
            SELECT name FROM sqlite_master WHERE type='table' AND name='partner_firmalar'
        `);
        
        if (tableExists.length === 0) {
            await run(`
                CREATE TABLE IF NOT EXISTS partner_firmalar (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    partner_firma_adi TEXT NOT NULL,
                    partner_telefon TEXT,
                    partner_eposta TEXT,
                    partner_acik_adres TEXT,
                    partner_logo TEXT,
                    partner_kodu TEXT,
                    partner_yetkili_kisi TEXT,
                    partner_il TEXT,
                    partner_ilce TEXT,
                    partner_mahalle TEXT,
                    tenant_id INTEGER DEFAULT 1,
                    is_active INTEGER DEFAULT 1,
                    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
                )
            `);
        } else {
            const columns = await query(`PRAGMA table_info(partner_firmalar)`);
            const columnNames = columns.map(c => c.name);
            if (!columnNames.includes('partner_kodu')) {
                await run(`ALTER TABLE partner_firmalar ADD COLUMN partner_kodu TEXT`);
                console.log('✅ partner_firmalar tablosuna partner_kodu kolonu eklendi');
            }
            if (!columnNames.includes('partner_logo')) {
                await run(`ALTER TABLE partner_firmalar ADD COLUMN partner_logo TEXT`);
                console.log('✅ partner_firmalar tablosuna partner_logo kolonu eklendi');
            }
            if (!columnNames.includes('partner_acik_adres')) {
                await run(`ALTER TABLE partner_firmalar ADD COLUMN partner_acik_adres TEXT`);
                console.log('✅ partner_firmalar tablosuna partner_acik_adres kolonu eklendi');
            }
            if (!columnNames.includes('partner_yetkili_kisi')) {
                await run(`ALTER TABLE partner_firmalar ADD COLUMN partner_yetkili_kisi TEXT`);
                console.log('✅ partner_firmalar tablosuna partner_yetkili_kisi kolonu eklendi');
            }
            if (!columnNames.includes('partner_il')) {
                await run(`ALTER TABLE partner_firmalar ADD COLUMN partner_il TEXT`);
                console.log('✅ partner_firmalar tablosuna partner_il kolonu eklendi');
            }
            if (!columnNames.includes('partner_ilce')) {
                await run(`ALTER TABLE partner_firmalar ADD COLUMN partner_ilce TEXT`);
                console.log('✅ partner_firmalar tablosuna partner_ilce kolonu eklendi');
            }
            if (!columnNames.includes('partner_mahalle')) {
                await run(`ALTER TABLE partner_firmalar ADD COLUMN partner_mahalle TEXT`);
                console.log('✅ partner_firmalar tablosuna partner_mahalle kolonu eklendi');
            }
        }

        const adi = partner_firma_adi ?? firma_adi;
        if (!adi || String(adi).trim() === '') {
            return res.status(400).json({
                success: false,
                error: 'Partner firma adı zorunludur'
            });
        }

        const kullaniciAdi = await getCurrentUsername(req);
        const result = await run(`
            INSERT INTO partner_firmalar (
                partner_firma_adi,
                partner_telefon,
                partner_eposta,
                partner_acik_adres,
                partner_logo,
                partner_kodu,
                partner_yetkili_kisi,
                partner_il,
                partner_ilce,
                partner_mahalle,
                tenant_id,
                is_active,
                created_by,
                updated_by
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `, [
            String(adi).trim(),
            (partner_telefon ?? firma_tel) || null,
            partner_eposta || null,
            partner_acik_adres || null,
            partner_logo || null,
            partner_kodu || null,
            partner_yetkili_kisi || null,
            partner_il || null,
            partner_ilce || null,
            partner_mahalle || null,
            tenantId,
            is_active !== undefined ? is_active : 1,
            kullaniciAdi,
            kullaniciAdi
        ]);

        const newId = result.lastID;

        console.log('✅ Partner firma oluşturuldu: ID', newId);

        res.json({
            success: true,
            message: 'Partner firma başarıyla oluşturuldu',
            data: { id: newId }
        });
    } catch (error) {
        console.error('❌ Partner firma oluşturma hatası:', error);
        res.status(500).json({
            success: false,
            error: 'Partner firma oluşturulamadı',
            message: error.message
        });
    }
});

